window.HADITH_CACHE["darimi_3"] = {"1501":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ يَعْنِي ابْنَ أَبِي خَالِدٍ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ أَنَّهُ قَالَ لِعَائِشَةَ يَا أُمَّ الْمُؤْمِنِينَ إِنَّ رِجَالًا يَبْعَثُ أَحَدُهُمْ بِالْهَدْيِ مَعَ الرَّجُلِ فَيَقُولُ إِذَا بَلَغْتَ مَكَانَ كَذَا وَكَذَا فَقَلِّدْهُ فَإِذَا بَلَغَ ذَلِكَ الْمَكَانَ لَمْ يَزَلْ مُحْرِمًا حَتَّى يَحِلَّ النَّاسُ قَالَ فَسَمِعْتُ صَفْقَتَهَا بِيَدِهَا مِنْ وَرَاءِ الْحِجَابِ وَقَالَتْ لَقَدْ كُنْتُ أَفْتِلُ الْقَلَائِدَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْعَثُ بِالْهَدْيِ إِلَى الْكَعْبَةِ مَا يَحْرُمُ عَلَيْهِ شَيْءٌ مِمَّا يَحِلُّ لِلرَّجُلِ مِنْ أَهْلِهِ حَتَّى يَرْجِعَ النَّاسُ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il yaitu Ibnu Abu Khalid] dari ['Amir] dari [Masruq] bahwa ia bertanya kepada ['Aisyah]; \"Wahai Ummul mukminin, salah seorang laki-laki mengirimkan hewan kurbannya kepada laki-laki lain dan berkata; \"Apabila kamu telah sampai pada tempat ini dan itu, kalungilah hewan kurban tersebut.\" Ketika laki-laki (yang diperintah) sampai di tempat tersebut, ternyata ia masih dalam keadaan ihram, hingga orang-orang selesai bertahallul.\" Musruq berkata; lalu saya mendengar tepuk tangannya dari balik hijab, 'Aisyah lalu berkata; \"Sungguh, aku telah memintal kalung-kalung untuk hewan kurban Rasulullah shallallahu 'alaihi wasallam, kemudian beliau mengirim hewan kurbannya ke Ka'bah, Segala sesuatu yang halal bagi seorang suami terhadap isterinya menjadi haram hingga orang-orang kembali (dari melaksanakan haji).\""},"1502":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَعَمْرَةُ بِنْتُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ قَالَتْ كُنْتُ أَفْتِلُ قَلَائِدَ هَدْيِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَبْعَثُ بِهَدْيِهِ مُقَلَّدَةً وَيُقِيمُ بِالْمَدِينَةِ وَلَا يَجْتَنِبُ شَيْئًا حَتَّى يُنْحَرَ هَدْيُهُ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku ['Urwah bin Az Zubair] dan ['Amrah binti Abdurrahman] bahwa ['Aisyah] berkata; \"Aku pernah memintal kalung-kalung hewan kurban Rasulullah shallallahu 'alaihi wasallam, kemudian beliau mengirim hewan kurbannya dalam keadaan mengenakan kalung, beliau bermukim di Madinah serta tidak menjauhi apapun hingga hewan kurbannya disembelih.\""},"1503":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا وَكِيعٌ حَدَّثَنَا إِسْرَائِيلُ عَنْ إِبْرَاهِيمَ بْنِ مُهَاجِرٍ عَنْ يُوسُفَ بْنِ مَاهَكَ عَنْ أُمِّهِ مُسَيْكَةَ وَأَثْنَى عَلَيْهَا خَيْرًا عَنْ عَائِشَةَ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ أَلَا نَبْنِي لَكَ بِمِنًى بِنَاءً يُظِلُّكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا مِنًى مُنَاخُ مَنْ سَبَقَ","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami [Waki'] telah menceritakan kepada kami [Isra'il] dari [Ibrahim bin Muhajir] dari [Yusuf bin Mahak] dari [Ibunya yaitu Musaikah] -ia memujinya dengan pujian yang baik- dari ['Aisyah], ia berkata; \"Aku bertanya; \"Wahai Rasulullah, tidakkah kami membangunkan suatu bangunan di Mina untuk menaungimu? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, Mina adalah tempat persinggahan orang-orang terdahulu.\""},"1504":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ خَالِدٍ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ ابْنِ شِهَابٍ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ عَامَ الْفَتْحِ وَعَلَى رَأْسِهِ مِغْفَرٌ فَلَمَّا نَزَعَهُ جَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا ابْنُ خَطَلٍ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتُلُوهُ قَالَ عَبْدُ اللَّهِ بْنُ خَالِدٍ وَقُرِئَ عَلَى مَالِكٍ قَالَ قَالَ ابْنُ شِهَابٍ وَلَمْ يَكُنْ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ مُحْرِمًا","id":"Telah mengabarkan kepada kami [Abdullah bin Khalid] telah menceritakan kepada kami [Malik bin Anas] dari [Ibnu Syihab] dari [Anas bin Malik] bahwa Rasulullah shallallahu 'alaihi wasallam memasuki Makkah pada tahun penaklukan Mekkah dan di atas kepala beliau terdapat topi besi. Tatkala beliau melepasnya, seorang laki-laki datang kepada beliau sambil berkata; \"Wahai Rasulullah, Ibnu Khathal bergantungan pada tirai Ka'bah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bunuhlah dia! \" Abdullah bin Khalid berkata; telah dibacakan kepada Malik, ia berkata; Ibnu Syihab berkata; \"Pada saat itu, Rasulullah shallallahu 'alaihi wasallam tidak dalam keadaan berihram.\""},"1505":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ أَبَانَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمَّارٍ الدُّهْنِيُّ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَكَّةَ حِينَ افْتَتَحَهَا وَعَلَيْهِ عِمَامَةٌ سَوْدَاءُ بِغَيْرِ إِحْرَامٍ قَالَ إِسْمَعِيلُ سَمِعَهُ مِنْ أَبِي الزُّبَيْرِ كَانَ مَعَ أَبِيهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Aban] telah menceritakan kepada kami [Mu'awiyah bin 'Ammar Ad Duhni] dari [Abu Az Zubair] dari [Jabir], ia berkata; Ketika penaklukan kota Makkah, Nabi shallallahu 'alaihi wasallam memasuki Makkah dengan memakai sorban hitam, tidak dalam keadaan berihram.\" [Isma'il] mengatakan; \"Mu'awiyah mendengarnya dari Abu Az Zubair, ketika dia bersama ayahnya.\""},"1506":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي الْحَسَنُ بْنُ مُسْلِمٍ وَعَبْدُ الْكَرِيمِ الْجَزَرِيُّ أَنَّ مُجَاهِدًا أَخْبَرَهُمَا أَنَّ عَبْدَ الرَّحْمَنِ بْنَ أَبِي لَيْلَى أَخْبَرَهُ أَنَّ عَلِيًّا أَخْبَرَهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يَقُومَ عَلَى بُدْنِهِ وَأَنْ يَقْسِمَ بُدْنَهُ كُلَّهَا لُحُومَهَا وَجُلُودَهَا وَجِلَالَهَا وَلَا يُعْطِيَ فِي جِزَارَتِهَا مِنْهَا شَيْئًا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Al Hasan bin Muslim] dan [Abdul Karim Al Jazari] bahwa [Mujahid] telah mengabarkan kepada mereka bahwa [Abdurrahman bin Abu Laila] telah mengabarkan kepadanya bahwa [Ali] telah mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam memerintahkannya agar mengurusi unta kurbannya dan membagikan seluruh unta tersebut, baik dagingnya, kulitnya serta sesuatu yang ada di punggungnya, dan tidak memberi sesuatupun darinya kepada penjagal, karena penyembelihan unta tersebut.\""},"1507":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي عَمَّارٍ عَنْ جَابِرٍ قَالَ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الضَّبُعِ فَقَالَ هُوَ صَيْدٌ وَفِيهِ كَبْشٌ إِذَا أَصَابَهُ الْمُحْرِمُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Jarir bin Hazim], ia berkata; saya mendengar [Abdullah bin 'Ubaid bin 'Umair] dari [Abdurrahman bin Abu 'Ammar] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah ditanya mengenai Dhabu' (sejenis anjing hutan), beliau bersabda: \"Itu adalah hewan buruan, dan padanya terdapat denda seekor domba, jika orang yang sedang berihram membunuhnya.\""},"1508":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي عَمَّارٍ قَالَ سَأَلْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ عَنْ الضَّبُعِ آكُلُهُ قَالَ نَعَمْ قُلْتُ هُوَ صَيْدٌ قَالَ نَعَمْ قُلْتُ سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نَعَمْ قِيلَ لِأَبِي مُحَمَّدٍ مَا تَقُولُ فِي الضَّبُعِ تَأْكُلُهُ قَالَ أَنَا أَكْرَهُ أَكْلَهُ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abdullah bin 'Ubaid bin 'Umair] dari [Abdurrahman bin Abdullah bin Abu 'Ammar], ia berkata; aku bertanya kepada [Jabir bin Abdullah] mengenai Dhabu' (sejenis anjing hutan) apakah aku boleh memakannya?\" Jabir menjawab; \"Ya.\" Aku bertanya lagi; \"Apakah itu hewan buruan?\" Jabir menjawab; \"Ya.\" Aku bertanya; \"Apakah engkau mendengarnya dari Rasulullah shallallahu 'alaihi wasallam?\" Jabir menjawab; \"Ya.\" Abu Muhammad ditanya; \"Apa pendapatmu mengenai Dhabu', apakah kamu memakannya?\" Abu Muhammad menjawab; \"Aku tidak suka memakannya.\""},"1509":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ الْعَّبَاسَ بْنَ عَبْدِ الْمُطَّلِبِ اسْتَأْذَنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَبِيتَ بِمَكَّةَ لَيَالِيَ مِنًى مِنْ أَجْلِ سِقَايَتِهِ فَأَذِنَ لَهُ حَدَّثَنَا سَعِيدُ بْنُ الْمُغِيرَةِ عَنْ عِيسَى بْنِ يُونُسَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] bahwa Al Abbas bin Abdul Muththalib meminta izin kepada Rasulullah shallallahu 'alaihi wasallam untuk bermalam di Makkah pada malam (mabit) di Mina, dalam rangka untuk memberi minum orang-orang yang berhaji. Kemudian beliau memberinya izin.\" Telah menceritakan kepada kami [Sa'id bin Al Mughirah] dari [Isa bin Yunus] dari ['Ubaidullah bin Umar] seperti hadits di atas."},"1510":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ ضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ أَمْلَحَيْنِ أَقْرَنَيْنِ وَيُسَمِّي وَيُكَبِّرُ لَقَدْ رَأَيْتُهُ يَذْبَحُهُمَا بِيَدِهِ وَاضِعًا عَلَى صِفَاحِهِمَا قَدَمَهُ قُلْتُ أَنْتَ سَمِعْتَهُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Qatadah] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan dua domba belang (warna putih lebih banyak dari yang hitam) dan bertanduk, beliau menyebut nama Allah dan bertakbir. Sungguh aku melihat beliau menyembelih keduanya dengan tangannya dengan meletakkan kakinya di pangkal leher domba tersebut.\""},"1511":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ خَالِدٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي عَيَّاشٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ ضَحَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِكَبْشَيْنِ فِي يَوْمِ الْعِيدِ فَقَالَ حِينَ وَجَّهَهُمَا { إِنِّي وَجَّهْتُ وَجْهِيَ لِلَّذِي فَطَرَ السَّمَوَاتِ وَالْأَرْضَ حَنِيفًا وَمَا أَنَا مِنْ الْمُشْرِكِينَ } { إِنَّ صَلَاتِي وَنُسُكِي وَمَحْيَايَ وَمَمَاتِي لِلَّهِ رَبِّ الْعَالَمِينَ لَا شَرِيكَ لَهُ وَبِذَلِكَ أُمِرْتُ وَأَنَا أَوَّلُ الْمُسْلِمِينَ } اللَّهُمَّ إِنَّ هَذَا مِنْكَ وَلَكَ عَنْ مُحَمَّدٍ وَأُمَّتِهِ ثُمَّ سَمَّى اللَّهَ وَكَبَّرَ وَذَبَحَ","id":"Telah mengabarkan kepada kami [Ahmad bin Khalid] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Abu Abbas] dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam berkurban dengan dua domba pada hari raya (Kurban), ketika beliau menghadapkan dua ekor domba tersebut (kea rah Kiblat), beliau mengucapkan: \"INNII WAJJAHTU WAJHIYA LILLADZII FATHARAS SAMAAWAATI WAL ARDHA HANIIFAN WA MAA ANA MINAL MUSYRIKIIN, INNA SHALAATII WA NUSUKII WA MAHYAAYA WA MAMAATII LILLAAHI RABBIL 'AALAMIIN LAA SYARIIKA LAHU WA BIDZAALIKA UMIRTU WA ANA AWWALUL MUSLIMIIN. ALLAHUMMA INNA HADZA MINKA WA LAKA 'AN MUHAMMAD WA UMMATIHI. (Aku hadapkan wajahku kepada Dzat yang telah menciptakan langit dan bumi, secara lurus, dan aku bukan termasuk orang-orang yang musyrik. Sesungguhnya shalatku, ibadahku, dan kehidupanku serta matiku adalah milik Allah, Rabb semesta alam) Ya Allah, sesungguhnya ini adalah dari-Mu dan untuk-Mu, dari Muhammad dan ummatnya.\" Kemudian beliau menyebut nama Allah dan bertakbir, setelah itu beliau menyembelihnya.\""},"1512":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي خَالِدٌ يَعْنِي ابْنَ يَزِيدَ حَدَّثَنِي سَعِيدٌ يَعْنِي ابْنَ أَبِي هِلَالٍ عَنْ عَمْرِو بْنِ مُسْلِمٍ قَالَ أَخْبَرَنِي ابْنُ الْمُسَيَّبِ أَنَّ أُمَّ سَلَمَةَ أَخْبَرَتْهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ أَرَادَ أَنْ يُضَحِّيَ فَلَا يُقَلِّمْ أَظْفَارَهُ وَلَا يَحْلِقْ شَيْئًا مِنْ شَعْرِهِ فِي الْعَشْرِ الْأُوَلِ مِنْ ذِي الْحِجَّةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Khalid yaitu Ibnu Yazid] telah menceritakan kepadaku [Sa'id yaitu Ibnu Abu Hilal] dari ['Amru bin Muslim], ia berkata; telah mengabarkan kepadaku [Ibnu Al Musayyab] bahwa [Ummu Salamah] telah mengabarkan kepadanya dari Rasulullah shallallahu 'alaihi wasallam, belaiu bersabda: \"Barangsiapa hendak berkurban, maka janganlah ia memotong kuku hewan kurbannya, dan mencukur bulu hwan tersebut pada sepuluh hari pertama bulan Dzul Hijjah.\""},"1513":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ حُمَيْدٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا دَخَلَتْ الْعَشْرُ وَأَرَادَ أَحَدُكُمْ أَنْ يُضَحِّيَ فَلَا يَمَسَّ مِنْ شَعْرِهِ وَلَا أَظْفَارِهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Abdurrahman bin Humaid] dari [Sa'id bin Al Musayyab] dari [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila telah masuk sepuluh hari pertama pada bulan Dzul Hijjah dan salah seorang diantara kalian hendak berkurban, maka janganlah ia memotong sebagian rambut dan kuku hwan kurbannya sedikitpun.\""},"1514":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ عُبَيْدِ بْنِ فَيْرُوزَ عَنْ الْبَرَاءِ بْنِ عَازِبٍ قَالَ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يُتَّقَى مِنْ الضَّحَايَا قَالَ الْعَوْرَاءُ الْبَيِّنُ عَوَرُهَا وَالْعَرْجَاءُ الْبَيِّنُ ظَلْعُهَا وَالْمَرِيضَةُ الْبَيِّنُ مَرَضُهَا وَالْعَجْفَاءُ الَّتِي لَا تُنْقِي","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari ['Amru bin Al Harits] dari ['Ubaid bin Fairuz] dari [Al Bara` bin 'Azib], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai apa yang perlu dihindari dari hewan kurban?\" Beliau menjawab: \"Yang buta sebelah matanya dan jelas kebutaannya, yang pincang dan jelas pincangnya, yang sakit dan jelas sakitnya, dan yang retak kakinya dan tidak dapat berdiri tegak.\""},"1515":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُبَيْدِ بْنِ فَيْرُوزَ قَالَ سَأَلْتُ الْبَرَاءَ عَمَّا نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْأَضَاحِيِّ فَقَالَ أَرْبَعٌ لَا يُجْزِئْنَ الْعَوْرَاءُ الْبَيِّنُ عَوَرُهَا وَالْعَرْجَاءُ الْبَيِّنُ ظَلْعُهَا وَالْمَرِيضَةُ الْبَيِّنُ مَرَضُهَا وَالْكَسِيرُ الَّتِي لَا تُنْقِي قَالَ قُلْتُ لِلْبَرَاءِ فَإِنِّي أَكْرَهُ أَنْ يَكُونَ فِي السِّنِّ نَقْصٌ وَفِي الْأُذُنِ نَقْصٌ وَفِي الْقَرْنِ نَقْصٌ قَالَ فَمَا كَرِهْتَ فَدَعْهُ وَلَا تُحَرِّمْهُ عَلَى أَحَدٍ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Sulaiman bin Abdurrahman] dari ['Ubaid bin Fairuz], ia berkata; saya bertanya kepada [Al Bara`] mengenai hewan kurban yang dilarang Rasulullah shallallahu 'alaihi wasallam. Al Barra` menjawab; Empat hal yang tidak layak (untuk dijadikan kurban), yaitu; buta sebelah matanya yang jelas kebutaannya, pincang yang jelas pincangnya, sakit yang jelas sakitnya, dan cacat kakinya yang tidak memiliki dapat berdiri tegak.\" 'Ubaid bin Fairuz berkata; aku katakan kepada Al Bara`; \"Sesungguhnya aku tidak suka bila terdapat kekurangan pada usianya, cacat pada telinganya, dan cacat pada tanduknya.\" Al Barra` menjawab; \"Apa yang tidak kamu sukai, maka tinggalkanlah dan jangan kamu mengharamkannya kepada orang lain.\""},"1516":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ حُجَيَّةَ بْنَ عَدِيٍّ قَالَ سَمِعْتُ عَلِيًّا وَسَأَلَهُ رَجُلٌ فَقَالَ يَا أَمِيرَ الْمُؤْمِنِينَ الْبَقَرَةُ فَقَالَ عَنْ سَبْعَةٍ قُلْتُ الْقَرْنُ قَالَ لَا يَضُرُّكَ قَالَ قُلْتُ الْعَرَجُ قَالَ إِذَا بَلَغَتْ الْمَنْسَكَ ثُمَّ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail], ia berkata; saya mendengar [Hujayyah bin 'Adi] ia berkata; saya mendengar [Ali] ketika ia ditanya oleh seseorang, laki-llaki itu berkata; \"Wahai amirul mukminin, (untuk berapa orangkah) seekor sapi?\" Ali menjawab; \"Untuk tujuh orang.\" Aku bertanya lagi; \"Bagaimana jika bertanduk? Ali menjawab; \"Tidak mengapa.\" Hujayyah melanjutkan; aku bertanya lagi; \"Bagaimana jika pincang?\" Ali menjawab; \"Apabila telah sampai tempat penyembelihan, maka sembelihlah.\" Kemudian Ali berkata; \"Rasulullah shallallahu 'alaihi wasallam telah memerintahkan kami agar meneliti mata dan telinganya.\""},"1517":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ شُرَيْحِ بْنِ النُّعْمَانِ الصَّائِدِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ نَسْتَشْرِفَ الْعَيْنَ وَالْأُذُنَ وَأَنْ لَا نُضَحِّيَ بِمُقَابَلَةٍ وَلَا مُدَابَرَةٍ وَلَا خَرْقَاءَ وَلَا شَرْقَاءَ فَالْمُقَابَلَةُ مَا قُطِعَ طَرَفُ أُذُنِهَا وَالْمُدَابَرَةُ مَا قُطِعَ مِنْ جَانِبِ الْأُذُنِ وَالْخَرْقَاءُ الْمَثْقُوبَةُ وَالشَّرْقَاءُ الْمَشْقُوقَةُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Israil] dari [Abu Ishaq] dari [Syuraih bin An Nu'aim Ash Sha`idi] dari [Ali] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami agar memeriksa mata, dan telinga serta agar kami tidak berkurban dengan muqabalah, mudabarah, kharqa` dan syarqa`. Muqabalah adalah hewan yang ujung telingannya terpotong, mudabarah adalah hewan yang samping telingannya terpotong, kharqa` adalah hewan yang telinganya dilubangi, sedangkan syarqa` adalah hewan yang telingannya terbelah.\""},"1518":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ بَعْجَةَ الْجُهَنِيِّ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَ قَسَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَحَايَا بَيْنَ أَصْحَابِهِ فَأَصَابَنِي جَذَعٌ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهَا صَارَتْ لِي جَذَعَةٌ فَقَالَ ضَحِّ بِهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Ba'jah Al Juhani] dari ['Uqbah bin 'Amir Al Juhani], ia berkata; Rasulullah shallallahu 'alaihi wasallam membagi-bagikan binatang kurban kepada para sahabatnya, kemudian aku mendapatkan jada'. Aku pun berkata; \"Wahai Rasulullah, aku hanya mendapatkan jada'!.\" Beliau bersabda: \"Berkurbanlah dengannya.\" "},"1519":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ أَعْطَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَنَمًا أَقْسِمُهَا عَلَى أَصْحَابِهِ فَقَسَمْتُهَا وَبَقِيَ مِنْهَا عَتُودٌ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ضَحِّ بِهِ قَالَ أَبُو مُحَمَّد الْعَتُودُ الْجَذَعُ مِنْ الْمَعْزِ","id":"Telah mengabarkan kepada [Abu Al Walid] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberiku beberapa ekor kambing yang aku bagikan kepada para sahabat beliau, setelah aku membagi-bagikan hewan kurban tersebut, ternyata masih tersisa seekor anak kambing. Lalu aku beritahukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Berkurbanlah dengannya.\" Abu Muhammad mengatakan; 'Atud adalah kambing yang berusia antara enam bulan hingga satu tahun."},"1520":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ نَحَرْنَا يَوْمَ الْحُدَيْبِيَةِ سَبْعِينَ بَدَنَةً الْبَدَنَةُ عَنْ سَبْعَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اشْتَرِكُوا فِي الْهَدْيِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Sufyan] dari [Abu Az Zubair] dari [Jabir], ia berkata; Ketika kami berada di Hudaibiyah, kami menyembelih tujuh puluh unta, satu unta untuk tujuh orang. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bergabunglah dalam menyembelih hewan kurban tersebut.\""},"1521":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ نَحَرْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَقَرَةَ عَنْ سَبْعَةٍ قِيلَ لِأَبِي مُحَمَّدٍ تَقُولُ بِهِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abu Az Zubair] dari [Jabir bin Abdullah], ia berkata; \"Kami pernah menyembelih seekor sapi bersama Rasulullah shallallahu 'alaihi wasallam untuk tujuh orang. Abu Muhammad ditanya; \"Apakah anda berpendapat demikian?\" dia menjawab; \"Ya.\""},"1522":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ لُحُومِ الْأَضَاحِيِّ أَوْ قَالَ لَا تَأْكُلُوا لُحُومَ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang memakan daging kurban, atau beliau bersabda: \"Janganlah kalian memakan daging kurban setelah tiga hari.\""},"1523":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدٍ هُوَ ابْنُ عَبْدِ اللَّهِ الطَّحَّانُ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمَلِيحِ عَنْ نُبَيْشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّا كُنَّا نَهَيْنَاكُمْ عَنْ لُحُومِ الْأَضَاحِيِّ أَنْ تَأْكُلُوهَا فَوْقَ ثَلَاثَةِ أَيَّامٍ كَيْ تَسَعَكُمْ فَقَدْ جَاءَ اللَّهُ بِالسَّعَةِ فَكُلُوا وَادَّخِرُوا وَاتَّجِرُوا قَالَ أَبُو مُحَمَّد اتَّجِرُوا اطْلُبُوا فِيهِ الْأَجْرَ","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] dari [Khalid yaitu Abdullah Ath Thahhan] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Malih] dari [Nubaisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya kami melarang kalian memakan hewan kurban lebih dari tiga hari agar kalian merasa lapang, sungguh Allah telah memberikan kelapangan kepada kalian, oleh karena itu makan, simpan dan carilah pahala.\" Abu Muhammad berkata; \"Ittajiru maknanya carilah pahala padanya.\""},"1524":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَهَى عَنْ لُحُومِ الْأَضَاحِيِّ بَعْدَ ثَلَاثٍ فَلَمَّا كَانَ الْعَامُ الْقَابِلُ وَضَحَّى النَّاسُ قُلْتُ يَا رَسُولَ اللَّهِ إِنْ كَانَتْ هَذِهِ الْأَضَاحِيُّ لَتَرْفُقُ بِالنَّاسِ كَانُوا يَدَّخِرُونَ مِنْ لُحُومِهَا وَوَدَكِهَا قَالَ فَمَا يَمْنَعُهُمْ مِنْ ذَلِكَ الْيَوْمَ قُلْتُ يَا نَبِيَّ اللَّهِ أَوَ لَمْ تَنْهَهُمْ عَامَ أَوَّلَ عَنْ أَنْ يَأْكُلُوا لُحُومَهَا فَوْقَ ثَلَاثٍ فَقَالَ إِنَّمَا نَهَيْتُ عَنْ ذَلِكَ لِلْحَاضِرَةِ الَّتِي حَضَرَتْهُمْ مِنْ أَهْلِ الْبَادِيَةِ لِيَنُثُّوا لُحُومَهَا فِيهِمْ فَأَمَّا الْآنَ فَلْيَأْكُلُوا وَلْيَدَّخِرُوا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad bin Ishaq] telah menceritakan kepadaku [Abdullah bin Abu Bakr] dari ['Amrah binti Abdurrahman] dari ['Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang memakan daging kurban setelah tiga hari. Ketika tiba tahun berikutnya, orang-orang banyak yang berkurban, aku pun berkata; \"Wahai Rasulullah, apabila daging hewan-hewan kurban ini dibagikan kepada orang-orang, niscaya mereka akan menyimpan sebagian daging dan lemaknya.\" Beliau bersabda: \"Lalu apa yang menghalangi mereka untuk tidak melakukan hal itu pada hari ini?\" aku berkata; \"Wahai Nabiyullah, bukankah anda telah melarang mereka untuk memakan dagingnya pada tahun lalu yaitu jika lewat tiga hari?\" Beliau bersabda: \"Sesungguhnya aku melarang hal itu untuk sekelompok orang yang datang dari suatu negeri agar mereka dapat membagikan daging tersebut diantara mereka. Adapun sekarang, mereka boleh memakannya dan menyimpannya.\""},"1525":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي مُحَمَّدُ بْنُ الْوَلِيدِ الزَّبِيدِيُّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ جُبَيْرِ بْنِ نُفَيْرٍ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ قَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ بِمِنًى أَصْلِحْ لَنَا مِنْ هَذَا اللَّحْمِ فَأَصْلَحْتُ لَهُ مِنْهُ فَلَمْ يَزَلْ يَأْكُلُ مِنْهُ حَتَّى بَلَغْنَا الْمَدِينَةَ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepadaku [Muhammad bin Al Walid Az Zabidi] dari [Abdurrahman bin Jubair bin Nufair] telah menceritakan kepadaku [Ayahku] bahwa ia mendengar [Tsauban] bekas budak Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepadaku, sementara kami berada di Mina: \"Simpanlah sebagian daging ini sebagai perbekalan.\" Kemudian aku pun menyimpan sebagian dari daging tersebut sebagai bekal. Dan beliau masih memakan sebagian dari daging tersebut hingga kami tiba di Madinah.\""},"1526":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرِو بْنِ دِينَارٍ قَالَ سَمِعْتُ عَطَاءً قَالَ سَمِعْتُ جَابِرًا يَقُولُ إِنْ كُنَّا لَنَتَزَوَّدُ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَبُو مُحَمَّد يَعْنِي لُحُومَ الْأَضَاحِيِّ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari ['Amru bin Dinar], ia berkata; aku mendengar [Atha`] berkata; aku mendengar [Jabir] berkata; \"Pada masa Rasulullah shallallahu 'alaihi wasallam, kami biasa membawa bekal dari Makkah menuju Madinah.\" Abu Muhammad berkata; \"Yaitu (membawa bekal) daging binatang kurban.\""},"1527":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ وَزُبَيْدٍ عَنْ الشَّعْبِيِّ عَنْ الْبَرَاءِ بْنِ عَازِبٍ أَنَّ أَبَا بُرْدَةَ بْنَ نِيَارٍ ضَحَّى قَبْلَ أَنْ يُصَلِّيَ فَلَمَّا صَلَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَعَاهُ فَذَكَرَ لَهُ مَا فَعَلَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا شَاتُكَ شَاةُ لَحْمٍ فَقَالَ يَا رَسُولَ اللَّهِ عِنْدِي عَنَاقٌ لِي جَذَعَةٌ مِنْ الْمَعْزِ هِيَ أَحَبُّ إِلَيَّ مِنْ شَاتَيْنِ قَالَ فَضَحِّ بِهَا وَلَا تُجْزِئُ عَنْ أَحَدٍ بَعْدَكَ قَالَ أَبُو مُحَمَّد قُرِئَ عَلَى مُحَمَّدٍ عَنْ سُفْيَانَ وَمَنْ ذَبَحَ بَعْدَ الصَّلَاةِ وَالْإِمَامُ يَخْطُبُ أَجْزَأَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dan [Zubaid] dari [Asy Sya'bi] dari [Al Bara` bin 'Azib] bahwa Abu Burdah bin Niyar telah berkurban sebelum melakukan shalat (iedul Adha), Seusai shalat, Nabi shallallahu 'alaihi wasallam memanggilnya, Abu Burdah pun memberitahukan apa yang telah ia lakukan. Lantas Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Sesungguhnya kambingmu hanya berupa daging biasa (bukan daging kurban).\" Abu Burdah berkata; \"Wahai Rasulullah, aku masih memiliki anak kambing betina, yaitu jada' yang lebih aku sukai daripada dua ekor kambing.\" Beliau bersabda: \"Berkurbanlah dengannya, namun kambing tersebut tidak layak lagi bagi seorangpun setelahmu.\" Abu Muhammad berkata; telah di bacakan kepada Muhammad dari Sufyan; \"Barangsiapa menyembelih binatang kurban setelah shalat (iedul adha), yaitu saat imam berkhutbah, maka hal itu sah baginya.\""},"1528":{"ar":" حَدَّثَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ حَدَّثَنَا مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ بُشَيْرِ بْنِ يَسَارٍ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ أَنَّ رَجُلًا ذَبَحَ قَبْلَ أَنْ يَنْصَرِفَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُعِيدَ","id":"Telah menceritakan kepada kami [Abu Ali Al Hanafi] telah menceritakan kepada kami [Malik] dari [Yahya bin Sa'id] dari [Busyair bin Yasar] dari [Abu Burdah bin Niyar] bahwa seorang laki-laki menyembelih kurban sebelum Nabi shallallahu 'alaihi wasallam shalat (ied), kemudian beliau memerintahkannya supaya mengulang (kurbannya).\""},"1529":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا فَرَعَ وَلَا عَتِيرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada fara' dan tidak ada 'atirah.\" "},"1530":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو عَوَانَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ وَكِيعِ بْنِ حُدُسٍ عَنْ أَبِي رَزِينٍ الْعُقَيْلِيِّ لَقِيطِ بْنِ عَامِرٍ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّا كُنَّا نَذْبَحُ فِي رَجَبٍ فَمَا تَرَى قَالَ لَا بَأْسَ بِذَلِكَ قَالَ وَكِيعٌ لَا أَدَعُهُ أَبَدًا","id":"Telah menceritakan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu 'Awanah] dari [Ya'la bin 'Atha`] dari [Waki' bin Hudus] dari [Abu Razin Al 'Uqaili Laqith bin Amir], ia berkata; aku bertanya; \"Wahai Rasulullah, sesungguhnya kami telah menyembelih penyembelihan pada bulan Rajab, apa pendapat anda? Beliau bersabda: \"Tidak mengapa dengan hal tersebut.\" Waki' berkata; \"Aku tidak akan meninggalkannya selamanya.\""},"1531":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ حَبِيبَةَ بِنْتِ مَيْسَرَةَ بْنِ أَبِي خُثَيْمٍ عَنْ أُمِّ كُرْزٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي الْعَقِيقَةِ عَنْ الْغُلَامِ شَاتَانِ مُكَافِئَتَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku ['Atha`] dari [Habibah binti Maisarah bin Abu Khutsaim] dari [Ummu Kurz] dari Nabi shallallahu 'alaihi wasallam beliau bersabda mengenai aqiqah: \"Untuk anak laki-laki dua kambing yang sama dan untuk anak perempuan satu kambing.\""},"1532":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ هِشَامٍ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ سَلْمَانَ بْنِ عَامِرٍ الضَّبِّيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَعَ الْغُلَامِ عَقِيقَةٌ فَأَهْرِيقُوا عَنْهُ الدَّمَ وَأَمِيطُوا عَنْهُ الْأَذَى","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Hisyam] dari [Hafshah binti Sirin] dari [Salman bin 'Amir Adh Dhabbi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bersama seorang anak laki-laki terdapat aqiqah, maka sembelihlah untuknya dan hilangkan gangguan darinya.\""},"1533":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْغُلَامِ شَاتَانِ مِثْلَانِ وَعَنْ الْجَارِيَةِ شَاةٌ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Ubaidullah bin Abu Yazid] dari [Siba' bin Tsabit] dari [Ummu Kurz], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"('Aqiqah) untuk anak laki-laki dua ekor kambing yang sama (umurnya) dan untuk anak perempuan satu ekor kambing.\""},"1534":{"ar":" أَخْبَرَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ كُلُّ غُلَامٍ رَهِينَةٌ بِعَقِيقَتِهِ يُذْبَحُ عَنْهُ يَوْمَ سَابِعِهِ وَيُحْلَقُ وَيُدَمَّى وَكَانَ قَتَادَةُ يَصِفُ الدَّمَ فَيَقُولُ إِذَا ذُبِحَتْ الْعَقِيقَةُ تُؤْخَذُ صُوفَةٌ فَيُسْتَقْبَلُ بِهَا أَوْدَاجُ الذَّبِيحَةِ ثُمَّ تُوضَعُ عَلَى يَافُوخِ الصَّبِيِّ حَتَّى إِذَا سَالَ شَبَهُ الْخَيْطِ غُسِلَ رَأْسُهُ ثُمَّ حُلِقَ بَعْدُ قَالَ عَفَّانُ حَدَّثَنَا أَبَانُ بِهَذَا الْحَدِيثِ قَالَ وَيُسَمَّى قَالَ عَبْد اللَّهِ وَلَا أُرَاهُ وَاجِبًا","id":"Telah mengabarkan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Al Hasan] dari [Samurah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Setiap anak laki-laki tergadaikan dengan aqiqahnya, disembelihkan pada hari ketujuh dan dicukur (rambutnya) serta di alirkan darah (hewan akikah) nya (ke kepalanya).\" Qatadah menjelaskan mengenai darah sembelihan tersebut, ia berkata; \"Apabila hewan aqiqah telah disembelih, maka diambil satu helai bulu domba kemudian urat-urat binatang yang disembelih dihadapkan kepadanya, setelah itu diletakkan pada ubun-ubun anak bayi, apabila telah mengalir seperti satu benang, maka kepalanya di cuci kemudian digundul. ['Affan] berkata; telah menceritakan kepada kami [Aban] dengan hadits ini. Ia berkata; \"Dan di beri nama.\" Abdullah berkata; aku berpendapat hal tersebut tidaklah wajib."},"1535":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْأَشْعَثِ الصَّنْعَانِيِّ عَنْ شَدَّادِ بْنِ أَوْسٍ قَالَ حَفِظْتُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اثْنَتَيْنِ قَالَ إِنَّ اللَّهَ كَتَبَ الْإِحْسَانَ عَلَى كُلِّ شَيْءٍ فَإِذَا قَتَلْتُمْ فَأَحْسِنُوا الْقِتْلَةَ وَإِذَا ذَبَحْتُمْ فَأَحْسِنُوا الذَّبْحَ وَلْيُحِدَّ أَحَدُكُمْ شَفْرَتَهُ ثُمَّ لِيُرِحْ ذَبِيحَتَهُ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Khalid Al Hadzdza`] dari [Abu Qilabah] dari [Abu Al Asy'ats Ash Shan'ani] dari [Syaddad bin Aus], ia berkata; aku hafal dua perkara dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah telah mewajibkan berbuat baik terhadap segala sesuatu, apabila kalian membunuh maka bunuhlah dengan cara yang baik, dan apabila kalian menyembelih, maka sembelihlah dengan cara yang baik, hendaknya salah seorang diantara kalian menajamkan mata pisaunya, dan hendaknya membuat hewan sembelihannya merasa tenang.\""},"1536":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ امْرَأَةً كَانَتْ تَرْعَى لِآلِ كَعْبِ بْنِ مَالِكٍ غَنَمًا بِسَلْعٍ فَخَافَتْ عَلَى شَاةٍ مِنْهَا أَنْ تَمُوتَ فَأَخَذَتْ حَجَرًا فَذَبَحَتْهَا بِهِ وَإِنَّ ذَلِكَ ذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُمْ بِأَكْلِهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya bin Sa'id] dari [Nafi'] dari [Ibnu Umar] bahwa seorang wanita mengembalakan kambing milik keluarga Ka'b bin Malik di daerah Sal' (nama lembah di Madinah), ketika ia khawatir seekor kambingnya akan mati, maka ia mengambil sebongkah batu dan menyembelihnya. Ketika hal itu diberitahukan kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu memerintahkan mereka agar memakannya.\""},"1537":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ وَعُثْمَانُ بْنُ عُمَرَ وَعَفَّانُ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ أَبِي الْعُشَرَاءِ عَنْ أَبِيهِ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ أَمَا تَكُونُ الذَّكَاةُ إِلَّا فِي الْحَلْقِ وَاللَّبَّةِ فَقَالَ لَوْ طَعَنْتَ فِي فَخِذِهَا لَأَجْزَأَ عَنْكَ قَالَ حَمَّادٌ حَمَلْنَاهُ عَلَى الْمُتَرَدِّي","id":"Telah mengabarkan kepada kami [Abu Al Walid], [Utsman bin Umar] dan ['Affan] dari [Hammad bin Salamah] dari [Abu Al 'Usyara`] dari [bapaknya] berkata; Wahai Rasulullah, bukankah penyembelihan itu kecuali hanya pada tenggorokan dan pangkal leher? Beliau menjawab: \"Sekiranya kamu menusuk di bagian pahanya, itu sudah cukup bagimu.\" Hammad menerangkan; Kami mengategorikan hal itu jika hewan itu terperosok atau terjatuh dari tempat yang tinggi."},"1538":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنِي الْمِنْهَالُ بْنُ عَمْرٍو قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ خَرَجْتُ مَعَ ابْنِ عُمَرَ فِي طَرِيقٍ مِنْ طُرُقِ الْمَدِينَةِ فَإِذَا غِلْمَةٌ يَرْمُونَ دَجَاجَةً فَقَالَ ابْنُ عُمَرَ مَنْ فَعَلَ هَذَا فَتَفَرَّقُوا فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَنَ مَنْ يُمَثِّلُ بِالْحَيَوَانِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepadaku [Al Minhal bin 'Amru], ia berkata; aku mendengar [Sa'id bin Jubair] berkata; aku keluar bersama [Ibnu Umar] lewat suatu jalan di Madinah, tiba-tiba kami bertemu dengan anak-anak yang melempari seekor ayam. Lalu Ibnu Umar berkata; \"Siapakah yang melakukan hal ini?\" mereka pun bubar, Ibnu Umar berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melaknat orang yang mencincang hewan.\""},"1539":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ أَبِيهِ عَنْ عُبَيْدِ بْنِ تِعْلَى عَنْ أَبِي أَيُّوبَ الْأَنْصَارِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ صَبْرِ الدَّابَّةِ قَالَ أَبُو أَيُّوبَ لَوْ كَانَتْ دَجَاجَةً مَا صَبَرْتُهَا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyaj] dari [Ayahnya] dari ['Ubaid bin Ti'la] dari [Abu Ayyub Al Anshari] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjadikan hewan sabagai sasaran. Abu Ayyub berkata; \"Seandainya itu adalah seekor ayam, maka aku tidak akan menjadikannya sebagai sasaran (yaitu dengan mengurung hewan dan melemparinya sebagai sasaran hingga mati).\""},"1540":{"ar":" حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا قَتَادَةُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ نَهَى عَنْ الْمُجَثَّمَةِ قَالَ أَبُو مُحَمَّد الْمُجَثَّمَةُ الْمَصْبُورَةُ","id":"Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad] telah mengabarkan kepada kami [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah telah melarang dari mujatstsamah. Abu Muhammad berkata; mujatstsamah adalah mashburah (yaitu mengurung hewan lalu melemparinya sebagai sasaran hingga mati).\""},"1541":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عَبْدُ الرَّحِيمِ هُوَ ابْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أُمِّ الْمُؤْمِنِينَ أَنَّ قَوْمًا قَالُوا يَا رَسُولَ اللَّهِ إِنَّ قَوْمًا يَأْتُونَا بِاللَّحْمِ لَا نَدْرِي أَذُكِرَ اسْمُ اللَّهِ عَلَيْهِ أَمْ لَا فَقَالَ سَمُّوا أَنْتُمْ وَكُلُوا وَكَانُوا حَدِيثَ عَهْدٍ بِجَاهِلِيَّةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Abdurrahim yaitu Ibnu Sulaiman] dari [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah ummul mukminin] bahwa suatu kaum pernah berkata; \"Wahai Rasulullah, sesungguhnya ada suatu kaum datang kepada kami dengan membawa daging, sementara kami tidak mengetahui apakah daging tersebut telah disebutkan nama Allah (ketika menyembelih) ataukah belum?\" Beliau bersabda: \"Sebutlah nama Allah, kemudian makanlah.\" Mereka adalah orang-orang yang masih dekat dengan kejahiliyahan."},"1542":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِيهِ عَنْ عَبَايَةَ بْنِ رِفَاعَةَ بْنِ رَافِعٍ عَنْ جَدِّهِ رَافِعِ بْنِ خَدِيجٍ أَنَّ بَعِيرًا نَدَّ وَلَيْسَ فِي الْقَوْمِ إِلَّا خَيْلٌ يَسِيرَةٌ فَرَمَاهُ رَجُلٌ بِسَهْمٍ فَحَبَسَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ لِهَذِهِ الْبَهَائِمِ أَوَابِدَ كَأَوَابِدِ الْوَحْشِ فَمَا غَلَبَكُمْ مِنْهَا فَاصْنَعُوا بِهِ هَكَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Ayahnya] dari ['Abayah bin Rifa'ah bin Rafi'] dari [kakeknya yaitu Rafi' bin Khadij] bahwa suatu ketika seekor unta kabur, sementara diantara orang-orang tersebut hanya ada kuda yang larinya tidak terlalu kencang, lantas unta tersebut dibidik oleh seorang laki-laki sehingga dapat menangkapnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hewan ini memiliki sifat-sifat yang di miliki oleh binatang liar, oleh Karena itu, bila hewan tersebut tidak dapat kalian kendalikan, maka tempuhlah dengan cara seperti ini.\""},"1543":{"ar":" حَدَّثَنَا أَبُو مَعْمَرٍ إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو هُوَ ابْنُ دِينَارٍ عَنْ صُهَيْبٍ مَوْلَى ابْنِ عَامِرٍ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ عَمْرٍو يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ عُصْفُورًا بِغَيْرِ حَقِّهِ سَأَلَهُ اللَّهُ عَنْهُ يَوْمَ الْقِيَامَةِ قِيلَ وَمَا حَقُّهُ قَالَ أَنْ تَذْبَحَهُ فَتَأْكُلَهُ","id":"Telah menceritakan kepada kami [Abu Ma'mar Isma'il bin Ibrahim] telah menceritakan kepada kami [Sufyan] dari ['Amru yaitu Ibnu Dinar] dari [Shuhaib] bekas budak Ibnu 'Amir, ia berkata; aku mendengar [Abdullah bin 'Amru] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa membunuh seekor burung (pipit) tanpa hak, maka Allah akan meminta pertanggungjawaban kepadanya pada hari Kiamat kelak.\" Beliau ditanya; \"Apakah haknya?\" Beliau menjawab: \"Engkau menyembelih lalu memakannya.\""},"1544":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا عَتَّابُ بْنُ بَشِيرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي زِيَادٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَكَاةُ الْجَنِينِ ذَكَاةُ أُمِّهِ قِيلَ لِأَبِي مُحَمَّدٍ يُؤْكَلُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami ['Attab bin Basyir] dari ['Ubaidullah bin Abu Ziyad] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"(Cara) penyembelihan janin adalah dengan menyembelih induknya.\" Abu Muhammad ditanya; \"Apakah janin tersebut boleh dimakan?\" Dia berkata; \"Ya.\""},"1545":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السَّبُعِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang memakan setiap binatang buas yang bertaring.\""},"1546":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا أَبُو أُوَيْسٍ ابْنُ عَمِّ مَالِكِ بْنِ أَنَسٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ الْخَوْلَانِيِّ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَطْفَةِ وَالْمُجَثَّمَةِ وَالنُّهْبَةِ وَعَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Abu Uwais] sepupu Malik bin Anas dari [Az Zuhri] dari [Abu Idris Al Khaulani] dari [Abu Tsa'labah Al Khusyani], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang memakan bagian (anggota badan) dari hewan yang diterkam oleh binatang buas, sedangkan hewan tersebut masih hidup, menjadikan hewan sebagai sasaran hingga mati, dan mengambil harta yang diambil bukan karena haknya, serta memakan setiap binatang buas yang bertaring.\""},"1547":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ أَبِي بِشْرٍ عَنْ مَيْمُونِ بْنِ مِهْرَانَ عَنْ ابْنِ عَبَّاسٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَكْلِ كُلِّ ذِي نَابٍ مِنْ السِّبَاعِ وَكُلِّ ذِي مِخْلَبٍ مِنْ الطَّيْرِ","id":"Telah mengabarkan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Abu 'Awanah] dari [Abu Bisyr] dari [Maimun bin Mahran] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang memakan setiap binatang buas yang bertaring, dan setiap burung yang memiliki cakar (kuku yang tajam).\""},"1548":{"ar":" أَخْبَرَنَا يَعْمَرُ بْنُ بِشْرٍ عَنْ ابْنِ الْمُبَارَكِ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ جُلُودِ السِّبَاعِ أَنْ تُفْتَرَشَ أَخْبَرَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ أَبِي الْمَلِيحِ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ya'mur bin Bisyr] dari [Ibnu Al Mubarak] dari [Sa'id] dari [Qatadah] dari [Abu Al Malih] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam melarang menjadikan kulit binatang buas sebagai permadani.\" Telah mengabarkan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sa'id] dari [Qatadah] dari [Abu Al Malih] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1549":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ عَنْ الْأَسْقِيَةِ فَقَالَ مَا أَدْرِي مَا أَقُولُ لَكَ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ أَيُّمَا إِهَابٍ دُبِغَ فَقَدْ طَهُرَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Zaid bin Aslam] dari [Abdurrahman bin Wa'lah], ia berkata; aku bertanya kepada [Ibnu Abbas] mengenai wadah minuman, Ibnu Abbas berkata; aku tidak tahu apa yang akan kukatakan kepadamu, hanya saja aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kulit apapun yang telah disamak, maka ia menjadi suci.\""},"1550":{"ar":" حَدَّثَنَا يَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ عَنْ جُلُودِ الْمَيْتَةِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِبَاغُهَا طَهُورُهَا قِيلَ لِأَبِي مُحَمَّدٍ عَبْدِ اللَّهِ تَقُولُ بِهَذَا قَالَ نَعَمْ إِذَا كَانَ يُؤْكَلُ لَحْمُهُ","id":"Telah menceritakan kepada kami [Ya'la] dari [Muhammad bin Ishaq] dari [Al Qa'qa' bin Hakim] dari [Abdurrahman bin Wa'lah], ia berkata; aku pernah bertanya kepada [Ibnu Abbas] mengenai kulit bangkai. Lalu ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kulit binatang yang disamak, maka ia suci.\" Abu Muhammad ditanya; \"Apakah anda berpendapat dengan hal ini?\" Dia menjawab; \"Ya, apabila daging hewan tersebut boleh dimakan.\""},"1551":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ يَزِيدَ بْنِ قُسَيْطٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَ عَنْ أُمِّهِ عَنْ عَائِشَةَ قَالَتْ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُسْتَمْتَعَ بِجُلُودِ الْمَيْتَةِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Yazid bin Qusaith] dari [Muhammad bin Abdurrahman bin Tsauban] dari [ibunya] dari ['Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk memanfaatkan kulit bangkai.\""},"1552":{"ar":" حَدَّثَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ مَاتَتْ شَاةٌ لِمَيْمُونَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ اسْتَمْتَعْتُمْ بِإِهَابِهَا قَالُوا يَا رَسُولَ اللَّهِ إِنَّهَا مَيْتَةٌ قَالَ إِنَّمَا حُرِّمَ أَكْلُهَا أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا بَقِيَّةُ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا الْحَدِيثِ قِيلَ لِأَبِي مُحَمَّدٍ مَا تَقُولُ فِي الثَّعَالِبِ إِذَا دُبِغَتْ قَالَ أَكْرَهُهَا","id":"Telah menceritakan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], ia berkata; \"Kambing Maimunah mati, maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya kalian memanfaatkan kulitnya.\" Mereka berkata; \"Wahai Rasulullah, sesungguhnya kambing tersebut telah menjadi bangkai?.\" Beliau bersabda: \"Sesungguhnya yang diharamkan adalah memakannya.\" Telah mengabarkan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Baqiyyah] dari [Az Zuhri] dari [Az Zubaidi] dari ['Ubaidullah] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Abu Muhammad ditanya; \"Apa pendapat anda mengenai musang apabila disamak kulitnya? Ia menjawab; \"Aku tidak menyukainya.\""},"1553":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ الْحَسَنِ وَعَبْدِ اللَّهِ ابْنَيْ مُحَمَّدٍ عَنْ أَبِيهِمَا عَنْ عَلِيٍّ أَنَّ عَلِيًّا قَالَ لِابْنِ عَبَّاسٍ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ مُتْعَةِ النِّسَاءِ يَوْمَ خَيْبَرَ وَعَنْ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari [Al Hasan] dan [Abdullah] keduanya adalah anak Muhammad, dari [ayah mereka] dari [Ali] bahwa Ali berkata kepada Ibnu Abbas; \"Rasulullah shallallahu 'alaihi wasallam telah melarang nikah mut'ah dan memakan daging keledai jinak pada saat perang Khaibar.\" "},"1554":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَامَ رَجُلٌ يَوْمَ خَيْبَرَ فَقَالَ يَا رَسُولَ اللَّهِ أُكِلَتْ الْحُمُرُ أَوْ أُفْنِيَتْ الْحُمُرُ ثُمَّ قَالَ يَا رَسُولَ اللَّهِ أُفْنِيَتْ الْحُمُرُ أَوْ أُكِلَتْ الْحُمُرُ فَأَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا فَنَادَى إِنَّ اللَّهَ وَرَسُولَهُ يَنْهَيَانِكُمْ عَنْ لُحُومِ الْحُمُرِ فَإِنَّهَا رِجْسٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Hisyam] dari [Ibnu Sirin] dari [Anas bin Malik], ia berkata; \"Pada waktu perang Khaibar, seorang laki-laki berdiri dan berkata; \"Wahai Rasulullah, daging keledai telah dimakan, atau telah dihabisi. Kemudian dia berkata lagi; \"Wahai Rasulullah, daging keledai telah dihabiskan atau telah dimakan.\" Lantas Rasulullah shallallahu 'alaihi wasallam memerintahkan seseorang supaya menyeru: \"Sesungguhnya Allah dan Rasulul-Nya telah melarang kalian memakan daging keledai, karena sesungguhnya daging tersebut najis.\""},"1555":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ فَاطِمَةَ بِنْتِ الْمُنْذِرِ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ قَالَتْ أَكَلْنَا لَحْمَ فَرَسٍ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمَدِينَةِ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Hisyam bin 'Urwah] dari [Fathimah binti Al Mundzir] dari [Asma` binti Abu Bakr], ia berkata; \"Kami pernah memakan daging kuda pada zaman Rasulullah shallallahu 'alaihi wasallam di Madinah.\""},"1556":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ وَأَذِنَ فِي لُحُومِ الْخَيْلِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari ['Amru bin Dinar] dari [Muhammad bin Ali] dari [Jabir bin Abdullah], ia berkata; \"Pada saat perang Khaibar, Rasulullah shallallahu 'alaihi wasallam melarang memakan daging keledai jinak dan mengizinkan makan daging kuda.\""},"1557":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَنْتَهِبُ نُهْبَةً ذَاتَ شَرَفٍ يَرْفَعُ الْمُؤْمِنُونَ فِيهَا أَبْصَارَهُمْ وَهُوَ حِينَ يَنْتَهِبُهَا مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Az Zuhri] dari [Sa'id bin Al Musayyab] dan [Abu Salamah bin Abdurrahman] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam berkata: \"Tidaklah (beriman) orang yang mengkorupsi harta berharga dan menjadi perhatian orang-orang mukmin, ketika mengkorupsinya ia dalam keadaan beriman.\""},"1558":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وَهْبُ بْنُ جَرِيرِ بْنِ حَازِمٍ عَنْ أَبِيهِ عَنْ يَعْلَى بْنِ حَكِيمٍ عَنْ أَبِي لَبِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ النُّهْبَةِ قَالَ أَبُو مُحَمَّد هَذَا فِي الْغَزْوِ إِذَا غَنِمُوا قَبْلَ أَنْ يُقْسَمَ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Wahb bin Jarir bin Hazim] dari [Ayahnya] dari [Ya'la bin Hakim] dari [Abu Labid] dari [Abdurrahman bin Samurah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang korupsi (merampas harta orang lain tanpa hak).\" Abu Muhammad berkata; \"Ini berlaku ketika dalam peperangan, yaitu ketika mereka mendapatkan rampasan perang sebelum dibagikan.\""},"1559":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ الْأَوْزَاعِيِّ عَنْ حَسَّانَ بْنِ عَطِيَّةَ عَنْ أَبِي وَاقِدٍ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ إِنَّا بِأَرْضٍ تَكُونُ بِهَا الْمَخْمَصَةُ فَمَا يَحِلُّ لَنَا مِنْ الْمَيْتَةِ قَالَ إِذَا لَمْ تَصْطَبِحُوا وَلَمْ تَغْتَبِقُوا وَلَمْ تَخْتَفِئُوا بَقْلًا فَشَأْنُكُمْ بِهَا قَالَ النَّاسُ يَقُولُونَ بِالْحَاءِ وَهَذَا قَالَ بِالْخَاءِ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Al Auza'i] dari [Hassan bin 'Athiyyah] dari [Abu Waqid], ia berkata; kami bertanya; \"Wahai Rasulullah, sesungguhnya kami berada di suatu negeri yang penduduknya kelaparan, apakah bangkai menjadi halal bagi kami?\" Beliau bersabda: \"Jika kalian tidak dapat memasak, tidak dapat minum di penghujung siang, dan menemui sayuran apapun, maka makanlah bangkai tersebut.\" Perawi berkata; Para perawi yang lain mengatakan dengan huruf ha` \"Tahtafu\" sedangkan perawi ini mengatakan dengan kha` \"Takhtafu.\""},"1560":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ يَعْقُوبَ بْنِ بَحِيرٍ عَنْ ضِرَارِ بْنِ الْأَزْوَرِ قَالَ أَهْدَيْتُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِقْحَةً فَأَمَرَنِي أَنْ أَحْلُبَهَا فَحَلَبْتُهَا فَجَهَدْتُ فِي حَلْبِهَا فَقَالَ دَعْ دَاعِيَ اللَّبَنِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Ya'qub bin Bahir] dari [Dhirar bin Al Azwar], ia berkata; aku memberi hadiah kepada Rasulullah shallallahu 'alaihi wasallam seekor unta yang memiliki banyak air susu dan hampir melahirkan. Kemudian beliau memerintahkan agar saya memerahnya, akupun memerahnya dan bersungguh-sungguh dalam memerahnya. Lalu beliau bersabda: \"Sisakanlah sedikit susu pada kantongnya, jangan kamu perah semuanya.\""},"1561":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ الْقَارِظِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عُثْمَانَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ قَتْلِ الضِّفْدَعِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id bin Khalid Al Qarizhi] dari [Sa'id bin Al Musayyab] dari [Abdurrahman bin Utsman] bahwa Rasulullah shallallahu 'alaihi wasallam melarang untuk membunuh katak."},"1562":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِ أَرْبَعَةٍ مِنْ الدَّوَابِّ النَّمْلَةِ وَالنَّحْلَةِ وَالْهُدْهُدِ وَالصُّرَدِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya] telah menceritakan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang membunuh empat jenis binatang, yaitu; semut, lebah, burung Hudhud dan burung Shurad."},"1563":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جُبَيْرِ بْنِ شَيْبَةَ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أُمِّ شَرِيكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْأَوْزَاغِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abdul Hamid bin Jubair bin Syaibah] dari [Sa'id bin Al Musayyab] dari [Ummu Syarik] bahwa Nabi shallallahu 'alaihi wasallam merintahkan untuk membunuh tokek."},"1564":{"ar":" حَدَّثَنَا أَبُو زَيْدٍ سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا هِشَامٌ الدَّسْتَوَائِيُّ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُجَثَّمَةِ وَعَنْ لَبَنِ الْجَلَّالَةِ وَأَنْ يُشْرَبَ مِنْ فِي السِّقَاءِ","id":"Telah menceritakan kepada kami [Abu Zaid Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Hisyam Ad Dastawa`i] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam melarang mengurung hewan untuk dijadikan sasaran hingga mati, (meminum) susu hewan pemakan kotoran, serta meminum (langsung) dari mulut geriba.\""},"1565":{"ar":" أَخْبَرَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْكَلْبِ فَقَالَ مَا أَمْسَكَ عَلَيْكَ فَكُلْ فَإِنَّ أَخْذَهُ ذَكَاتُهُ وَإِنْ وَجَدْتَ مَعَهُ كَلْبًا فَخَشِيتَ أَنْ يَكُونَ قَدْ أَخَذَهُ مَعَهُ وَقَدْ قَتَلَهُ فَلَا تَأْكُلْهُ فَإِنَّكَ إِنَّمَا ذَكَرْتَ اسْمَ اللَّهِ عَلَى كَلْبِكَ وَلَمْ تَذْكُرْهُ عَلَى غَيْرِهِ أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَ سَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ صَيْدِ الْمِعْرَاضِ فَذَكَرَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Zakariya] dari ['Amir] dari ['Adi bin Hatim], ia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai buruan anjing. Beliau bersabda: \"Makanlah buruan yang di tangkap oleh anjingmu, sebab tangkapannya adalah penyembelihan bagi hewan tersebut secara syar'I, Dan apabila kamu mendapati bersamanya anjing yang lain dan kamu khawatir anjing yang lain menangkap dan membunuh buruan bersama anjingmu, maka janganlah kamu memakannya, sebab kamu hanya menyebut nama Allah pada anjingmu saja dan tidak menyebut untuk yang lain.\" Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Zakariya] dari ['Amir] dari ['Adi bin Hatim], ia berkata; aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai buruan yang terkena anak panah pada bagian yang tumpul (bukan bagian yang tajam), lalu perawi menyebutkan redaksi hadits yang sama."},"1566":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اقْتَنَى كَلْبًا إِلَّا كَلْبَ صَيْدٍ أَوْ مَاشِيَةٍ نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطَانِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing kecuali anjing pemburu, atau penjaga ternak, maka pahalanya akan berkurang dua Qirath setiap harinya.\""},"1567":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكٌ عَنْ يَزِيدَ بْنِ خُصَيْفَةَ عَنْ السَّائِبِ بْنِ يَزِيدَ أَنَّهُ سَمِعَ سُفْيَانَ بْنَ أَبِي زُهَيْرٍ يُحَدِّثُ نَاسًا مَعَهُ عِنْدَ بَابِ الْمَسْجِدِ فَقَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ اقْتَنَى كَلْبًا لَا يُغْنِي عَنْهُ زَرْعًا وَلَا ضَرْعًا نَقَصَ مِنْ عَمَلِهِ كُلَّ يَوْمٍ قِيرَاطٌ قَالُوا أَنْتَ سَمِعْتَ هَذَا مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِي وَرَبِّ هَذَا الْمَسْجِدِ","id":"Telah menceritakan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik] dari [Yazid bin Khushaifah] dari [As Sa`ib bin Yazid] bahwa ia mendengar [Sufyan bin Abu Zuhair] bercerita kepada orang-orang yang bersamanya di depan pintu masjid, ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memelihara anjing yang tidak di gunakan untuk menjaga tanaman atau (menjaga) binatang ternak, maka pahalanya akan berkurang setiap hari satu qirath.\" Mereka bertanya; \"Apakah anda mendengar hadits ini dari Rasulullah shallallahu 'alaihi wasallam?\" Sufyan menjawab; \"Ya, demi Rabb pemilik masjid ini.\""},"1568":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ عَنْ مُطَرِّفٍ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ بِقَتْلِ الْكِلَابِ ثُمَّ قَالَ مَا بَالِي وَلِلْكِلَابِ ثُمَّ رَخَّصَ فِي كَلْبِ الزَّرْعِ وَكَلْبِ الصَّيْدِ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] dari [Mutharrif] dari [Abdullah bin Mughaffal] bahwa Nabi shallallahu 'alaihi wasallam memerintahkan untuk membunuh seluruh anjing, lalu beliau bersabda: \"Aku tidak memiliki urusan dengan anjing-anjing itu.\" kemudian beliau memberi keringanan pada anjing penjaga tanaman dan anjing untuk berburu."},"1569":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِقَتْلِ الْكِلَابِ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik dari [Nafi'] dari [Ibnu Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memerintahkan untuk membunuh anjing.\""},"1570":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ حَدَّثَنَا عَوْفٌ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ مُغَفَّلٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا أَنَّ الْكِلَابَ أُمَّةٌ مِنْ الْأُمَمِ لَأَمَرْتُ بِقَتْلِهَا كُلِّهَا وَلَكِنْ اقْتُلُوا مِنْهَا كُلَّ أَسْوَدَ بَهِيمٍ قَالَ سَعِيدُ بْنُ عَامِرٍ الْبَهِيمُ الْأَسْوَدُ كُلُّهُ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] telah menceritakan kepada kami ['Auf] dari [Al Hasan] dari [Abdullah bin Mughaffal], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya anjing bukan termasuk salah satu dari berbagai umat, niscaya aku akan memerintahkan untuk membunuh seluruhnya, akan tetapi bunuhlah setiap anjing hitam bahim (legam).\" [Sa'id bin 'Amir] berkata; \"Al Bahim adalah yang hitam seluruhnya.\""},"1571":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ عَدِيَّ بْنَ حَاتِمٍ قَالَ سَأَلْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْمِعْرَاضِ فَقَالَ إِذَا أَصَابَ بِحَدِّهِ فَكُلْ وَإِذَا أَصَابَ بِعَرْضِهِ فَقَتَلَ فَإِنَّهُ وَقِيذٌ فَلَا تَأْكُلْ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi], ia berkata; aku mendengar ['Adi bin Hatim] berkata; aku bertanya kepada Nabi shallallahu 'alaihi wasallam mengenai anak panah yang (mengenai buruan) pada bagian yang tumpul.\" Beliau bersabda: \"Apabila yang mengenai bagian yang tajamnya, maka makanlah dan apabila mengenai bagian yang tumpulnya maka itu adalah hewan yang mati karena terkena benda tumpul, oleh karena itu janganlah kamu memakannya.\""},"1572":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِي يَعْفُورٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي أَوْفَى قَالَ غَزَوْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ نَأْكُلُ الْجَرَادَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abu Ya'fur] dari [Abdullah bin Abu Aufa], ia berkata; \"Kami pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam sebanyak tujuh kali dan hanya memakan belalang.\""},"1573":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ قِرَاءَةً عَنْ مَالِكٍ عَنْ صَفْوَانَ بْنِ سُلَيْمٍ عَنْ سَعِيدِ بْنِ سَلَمَةَ مِنْ آلِ الْأَزْرَقِ أَنَّ الْمُغِيرَةَ بْنَ أَبِي بُرْدَةَ وَهُوَ رَجُلٌ مِنْ بَنِي عَبْدِ الدَّارِ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ سَأَلَ رَجُلٌ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّا نَرْكَبُ الْبَحْرَ وَنَحْمِلُ مَعَنَا الْقَلِيلَ مِنْ الْمَاءِ فَإِنْ تَوَضَّأْنَا بِهِ عَطِشْنَا أَفَنَتَوَضَّأُ مِنْ مَاءِ الْبَحْرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ الطَّهُورُ مَاؤُهُ الْحِلُّ مَيْتَتُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] melalui bacaan riwayat [Malik] dari [Shafwan bin Sulaim] dari [Sa'id bin Salamah] dari keluarga Al Azraq bahwa [Al Mughirah bin Abu Burdah] -yaitu seorang laki-laki dari kalangan Bani Abdud Dar- ia telah mengabarkan kepadanya, bahwa ia mendengar [Abu Hurairah] berkata; seorang laki-laki bertanya kepada Nabi shallallahu 'alaihi wasallam; \"Sesungguhnya kami pernah mengarungi lautan dan hanya membawa sedikit air, apabila kami berwudhu dengannya maka kami akan kehausan, apakah kami boleh berwudhu dengan air laut?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Air laut itu suci airnya dan bangkainya binatangnya pun halal.\""},"1574":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ جَابِرٍ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ثَلَاثِ مِائَةٍ فَأَصَابَنَا جُوعٌ حَتَّى أَتَيْنَا الْبَحْرَ وَقَدْ قَذَفَ دَابَّةً فَأَكَلْنَا مِنْهَا حَتَّى ثَابَتْ أَجْسَامُنَا فَأَخَذَ أَبُو عُبَيْدَةَ ضِلْعًا مِنْ أَضْلَاعِهَا فَوَضَعَهُ ثُمَّ حَمَلَ أَطْوَلَ رَجُلٍ فِي الْجَيْشِ عَلَى أَعْظَمِ بَعِيرٍ فِي الْجَيْشِ فَمَرَّ تَحْتَهُ هَذَا مَعْنَاهُ","id":"Telah mengabarkan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amr yaitu Ibnu Dinar] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutus kami diantara tiga ratus orang, kemudian kami mengalami kelaparan, hingga kami pergi ke laut, sungguh laut itu telah mendamparkan seekor binatang, kami pun memakan sebagian dari dagingnya. Hingga badan kami kembali seperti semula. Kemudian Abu 'Ubaidah mengambil salah satu tulang rusuk dan meletakkannya, kemudian ia membawa seorang yang paling tinggi di kalangan pasukan tersebut di atas unta yang paling besar, dan melewati dari bawahnya.\" Inilah makna hadits sebelumnya (bahwa binatang laut halal hukum memakannya)."},"1575":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ هِشَامُ بْنُ زَيْدِ بْنِ أَنَسٍ أَخْبَرَنِي قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُ أَنْفَجْنَا أَرْنَبًا وَنَحْنُ بِمَرِّ الظَّهْرَانِ فَسَعَى الْقَوْمُ فَلَغِبُوا فَأَخَذْتُهَا وَجِئْتُ بِهَا إِلَى أَبِي طَلْحَةَ فَذَبَحَهَا وَبَعَثَ بِوَرِكَيْهَا أَوْ فَخِذَيْهَا شَكَّ شُعْبَةُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَبِلَهَا","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] ia berkata, telah mengabarkan kepadaku [Hisyam bin Zaid bin Anas] ia berkata; aku mendengar [Anas bin Malik] berkata; \"Kami pernah menyergap seekor kelinci ketika di Marruzh Zhahran, kemudian orang-orang berusaha menangkapnya, lalu mereka merasa letih. Kemudian aku berhasil menangkapnya, dan membawanya kepada Abu Thalhah, ia lalu menyembelihnya. Kemudian dia mengirim kedua pangkal pahanya atau dua pahanya -Syu'bah ragu dengan redaksi haditsnya- kepada Rasulullah shallallahu 'alaihi wasallam, beliau pun menerimanya.\""},"1576":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا دَاوُدُ بْنُ أَبِي هِنْدٍ عَنْ عَامِرٍ عَنْ مُحَمَّدِ بْنِ صَفْوَانَ أَنَّهُ مَرَّ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِأَرْنَبَيْنِ مُعَلِّقُهُمَا فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي دَخَلْتُ غَنَمَ أَهْلِي فَاصْطَدْتُ هَذَيْنِ الْأَرْنَبَيْنِ فَلَمْ أَجِدْ حَدِيدَةً أُذَكِّيهِمَا بِهَا فَذَكَّيْتُهُمَا بِمَرْوَةٍ أَفَآكُلُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Daud bin Abu Hindun] dari ['Amir] dari [Muhammad bin Shafwan] bahwa ia melewati Nabi shallallahu 'alaihi wasallam dengan membawa dua ekor kelinci yang di gantungkan, lalu ia berkata; \"Wahai Rasulullah, sesungguhnya (ketika) aku mendatangi kambing keluargaku, aku berhasil menangkap dua ekor kelinci ini. Namun aku tidak mendapatkan besi untuk menyembelihnya, maka aku menyembelihnya menggunakan batu putih yang tajam, apakah aku boleh memakannya?\" Beliau menjawab: \"Ya.\""},"1577":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَبْدِ اللَّهِ بْنِ دِينَارٍ عَنْ ابْنِ عُمَرَ قَالَ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الضَّبِّ فَقَالَ لَسْتُ بِآكِلِهِ وَلَا مُحَرِّمِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abdullah bin Dinar] dari [Ibnu Umar], ia berkata; Nabi shallallahu 'alaihi wasallam ditanya mengenai daging biawak, beliau bersabda: \"Aku tidak memakannya dan tidak pula mengharamkannya.\""},"1578":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا الْحَكَمُ قَالَ سَمِعْتُ زَيْدَ بْنَ وَهْبٍ يُحَدِّثُ عَنْ الْبَرَاءِ بْنِ عَازِبٍ عَنْ ثَابِتِ بْنِ وَدِيعَةَ قَالَ أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِضَبٍّ فَقَالَ أُمَّةٌ مُسِخَتْ وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Al Hakam], ia berkata; aku mendengar [Zaid bin Wahb] menceritakan dari [Al Bara` bin 'Azib] dari [Tsabit bin Wadi'ah], ia berkata; Ketika Nabi shallallahu 'alaihi wasallam ditawari daging biawak, beliau bersabda: \"Itu adalah (jelmaan) dari suatu umat yang telah diubah bentuknya, wallahu a'lam.\""},"1579":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّهُ قَالَ أَخْبَرَنِي أَبُو أُمَامَةَ بْنُ سَهْلِ بْنِ حُنَيْفٍ الْأَنْصَارِيُّ أَنَّ عَبْدَ اللَّهِ بْنَ عَبَّاسٍ أَخْبَرَهُ أَنَّ خَالِدَ بْنَ الْوَلِيدِ الَّذِي يُقَالُ لَهُ سَيْفُ اللَّهِ أَخْبَرَهُ أَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ خَالَتُهُ وَخَالَةُ ابْنِ عَبَّاسٍ فَوَجَدَ عِنْدَهَا ضَبًّا مَحْنُوذًا قَدِمَتْ بِهِ أُخْتُهَا حُفَيْدَةُ بِنْتُ الْحَارِثِ مِنْ نَجْدٍ فَقَدَّمَتْ الضَّبَّ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ قَلَّ مَا يُقَدِّمُ يَدَهُ لِطَعَامٍ حَتَّى يُحَدَّثَ بِهِ وَيُسَمَّى لَهُ فَأَهْوَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ إِلَى الضَّبِّ فَقَالَتْ امْرَأَةٌ مِنْ نِسْوَةِ الْحُضُورِ أَخْبِرْنَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قَدَّمْتُنَّ لَهُ قُلْنَ هَذَا الضَّبُّ فَرَفَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ فَقَالَ خَالِدُ بْنُ الْوَلِيدِ أَتُحَرِّمُ الضَّبَّ يَا رَسُولَ اللَّهِ قَالَ أُرَاهُ لَا وَلَكِنَّهُ لَمْ يَكُنْ بِأَرْضِ قَوْمِي فَأَجِدُنِي أَعَافُهُ قَالَ خَالِدٌ فَاجْتَرَرْتُهُ فَأَكَلْتُهُ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْظُرُ فَلَمْ يَنْهَنِي","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] bahwa ia berkata; telah mengabarkan kepadaku [Abu Umamah bin Sahl bin Hunaif Al Anshari] bahwa [Abdullah bin Abbas] telah mengabarkan kepadanya, bahwa [Khalid bin Al Walid] yang dijuluki pedang Allah telah mengabarkan kepadanya, bahwa ia pernah menemui Maimunah isteri Nabi bersama Rasulullah shallallahu 'alaihi wasallam -Maimunah adalah bibinya dan juga bibi Ibnu Abbas- Kemudian dia mendapatkan biawak panggang, daging biawak itu hasil pemberian dari saudara perempuannya yang bernama Hufaidah binti Al Harits dari Najed. Kemudian Maimunah menghidangkan daging biawak tersebut kepada Rasulullah shallallahu 'alaihi wasallam. Dan jarang sekali beliau mengulurkan tangan untuk mengambil makanan kecuali nama makanan tersebut diberitahukan terlebih dahulu, Rasulullah shallallahu 'alaihi wasallam lalu mengulurkan tangannya untuk mengambil daging biawak tersebut, maka seorang wanita yang ikut hadir berkata; \"Beritahukanlah kepada Rasulullah shallallahu 'alaihi wasallam mengenai sesuatu yang telah kalian hidangkan kepada beliau.\" Mereka lalu mengatakan; \"Ini adalah daging biawak.\" Rasulullah shallallahu 'alaihi wasallam pun mengangkat tangannya, lalu Khalid bin Al Walid berkata; \"Apakah anda mengharamkan daging biawak wahai Rasulullah?\" Beliau menjawab: \"Tidak, akan tetapi ia tidak ada di negeri kaumku, hingga diriku merasa jijik.\" Khalid berkata; \"Kemudian aku menarik daging biawak itu dan memakannya, sementara Rasulullah shallallahu 'alaihi wasallam hanya melihatku dan tidak melarang.\""},"1580":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ دِينَارٍ حَدَّثَنَا زَيْدُ بْنُ أَسْلَمَ قَالَ عَبْدُ الرَّحْمَنِ أَحْسَبُهُ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ أَبِي وَاقِدٍ اللَّيْثِيِّ قَالَ قَدِمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ وَالنَّاسُ يَجُبُّونَ أَسْنِمَةَ الْإِبِلِ وَأَلْيَاتِ الْغَنَمِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا قُطِعَ مِنْ بَهِيمَةٍ وَهِيَ حَيَّةٌ فَهُوَ مَيْتَةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Abdurrahman bin Abdullah bin Dinar] telah menceritakan kepada kami [Zaid bin Aslam], -Abdurrahman mengatakan; akuu menyangka- dari ['Atha` bin Yasar] dari [Abu Waqid Al Laitsi] ia berkata; \"Setibanya Rasulullah shallallahu 'alaihi wasallam di Madinah, orang-orang memotong punuk-punuk unta dan pantat kambing. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dipotong dari hewan, sementara hewan tersebut masih hidup, maka potongan tersebut adalah bangkai.\""},"1581":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ سَمِّ اللَّهَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Wahb bin Kaisan] dari [Umar bin Abu Salamah] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Sebutlah nama Allah dan makanlah dari apa yang lebih dekat denganmu.\""},"1582":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا هِشَامٌ عَنْ بُدَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْكُلُ طَعَامًا فِي سِتَّةِ نَفَرٍ مِنْ أَصْحَابِهِ فَجَاءَ أَعْرَابِيٌّ فَأَكَلَهُ بِلُقْمَتَيْنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَا إِنَّهُ لَوْ ذَكَرَ اسْمَ اللَّهِ لَكَفَاكُمْ فَإِذَا أَكَلَ أَحَدُكُمْ فَلْيَذْكُرْ اسْمَ اللَّهِ فَإِنْ نَسِيَ أَنْ يَذْكُرَ اسْمَ اللَّهِ فَلْيَقُلْ بِسْمِ اللَّهِ أَوَّلَهُ وَآخِرَهُ أَخْبَرَنَا بُنْدَارٌ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ عَنْ أَبِيهِ عَنْ بُدَيْلٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ أُمِّ كُلْثُومٍ عَنْ عَائِشَةَ بِهَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Hisyam] dari [Budail] dari [Abdullah bin 'Ubaid bin 'Umair] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam sedang menyantap memakan bersama enam orang sahabatnya, tiba-tiba seorang badui datang dan langsung memakannya dengan hanya dua kali suapan. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ketahuilah, apabila ia menyebut nama Allah, niscaya makanan tersebut dapat mencukupi kalian. Apabila salah seorang dari kalian makan, hendaknya ia menyebut nama Allah, apabila ia lupa menyebut nama Allah, hendaknya ia mengatakan; BISMILLAAHI AWWALAHU WA AAKHIRAHU.\" (dengan nama Allah, pada awal dan akhirnya).\" Telah mengabarkan kepada kami [Bundar] telah menceritakan kepada kami [Mu'adz bin Hisyam] dari [Ayahnya] dari [Budail] dari [Abdullah bin 'Ubaid bin 'Umari] dari [Ummu Kultsum] dari ['Aisyah] dengan hadits seperti ini."},"1583":{"ar":" أَخْبَرَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ صَفْوَانَ بْنِ عَمْرٍو حَدَّثَنَا عَبْدُ اللَّهِ بْنُ بُسْرٍ وَكَانَتْ لَهُ صُحْبَةٌ يَسِيرَةٌ قَالَ قَالَ أَبِي لِأُمِّي لَوْ صَنَعْتِ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَعَامًا فَصَنَعَتْ ثَرِيدَةً وَقَالَ بِيَدِهِ يُقْلِلُ فَانْطَلَقَ أَبِي فَدَعَاهُ فَوَضَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدَهُ عَلَى ذِرْوَتِهَا ثُمَّ قَالَ خُذُوا بِاسْمِ اللَّهِ فَأَخَذُوا مِنْ نَوَاحِيهَا فَلَمَّا طَعِمُوا دَعَا لَهُمْ فَقَالَ اللَّهُمَّ اغْفِرْ لَهُمْ وَارْحَمْهُمْ وَبَارِكْ لَهُمْ فِي رِزْقِهِمْ","id":"Telah mengabarkan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Isa bin Yunus] dari [Shafwan bin 'Amr] telah menceritakan kepada kami [Abdullah bin Busr] -dia pernah bersahabat dengan Rasulullah shallallahu 'alaihi wasallam, namun hanya sebentar- dia berkata; Ayahku pernah berkata kepada ibuku; \"Alangkah baiknya jika kamu membuat makanan untuk Rasulullah shallallahu 'alaihi wasallam. Ibu kemudian membuat bubur (adonan yang terbuat dari campuran daging dan roti ditambah kuah). Ayahku memberi isyarat dengan tangannya menandakan bahwa makanan itu sedikit. Kemudian ayahku pergi untuk mengundang beliau, setelah itu Rasulullah shallallahu 'alaihi wasallam meletakkan tangannya di atas makanan tersebut, kemudian beliau berkata: \"Ambillah dengan menyebut nama Allah.\" Para sahabat pun mengambil dari bagian pinggirnya, seusai makan, beliau mendoakan untuk mereka, beliau mengucapkan: \"Ya Allah, ampunilah dosa mereka dan rahmatilah mereka, serta berkahilah dalam rizqi mereka.\""},"1584":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْقَاسِمِ الْأَسَدِيُّ حَدَّثَنَا ثَوْرٌ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي أُمَامَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَكَلَ أَوْ شَرِبَ قَالَ الْحَمْدُ لِلَّهِ حَمْدًا كَثِيرًا طَيِّبًا مُبَارَكًا فِيهِ غَيْرَ مَكْفُورٍ وَلَا مُوَدَّعٍ وَلَا مُسْتَغْنًى عَنْ رَبِّنَا","id":"Telah mengabarkan kepada kami [Muhammad bin Al Qasim Al Asdi] telah menceritakan kepada kami [Tsaur] dari [Khalid bin Ma'dan] dari [Abu Umamah], ia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam selesai makan atau minum, beliau mengucapkan: \"Al HAMDULLILLAAHI HAMDAN KATSIIRAN THAYYIBAN MUBAARAKAN FIIHI GHAIRA MAKFUURIN WA LAA MUWADDA'IN WA LAA MUS TAGHNAN 'AN RABBINAA. (segala puji bagi Allah, dengan pujian yang banyak dan baik serta mengandung berkah padanya, dalam keadaan tidak diingkari, ditinggalkan dan tidak diperlukan oleh Rabb kami).\""},"1585":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي حُرَّةَ عَنْ عَمِّهِ عَنْ سِنَانِ بْنِ سَنَّةَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الطَّاعِمُ الشَّاكِرُ كَالصَّائِمِ الصَّابِرِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] dari [Abdul 'Aziz bin Muhammad] dari [Muhammad bin Abdullah bin Abu Hurrah] dari [pamannya] dari [Sinan bin Sannah] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang makan lalu bersyukur seperti orang yang berpuasa dan bersabar.\""},"1586":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى أَخْبَرَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَلْعَقْ أَصَابِعَهُ الثَّلَاثَ","id":"Telah menceritakan kepada kami [Ishaq bin Isa] telah mengabarkan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila salah seorang dari kalian telah makan, hendaknya ia menjilati jari-jemarinya.\" Beliau mengucapkannya sebanyak tiga kali."},"1587":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلَا يَمْسَحْ يَدَهُ حَتَّى يَلْعَقَ أَصَابِعَهُ أَوْ يُلْعِقَهَا","id":"Telah mengabarkan kepada kami ['Amru bin 'Aun] telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amru bin Dinar] dari ['Atha`] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian makan, janganlah ia mengusap tangannya hingga ia menjilat jari-jarinya atau menjilatkannya kepada orang lain.\""},"1588":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا أَبُو الْيَمَانِ الْبَرَّاءُ هُوَ مُعَلَّى بْنُ رَاشِدٍ قَالَ حَدَّثَتْنِي جَدَّتِي أُمُّ عَاصِمٍ قَالَتْ دَخَلَ عَلَيْنَا نُبَيْشَةُ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ نَأْكُلُ طَعَامًا فَدَعَوْنَاهُ فَأَكَلَ مَعَنَا ثُمَّ قَالَ حَدَّثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَنْ أَكَلَ فِي قَصْعَةٍ ثُمَّ لَحِسَهَا اسْتَغْفَرَتْ لَهُ الْقَصْعَةُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abu Al Yaman Al Barra` yaitu Mu'alla bin Rasyid], ia berkata; telah menceritakan kepadaku nenekku yaitu [Ummu 'Ashim] ia berkata; suatu ketika [Nubaisyah] yaitu mantan budak Rasulullah shallallahu 'alaihi wasallam menemui kami, sementara kami sedang makan makanan, maka kami mengundangnya hingga ia makan bersama kami. Kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam menceritakan kepada kami bahwa: \"Barangsiapa makan dalam piring, kemudian ia menjilatinya maka piring tersebut akan memintakan ampun untuknya.\""},"1589":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَقَطَتْ لُقْمَةُ أَحَدِكُمْ فَلْيَمْسَحْ عَنْهَا التُّرَابَ وَلْيُسَمِّ اللَّهَ وَلْيَأْكُلْهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Isa] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila sesuap makanan kalian terjatuh, hendaknya ia membersihkan debu (yang melekat) padanya dan hendaknya ia menyebut nama Allah lalu memakannya.\""},"1590":{"ar":" أَخْبَرَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ كَانَ مَعْقِلُ بْنُ يَسَارٍ يَتَغَدَّى فَسَقَطَتْ لُقْمَتُهُ فَأَخَذَهَا فَأَمَاطَ مَا بِهَا مِنْ أَذًى ثُمَّ أَكَلَهَا فَجَعَلَ أُولَئِكَ الدَّهَاقِينُ يَتَغَامَزُونَ بِهِ فَقَالُوا لَهُ مَا تَرَى مَا يَقُولُ هَؤُلَاءِ الْأَعَاجِمُ يَقُولُونَ انْظُرُوا إِلَى مَا بَ��ْنَ يَدَيْهِ مِنْ الطَّعَامِ وَإِلَى مَا يَصْنَعُ بِهَذِهِ اللُّقْمَةِ فَقَالَ إِنِّي لَمْ أَكُنْ أَدَعُ مَا سَمِعْتُ بِقَوْلِ هَؤُلَاءِ الْأَعَاجِمِ إِنَّا كُنَّا نُؤْمَرُ إِذَا سَقَطَتْ مِنْ أَحَدِنَا لُقْمَةٌ أَنْ يُمِيطَ مَا بِهَا مِنْ الْأَذَى وَأَنْ يَأْكُلَهَا","id":"Telah mengabarkan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami [Yazid bin Zurai'] dari [Yunus] dari [Al Hasan], ia berkata; \" [Ma'qil bin Yasar] pernah makan siang, kemudian sesuap makanannya terjatuh, lalu ia mengambilnya dan menghilangkan kotoran yang (melekat) padanya, lalu ia memakannya. Beberapa tokoh pembesar pun mencibirnya. Para sahabatnya pun berkata kepadanya; \"Menurutmu apa yang dikatakan orang-orang asing itu?\" mereka telah mengatakan; \"Lihatlah makanan yang ada di hadapannya dan apa yang ia lakukan terhadap sesuap makanan ini.\" Ma'qil pun berkata; \"Sesungguhnya aku tidak akan meninggalkan apa yang telah aku dengar karena perkataan orang-orang asing itu. Sesungguhnya kami diperintahkan membersihkan kotoran yang melekat pada makanan lalu memakannya, apabila terdapat sesuap makanan dari kami yang terjatuh.\""},"1591":{"ar":" أَخْبَرَنَا أَبُو مُحَمَّدٍ الْحَنَفِيُّ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي بَكْرِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَكَلَ أَحَدُكُمْ فَلْيَأْكُلْ بِيَمِينِهِ وَلْيَشْرَبْ بِيَمِينِهِ فَإِنَّ الشَّيْطَانَ يَأْكُلُ بِشِمَالِهِ وَيَشْرَبُ بِشِمَالِهِ أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ ابْنِ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ أَبِي بَكْرٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Abu Muhammad Al Hanafi] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Bakr bin 'Ubaidullah bin Abdullah bin Umar] dari [Abdullah bin Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian makan, hendaknya ia makan dengan tangan kanannya dan minum dengan tangan kanannya, karena syetan makan dengan tangan kirinya dan minum dengan tangan kirinya.\" Telah mengabarkan kepada kami ['Amru bin 'Aun] dari [Ibnu 'Uyainah] dari [Az Zuhri] dari [Abu Bakr] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam dengan redaksi hadits yang sama."},"1592":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا عِكْرِمَةُ بْنُ عَمَّارٍ حَدَّثَنِي إِيَاسُ بْنُ سَلَمَةَ حَدَّثَنِي أَبِي قَالَ أَبْصَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بُسْرَ بْنَ رَاعِي الْعِيرِ يَأْكُلُ بِشِمَالِهِ فَقَالَ كُلْ بِيَمِينِكَ قَالَ لَا أَسْتَطِيعُ قَالَ لَا اسْتَطَعْتَ قَالَ فَمَا وَصَلَتْ يَمِينُهُ إِلَى فِيهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Ikrimah bin 'Ammar] telah menceritakan kepadaku [Iyas bin Salamah] telah menceritakan kepadaku [ayahku], ia berkata; Rasulullah shallallahu 'alaihi wasallam melihat Busr bin Ra'i Al 'Ir makan menggunakan tangan kiri, maka beliau bersabda: \"Makanlah dengan tangan kananmu.\" Busr berkata; \"Aku tidak bisa.\" Beliau bersabda: \"Engkau tidak akan bias?.\" Setelah itu tangan kanan Busr tidak mampu sampai ke mulutnya."},"1593":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ الْمَدَنِيِّ عَنْ ابْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ بِثَلَاثِ أَصَابِعَ وَلَا يَمْسَحُ يَدَهُ حَتَّى يَلْعَقَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam bin 'Urwah] dari [Abdurrahman bin Sa'd Al Madani] dari [Ibnu Ka'b bin Malik] dari [Ayahnya], ia berkata; Nabi shallallahu 'alaihi wasallam makan menggunakan tiga jari, dan beliau tidak mengusap tangannya hingga beliau menjilatnya.\""},"1594":{"ar":" حَدَّثَنَا مُوسَى بْنُ خَالِدٍ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَعْدٍ الْمَدَنِيِّ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ أَوْ عَبْدَ الرَّحْمَنِ بْنَ كَعْبٍ شَكَّ هِشَامٌ أَخْبَرَهُ عَنْ أَبِيهِ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَأْكُلُ بِأَصَابِعِهِ الثَّلَاثِ فَإِذَا فَرَغَ لَعِقَهَا وَأَشَارَ هِشَامٌ بِأَصَابِعِهِ الثَّلَاثِ","id":"Telah menceritakan kepada kami [Musa bin Khalid] telah menceritakan kepada kami [Isa bin Yunus] dari [Hisyam bin 'Urwah] dari [Abdurrahman Sa'd Al Madani] bahwa [Abdullah bin Ka'b] atau [Abdurrahman bin Ka'b] -Hisyam ragu dengan redaksi haditsnya- telah mengabarkan kepadanya, dari [Ayahnya] bahwa Nabi shallallahu 'alaihi wasallam makan dengan tiga jarinya, seusai makan, beliau menjilatnya.\" Dan Hisyam memberi isyarat dengan menggunakan tiga jarinya."},"1595":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ جَارَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ جَائِزَتَهُ يَوْمًا وَلَيْلَةً وَالضِّيَافَةُ ثَلَاثَةُ أَيَّامٍ وَمَا بَعْدَ ذَلِكَ صَدَقَةٌ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Sa'id bin Abu Sa'id] dari [Abu Syuraih Al Khuza'i], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berimana kepada Allah dan Hari Akhir, hendaknya ia memuliakan tetangganya. Barangsiapa beriman kepada Allah dan Hari Akhir, hendaknya ia berkata baik atau diam. Barangsiapa beriman kepada Allah dan Hari Akhir, hendaknya ia memuliakan tamunya dengan menjamunya pada siang dan malam harinya, dan hak bertamu adalah tiga hari, dan setelah itu adalah sedekah.\""},"1596":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ سَمِعَ نَافِعَ بْنَ جُبَيْرٍ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُحْسِنْ إِلَى جَارِهِ وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَسْكُتْ","id":"Telah mengbarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Amr bin Dinar] ia mendengar [Nafi' bin Jubair] dari [Abu Syuraih Al Khuza'i] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan Hari Akhir, hendaknya ia memuliakan tamunya. Barangsiapa beriman kepada Allah dan Hari Akhir, hendaknya ia bersikap baik terhadap tetangganya. Barangsiapa beriman kepada Allah dan Hari Akhir, hendaknya ia berkata baik atau diam.\""},"1597":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْجُودِيِّ عَنْ سَعِيدِ بْنِ الْمُهَاجِرِ عَنْ الْمِقْدَامِ بْنِ مَعْدِي كَرِبَ أَبِي كَرِيمَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا مُسْلِمٍ ضَافَ قَوْمًا فَأَصْبَحَ الضَّيْفُ مَحْرُومًا فَإِنَّ عَلَى كُلِّ مُسْلِمٍ نَصْرَهُ حَتَّى يَأْخُذَ لَهُ بِقِرَى لَيْلَتِهِ مِنْ زَرْعِهِ وَمَالِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Syu'bah] dari [Abu Al Judi] dari [Sa'id bin Al Muhajir] dari [Al Miqdam bin Ma'di Karib Abu Karimah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang muslim manapun yang bertamu ke suatu kaum namun hingga pagi hari ia tidak mendapatkan jamuan, maka kewajiban setiap muslim lainnya untuk menolong hingga ia mengambil haknya dengan membuatkan jamuan malamnya dari tanaman dan hartanya.\""},"1598":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ عُتْبَةَ بْنِ مُسْلِمٍ أَنَّ عُبَيْدَ بْنَ حُنَيْنٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَقَطَ الذُّبَابُ فِي شَرَابِ أَحَدِكُمْ فَلْيَغْمِسْهُ كُلَّهُ ثُمَّ لِيَنْزِعْهُ فَإِنَّ فِي أَحَدِ جَنَاحَيْهِ دَاءً وَفِي الْآخَرِ شِفَاءً","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Sulaiman bin Bilal] dari ['Utbah bin Muslim] bahwa ['Ubaid bin Hunain] telah mengabarkan kepadanya bahwa ia mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila seekor lalat terjatuh dalam minuman salah seorang dari kalian, hendaknya ia mencelupkan seluruhnya kemudian mengangkatnya, karena di salah satu sayapnya terdapat penyakit dan sayap yang lain adalah penawarnya.\""},"1599":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثُمَامَةَ بْنِ عَبْدِ اللَّهِ بْنِ أَنَسٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا وَقَعَ الذُّبَابُ فِي إِنَاءِ أَحَدِكُمْ فَلْيَغْمِسْهُ فَإِنَّ فِي أَحَدِ جَنَاحَيْهِ دَاءً وَفِي الْآخَرِ شِفَاءً قَالَ أَبُو مُحَمَّد قَالَ غَيْرُ حَمَّادٍ ثُمَامَةُ عَنْ أَنَسٍ مَكَانَ أَبِي هُرَيْرَةَ وَقَوْمٌ يَقُولُونَ عَنْ الْقَعْقَاعِ عَنْ أَبِي هُرَيْرَةَ وَحَدِيثُ عُبَيْدِ بْنِ حُنَيْنٍ أَصَحُّ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsumamah bin Abdullah bin Anas] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Apabila seekor lalat terjatuh dalam bejana salah seorang dari kalian, hendaknya ia mencelupkannya, karena sesungguhnya di salah satu sayapnya terdapat penyakit dan sayap yang lain adalah penawarnya.\" Abu Muhammad berkata; [selain Hammad] mengatakan; [Tsumamah] dari [Anas] sebagai ganti Abu Hurairah, dan [beberapa perawi yang lain] mengatakan dari [Al Qa'qa'] dari [Abu Hurairah]. Sedangkan hadits 'Ubaid bin Hunain lebih shahih."},"1600":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ وَالْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عُمَرَ الْقَوَارِيرِيُّ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و حَدَّثَنِي يَحْيَى عَنْ مُجَالِدٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang mukmin makan dengan satu usus, sedangkan orang kafir makan dengan tujuh usus.\" Telah mengabarkan kepada kami ['Ubaidullah bin Umar Al Qawariri] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah], telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam. (Dan diriwayatkan dari jalur lain) telah menceritakan kepadaku [Yahya] dari [Mujalid] dari [Abu Al Waddak] dari [Abu Sa'id] dari Nabi shallallahu 'alaihi wasallam."},"1601":{"ar":" و حَدَّثَنِي يَحْيَى عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُؤْمِنُ يَأْكُلُ فِي مِعًى وَاحِدٍ وَالْكَافِرُ يَأْكُلُ فِي سَبْعَةِ أَمْعَاءٍ","id":"Dan telah menceritakan kepada kami [Yahya] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang mukmin makan dengan satu usus, sedangkan orang kafir makan dengan tujuh usus.\""},"1602":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْه�� وَسَلَّمَ طَعَامُ الْوَاحِدِ يَكْفِي الِاثْنَيْنِ وَطَعَامُ الِاثْنَيْنِ يَكْفِي الْأَرْبَعَةَ وَطَعَامُ الْأَرْبَعَةِ يَكْفِي ثَمَانِيَةً","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Makanan satu orang cukup untuk dua orang dan makanan dua orang cukup untuk empat orang dan makanan empat orang cukup untuk delapan orang.\""},"1603":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ عُمَرَ بْنِ أَبِي سَلَمَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَهُ سَمِّ اللَّهَ وَكُلْ مِمَّا يَلِيكَ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Wahb bin Kaisan] dari [Umar bin Abu Salamah] bahwa Nabi shallallahu 'alaihi wasallam berkata kepadanya: \"Sebutlah nama Allah dan makanlah dari yang lebih dekat denganmu.\""},"1604":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِجَفْنَةٍ أَوْ قَالَ قَصْعَةٍ مِنْ ثَرِيدٍ فَقَالَ كُلُوا مِنْ حَافَاتِهَا أَوْ قَالَ جَوَانِبِهَا وَلَا تَأْكُلُوا مِنْ وَسَطِهَا فَإِنَّ الْبَرَكَةَ تَنْزِلُ فِي وَسَطِهَا","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari ['Atha` bin As Sa`ib] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam pernah diberi semangkok atau sepiring Tsarid, kemudian beliau bersabda: \"Makanlah dari pinggirnya.\" Atau beliau bersabda: \"Dari samping-sampingnya, dan janganlah kalian makan dari tengahnya, karena berkah turun di tengahnya.\" "},"1605":{"ar":" حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ قُرَّةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ أَسْمَاءَ بِنْتِ أَبِي بَكْرٍ أَنَّهَا كَانَتْ إِذَا أُتِيَتْ بِثَرِيدٍ أَمَرَتْ بِهِ فَغُطِّيَ حَتَّى يَذْهَبَ فَوْرَةُ دُخَانِهِ وَتَقُولُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ هُوَ أَعْظَمُ لِلْبَرَكَةِ","id":"Telah menceritakan kepada kami [Abdurrahman bin Ibrahim Ad Dimasyqi] telah menceritakan kepada kami [Ibnu Wahb] dari [Qurrah bin Abdurrahman] dari [Az Zuhri] dari ['Urwah] dari [Asma` binti Abu Bakr] bahwa jika ia diberi Tsarid, maka ia memerintahkan supaya ditutup hingga panas dan asapnya hilang, dia berkata; \"Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hal itu lebih besar keberkahannya.\""},"1606":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا الْمُثَنَّى بْنُ سَعِيدٍ حَدَّثَنَا طَلْحَةُ بْنُ نَافِعٍ أَبُو سُفْيَانَ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَ أَخَذَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِيَدِي ذَاتَ يَوْمٍ إِلَى مَنْزِلِهِ فَقَالَ هَلْ مِنْ غَدَاءٍ أَوْ مِنْ عَشَاءٍ شَكَّ طَلْحَةُ قَالَ فَأَخْرَجَ إِلَيْهِ فِلَقًا مِنْ خُبْزٍ فَقَالَ أَمَا مِنْ أُدْمٍ قَالُوا لَا إِلَّا شَيْءٌ مِنْ خَلٍّ فَقَالَ هَاتُوهُ فَنِعْمَ الْإِدَامُ الْخَلُّ قَالَ جَابِرٌ فَمَا زِلْتُ أُحِبُّ الْخَلَّ مُنْذُ سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَبُو سُفْيَانَ فَمَا زِلْتُ أُحِبُّهُ مُنْذُ سَمِعْتُهُ مِنْ جَابِرٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Al Mutsanna bin Sa'id] telah menceritakan kepada kami [Thalhah bin Nafi' Abu Sufyan] telah menceritakan kepada kami [Jabir bin Abdullah], ia berkata; Suatu hari Nabi shallallahu 'alaihi wasallam menggandeng tanganku menuju rumahnya, kemudian beliau bersabda: \"Apakah ada makan siang -atau makan malam?\" Thalhah ragu dengan redaksi haditsnya- Thalhah berkata; Beliau kemudian di hidangkan sepotong roti, beliau bertanya: \"Tidakkah ada kuah?\" Mereka menjawab; \"Tidak, hanya sedikit cuka.\" Lalu beliau bersabda: \"Berikanlah, sebaik-baik lauk adalah cuka.\" Jabir berkata; aku senantiasa menyenangi cuka semenjak aku mendengarnya dari Rasulullah shallallahu 'alaihi wasallam. Lalu Abu Sufyan juga berkata; aku senantiasa menyenangi cuka semenjak aku mendengarnya dari Jabir."},"1607":{"ar":" حَدَّثَنِي يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ نِعْمَ الْإِدَامُ أَوْ نِعْمَ الْأُدْمُ الْخَلُّ","id":"Telah menceritakan kepadaku [Yahya bin Hassan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sebaik-baik lauk adalah cuka.\""},"1608":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَ رَأَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِمَرَقَةٍ فِيهَا دُبَّاءٌ وَقَدِيدٌ فَرَأَيْتُهُ يَتَتَبَّعُ الدُّبَّاءَ يَأْكُلُهُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Malik] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Anas], ia berkata; aku melihat Nabi shallallahu 'alaihi wasallam diberi kuah yang dicampur dengan Dubba` dan dendeng. Kemudian aku melihat beliau mencari-cari Dubba` dan memakannya.\" "},"1609":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ كَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعْجِبُهُ الْقَرْعُ قَالَ فَقُدِّمَ إِلَيْهِ فَجَعَلْتُ أَتَنَاوَلُهُ وَأَجْعَلُهُ بَيْنَ يَدَيْهِ","id":"Telah mengabarkan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas], ia berkata; Nabi shallallahu 'alaihi wasallam menyukai Qar'.\" Anas melanjutkan; \"Kemudian qar' tersebut dihidangkan kepada beliau, lalu aku mengambilnya serta meletakkannya di hadapan beliau.\" Qar' adalah tumbuhan sejenis labu."},"1610":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ اللَّهِ بْنِ عِيسَى عَنْ عَطَاءٍ وَلَيْسَ بِابْنِ أَبِي رَبَاحٍ عَنْ أَبِي أَسِيدٍ الْأَنْصَارِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كُلُوا الزَّيْتَ وَائْتَدِمُوا بِهِ وَادَّهِنُوا بِهِ فَإِنَّهُ يَخْرُجُ مِنْ شَجَرَةٍ مُبَارَكَةٍ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abdullah bin Isa] dari ['Atha`] bukan Ibnu Abu Rabbah, dari [Abu Usaid Al Anshari], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Konsumsilah minyak (zaitun), jadikanlah sebagai lauk dan pakailah sebagai minyak, karena sesungguhnya ia berasal dari pohon yang diberkahi.\""},"1611":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي غَزْوَةِ خَيْبَرَ مَنْ أَكَلَ مِنْ هَذِهِ الشَّجَرَةِ يَعْنِي الثُّومَ فَلَا يَأْتِيَنَّ الْمَسَاجِدَ","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda pada saat perang Khaibar: \"Barangsiapa makan dari pohon ini yaitu bawang putih, janganlah ia mendatangi masjid.\""},"1612":{"ar":" أَخْبَرَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ أَبِي يَزِيدَ عَنْ أَبِيهِ أَنَّ أُمَّ أَيُّوبَ أَخْبَرَتْهُ قَالَتْ نَزَلَ عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَكَلَّفْنَا لَهُ طَعَامًا فِيهِ شَيْءٌ مِنْ بَعْضِ هَذِهِ الْبُقُولِ فَلَمَّا أَتَيْنَاهُ بِهِ كَرِهَهُ وَقَالَ لِأَصْحَابِهِ كُلُوهُ فَإِنِّي لَسْتُ كَأَحَدٍ مِنْكُمْ إِنِّي أَخَافُ أَنْ أُوذِيَ صَاحِبِي قَالَ أَبُو مُحَمَّد إِذَا لَمْ يُؤْذِ أَحَدًا فَلَا بَأْسَ بِأَكْلِهِ","id":"Telah mengabarkan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] telah menceritakan kepadaku ['Ubaidullah bin Abu Yazid] dari [Ayahnya] bahwa [Ummu Ayyub] telah mengabarkan kepadanya, katanya; \"Rasulullah shallallahu 'alaihi wasallam singgah di rumah kami, kemudian kami membuatkan makanan untuknya yang mengandung sesuatu dari janis sayur ini, tatkala kami menghidangkan kepadanya, beliau tidak menyukainya dan berkata kepada para sahabatnya: \"Makanlah, karena sesungguhnya aku tidak sama seperti seorangpun diantara kalian, aku khawatir mengganggu sahabatku.\" Abu Muhammad berkata; \"Apabila tidak khawatir dapat mengganggu seorangpun, maka tidak mengapa memakannya.\""},"1613":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ التَّمِيمِيِّ عَنْ زَهْدَمٍ الْجَرْمِيِّ قَالَ كُنَّا عِنْدَ أَبِي مُوسَى فَقُدِّمَ طَعَامُهُ فَقُدِّمَ فِي طَعَامِهِ لَحْمُ دَجَاجٍ وَفِي الْقَوْمِ رَجُلٌ مِنْ بَنِي تَيْمِ اللَّهِ أَحْمَرُ فَلَمْ يَدْنُ فَقَالَ لَهُ أَبُو مُوسَى ادْنُ فَإِنِّي قَدْ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ مِنْهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ayyub] dari [Al Qasim At Taimi] dari [Zahdam Al Jarmi], ia berkata; \"Kami pernah berada di rumah Abu Musa, ketika itu dia menghidangkan daging ayam jantan pada jamuan makanannya tersebut, sementara di antara orang-orang terdapat seorang laki-laki dari Bani Taimullah Ahmar, laki-laki itu tidak mau mendekat. [Abu Musa] pun berkata kepadanya; \"Mendekatlah, karena aku telah melihat Rasulullah shallallahu 'alaihi wasallam pernah memakan daging ayam jantan tersebut.\""},"1614":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ زَهْدَمٍ الْجَرْمِيِّ عَنْ أَبِي مُوسَى أَنَّهُ ذَكَرَ الدَّجَاجَ فَقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Ayyub] dari [Abu Qilabah] dari [Zahdam Al Jarmi] dari [Abu Musa] bahwa ia menyebutkan perihal ayam jantan. Lalu ia berkata; \"Aku pernah melihat Rasulullah shallallahu 'alaihi wasallam memakannya.\""},"1615":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا حَيْوَةُ حَدَّثَنَا سَالِمُ بْنُ غَيْلَانَ أَنَّ الْوَلِيدَ بْنَ قَيْسٍ أَخْبَرَهُ أَنَّهُ سَمِعَ أَبَا سَعِيدٍ أَوْ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ سَمِعَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا تَصْحَبْ إِلَّا مُؤْمِنًا وَلَا يَأْكُلْ طَعَامَكَ إِلَّا تَقِيٌّ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Haiwah] telah menceritakan kepada kami [Salim bin Ghailan] bahwa [Al Walid bin Qais] telah mengabarkan kepadanya, bahwa ia mendengar [Abu Sa'id] atau [Abu Al Haitsam] dari [Abu Sa'id Al Khudri] bahwa ia mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah kamu bersahabat kecuali dengan orang mukmin, dan janganlah ada yang memakan makananmu kecuali orang yang bertakwa.\""},"1616":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ جَعْفَرٍ قَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ الْقِثَّاءَ بِالرُّطَبِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Ibraihim bin Sa'd] dari [ayahnya] dari [Abdullah bin Ja'far], ia berkata; aku melihat Rasulullah shallallahu 'alaihi wasallam memakan mentimun dengan ruthab.\" "},"1617":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا جَبَلَةُ بْنُ سُحَيْمٍ قَالَ كُنَّا بِالْمَدِينَةِ فَأَصَابَتْنَا سَنَةٌ فَكَانَ ابْنُ الزُّبَيْرِ يَرْزُقُ التَّمْرَ وَكَانَ ابْنُ عُمَرَ يَمُرُّ بِنَا وَيَقُولُ لَا تُقَارِنُوا فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَ��َلَّمَ نَهَى عَنْ الْقِرَانِ إِلَّا أَنْ يَسْتَأْذِنَ الرَّجُلُ أَخَاهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Jabalah bin Suhaim], ia berkata; \"Kami pernah tertimpa musim paceklik di Madinah, kemudian Ibnu Az Zubair memberi kurma, sementara [Ibnu Umar] melewati kami dan berkata; \"Janganlah kalian menggabungkan dua jenis kurma saat makan, karena Rasulullah shallallahu 'alaihi wasallam melarang menggabungkan dua jenis kurma ketika makan, kecuali seseorang meminta izin kepada saudaranya.\""},"1618":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا يَعْقُوبُ بْنُ مُحَمَّدِ بْنِ طَحْلَاءَ عَنْ أَبِي الرِّجَالِ عَنْ أُمِّهِ عَمْرَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَا عَائِشَةُ بَيْتٌ لَا تَمْرَ فِيهِ جِيَاعٌ أَهْلُهُ أَوْ جَاعَ أَهْلُهُ مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Ya'qub bin Muhammad bin Thahla`] dari [Abu Ar Rijal] dari pamannya yaitu ['Amrah] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Aisyah, rumah yang tidak ada (persediaan) kurma di dalamnya adalah rumah yang lapar penghuninya.' -atau penghuninya mengalami kelaparan- Beliau mengucapkan hingga dua atau tiga kali."},"1619":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَسَّانَ حَدَّثَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَجُوعُ أَهْلُ بَيْتٍ عِنْدَهُمْ التَّمْرُ","id":"Telah mengabarkan kepada kami [Yahya bin Hassan] telah menceritakan kepada kami [Sulaiman bin Bilal] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak akan kelaparan penghuni rumah yang terdapat (persediaan) kurma didalamnya.\""},"1620":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا مُصْعَبُ بْنُ سُلَيْمٍ قَالَ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُ أُهْدِيَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَمْرٌ فَأَخَذَ يُهَدِّيهِ وَقَالَ رَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْكُلُ تَمْرًا مُقْعِيًا مِنْ الْجُوعِ قَالَ أَبُو مُحَمَّد يُهَدِّيهِ يَعْنِي يُهْدِي هَاهُنَا وَهَاهُنَا","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Mush'ab bin Sulaim], ia berkata; aku mendengar [Anas bin Malik] berkata; Nabi shallallahu 'alaihi wasallam pernah diberi hadiah kurma, kemudian beliau menghadiahkan kurma tersebut. Anas melanjutkan; Aku melihat Rasulullah shallallahu 'alaihi wasallam makan kurma dengan duduk di atas pantatnya dan mengangkat kedua betisnya karena lapar. Abu Muhammad berkata; \"Yuhaddihi artinya memberikan hadiah ke sana dan ke sini.\""},"1621":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَامَ وَفِي يَدِهِ رِيحُ غَمَرٍ فَعَرَضَ لَهُ عَارِضٌ فَلَا يَلُومَنَّ إِلَّا نَفْسَهُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Khalid] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa ketika tidur di tangannya masih terdapat bau lemak daging, kemudian terjadi sesuatu padanya, maka janganlah ia mencela kecuali kepada dirinya sendiri.\""},"1622":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا حُمَيْدٌ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ وَرَأَى عَلَيْهِ وَضَرًا مِنْ صُفْرَةٍ مَهْيَمْ قَالَ تَزَوَّجْتُ قَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Abdurrahman bin 'Auf, ketika beliau melihat bekas wewangian berwarna kuning: \"Apa ini?\" Abdurrahman menjawab; \"Aku telah menikah.\" Beliau bersabda: \"Buatlah pesta perkawinan walaupun hanya dengan seekor kambing.\""},"1623":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ عُثْمَانَ الثَّقَفِيِّ عَنْ رَجُلٍ مِنْ ثَقِيفَ أَعْوَرَ قَالَ كَانَ يُقَالُ لَهُ مَعْرُوفٌ أَيْ يُثْنَى عَلَيْهِ خَيْرٌ إِنْ لَمْ يَكُنْ اسْمُهُ زُهَيْرَ بْنَ عُثْمَانَ فَلَا أَدْرِي مَا اسْمُهُ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلِيمَةُ أَوَّلَ يَوْمٍ حَقٌّ وَالثَّانِيَ مَعْرُوفٌ وَالثَّالِثَ سُمْعَةٌ وَرِيَاءٌ قَالَ قَتَادَةُ وَحَدَّثَنِي رَجُلٌ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ أَنَّهُ دُعِيَ أَوَّلَ يَوْمٍ فَأَجَابَ وَدُعِيَ الْيَوْمَ الثَّانِيَ فَأَجَابَ وَدُعِيَ الْيَوْمَ الثَّالِثَ فَحَصَبَ الرَّسُولَ وَلَمْ يُجِبْهُ وَقَالَ أَهْلُ سُمْعَةٍ وَرِيَاءٍ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Al Hasan] dari [Abdullah bin Utsman Ats Tsaqafi] -dari seorang laki-laki penduduk Tsaqif yang buta matanya, ia biasa di sebut-sebut dengan kebaikannya, maksudnya dipuji dengan kebaikan, kalau tidak salah namanya adalah- [Zuhair bin Utsman] -aku tidak tahu siapa nama aslinya- ia berkata; bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Pesta pernikahan (yang di selenggarakan) pada hari pertama adalah hak, hari keduanya adalah kebaikan dan hari ketiganya adalah sum'ah dan riya`.\" Qatadah berkata; telah menceritakan kepadaku seorang laki-laki dari Sa'id bin Al Musayyab bahwa ia diundang (pesta pernikahan) pada hari pertama, lalu ia memenuhi undangan tersebut, dan diundang pada hari kedua, dan dia memenuhi undangan tersebut, ketika di undang pada hari ketiga, ia melempar utusan (orang yang mengundang) dengan kerikil, dan tidak memenuhi undangan tersebut, Sa'id bin Musayyab lalu berkata; \"orang yang melakukan hal ini adalah sum'ah dan riya`.\""},"1624":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ قَالَ شَرُّ الطَّعَامِ طَعَامُ الْوَلِيمَةِ يُدْعَى إِلَيْهَا الْأَغْنِيَاءُ وَيُتْرَكُ الْمَسَاكِينُ وَمَنْ تَرَكَ الدَّعْوَةَ فَقَدْ عَصَى اللَّهَ وَرَسُولَهُ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Al A'raj] dari [Abu Hurairah] bahwa ia berkata; \"Seburuk-buruk makanan adalah makanan pesta pernikahan, yang hanya mengundang orang-orang kaya, sementara orang-orang miskin ditinggalkan. Barangsiapa tidak memenuhi undangan, sungguh ia telah durhaka kepada Allah dan rasulNya.\""},"1625":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ سُلَيْمَانَ بْنِ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَ جَاءَ رَجُلٌ قَدْ صَنَعَ طَعَامًا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعْنِي فَدَعَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا وَأَوْمَأَ إِلَيْهِ بِيَدِهِ قَالَ يَقُولُ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا وَأَشَارَ إِلَى عَائِشَةَ قَالَ لَا فَأَعْرَضَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَوْمَأَ إِلَيْهِ الثَّانِيَةَ وَأَوْمَأَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْرَضَ عَنْهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَوْمَأَ إِلَيْهِ الثَّالِثَةَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذِهِ قَالَ نَعَمْ فَانْطَلَقَ مَعَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَائِشَةُ فَأَكَلَا مِنْ طَعَامِهِ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas], ia berkata; Seorang laki-laki yang membuat makanan datang kepada Rasulullah shallallahu 'alaihi wasallam datang -maksudnya adalah mengundang beliau- maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah dengan ini?\" Laki-laki itu memberi isyarat dengan tangannya. Anas berkata; Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya: \"Apakah dengan ini?\" beliau menunjuk kepada 'Aisyah. Laki-laki itu berkata; \"Jangan.\" Rasulullah shallallahu 'alaihi wasallam lalu berpaling darinya. Laki-laki itu memberi isyarat yang kedua kalinya dan Rasulullah shallallahu 'alaihi wasallam juga memberi isyarat kepadanya lalu berpaling. Dan orang tersebut memberikan isyarat untuk ketiga kali, kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Dan wanita ini?\" Orang tersebut berkata; \"Ya.\" Lalu Rasulullah shallallahu 'alaihi wasallam dan 'Aisyah pergi bersamanya dan menyantap makanannya.\""},"1626":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ أَبِي مَسْعُودٍ قَالَ جَاءَ رَجُلٌ يُقَالُ لَهُ أَبُو شُعَيْبٍ وَكَانَ لَهُ غُلَامٌ لَحَّامٌ فَقَالَ اصْنَعْ لِي طَعَامًا أَدْعُو رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ قَالَ فَدَعَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَامِسَ خَمْسَةٍ فَتَبِعَهُمْ رَجُلٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ دَعَوْتَنَا خَامِسَ خَمْسَةٍ وَهَذَا رَجُلٌ قَدْ تَبِعَنِي فَإِنْ شِئْتَ أَذِنْتَ لَهُ وَإِنْ شِئْتَ تَرَكْتَهُ قَالَ فَأَذِنَ لَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Al A'masy] dari [Abu Wa`il] dari [Abu Mas'ud], ia berkata; \"Seorang laki-laki yang bernama Abu Syu'aib memiliki seorang budak yang pandai memasak daging. Abu Syu'aib berkata kepadanya; \"Buatlah makanan dengan lima porsi, aku ingin mengundang Rasulullah shallallahu 'alaihi wasallam.\" Ia lalu mengundang Rasulullah shallallahu 'alaihi wasallam dengan sejumlah lima porsi. lalu ada seorang laki-laki yang mengikuti beliau, maka Nabi shallallahu 'alaihi wasallam pun bersabda: \"Engkau mengundang kami dengan lima porsi, padahal ada seorang laki-laki (lain) yang ingin ikut. Sekarang terserah kamu, memberi izin atau tidak.\" Abu Mas'ud menjawab, \"lalu Abu Syu'aib memberinya izin.\""},"1627":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا خَالِدٌ عَنْ أَبِي طُوَالَةَ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ مَعْمَرٍ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضْلُ عَائِشَةَ عَلَى النِّسَاءِ كَفَضْلِ الثَّرِيدِ عَلَى سَائِرِ الطَّعَامِ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Khalid] dari [Abu Thuwalah Abdullah bin Abdurrahman bin Ma'mar] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Keutamaan Aisyah atas wanita-wanita yang lain seperti keutamaan bubur atas seluruh makanan.\""},"1628":{"ar":" حَدَّثَنَا عَلِيُّ بْنُ الْمَدِينِيِّ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا عَبْدُ الْكَرِيمِ أَبُو أُمَيَّةَ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ الْحَارِثِ بْنِ نَوْفَلٍ زَوَّجَنِي أَبِي فِي إِمَارَةِ عُثْمَانَ فَدَعَا رَهْطًا مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَانَ فِيمَنْ دَعَا صَفْوَانُ بْنُ أُمَيَّةَ وَهُوَ شَيْخٌ كَبِيرٌ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ انْهَسُوا اللَّحْمَ نَهْسًا فَإِنَّهُ أَشْهَى وَأَمْرَأُ","id":"Telah menceritakan kepada kami [Ali bin Al Madini] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Abdul Karim Abu Umayyah], ia berkata; [Abdullah bin Al Harits bin Naufal] berkata; Ayahku telah menikahkan diriku pada masa kepemimpinan Utsman. Ketika itu ia mengundang sekelompok dari sahabat Rasulullah shallallahu 'alaihi wasallam. Diantara tamu undangan tersebut terdapat [Shafwan bin Umayyah], ia adalah orang yang tua renta, lalu ia berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gigitlah daging itu dengan ujung gigi, sesungguhnya hal itu lebih berselera dan lebih nikmat.\""},"1629":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ عَلِيِّ بْنِ الْأَقْمَرِ حَدَّثَنِي أَبُو جُحَيْفَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا آكُلُ مُتَّكِئًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ali bin Al Aqmar] telah menceritakan kepadaku [Abu Juhaifah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku tidak pernah makan sambil bersandar.\""},"1630":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ مُحَمَّدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أُتِيَ بِالْبَاكُورَةِ بِأَوَّلِ الثَّمَرَةِ قَالَ اللَّهُمَّ بَارِكْ لَنَا فِي مَدِينَتِنَا وَفِي ثَمَرَتِنَا وَفِي مُدِّنَا وَفِي صَاعِنَا بَرَكَةً مَعَ بَرَكَةٍ ثُمَّ يُعْطِيهِ أَصْغَرَ مَنْ يَحْضُرُهُ مِنْ الْوِلْدَانِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim bin Hammad] dari [Abdul Aziz bin Muhammad] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah], ia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam pertama diberi buah, maka beliau mengucapkan: \"Ya Allah, berkahilah kami, Madinah kami, buah kami, mud kami, sha' kami dengan keberkahan yang diiringi dengan keberkahan lainnya.\" Kemudian beliau memberikannya kepada anak paling kecil yang ikut hadir dari kalangan anak-anak.\""},"1631":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا جَاءَ خَادِمُ أَحَدِكُمْ بِالطَّعَامِ فَلْيُجْلِسْهُ فَإِنْ أَبَى فَلْيُنَاوِلْهُ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [ayahnya] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila pembantu salah seorang dari kalian datang dengan membawa makanan, hendaknya ia mempersilahkannya duduk, apabila pembantu itu menolak, hendaknya ia mengambilkan makan untuknya.\""},"1632":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مُحَمَّدِ بْنِ زِيَادٍ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ يُحَدِّثُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا أَتَى أَحَدَكُمْ خَادِمُهُ بِطَعَامِهِ فَلْيُجْلِسْهُ مَعَهُ وَلْيُنَاوِلْهُ لُقْمَةً أَوْ لُقْمَتَيْنِ أَوْ أُكْلَةً أَوْ أُكْلَتَيْنِ فَإِنَّهُ وَلِيَ حَرَّهُ وَدُخَانَهُ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Muhammad bin Ziyad], ia berkata; Aku mendengar [Abu Hurairah] menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila pembantu salah seorang dari kalian datang dengan membawa makanan, hendaknya ia mempersilahkan duduk bersamanya, jika pembantu itu menolak, hendaknya ia mengambilkan untuknya satu atau dua suap, -atau satu atau dua makan- Karena dialah orang yang mengurusi panas dan asap makanan tersebut.\""},"1633":{"ar":" حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُحِبُّ الْحَلْوَاءَ وَالْعَسَلَ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari [Aisyah] radliallahu 'anha, ia berkata; \"Rasulullah shallallahu 'alaihi wasallam menyukai makanan yang manis dan kurma.\""},"1634":{"ar":" حَدَّثَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ أَبِي الْحُوَيْرِثِ عَنْ ابْنِ عَبَّاسٍ قَالَ خَرَجَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ الْبِرَازِ فَقُدِّمَ إِلَيْهِ طَعَامٌ فَقِيلَ لَهُ أَلَا تَوَضَّأُ قَالَ فَقَالَ أُصَلِّي فَأَتَوَضَّأُ قَالَ أَبُو مُحَمَّد إِنَّمَا هُوَ سَعِيدُ بْنُ الْحُوَيْرِثِ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ بْنِ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ الْحُوَيْرِثِ عَنْ ابْنِ عَبَّاسٍ قَالَ وَسَمِعْتُ أَبَا عَاصِمٍ يُحَدِّثُ عَنْ ابْنِ جُرَيْجٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ سَعِيدِ بْنِ الْحُوَيْرِثِ عَنْ ابْنِ عَبَّاسٍ بِإِسْنَادِهِ","id":"Telah menceritakan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari ['Amr bin Dinar] dari [Sa'id bin Abu Al Huwairits] dari [Ibnu Abbas], ia berkata; Sehabis buang hajat, Nabi shallallahu 'alaihi wasallam di beri hidangan, lalu diberitahukan kepada beliau; \"Apakah anda tidak berwudhu?\" Beliau menjawab: \"Apakah aku akan melakukan shalat hingga harus berwudhu?\" Perawi berkata; Abu Muhammad adalah Sa'id bin Al Huwairits, telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan bin 'Uyainah] dari ['Amr bin Dinar] dari [Sa'id bin Al Huwairits] dari [Ibnu Abbas], ia berkata; aku mendengar [Abu 'Ashim] menceritakan dari [Ibnu Juraij] dari ['Amr bin Dinar] dari [Sa'id bin Al Huwairits] dari [Ibnu Abbas] dengan sanad yang sama."},"1635":{"ar":" حَدَّثَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ إِبْرَاهِيمَ يُحَدِّثُ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَجْنَبَ فَأَرَادَ أَنْ يَأْكُلَ أَوْ يَنَامَ تَوَضَّأَ","id":"Telah menceritakan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam], ia berkata; aku mendengar [Ibrahim] menceritakan dari [Al Aswad] dari ['Aisyah], ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam junub lalu beliau hendak makan atau minum atau tidur, maka beliau berwudhu.\""},"1636":{"ar":"أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي عِمْرَانَ الْجَوْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَ أَوْصَانِي خَلِيلِي صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِذَا طَبَخْتَ مَرَقَةً فَأَكْثِرْ مَاءَهَا ثُمَّ انْظُرْ أَهْلَ بَيْتٍ مِنْ جِيرَتِكَ فَاغْرِفْ لَهُمْ مِنْهَا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syu'bah] dari [Abu Imran Al Jauni] dari [Abdullah bin Ash Shamit] dari [Abu Dzar], ia berkata; Kekasihku shallallahu 'alaihi wasallam telah berwasiat kepadaku, beliau bersabda: \"Apabila kalian memasak kuah, maka perbanyaklah airnya, kemudian perhatikanlah keluarga tetanggamu lalu bagikanlah kepada mereka.\""},"1637":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ مُوسَى بْنِ مُحَمَّدِ بْنِ إِبْرَاهِيمَ حَدَّثَنِي أَبِي عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا وُضِعَ الطَّعَامُ فَاخْلَعُوا نِعَالَكُمْ فَإِنَّهُ أَرْوَحُ لِأَقْدَامِكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Sa'id] telah menceritakan kepada kami [Uqbah bin Khalid] dari [Musa bin Muhammad bin Ibrahim] telah menceritakan kepadaku [bapakku] dari [Anas bin Malik] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila makanan telah dihidangkan maka lepaslah sandal kalian, karena hal itu membuat telapak kaki lebih nyaman.\""},"1638":{"ar":" أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْبُدُوا الرَّحْمَنَ وَأَفْشُوا السَّلَامَ وَأَطْعِمُوا الطَّعَامَ تَدْخُلُوا الْجِنَانَ","id":"Telah mengabarkan kepada kami [Ibrahim bin Musa] telah menceritakan kepada kami [Jarir] dari ['Atha` bin As Sa`ib] dari [Ayahnya] dari [Abdullah bin 'Amr] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Beribadahlah kepada Allah yang Maha Pengasih, dan tebarkanlah salam serta berilah makan, niscaya kalian akan masuk Surga.\""},"1639":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَجِيبُوا الدَّاعِيَ إِذَا دُعِيتُمْ قَالَ وَكَانَ عَبْدُ اللَّهِ يَأْتِي الدَّعْوَةَ فِي الْعُرْسِ وَفِي غَيْرِ الْعُرْسِ وَيَأْتِيهَا وَهُوَ صَائِمٌ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penuhilah undangan orang yang mengundang, jika kalian diundang.\" Ibnu Umar berkata; Dan Abdullah biasa mendatangi undangan pesta pernikahan dan selainnya, dan ia mendatanginya meskipun dalam keadaan berpuasa.\""},"1640":{"ar":" أَخْبَرَنَا عَلِيُّ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ فَأْرَةٍ وَقَعَتْ فِي سَمْنٍ فَقَالَ أَلْقُوهَا وَمَا حَوْلَهَا وَكُلُوا أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ ابْنِ عُيَيْنَةَ بِإِسْنَادِهِ","id":"Telah mengabarkan kepada kami [Ali bin Abdullah] telah menceritakan kepada kami [Sufyan] telah menceritakan kepada kami [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] bahwa Rasulullah shallallahu 'alaihi wasallam ditanya mengenai seekor tikus yang jatuh di atas minyak samin. Beliau bersabda: \"Buanglah tikus tersebut dan apa yang ada disekitarnya, lalu makanlah.\" Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Ibnu 'Uyainah] dengan sanadnya.\""},"1641":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ سُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ فَأْرَةٍ وَقَعَتْ فِي سَمْنٍ فَمَاتَتْ فَقَالَ خُذُوهَا وَمَا حَوْلَهَا فَاطْرَحُوهُ حَدَّثَنَا زَيْدُ بْنُ يَحْيَى حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ مَيْمُونَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ قَالَ أَبُو مُحَمَّد إِذَا كَانَ ذَائِبًا أُهَرِيقَ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], ia berkata; Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai seekor tikus yang terjatuh di atas minyak samin kemudian mati. Beliau menjawab: \"Ambillah tikus tersebut dan apa-apa yang ada di sekitarnya, kemudian buanglah.\" Telah menceritakan kepada kami [Zaid bin Yahya] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Maimunah] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas. Abu Muhammad mengatakan; \"Apabila mencair maka minyak samin terseut harus di tumpahkan.\""},"1642":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا ثَوْرُ بْنُ يَزِيدَ حَدَّثَنَا حُصَيْنٌ الْحِمْيَرِيُّ أَخْبَرَنِي أَبُو سَعْدٍ الْخَيْرُ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَكَلَ فَلْيَتَخَلَّلْ فَمَا تَخَلَّلَ فَلْيَلْفِظْهُ وَمَا لَاكَ بِلِسَانِهِ فَلْيَبْتَلِعْ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Tsaur bin Yazid] telah menceritakan kepada kami [Hushain Al Himyari] telah mengabarkan kepadaku [Abu Sa'd Al Khair] dari [Abu Hurairah] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang sehabis makan, hendaknya ia mengeluarkan apa yang ada disela-sela giginya, dan barangsiapa telah mengeluarkan apa yang ada di sela-sela giginya, hendaknya ia membuangnya sementara yang ada di lidah, hendaknya ditelan.\""},"1643":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُ أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْلَةَ أُسْرِيَ بِهِ بِإِيلِيَاءَ بِقَدَحَيْنِ مِنْ خَمْرٍ وَلَبَنٍ فَنَظَرَ إِلَيْهِمَا ثُمَّ أَخَذَ اللَّبَنَ فَقَالَ جِبْرِيلُ الْحَمْدُ لِلَّهِ الَّذِي هَدَاكَ لِلْفِطْرَةِ لَوْ أَخَذْتَ الْخَمْرَ غَوَتْ أُمَّتُكَ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa ia mendengar [Abu Hurairah] berkata; Nabi shallallahu 'alaihi wasallam pernah di beri dua gelas yang berisi arak dan susu di Iliya' pada malam isra`, beliau kemudian melihat keduanya dan mengambil susu. Jibril berkata; segala puji bagi Allah Yang telah menunjukimu kepadamu kesucian, seandainya engkau mengambil arak, niscaya umatmu akan sesat.\""},"1644":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَ كُنْتُ سَاقِيَ الْقَوْمِ فِي مَنْزِلِ أَبِي طَلْحَةَ قَالَ فَنَزَلَ تَحْرِيمُ الْخَمْرِ قَالَ فَأَمَرَ مُنَادِيًا فَنَادَى فَقَالَ أَبُو طَلْحَةَ اخْرُجْ فَانْظُرْ مَا هَذَا فَخَرَجْتُ فَقُلْتُ هَذَا مُنَادٍ يُنَادِي أَلَا إِنَّ الْخَمْرَ قَدْ حُرِّمَتْ فَقَالَ لِيَ اذْهَبْ فَأَهْرِقْهَا قَالَ فَجَرَتْ فِي سِكَكِ الْمَدِينَةِ قَالَ وَكَانَتْ خَمْرُهُمْ يَوْمَئِذٍ الْفَضِيخَ فَقَالَ بَعْضُ الْقَوْمِ قُتِلَ قَوْمٌ وَهِيَ فِي بُطُونِهِمْ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ { لَيْسَ عَلَى الَّذِينَ آمَنُوا وَعَمِلُوا الصَّالِحَاتِ جُنَاحٌ فِيمَا طَعِمُوا إِذَا مَا اتَّقَوْا وَآمَنُوا } الْآيَةَ","id":"Telah mengabarkan kepada kami [Abu Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] telah menceritakan kepada kami [Tsabit] dari [Anas], ia berkata; Ketika aku menuangkan minuman di rumah Abu Thalhah. Anas melanjutkan; tiba-tiba turunlah (ayat) yang mengharamkan khamer. Kemudian beliau memerintahkan seseorang untuk menyeru, ia pun menyeru. Lalu Abu Thalhah berkata; \"Keluarlah dan lihatlah ada apa itu?, \" Akupun keluar, setelah itu aku berkata; \"Itu adalah orang yang menyeru, ketahuilah bahwa khamer telah diharamkan.\" Abu Thalhah berkata kepadaku; \"Pergi dan tumpahkanlah khamer tersebut.\" Anas berkata; \"Berita itu kemudian tersebar ke seantero penjuru Madinah, khamer mereka saat itu adalah fadikh (khmer yang terbuat dari rendaman kurma pentil). Kemudian sebagian orang mengatakan; \"Beberapa orang telah meninggal, sementara perut mereka masih terisi khamer.\" Maka Allah 'azza wajalla menurunkan ayat: Tidak ada dosa bagi orang-orang yang beriman dan mengerjakan amalan yang saleh karena memakan makanan yang telah mereka makan dahulu, apabila mereka bertakwa serta beriman. QS Al Ma`idah; 93."},"1645":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ شَرِبَ الْخَمْرَ فِي الدُّنْيَا ثُمَّ لَمْ يَتُبْ مِنْهَا حُرِمَهَا فِي الْآخِرَةِ فَلَمْ يُسْقَهَا","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum khamer di dunia, kemudian ia tidak bertaubat darinya, maka ia diharamkan darinya di Akherat, dan tidak akan diberi minum darinya.\""},"1646":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي رَبِيعَةُ بْنُ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ قَالَ دَخَلْتُ عَلَى عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ فِي حَائِطٍ لَهُ بِالطَّائِفِ يُقَالُ لَهُ الْوَهْطُ فَإِذَا هُوَ مُخَاصِرٌ فَتًى مِنْ قُرَيْشٍ يُزَنُّ ذَلِكَ الْفَتَى بِشُرْبِ الْخَمْرِ فَقُلْتُ خِصَالٌ بَلَغَتْنِي عَنْكَ أَنَّكَ تُحَدِّثُ بِهَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ مَنْ شَرِبَ الْخَمْرَ شَرْبَةً لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ صَبَاحًا فَلَمَّا أَنْ سَمِعَهُ الْفَتَى يَذْكُرُ الْخَمْرَ اخْتَلَجَ يَدَهُ مِنْ يَدِ عَبْدِ اللَّهِ ثُمَّ وَلَّى فَقَالَ عَبْدُ اللَّهِ اللَّهُمَّ إِنِّي لَا أُحِلُّ لِأَحَدٍ أَنْ يَقُولَ عَلَيَّ مَا لَمْ أَقُلْ وَإِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ شَرِبَ الْخَمْرَ شَرْبَةً لَمْ تُقْبَلْ لَهُ صَلَاةٌ أَرْبَعِينَ صَبَاحًا فَإِنْ تَابَ تَابَ اللَّهُ عَلَيْهِ فَلَا أَدْرِي فِي الثَّالِثَةِ أَمْ فِي الرَّابِعَةِ كَانَ حَقًّا عَلَى اللَّهِ أَنْ يَسْقِيَهُ مِنْ رَدْغَةِ الْخَبَالِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i], ia berkata; telah menceritakan kepadaku [Rabi'ah bin Yazid] dari [Abdullah bin Ad Dailami], ia berkata; aku menemui [Abdullah bin 'Amr bin Al 'Ash] di kebunnya di Thaif, kebun itu disebut Al Wahth. Ternyata ia sedang menahan tangan seorang pemuda dari Quraisy yang dituduh meminum khamer. Aku kemudian berkata; \"Beberapa perkara yang sampai kepadaku bahwa anda menceritakannya dari Rasulullah shallallahu 'alaihi wasallam, bahwa: \"Barangsiapa meminum khamer satu teguk, maka tidak akan diterima shalatnya selama empat puluh hari.\" Ketika pemuda tersebut mendengar ia menyebutkan khamer, maka pemuda itu menarik dari tangan Abdullah, kemudian pergi. Abdullah lalu berkata; \"Ya Allah, sesungguhnya aku tidak mengahalalkan orang yang memfitnahku telah mengucapkan sesuatu yang tidak aku katakan. Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum seteguk khamer, maka tidak akan diterima shalatnya selama empat puluh hari, apabila ia bertaubat maka Allah menerima taubatnya -Aku tidak tahu, apakah hal itu pada kali ketiga atau keempat-Maka Allah berhak untuk memberinya minuman dari Lumpur penghuni Neraka pada Hari Kiamat.\""},"1647":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا الْحَسَنُ بْنُ أَبِي جَعْفَرٍ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلَا يَقْعُدْ عَلَى مَائِدَةٍ يُشْرَبُ عَلَيْهَا الْخَمْرُ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Al Hasan bin Abu Ja'far] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa beriman kepada Allah dan Hari Akhir, maka janganlah ia duduk di hidangan yang terdapat khamer.\""},"1648":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْبَصْرِيُّ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ جَابَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ وَلَدُ زِنْيَةٍ وَلَا مَنَّانٌ وَلَا عَاقٌّ وَلَا مُدْمِنُ خَمْرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir Al Bashri] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Jaban] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak akan masuk surga anak hasil zina, orang yang mengungkit pemberiannya, anak durhaka dan pecandu khamer.\""},"1649":{"ar":" حَدَّثَنَا أَحْمَدُ بْنُ الْحَجَّاجِ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ نُبَيْطِ بْنِ شَرِيطٍ عَنْ جَابَانَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَدْخُلُ الْجَنَّةَ عَاقٌّ وَلَا مَنَّانٌ وَلَا مُدْمِنُ خَمْرٍ","id":"Telah menceritakan kepada kami [Ahmad bin Al Hajjaj] telah menceritakan kepada kami [Abdurrahman bin Mahdi] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Salim bin Abu Al Ja'd] dari [Nubaith bin Syarith] dari [Jaban] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak akan masuk surga anak durhaka, orang yang mengungkit pemberiannya dan pecandu khamer.\""},"1650":{"ar":" أَخْبَرَنَا سُهَيْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا سِمَاكٌ قَالَ سَمِعْتُ عَلْقَمَةَ بْنَ وَائِلٍ يُحَدِّثُ عَنْ أَبِيهِ وَائِلٍ أَنَّ سُوَيْدَ بْنَ طَارِقٍ سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْخَمْرِ فَنَهَاهُ عَنْهَا أَنْ يَصْنَعَهَا فَقَالَ إِنَّهَا دَوَاءٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَيْسَتْ دَوَاءً وَلَكِنَّهَا دَاءٌ","id":"Telah mengabarkan kepada kami [Suhail bin Hammad] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Simak], ia berkata; aku bertanya kepada ['Alqamah bin Wail] dia menceritakan dari ayahnya yaitu [Wail] bahwa Suwaid bin Thariq bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai khamer. Lantas beliau melarang untuk membuatnya. Ia pun berkata; \"Sesungguhnya khamer dapat di jadikan obat.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya khamer bukanlah obat, melainkan penyakit.\""},"1651":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ عَنْ الْأَوْزَاعِيِّ قَالَ سَمِعْتُ أَبَا كَثِيرٍ يَقُولُ سَمِعْتُ أَبَا هُرَيْرَةَ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَمْرُ فِي هَاتَيْنِ الشَّجَرَتَيْنِ النَّخْلَةِ وَالْعِنَبَةِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] dari [Al Auza'i], ia berkata; aku mendengar [Abu Katsir] berkata; aku mendengar [Abu Hurairah] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Khamer dapat di buat dari dua pohon ini yaitu pohon kurma dan pohon anggur.\""},"1652":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْبِتْعِ قَالَ كُلُّ شَرَابٍ أَسْكَرَ حَرَامٌ","id":"Telah menceritakan kapada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Abu Salamah] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah ditanya mengenai Al Bit', Beliau bersabda: \"Semua minuman yang memabukkan adalah haram.\" "},"1653":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ إِسْرَائِيلَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِيهِ قَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَا وَمُعَاذَ بْنَ جَبَلٍ إِلَى الْيَمَنِ فَقَالَ اشْرَبُوا وَلَا تَشْرَبُوا مُسْكِرًا فَإِنَّ كُلَّ مُسْكِرٍ حَرَامٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Isra`il] dari [Abu Ishaq] dari [Abu Burdah bin Abu Musa] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengutusku dan Mu'adz bin Jabal ke Yaman, Beliau berkata: \"Minumlah dan janganlah kalian minum sesuatu yang memabukkan, karena sesungguhnya segala yang memabukkan adalah haram.\""},"1654":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ أَخْبَرَنَا أَبُو أُسَامَةَ حَدَّثَنَا الْوَلِيدُ بْنُ كَثِيرِ بْنِ سِنَانٍ حَدَّثَنِي الضَّحَّاكُ بْنُ عُثْمَانَ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنْهَاكُمْ عَنْ قَلِيلِ مَا أَسْكَرَ كَثِيرُهُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah mengabarkan kepada kami [Abu Usamah] telah menceritakan kepada kami [Al Walid bin Katsir bin Sinan] telah menceritakan kepadaku [Adh Dhahhak bin Utsman] dari [Bukair bin Abdullah bin Al Asyajj] dari ['Amir bin Sa'd] dari [Sa'd] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Aku melarang kalian dari sedikit yang banyaknya menyebabkan mabuk.\""},"1655":{"ar":" حَدَّثَنَا زَيْدُ بْنُ يَحْيَى حَدَّثَنَا مُحَمَّدُ بْنُ رَاشِدٍ عَنْ أَبِي وَهْبٍ الْكَلَاعِيِّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ أَوَّلَ مَا يُكْفَأُ قَالَ زَيْدٌ يَعْنِي الْإِسْلَامَ كَمَا يُكْفَأُ الْإِنَاءُ كَفْيَ الْخَمْرِ فَقِيلَ فَكَيْفَ يَا رَسُولَ اللَّهِ وَقَدْ بَيَّنَ اللَّهُ فِيهَا مَا بَيَّنَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَمُّونَهَا بِغَيْرِ اسْمِهَا فَيَسْتَحِلُّونَهَا","id":"Telah menceritakan kepada kami [Zaid bin Yahya] telah menceritakan kepada kami [Muhammad bin Rasyid] dari [Abu Wahb Al Kala'i] dari [Al Qasim bin Muhammad] dari ['Aisyah], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya sesuatu pertama yang ditumpahkan-Zaid berkata; yaitu dalam Islam- seperti membalikkah bejana adalah mrnumpshksn (bejana) khamer.\" Beliau dtanya; \"Bagaimana hal itu terjadi wahai Rasulullah? Padahal Allah telah menjelaskan mengenai khamer sebagaimana yang telah Allah jelaskan?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka menamakannya dengan selain namanya, kemudian mereka menghalalkannya.\""},"1656":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ حَدَّثَنِي أَبُو وَهْبٍ عَنْ مَكْحُولٍ عَنْ أَبِي ثَعْلَبَةَ الْخُشَنِيِّ عَنْ أَبِي عُبَيْدَةَ بْنِ الْجَرَّاحِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَّلُ دِينِكُمْ نُبُوَّةٌ وَرَحْمَةٌ ثُمَّ مُلْكٌ وَرَحْمَةٌ ثُمَّ مُلْكٌ أَعْفَرُ ثُمَّ مُلْكٌ وَجَبَرُوتٌ يُسْتَحَلُّ فِيهَا الْخَمْرُ وَالْحَرِيرُ قَالَ أَبُو مُحَمَّد الْأَعْفَرُ شِبْهُ التُّرَابِ لَيْسَ فِيهِ طَمَعٌ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Yahya bin Hamzah] telah menceritakan kepadaku [Abu Wahb] dari [Makhul] dari [Abu Tsa'labah Al Khusyani] dari [Abu 'Ubaidah bin Al Jarrah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pertama kali dalam agama kalian adalah kenabian dan rahmat, kemudian kerajaan dan rahmat, kemudian kerajaan yang dipimpin dengan keburukan kemudian kerajaan dan keangkuhan serta otoriter, padanya dihalalkan khamer dan kain sutera.\" Abu Muhammad berkata; Al A'far adalah menyerupai debu dan tidak ada harapan padanya."},"1657":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا طُعْمَةُ حَدَّثَنَا عَمْرُو بْنُ بَيَانٍ التَّغْلِبِيُّ عَنْ عُرْوَةَ بْنِ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ أَبِيهِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ مَنْ بَاعَ الْخَمْرَ فَلْيُشَقِّصْ الْخَنَازِيرَ قَالَ أَبُو مُحَمَّد إِنَّمَا هُوَ عُمَرُ بْنُ بَيَانٍ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Thu'mah] telah menceritakan kepada kami ['Amr bin Bayan At Taghlibi] dari ['Urwah bin Al Mughirah bin Syu'bah] dari [Ayahnya] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Barangsiapa menjual khamer, sebagaimana ia menghalalkan daging babi.\" Abu Muhammad berkata; sesungguhnya yang benar adalah Umar bin Bayan."},"1658":{"ar":" حَدَّثَنَا يَعْلَى عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ وَعْلَةَ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ عَنْ بَيْعِ الْخَمْرِ فَقَالَ كَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدِيقٌ مِنْ ثَقِيفٍ أَوْ مِنْ دَوْسٍ فَلَقِيَهُ بِمَكَّةَ عَامَ الْفَتْحِ بِرَاوِيَةٍ مِنْ خَمْرٍ يُهْدِيهَا لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فُلَانُ أَمَا عَلِمْتَ أَنَّ اللَّهَ تَعَالَى قَدْ حَرَّمَهَا قَالَ فَأَقْبَلَ الرَّجُلُ عَلَى غُلَامِهِ فَقَالَ اذْهَبْ فَبِعْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَاذَا أَمَرْتَهُ يَا فُلَانُ قَالَ أَمَرْتُهُ بِبَيْعِهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الَّذِي حَرَّمَ شُرْبَهَا حَرَّمَ بَيْعَهَا فَأَمَرَ بِهَا فَأُكْفِئَتْ فِي الْبَطْحَاءِ","id":"Telah menceritakan kepada kami [Ya'la] dari [Muhammad bin Ishaq] dari [Al Qa'qa' bin Hakim] dari [Abdurrahman bin Wa'lah] ia berkata; Aku bertanya kepada [Ibnu Abbas] mengenai penjualan khamer. Ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah memiliki seorang teman dari Tsaqif atau dari Daus, beliau bertemu dengannya di Makkah pada saat penaklukan kota Makkah, dia membawa geriba berisi khamer yang dihadiahkan kepada beliau. Maka beliau berkata kepadanya: \"Wahai Fulan, tidakkah kamu tahu bahwa Allah Ta'ala telah mengharamkannya?\" Orang itu lalu menghadap kepada budaknya dan berkata; \"Pergi dan juallah khamer tersebut.\" Spontan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang engkau perintahkan kepadanya wahai Fulan?\" Ia berkata; \"Aku memerintahkannya untuk menjualnya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Dzat Yang mengharamkan untuk meminumnya mengharamkan pula untuk menjualnya.\" Kemudian beliau memerintahkan supaya khamer tersebut ditumpahkan di Bathha`."},"1659":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ أَحْمَدَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو يَعْنِي ابْنَ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ بَلَغَ عُمَرَ أَنَّ سَمُرَةَ بَاعَ خَمْرًا فَقَالَ قَاتَلَ اللَّهُ سَمُرَةَ أَمَا عَلِمَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعَنَ اللَّهُ الْيَهُودَ حُرِّمَتْ عَلَيْهِمْ الشُّحُومُ فَجَمَلُوهَا فَبَاعُوهَا قَالَ سُفْيَانُ جَمَلُوهَا أَذَابُوهَا","id":"Telah menceritakan kepada kami [Muhammad bin Ahmad] telah menceritakan kepada kami [Sufyan] dari ['Amr yaitu Ibnu Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata; telah sampai berita kepada Umar, bahwa Samurah telah menjual arak. Umar berkata; \"Semoga Allah memerangi Samurah. Tidakkah ia mengetahui bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Semoga Allah melaknat orang-orang Yahudi, lemak telah diharamkan kepada mereka kemudian mereka mencairkannya dan menjualnya.\" Sufyan berkata; \"Jamaluuha artinya mencairkannya.\""},"1660":{"ar":" حَدَّثَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَكِرَ فَاجْلِدُوهُ ثُمَّ إِذَا سَكِرَ فَاجْلِدُوهُ ثُمَّ إِذَا سَكِرَ فَاجْلِدُوهُ ثُمَّ إِذَا سَكِرَ فَاضْرِبُوا عُنُقَهُ يَعْنِي فِي الرَّابِعَةِ","id":"Telah menceritakan kepada kami ['Ashim bin Ali] telah menceritakan kepada kami [Ibnu Abu Dzi'b] dari [Al Harits bin Abdurrahman] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila ia mabuk maka cambuklah dia, kemudian bila mabuk, cambuklah dia, jika masih mabuk, cambuklah dia, dan apabila masih saja mabuk, maka penggallah lehernya dikeempat kali.\""},"1661":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزْنِي الزَّانِي حِينَ يَزْنِي وَهُوَ مُؤْمِنٌ وَلَا يَسْرِقُ السَّارِقُ حِينَ يَسْرِقُ وَهُوَ مُؤْمِنٌ وَلَا يَشْرَبُ الْخَمْرَ حِينَ يَشْرَبُهَا وَهُوَ مُؤْمِنٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah berzina orang yang berzina ketika ia berzina ia dalam keadaan beriman, dan tidaklah mencuri orang yang mencuri ketika mencuri ia dalam keadaan beriman, dan tidaklah minum arak ketika meminumnya ia dalam keadaan beriman.\""},"1662":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي سُلَيْمَانَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ كَانَ يُنْبَذُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السِّقَاءِ فَإِنْ لَمْ يَكُنْ سِقَاءٌ نُبِذَ لَهُ فِي تَوْرٍ مِنْ بِرَامٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Abdul Malik bin Abu Sulaiman] dari [Abu Az Zubair] dari [Jabir] ia berkata; Nabi shallallahu 'alaihi wasallam pernah dibuatkan rendaman khamer di dalam wadah dari kulit. Apabila tidak ada wadah dari kulit, beliau dibuatkan rendamana khamer dalam bejana kecil yang terbuat dari batu.\""},"1663":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي عَمْرٍو السَّيْبَانِيِّ عَنْ عَبْدِ اللَّهِ بْنِ الدَّيْلَمِيِّ عَنْ أَبِيهِ أَنَّ أَبَاهُ أَوْ أَنَّ رَجُلًا مِنْهُمْ سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّا قَدْ خَرَجْنَا مِنْ حَيْثُ عَلِمْتَ وَنَزَلْنَا بَيْنَ ظَهْرَانَيْ مَنْ قَدْ عَلِمْتَ فَمَنْ وَلِيُّنَا قَالَ اللَّهُ وَرَسُولُهُ قَالُوا يَا رَسُولَ اللَّهِ إِنَّا كُنَّا أَصْحَابَ كَرْمٍ وَخَمْرٍ وَإِنَّ اللَّهَ قَدْ حَرَّمَ الْخَمْرَ فَمَا نَصْنَعُ بِالْكَرْمِ قَالَ اصْنَعُوهُ زَبِيبًا قَالُوا فَمَا نَصْنَعُ بِالزَّبِيبِ قَالَ انْقَعُوهُ فِي الشِّنَانِ انْقَعُوهُ عَلَى غَدَائِكُمْ وَاشْرَبُوهُ عَلَى عَشَائِكُمْ وَانْقَعُوهُ عَلَى عَشَائِكُمْ وَاشْرَبُوهُ عَلَى غَدَائِكُمْ فَإِنَّهُ إِذَا أَتَى عَلَيْهِ الْعَصْرَانِ كَانَ خَلًّا قَبْلَ أَنْ يَكُونَ خَمْرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] dari [Yahya bin Abu 'Amr As Saibani] dari [Abdullah bin Ad Dailami] dari [Ayahnya] bahwa ayahnya atau seorang laki-laki diantara mereka bertanya kepada Nabi shallallahu 'alaihi wasallam, ia berkata; \"Wahai Rasulullah, sesungguhnya kami keluar dari tempat yang telah engkau ketahui dan kami singgah diantara orang-orang yang telah engkau ketahui, maka siapakah penolong-penolong kami?\" Beliau menjawab: \"Allah dan RasulNya.\" Ia berkata lagi; \"Wahai Rasulullah, sesungguhnya kami adalah orang-orang yang memiliki anggur dan khamer, sementara Allah telah mengharamkan khamer, lalu apa yang harus kami perbuat terhadap anggur?\" Beliau menjawab: \"Buatlah menjadi kismis.\" Mereka mengatakan; \"Apa yang harus kami perbuat terhadap kismis?\" Beliau menjawab: \"Rendamlah dalam geriba basah, rendamlah untuk makan siang kalian, dan minumlah untuk makan malam kalian, dan rendamlah untuk makan malam kalian serta minumlah untuk makan siang kalian, karena apabila tiba pagi hari dan senja, ia akan menjadi cuka sebelum menjadi khamer.\""},"1664":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عُمَرَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ حَرَّمَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيتُ ابْنَ عَبَّاسٍ فَأَخْبَرْتُهُ بِقَوْلِ ابْنِ عُمَرَ فَقَالَ صَدَقَ أَبُو عَبْدِ الرَّحْمَنِ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Sa'id bin 'Arubah] dari [Qatadah] dari ['Azrah] dari [Sa'id bin Jubair], ia berkata; Aku bertanya kepada [Ibnu Umar] mengenai Nabidzul Jarr, Ia menjawab; Rasulullah shallallahu 'alaihi wasallam telah mengharamkannya. Kemudian aku bertemu dengan Ibnu Abbas dan mengabarkan kepadanya mengenai perkataan Ibnu Umar, [Ibnu Abbas] menjawab; \"Abu Abdurrahman benar.\" "},"1665":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ نَافِعٍ عَنْ شُعَيْبِ بْنِ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي أَنَسُ بْنُ مَالِكٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْتَبِذُوا فِي الدُّبَّاءِ وَالْمُزَفَّتِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Nafi'] dari [Syu'aib bin Abu Hamzah] dari [Az Zuhri], ia berkata; telah menceritakan kepadaku [Anas bin Malik] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah membuat rendaman (anggur atau kurma) dalam Dubba`dan muzaffat.\" "},"1666":{"ar":" أَخْبَرَنَا أَبُو زَيْدٍ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ أَبَا الْحَكَمِ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ أَوْ سَمِعْتُهُ سُئِلَ عَنْ نَبِيذِ الْجَرِّ فَقَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْجَرِّ وَالدُّبَّاءِ وَسَأَلْتُ ابْنَ الزُّبَيْرِ فَقَالَ مِثْلَ قَوْلِ ابْنِ عَبَّاسٍ قَالَ وَقَالَ ابْنُ عَبَّاسٍ مَنْ سَرَّهُ أَنْ يُحَرِّمَ مَا حَرَّمَ اللَّهُ وَرَسُولُهُ أَوْ مَنْ كَانَ مُحَرِّمًا مَا حَرَّمَ اللَّهُ وَرَسُولُهُ فَلْيُحَرِّمْ النَّبِيذَ قَالَ و حَدَّثَنِي أَخِي عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْجَرِّ وَالدُّبَّاءِ وَالْمُزَفَّتِ وَعَنْ الْبُسْرِ وَالتَّمْرِ","id":"Telah mengabarkan kepada kami [Abu Zaid] telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail], ia berkata; aku mendengar [Abu Al Hakam] berkata; aku bertanya kepada [Ibnu Abbas] atau aku mendengar dia ditanya mengenai Nabidzul jarr, Ibnu Abbas menjawab; \"Rasulullah shallallahu 'alaihi wasallam melarang dari jarr dan Dubba'.\" Kemudian aku bertanya kepada [Ibnu Az Zubair], dia pun mengatakan seperti perkataan [Ibnu Abbas]. Dan Ibnu Abbas berkata; \"Barangsiapa senang mengharamkan apa yang telah diharamkan Allah dan RasulNya, atau barangsiapa menghamkan apa yang telah diharamkan Allah dan RasulNya, hendaknya ia mengharamkan rendaman kurma dan anggur.\" Perawi berkata; telah menceritakan kepadaku [saudaraku] dari [Abu Sa'id Al Khudri] bahwa Rasulullah shallallahu 'alaihi wasallam telah melarang dari jarr, dubba' dan muzaffat, serta (rendaman) dari Busr dan tamr. "},"1667":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا ثَابِتُ بْنُ يَزِيدَ حَدَّثَنَا عَاصِمٌ عَنْ فُضَيْلِ بْنِ زَيْدٍ الرَّقَاشِيِّ أَنَّهُ أَتَى عَبْدَ اللَّهِ بْنَ مُغَفَّلٍ فَقَالَ أَخْبِرْنِي بِمَا يَحْرُمُ عَلَيْنَا مِنْ الشَّرَابِ فَقَالَ الْخَمْرُ قَالَ قُلْتُ هُوَ فِي الْقُرْآنِ قَالَ مَا أُحَدِّثُكَ إِلَّا مَا سَمِعْتُ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ بِالِاسْمِ أَوْ قَالَ بِالرِّسَالَةِ قَالَ نَهَى عَنْ الدُّبَّاءِ وَالْحَنْتَمِ وَالنَّقِيرِ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Tsabit bin Yazid] telah menceritakan kepada kami ['Ashim] dari [Fudhail bin Zaid Ar Raqasyi] bahwa ia pernah menemui [Abdullah bin Mughaffal] lalu berkata; \"Beritahukanlah kepadaku mengenai minuman yang diharamkan atas kita!.\" Abdullah bin Mughaffal menjawab; \"Yaitu khamer.\" Fudhail berkata; saya katakan; \"Apakah hal itu (tercantum) dalam Al Qur'an?\" Abdullah bin Mughaffal menjawab; \"Tidaklah aku menceritakan kepadamu kecuali apa yang telah aku dengar dari Muhammad shallallahu 'alaihi wasallam -Abdullah bin Mughaffal (mengatakan dengan) mendahulukan nama yaitu Muhammad Rasulullah, atau mendahulukan risalah yaitu Rasulullah Muhammad- dia melanjutkan; \"Beliau telah melarang bejana dari dubba', hantam dan naqir.\" "},"1668":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ وَسَعِيدُ بْنُ عَامِرٍ وَاللَّفْظُ لِيَزِيدَ قَالَا أَخْبَرَنَا هِشَامٌ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَنْتَبِذُوا الزَّهْوَ وَالرُّطَبَ جَمِيعًا وَلَا تَنْتَبِذُوا الزَّبِيبَ وَالتَّمْرَ جَمِيعًا وَانْتَبِذُوا كُلَّ وَاحِدٍ مِنْهُمَا عَلَى حِدَتِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dan [Sa'id bin 'Amir] sedangkan redaksi haditsnya dari Yazid, keduanya berkata; telah mengabarkan kepada kami [Hisyam] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Buatlah rendaman dari Zahwu (kurma masak) serta Ruthab (kurma basah) secara bersamaan, dan janganlah membuat rendaman dari Kismis dan tamr (kurma kering) secara bersamaan, dan buatlah rendaman dari salah satunya secara terpisah.\""},"1669":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا شُعْبَةُ عَنْ سِمَاكٍ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُولُوا الْكَرْمَ وَقُولُوا الْعِنَبَ أَوْ الْحَبَلَةَ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Syu'bah] dari [Simak] dari ['Alqamah bin Wail] dari [Ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian mengatakan Al Karam, akan tetapi katakanlah anggur atau habalah.\""},"1670":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ السُّدِّيِّ عَنْ يَحْيَى بْنِ عَبَّادٍ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ كَانَ فِي حِجْرِ أَبِي طَلْحَةَ يَتَامَى فَاشْتَرَى لَهُمْ خَمْرًا فَلَمَّا نَزَلَ تَحْرِيمُ الْخَمْرِ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ أَجْعَلُهُ خَلًّا قَالَ لَا فَأَهْرَاقَهُ","id":"Telah menceritakan kepada kami ['Ubaidullah bin Musa] dari [Isra`il] dari [As Suddi] dari [Yahya bin 'Abbad] dari [Anas bin Malik] ia berkata; \"Abu Thalhah memiliki tanggungan anak-anak yatim, kemudian ia membelikan khamer untuk mereka, katika turun pengharaman khamer, ia datang kepada Nabi shallallahu 'alaihi wasallam dan memberitahukan hal itu kepada beliau, lantas Abu Thalhah berkata; \"Apakah aku boleh menjadikannya cuka?\" Beliau bersabda: \"Tidak.\" Setelah itu Abu Thalhah menumpahkannya."},"1671":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا الزُّهْرِيُّ عَنْ أَنَسِ بْنِ مَالِكٍ أَنَّهُ رَأَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ لَبَنًا وَعَنْ يَسَارِهِ أَبُو بَكْرٍ وَعَنْ يَمِينِهِ رَجُلٌ أَعْرَابِيٌّ فَأَعْطَى الْأَعْرَابِيَّ فَضْلَهُ ثُمَّ قَالَ الْأَيْمَنَ فَالْأَيْمَنَ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Az Zuhri] dari [Anas bin Malik] bahwa dia pernah melihat Rasulullah shallallahu 'alaihi wasallam meminum susu, sementara di sebelah kirinya terdapat Abu Bakr dan disebelah kanannya terdapat seorang arab badui, maka beliau memberikan sisanya kepada orang badui tersebut, beliau bersabda: \"(Dari) yang sebelah kanan kemudian yang sebelah kanan.\""},"1672":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا قَتَادَةُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُشْرَبَ مِنْ فِي السِّقَاءِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam melarang minum (langsung) dari mulut geriba.\""},"1673":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وُهَيْبٌ عَنْ خَالِدٍ الْحَذَّاءِ عَنْ عِكْرِمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُشْرَبَ مِنْ فِي السِّقَاءِ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Wuhaib] dari [Khalid Al Hadzdza`] dari [Ikrimah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang minum (langsung) dari mulut geriba.\" "},"1674":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ اخْتِنَاثِ الْأَسْقِيَةِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Abu Sa'id Al Khudri] bahwa Nabi shallallahu 'alaihi wasallam melarang memotong mulut bejana lalu minum (langsung) darinya.\""},"1675":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَزْرَةُ بْنُ ثَابِتٍ عَنْ ثُمَامَةَ قَالَ كَانَ أَنَسٌ يَتَنَفَّسُ فِي الْإِنَاءِ مَرَّتَيْنِ أَوْ ثَلَاثًا وَزَعَمَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَتَنَفَّسُ فِي الْإِنَاءِ مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami ['Azrah bin Tsabit] dari [Tsumamah] ia berkata; [Anas] bernafas dalam bejana dua atau tiga kali, dan mengira bahwa Rasulullah shallallahu 'alaihi wasallam pernah bernafas dalam bejana dua atau tiga kali (ketika minum).\""},"1676":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى عَنْ مَالِكٍ عَنْ أَيُّوبَ بْنِ حَبِيبٍ عَنْ الزُّهْرِيِّ عَنْ أَبِي الْمُثَنَّى قَالَ كُنْتُ عِنْدَ مَرْوَانَ فَجَاءَ أَبُو سَعِيدٍ فَقَالَ قَالَ رَجُلٌ يَا رَسُولَ اللَّهِ إِنِّي لَا أَرْوَى مِنْ نَفَسٍ وَاحِدٍ قَالَ فَأَبِنْ الْإِنَاءَ عَنْ فِيكَ ثُمَّ تَنَفَّسْ قَالَ إِنِّي أَرَى الْقَذَاةَ قَالَ أَهْرِقْهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Isa] dari [Malik] dari [Ayyub bin Habib] dari [Az Zuhri] dari [Abu Al Mutsanna] ia berkata; aku pernah berada di rumah Marwan, kemudian [Abu Sa'id] datang lalu berkata; seorang laki-laki berkata; \"Wahai Rasulullah, sesungguhnya aku tidak minum dengan satu nafas.\" Beliau lalu bersabda: \"Jauhkanlah bejana dari mulutmu, kemudian bernafaslah.\" Orang tersebut berkata; \"Ternyata setelah itu aku melihat kotoran.\" Beliau bersabda: \"Maka tuangkanlah.\""},"1677":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ قَالَ حَدَّثَنِي أَبِي أَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا بَالَ أَحَدُكُمْ فَلَا يَمَسَّ ذَكَرَهُ بِيَمِينِهِ وَلَا يَسْتَنْجِي بِيَمِينِهِ وَلَا يَتَنَفَّسْ فِي الْإِنَاءِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abdullah bin Abu Qatadah], ia berkata; telah menceritakan kepadaku [Ayahku] bahwa ia telah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang diantara kalian kencing, hendaknya ia tidak memegang kemaluannya dengan tangan kanannya dan tidak cebok dengan tangan kanannya, serta janganlah ia bernafas dalam bejana.\""},"1678":{"ar":" أَخْبَرَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنَا فُلَيْحُ بْنُ سُلَيْمَانَ عَنْ سَعِيدِ بْنِ الْحَارِثِ الْأَنْصَارِيِّ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَ أَتَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَجُلًا مِنْ الْأَنْصَارِ يَعُودُهُ وَجَدْوَلٌ يَجْرِي فَقَالَ إِنْ كَانَ عِنْدَكُمْ مَاءٌ بَاتَ فِي الشَّنِّ وَإِلَّا كَرَعْنَا","id":"Telah mengabarkan kepada kami [Ishaq bin Isa] telah menceritakan kepada kami [Fulaih bin Sulaiman] dari [Sa'id bin Al Harits Al Anshari] dari [Jabir bin Abdullah] ia berkata; Nabi shallallahu 'alaihi wasallam datang mengunjungi seorang laki-laki dari kalangan Anshar, sementara sungai kecil mengalir (di dekatnya). Kemudian beliau bersabda: \"Seandainya kalian memiliki air dalam bejana, jika tidak maka kami akan meminumnya (langsung) dengan mulut kami.\""},"1679":{"ar":" حَدَّثَنَا مَنْصُورُ بْنُ سَلَمَةَ الْخُزَاعِيُّ حَدَّثَنَا شَرِيكٌ عَنْ عَبْدِ الْكَرِيمِ عَنْ الْبَرَاءِ ابْنِ ابْنَةِ أَنَسٍ عَنْ أَنَسٍ عَنْ أُمِّ سُلَيْمٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَرِبَ مِنْ فَمِ قِرْبَةٍ قَائِمًا","id":"Telah menceritakan kepada kami [Manshur bin Salamah Al Khuza'i] telah menceritakan kepada kami [Syarik] dari [Abdul Karim] dari [Al Bara`] cucu Anas, dari [Anas] dari [Ummu Sulaim] bahwa Nabi shallallahu 'alaihi wasallam minum dari mulut geriba sambil berdiri.\""},"1680":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا عِمْرَانُ بْنُ حُدَيْرٍ عَنْ أَبِي الْبَزَرِيِّ يَزِيدَ بْنِ عُطَارِدَ عَنْ ابْنِ عُمَرَ قَالَ كُنَّا نَشْرَبُ وَنَحْنُ قِيَامٌ وَنَأْكُلُ وَنَحْنُ نَسْعَى عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَنَا أَبُو بَكْرِ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ نَحْوَهُ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Imran bin Hudair] dari [Abu Al Bazari Yazid bin 'Utharid] dari [Ibnu Umar] ia berkata; \"Pada saman Rasulullah shallallahu 'alaihi wasallam, kami biasa minum sambil berdiri, dan makan sambil berjalan.\" Telah mengabarkan kepada kami [Abu Bakr bin Abu Syaibah] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] sama seperti hadits di atas."},"1681":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشُّرْبِ قَائِمًا قَالَ فَسَأَلْتُهُ عَنْ الْأَكْلِ فَقَالَ ذَاكَ أَخْبَثُ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam melarang minum sambil berdiri.\" Anas berkata; kemudian aku bertanya kepada beliau mengenai makan, beliau bersabda: \"Itu lebih buruk lagi.\""},"1682":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي زِيَادٍ الطَّحَّانِ قَالَ سَمِعْتُ أَبَا هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِرَجُلٍ رَآهُ يَشْرَبُ قَائِمًا قِئْ قَالَ لِمَ قَالَ أَتُحِبُّ أَنْ تَشْرَبَ مَعَ الْهِرِّ قَالَ لَا قَالَ فَقَدْ شَرِبَ مَعَكَ شَرٌّ مِنْهُ الشَّيْطَانُ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Abu Ziyad Ath Thahhan] ia berkata; aku mendengar [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda kepada seorang laki-laki yang beliau lihat sedang minum sambil berdiri: \"Muntahkanlah.\" Orang itu berkata; \"Kenapa?\" Beliau bersabda: \"Apakah kamu senang minum bersama kucing?\" laki-laki itu menjawab; \"Tidak.\" Beliau bersabda: \"Sungguh telah minum bersamamu sesuatu yang lebih buruk dari kucing yaitu Syetan.\""},"1683":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ يُونُسَ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ نَافِعٍ عَنْ زَيْدِ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي بَكْرٍ عَنْ أُمِّ سَلَمَةَ أَنَّهَا أَخْبَرَتْهُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الَّذِي يَشْرَبُ فِي آنِيَةٍ مِنْ فِضَّةٍ فَإِنَّمَا يُجَرْجِرُ فِي بَطْنِهِ نَارَ جَهَنَّمَ","id":"Telah mengabarkan kepada kami [Ahmad bin Yunus] telah menceritakan kepada kami [Laits bin Sa'd] dari [Nafi'] dari [Zaid bin Abdullah bin Umar] dari [Abdullah bin Abdurrahman bin Abu Bakr] dari [Ummu Salamah] bahwa ia mengabarkan kepadanya, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa minum dari bejana yang terbuat dari perak, sesungguhnya ia telah menuangkan api Jahannam ke dalam perutnya.\""},"1684":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُجَاهِدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى قَالَ خَرَجْنَا مَعَ حُذَيْفَةَ إِلَى الْمَدَائِنِ فَاسْتَسْقَى فَأَتَاهُ دِهْقَانٌ بِإِنَاءٍ مِنْ فِضَّةٍ فَرَمَى بِهِ وَجْهَهُ فَقُلْنَا اسْكُتُوا فَإِنَّا إِنْ سَأَلْنَاهُ لَمْ يُحَدِّثْنَا فَلَمَّا كَانَ بَعْدُ قَالَ أَتَدْرُونَ لِمَ رَمَيْتُهُ قُلْنَا لَا قَالَ إِنِّي كُنْتُ نَهَيْتُهُ وَذَكَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ الشُّرْبِ فِي آنِيَةِ الذَّهَبِ وَالْفِضَّةِ وَعَنْ لُبْسِ الْحَرِيرِ وَالدِّيبَاجِ وَقَالَ هُمَا لَهُمْ فِي الدُّنْيَا وَلَكُمْ فِي الْآخِرَةِ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Ibnu 'Aun] dari [Mujahid] dari [Abdurrahman bin Abu Laila] ia berkata; kami pernah keluar bersama [Hudzaifah] menuju Madain, kemudian dia meminta air minum. Lantas Dihqan datang membawa bejana yang terbuat dari perak. Hudzaifah langsung melempar bejana tersebut ke wajahnya. Kami pun berkata; \"Diamlah kalian, sebab bila kita bertanya kepadanya, maka Hudzaifah tidak akan menceritakan kepada kita. Setelah itu, Hudzaifah berkata: \"Tahukah kalian, kenapa aku melemparnya?\" Kami menjawab: \"Tidak.\" Dia berkata; \"Sesungguhnya aku telah melarangnya....\" Abdurrahman bin Laila kemudian menyebutkan bahwa Nabi shallallahu 'alaihi wasallam telah melarang minum dari bejana yang terbuat dari emas dan perak, dan (melarang) mengenakan sutera dan dibaj (jenis sutera murni). Beliau bersabda: \"Keduanya adalah untuk mereka di dunia dan untuk kalian di Akhirat.\""},"1685":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ حَدَّثَنِي جَابِرٌ قَالَ حَدَّثَنِي أَبُو حُمَيْدٍ السَّاعِدِيُّ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَبَنٍ فَقَالَ أَلَا خَمَّرْتَهُ وَلَوْ تَعْرِضُ عَلَيْهِ عُودًا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abu Az Zubair] telah menceritakan kepadaku [Jabir] ia berkata; telah menceritakan kepadaku [Abu Humaid As Sa'idi] ia berkata; aku datang kepada Rasulullah shallallahu 'alaihi wasallam membawa susu. Kemudian beliau bersabda: \"Tidakkah engkau menutupinya walau hanya menaruh dahan diatasnya?\""},"1686":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ عَنْ خَالِدٍ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ أَمَرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَغْطِيَةِ الْوَضُوءِ وَإِيكَاءِ السِّقَاءِ وَإِكْفَاءِ الْإِنَاءِ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun] dari [Khalid] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkan kami untuk menutupi (wadah) air untuk berwudhu, mengikat geriba, dan membalikkan bejana (apabila kosong).\""},"1687":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ أَيُّوبَ بْنِ حَبِيبٍ عَنْ أَبِي الْمُثَنَّى الْجُهَنِيِّ قَالَ قَالَ مَرْوَانُ لِأَبِي سَعِيدٍ الْخُدْرِيِّ هَلْ سَمِعْتَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْهَى عَنْ النَّفْخِ فِي الشَّرَابِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ayyub bin Habib] dari [Abu Al Mutsanna Al Juhani] ia berkata; Marwan pernah berkata kepada [Abu Sa'id Al Khudri]; \"Apakah kamu pernah mendengar Rasulullah shallallahu 'alaihi wasallam melarang untuk meniup air minum?\" Dia menjawab; \"Ya.\""},"1688":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ عَنْ ابْنِ عُيَيْنَةَ عَنْ عَبْدِ الْكَرِيمِ الْجَزَرِيِّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ النَّفْخِ فِي الشَّرَابِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] dari [Ibnu 'Uyainah] dari [Abdul Karim Al Jazari] dari [Ikrimah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam melarang meniup air minum.\""},"1689":{"ar":" حَدَّثَنَا عَفَّانُ بْنُ مُسْلِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ وَسُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ عَبْدِ اللَّهِ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَاقِي الْقَوْمِ آخِرُهُمْ شُرْبًا","id":"Telah menceritakan kepada kami ['Affan bin Muslim] telah menceritakan kepada kami [Hammad bin Salamah] dan [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Abdullah bin Rabah] dari [Abu Qatadah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang menuangkan air minum adalah orang yang teraikhir minum.\""},"1690":{"ar":" أَخْبَرَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا أَبَانُ حَدَّثَنَا يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ قُلْتُ يَا نَبِيَّ اللَّهِ قَوْلُ اللَّهِ { لَهُمْ الْبُشْرَى فِي الْحَيَاةِ الدُّنْيَا } فَقَالَ سَأَلْتَنِي عَنْ شَيْءٍ مَا سَأَلَنِي عَنْهُ أَحَدٌ قَبْلَكَ أَوْ أَحَدٌ مِنْ أُمَّتِي قَالَ هِيَ الرُّؤْيَا الصَّالِحَةُ يَرَاهَا الْمُسْلِمُ أَوْ تُرَى لَهُ","id":"Telah mengabarkan kepada kami [Muslim bin Ibrahim] telah menceritakan kepada kami [Aban] telah menceritakan kepada kami [Yahya] dari [Abu Salamah] dari ['Ubadah bin Ash Shamit] ia berkata; aku berkata; \"Wahai Nabiyullah, apakah maksud firman Allah Bagi mereka berita gembira dikehidupan dunia.\" Beliau menjawab: \"Engkau telah menanyakan sesuatu yang belum pernah ditayakan seorangpun sebelummu, atau seorangpun dari umatku.\" Beliau bersabda: \"Itu adalah mimpi baik yang dimimpikan oleh seorang muslim atau diperlihatkan kepadanya.\""},"1691":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُؤْيَا الْمُؤْمِنِ جُزْءٌ مِنْ سِتَّةٍ وَأَرْبَعِينَ جُزْءًا مِنْ النُّبُوَّةِ","id":"Telah mengabarkan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] dari ['Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Mimpi seorang mukmin merupakan satu bagian dari empat puluh enam bagian kenabian.\""},"1692":{"ar":" حَدَّثَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ أَبِي يَزِيدَ عَنْ أَبِيهِ عَنْ سِبَاعِ بْنِ ثَابِتٍ عَنْ أُمِّ كُرْزٍ الْكَعْبِيَّةِ قَالَتْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ذَهَبَتْ النُّبُوَّةُ وَبَقِيَتْ الْمُبَشِّرَاتُ","id":"Telah menceritakan kepada kami [Harun bin Abdullah] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ubaidullah bin Abu Yazid] dari [Ayahnya] dari [Siba' bin Tsabit] dari [Ummu Kurz Al Ka'biyyah] ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kenabian telah pergi dan yang tersisa adalah kabar gembira.\""},"1693":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَآنِي فَإِنَّ الشَّيْطَانَ لَا يَتَمَثَّلُ مِثْلِي","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihatku dalam mimpi, sungguh ia telah melihatku, karena sesungguhnya Syetan tidak dapat menyerupaiku.\""},"1694":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُصَفَّى حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي قَتَادَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَآنِي فِي الْمَنَامِ فَقَدْ رَأَى الْحَقَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mushaffa] telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari [Abu Salamah] dari [Abu Qatadah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa melihatku dalam mimpi, maka ia telah melihat kebenaran.\""},"1695":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ يَحْيَى عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا الصَّالِحَةُ مِنْ اللَّهِ وَالْحُلْمُ مِنْ الشَّيْطَانِ فَإِذَا حَلَمَ أَحَدُكُمْ حُلْمًا يَخَافُهُ فَلْيَبْصُقْ عَنْ شِمَالِهِ ثَلَاثَ مَرَّاتٍ وَلْيَتَعَوَّذْ بِاللَّهِ مِنْ الشَّيْطَانِ فَإِنَّهَا لَا تَضُرُّهُ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] dari [Yahya] dari [Abdullah bin Abu Qatadah] dari [Ayahnya] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi baik datangnya dari Allah sedangkan mimpi buruk datangnya dari Syetan. Apabila salah seorang dari kalian mimpi buruk yang ia khawatirkan, hendaknya ia meludah ke sebelah kiri sebanyak tiga kali, dan berlindung kepada Allah dari Syetan, sebab hal itu tidak akan membahayakan dirinya.\""},"1696":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ رَبِّهِ بْنِ سَعِيدٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ يَقُولُ إِنْ كُنْتُ لَأَرَى الرُّؤْيَا تُمْرِضُنِي فَذَكَرْتُ ذَلِكَ لِأَبِي قَتَادَةَ قَالَ وَأَنَا إِنْ كُنْتُ لَأَرَى الرُّؤْيَا تُمْرِضُنِي حَتَّى سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا الصَّالِحَةُ مِنْ اللَّهِ فَإِذَا رَأَى أَحَدُكُمْ مَا يُحِبُّ فَلْيَحْمَدْ اللَّهَ وَلَا يُحَدِّثْ بِهَا إِلَّا مَنْ يُحِبُّ وَإِذَا رَأَى مَا يَكْرَهُ فَلْيَتْفُلْ عَنْ يَسَارِهِ ثَلَاثًا وَلْيَتَعَوَّذْ بِاللَّهِ مِنْ شَرِّهَا وَلَا يُحَدِّثْ بِهَا أَحَدًا فَإِنَّهَا لَنْ تَضُرَّهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Abd Rabbih bin Sa'id] ia berkata; aku mendengar [Abu Salamah bin Abdurrahman] berkata; Sungguh aku pernah bermimpi sesuatu yang membuatku sakit, kemudian aku ceritakan kepada [Abu Qatadah]. Abu Qatadah berkata; \"Sungguh aku juga pernah bermimpi yang mmebuatkau sakit, hingga aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi baik datangnya dari Allah, maka apabila salah seorang dari kalian bermimpi sesuatu yang ia senangi hendaknya ia memuji Allah, dan tidak menceritakannya kecuali kepada orang yang ia senangi. Apabila ia bermimpi sesuatu yang tidak ia senangi, hendaknya ia meludah ke sebelah kirinya sebanyak tiga kali dan berlindung kepada Allah dari keburukannya, serta tidak menceritakannya kepada seorangpun, maka hal itu tidak akan membahayakan dirinya.\""},"1697":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ مَخْلَدِ بْنِ حُسَيْنٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الرُّؤْيَا ثَلَاثٌ فَالرُّؤْيَا الْحَسَنَةُ بُشْرَى مِنْ اللَّهِ وَالرُّؤْيَا تَحْزِينٌ مِنْ الشَّيْطَانِ وَالرُّؤْيَا مِمَّا يُحَدِّثُ بِهِ الْإِنْسَانُ نَفْسَهُ فَإِذَا رَأَى أَحَدُكُمْ مَا يَكْرَهُهُ فَلَا يُحَدِّثْ بِهِ وَلْيَقُمْ وَلْيُصَلِّ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Makhlad bin Husain] dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi ada tiga, yaitu; mimpi baik yang merupakan kabar gembira dari Allah, dan mimpi menyedihkan yang datangnya dari Syetan, serta mimpi yang terjadi karena ilusi seseorang. Apabila salah seorang dari kalian bermimpi sesuatu yang tidak ia sukai, hendaknya ia tidak menceritakannya dan hendaknya ia berdiri lalu mengerjakan shalat.\""},"1698":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ مَخْلَدِ بْنِ حُسَيْنٍ عَنْ هِشَامٍ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا اقْتَرَبَ الزَّمَانُ لَمْ تَكَدْ رُؤْيَا الْمُؤْمِنِ تَكْذِبُ وَأَصْدَقُهُمْ رُؤْيَا أَصْدَقُهُمْ حَدِيثًا","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Makhlad bin Husain] dari [Hisyam] dari [Ibnu Sirin] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila zaman telah mendekati (hari Kiamat), nyaris mimpi seorang mukmin tidak (disertai) dengan kebohongan, maka orang yang paling benar mimpinya adalah orang yang paling jujur pembicaraannya.\""},"1699":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا إِسْرَائِيلُ عَنْ عَبْدِ الْأَعْلَى عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ عَلِيٍّ يَرْفَعُ الْحَدِيثَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ كَذَبَ فِي حُلْمِهِ كُلِّفَ عَقْدَ شَعِيرَتَيْنِ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Isra`il] dari [Abdul A'la] dari [Abu Abdurrahman] dari [Ali] -yang dirafa'kan sampai kepada Nabi shallallahu 'alaihi wasallam- dia berkata: \"Barangsiapa berbohong dengan mimpinya, maka pada hari Kiamat akan dibebankan kepadanya untuk menghitung biji gandum.\""},"1700":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ وَهْبٍ عَنْ عَمْرِو بْنِ الْحَارِثِ عَنْ دَرَّاجٍ أَبِي السَّمْحِ عَنْ أَبِي الْهَيْثَمِ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصْدَقُ الرُّؤْيَا بِالْأَسْحَارِ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad] telah menceritakan kepada kami [Abdullah bin Wahb] dari ['Amr bin Al Harits] dari [Darraj Abu As Samh] dari [Al Haitsam] dari [Abu Sa'id Al Khudri], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi yang paling benar adalah pada waktu sahur.\""},"1701":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ يَقُولُ لَا تَقُصُّوا الرُّؤْيَا إِلَّا عَلَى عَالِمٍ أَوْ نَاصِحٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Ibnu Sirin] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian menceritakan mimpi kecuali kepada orang yang berilmui atau orang yang dapat memberikan nasehat.\""},"1702":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ يَعْلَى بْنِ عَطَاءٍ قَالَ سَمِعْتُ وَكِيعَ بْنَ عُدُسٍ يُحَدِّثُ عَنْ عَمِّهِ أَبِي رَزِينٍ الْعُقَيْلِيِّ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الرُّؤْيَا هِيَ عَلَى رِجْلِ طَائِرٍ مَا لَمْ يُحَدَّثْ بِهَا فَإِذَا حُدِّثَ بِهَا وَقَعَتْ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Ya'la bin 'Atha`] ia berkata; aku mendengar [Waki' bin 'Udus] menceritakan dari pamannya yaitu [Abu Razin Al 'Uqaili] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mimpi tidak tetap keputusannya selama belum diceritakan, apabila telah diceritakan maka akan terjadi.\""},"1703":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنِي الْوَلِيدُ حَدَّثَنِي ابْنُ جَابِرٍ عَنْ خَالِدِ بْنِ اللَّجْلَاجِ وَسَأَلَهُ مَكْحُولٌ أَنْ يُحَدِّثَهُ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ عَائِشٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رَأَيْتُ رَبِّي فِي أَحْسَنِ صُورَةٍ قَالَ فِيمَ يَخْتَصِمُ الْمَلَأُ الْأَعْلَى فَقُلْتُ أَنْتَ أَعْلَمُ يَا رَبِّ قَالَ فَوَضَعَ كَفَّهُ بَيْنَ كَتِفَيَّ فَوَجَدْتُ بَرْدَهَا بَيْنَ ثَدْيَيَّ فَعَلِمْتُ مَا فِي السَّمَوَاتِ وَالْأَرْضِ وَتَلَا { وَكَذَلِكَ نُرِي إِبْرَاهِيمَ مَلَكُوتَ السَّمَوَاتِ وَالْأَرْضِ وَلِيَكُونَ مِنْ الْمُوقِنِينَ }","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepadaku [Al Walid bin Jabir] dari [Khalid bin Al Lajlaj] dan Makhul telah memintanya agar menceritakan kepadanya, ia berkata; \"Aku mendengar [Abdurrahman bin 'Aisy] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku bermimpi melihat Tuhanku dalam bentuk yang sebaik-baiknya. Dia berfirman: \"Dalam masalah apakah para Malaikat berselisih?\" Lalu aku katakan: \"Engkau lebih mengetahui wahai Tuhanku.\" Beliau bersabda: \"Kemudian Dia meletakkan telapak tanganNya diantara kedua pundakku sehingga aku merasakan dingin tanganNya diantara kedua dadaku. Lalu aku mengetahui apa yang ada di langit dan bumi.\" Lalu beliau membaca ayat Dan demikianlah Kami perlihatkan kepada Ibrahim tanda-tanda keagungan (Kami yang terdapat) di langit dan bumi dan (Kami memperlihatkannya) agar dia termasuk orang yang yakin.\" QS Al An'am; 75."},"1704":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ قُطْبَةَ عَنْ يُوسُفَ عَنْ ابْنِ سِيرِينَ قَالَ مَنْ رَأَى رَبَّهُ فِي الْمَنَامِ دَخَلَ الْجَنَّةَ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] dari [Abdul Hamid bin Abdurrahman] dari [Quthbah] dari [Yusuf] dari [Ibnu Sirin] ia berkata; \"Barangsiapa bermimpi (bertemu) Rabbnya ketika tidur, maka ia akan masuk Surga.\""},"1705":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنَا إِبْرَاهِيمُ هُوَ ابْنُ سَعْدٍ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّه�� عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا إِذَا أَنَا نَائِمٌ رَأَيْتُ النَّاسَ يُعْرَضُونَ عَلَيَّ وَعَلَيْهِمْ قُمُصٌ مِنْهَا مَا يَبْلُغُ الثُّدِيَّ وَمِنْهَا مَا يَبْلُغُ دُونَ ذَلِكَ وَعُرِضَ عَلَيَّ عُمَرُ بْنُ الْخَطَّابِ وَعَلَيْهِ قَمِيصٌ يَجُرُّهُ فَقَالَ مَنْ حَوْلَهُ فَمَاذَا تَأَوَّلْتَ ذَلِكَ يَا رَسُولَ اللَّهِ قَالَ الدِّينَ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Ibrahim yaitu Ibnu Sa'd] dari [Shalih bin Kaisan] dari [Ibnu Syihab] dari [Abu Umamah bin Sahl bin Hunaif] dari [Abu Sa'id Al Khudri] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ketika aku sedang tidur, aku melihat orang-orang diperlihakan kepadaku, mereka memakai jubah, diantaranya ada yang sampai ke dadanya, dan diantaranya ada yang sampai kurang dari itu, dan tidak lama kemudian ditampakkan kepadaku Umar bin Al Khathab sambil mengenakan jubah yang ia seret.\" Para sahabat yang ada disekitar beliau bertanya; \"Wahai Rasulullah, menurut anda bagaimana tafsir mimpi itu? Beliau menjawab: \"Itu tentang masalah Agama.\""},"1706":{"ar":" أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ حَدَّثَنَا عَبْدُ اللَّهِ هُوَ ابْنُ عُمَرَ عَنْ نَافِعٍ أَنَّ ابْنَ عُمَرَ قَالَ كُنْتُ فِي عَهْدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا لِي مَبِيتٌ إِلَّا فِي مَسْجِدِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَصْبَحَ يَأْتُونَهُ فَيَقُصُّونَ عَلَيْهِ الرُّؤْيَا قَالَ فَقُلْتُ مَا لِي لَا أَرَى شَيْئًا فَرَأَيْتُ كَأَنَّ النَّاسَ يُحْشَرُونَ فَيُرْمَى بِهِمْ عَلَى أَرْجُلِهِمْ فِي رَكِيٍّ فَأُخِذْتُ فَلَمَّا دَنَا إِلَى الْبِئْرِ قَالَ رَجُلٌ خُذُوا بِهِ ذَاتَ الْيَمِينِ فَلَمَّا اسْتَيْقَظْتُ هَمَّتْنِي رُؤْيَايَ وَأَشْفَقْتُ مِنْهَا فَسَأَلْتُ حَفْصَةَ عَنْهَا فَقَالَتْ نِعْمَ مَا رَأَيْتَ فَقُلْتُ لَهَا سَلِي النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَتْهُ فَقَالَ نِعْمَ الرَّجُلُ عَبْدُ اللَّهِ لَوْ كَانَ يُصَلِّي مِنْ اللَّيْلِ حَدَّثَنَا مُوسَى بْنُ خَالِدٍ عَنْ إِبْرَاهِيمَ بْنِ مُحَمَّدٍ الْفَزَارِيِّ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ بِهَذَا الْحَدِيثِ قَالَ ابْنُ عُمَرَ وَكُنْتُ إِذَا نِمْتُ لَمْ أَقُمْ حَتَّى أُصْبِحَ قَالَ نَافِعٌ وَكَانَ ابْنُ عُمَرَ يُصَلِّي اللَّيْلَ","id":"Telah mengabarkan kepada kami [Abu Ali Al Hanafi] telah menceritakan kepada kami [Abdullah yaitu Ibnu Umar] dari [Nafi'] bahwa [Ibnu Umar] berkata; Pada zaman Nabi shallallahu 'alaihi wasallam, aku tidak memiliki tempat bermalam kecuali di Masjid Nabi shallallahu 'alaihi wasallam. Pada pagi harinya Nabi shallallahu 'alaihi wasallam biasa didatangi orang-orang yang menceritakan berbagai mimpi kepada beliau. Lalu aku katakan; \"Kenapa aku tidak bermimpi sesuatu?\", Setelah itu aku bermimpi, seakan-akan manusia dikumpulkan, kemudian mereka dilemparkan dengan kaki terjungkir di sebuah sumur, kemudian aku ditangkap, tatkala hamper sampai kesebuah sumur, seorang laki-laki berkata; \"Tologn selamatkanlah ia ke sebelah kanan.\" setelah aku bangun, mimpiku itu membuatku resah dan khawatir. Kemudian kulaporkan mimpiku kepada Hafshah. Hafshah berkata; \"Alangkah indah mimpimu.\" Aku berkata kepadanya; \"Tolong tanyakan mimpiku kepada Nabi shallallahu 'alaihi wasallam.\" Setelah itu Hafshah bertanya kepada beliau, dan beliau bersabda: \"Sebaik-baik lelaki adalah Abdullah, seandainya ia sering melakukan shalat malam.\" Telah menceritakan kepada kami [Musa bin Khalid] dari [Ibrahim bin Muhammad Al Fazari] dari ['Ubaidullah dari [Nafi'] dari [Ibnu Umar] dengan hadits ini. Ibnu Umar mengatakan; \"Dan apabila aku tidur, aku tidak bengun hingga pagi hari.\" Nafi' berkata; \"Dan Ibnu Umar sering melakukan shalat malam.\""},"1707":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ عَنْ الزُّهْرِيِّ عَنْ حَمْزَةَ بْنِ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ ابْنِ عُمَرَ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ بَيْنَا أَنَا نَائِمٌ إِذْ أُتِيتُ بِقَدَحٍ مِنْ لَبَنٍ فَشَرِبْتُ مِنْهُ حَتَّى إِنِّي لَأَرَى الرِّيَّ فِي ظُفْرِي أَوْ قَالَ فِي أَظْفَارِي ثُمَّ نَاوَلْتُ فَضْلَهُ عُمَرَ فَقَالُوا يَا رَسُولَ اللَّهِ مَا أَوَّلْتَهُ قَالَ الْعِلْمَ","id":"Telah mengabarkan kepada kami [Muhammad Ash Shalt] telah menceritakan kepada kami [Ibnu Mubarak] dari [Yunus] dari [Az Zuhri] dari [Hamzah bin Abdullah bin Umar] dari [Ibnu Umar], ia berkata; aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Ketika aku tidur, tiba-tiba aku diberi segelas susu, kemudian aku meminum sebagian darinya hingga aku merasa puas sampai ke dalam kukuku -atau beliau berkata- dalam kuku-kukuku, kemudian aku berikan sisanya kepada Umar.\" Para sahabat bertanya; \"Wahai Rasulullah, apa yang anda tafsirkan?\" Beliau bersabda: \"Ilmu.\""},"1708":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا الْوَلِيدُ حَدَّثَنَا ابْنُ جَابِرٍ حَدَّثَنِي مُحَمَّدُ بْنُ قَيْسٍ حَدَّثَنِي بَعْضُ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّبَنُ الْفِطْرَةُ وَالسَّفِينَةُ نَجَاةٌ وَالْجَمَلُ حُزْنٌ وَالْخُضْرَةُ الْجَنَّةُ وَالْمَرْأَةُ خَيْرٌ","id":"Telah mengabarkan kepadaku [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Al Walid] telah menceritakan kepada kami [Ibnu Jabir] telah menceritakan kepadaku [Muhammad bin Qais] telah menceritakan kepadaku [sebagian para sahabat] Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Susu adalah fitrah, perahu adalah keberhasilan, unta adalah kesedihan dan warna hijau adalah surga serta wanita adalah kebaikan.\""},"1709":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ حَدَّثَنَا سُلَيْمَانُ هُوَ ابْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ مِمَّا يَقُولُ لِأَصْحَابِهِ مَنْ رَأَى مِنْكُمْ رُؤْيَا فَلْيَقُصَّهَا عَلَيَّ فَأَعْبُرَهَا لَهُ قَالَ فَجَاءَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ رَأَيْتُ ظُلَّةً بَيْنَ السَّمَاءِ وَالْأَرْضِ تَنْطِفُ عَسَلًا وَسَمْنًا وَرَأَيْتُ أُنَاسًا يَتَكَفَّفُونَ مِنْهَا فَمُسْتَكْثِرٌ وَمُسْتَقِلٌّ وَرَأَيْتُ سَبَبًا وَاصِلًا مِنْ السَّمَاءِ إِلَى الْأَرْضِ فَأَخَذْتَ بِهِ فَعَلَوْتَ فَأَعْلَاكَ اللَّهُ ثُمَّ أَخَذَ بِهِ الَّذِي بَعْدَكَ فَعَلَا فَأَعْلَاهُ اللَّهُ ثُمَّ أَخَذَهُ الَّذِي بَعْدَهُ فَعَلَا فَأَعْلَاهُ اللَّهُ ثُمَّ أَخَذَهُ الَّذِي بَعْدَهُ فَقُطِعَ بِهِ ثُمَّ وُصِلَ فَاتَّصَلَ فَقَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ ائْذَنْ لِي فَأَعْبُرَهَا فَقَالَ اعْبُرْهَا وَكَانَ أَعْبَرَ النَّاسِ لِلرُّؤْيَا بَعْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَمَّا الظُّلَّةُ فَالْإِسْلَامُ وَأَمَّا الْعَسَلُ وَالسَّمْنُ فَالْقُرْآنُ حَلَاوَةُ الْعَسَلِ وَلِينُ السَّمْنِ وَأَمَّا الَّذِينَ يَتَكَفَّفُونَ مِنْهُ فَمُسْتَكْثِرٌ وَمُسْتَقِلٌّ فَهُمْ حَمَلَةُ الْقُرْآنِ فَقَالَ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَصَبْتَ وَأَخْطَأْتَ فَقَالَ فَمَا الَّذِي أَصَبْتُ وَمَا الَّذِي أَخْطَأْتُ فَأَبَى أَنْ يُخْبِرَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Katsir] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] bahwa diantara yang disampaikan Rasulullah shallallahu 'alaihi wasallam kepada para sahabatnya adalah: \"Barangsiapa diantara kalian bermimpi, hendaknya ia menceritakannya kepadaku, hingga aku menafsirkan untuk dirinya.\" Kemudian seorang laki-laki datang dan berkata; \"Wahai Rasulullah, aku bermimpi melihat awan diantara langit dan bumi, awan tersebut meneteskan madu dan mentega. Dan aku melihat beberapa orang mengambil dengan telapak tangannya. Diantara mereka ada yang mengambil banyak dan ada yang mengambil sedikit. Dan aku melihat dari langit sampai ke bumi, kemudian engkau mengambilnya lalu engkau naik ke atas, dan Allah meninggikanmu, setelah itu orang setelahmu mengambilnya, lalu ia naik dan Allah pun meninggikannya, kemudian diambil orang setelahnya lalu ia naik dan Allah meninggikannya, kemudian diambil orang setelahnya lalu diputus, kemudian disambung sehingga tersambung.\" Abu Bakr berkata; \"Wahai Rasulullah, izinkan saya menafsirkannya.\" Beliau bersabda: \"Tafsirkan mimpi terssebut.\" -Abu Bakar adalah sosok yang pandai menafsirkan mimpi setelah Rasulullah shallallahu 'alaihi wasallam- ia berkata; \"Adapun awan tersebut adalah Islam, madu dan mentega adalah Al Qur'an, semanis madu dan selembut mentega. Sedangkan orang-orang yang mengambil dengan telapak tangannya kemudian ada yang mengambil banyak dan ada yang mengambil sedikit, mereka adalah para pembawa Al Qur'an.\" Setelah itu Rasulullah shallallahu 'alaihi wasallam bersabda; \"Engkau benar dan engkau salah.\" Lalu Abu Bakar berkata; \"Apa yang aku tafsirkan dengan benar dan apa yang aku tafsirkan dengan salah?\" Namun Rasulullah shallallahu 'alaihi wasallam enggan memberitahukannya."},"1710":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ بَرِيدَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ فِي رُؤْيَايَ هَذِهِ أَنِّي هَزَزْتُ سَيْفًا فَانْقَطَعَ صَدْرُهُ فَإِذَا هُوَ مَا أُصِيبَ مِنْ الْمُؤْمِنِينَ يَوْمَ أُحُدٍ ثُمَّ هَزَزْتُهُ أُخْرَى فَعَادَ كَأَحْسَنِ مَا كَانَ فَإِذَا هُوَ مَا جَاءَ اللَّهُ بِهِ مِنْ الْفَتْحِ وَاجْتِمَاعِ الْمُؤْمِنِينَ وَرَأَيْتُ فِيهَا أَيْضًا بَقَرًا وَاللَّهِ خَيْرٌ فَإِذَا هُوَ النَّفَرُ مِنْ الْمُؤْمِنِينَ يَوْمَ أُحُدٍ وَإِذَا الْخَيْرُ مَا جَاءَ اللَّهُ بِهِ مِنْ الْخَيْرِ وَثَوَابِ الصِّدْقِ الَّذِي آتَانَا بَعْدَ يَوْمِ بَدْرٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Barid] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Aku melihat dalam mimpiku ini, bahwa aku mengayun-ayunkan pedang, hingga patah pada bagian pangkalnya, yang ternyata itu merupakan isyarat tentang apa yang menimpa Kaum Mu'minin pada perang Uhud, lalu aku mengayun-ayunkan kembali pedang tersebut hingga pedang itu kembali menjadi utuh seperti sedia kala, ternyata itu berarti apa yang Allah akan datangkan berupa kemenangan dan bersatunya Kaum Mu'minin dan aku melihat pula dalam mimpiku seekor sapi, yang demi Allah sangat bagus bentuknya, ternyata itu berarti Kaum Mu'minin pada perang Uhud yang akan mendapatkan kebaikan seperti yang Allah datangkan dari kebaikan dan pahala, sebagai janji yang benar yang telah Allah berikan kepada kita pada perang Badar.\""},"1711":{"ar":" أَخْبَرَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا أَبُو الزُّبَيْرِ عَنْ جَابِرٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَأَيْتُ كَأَنِّي فِي دِرْعٍ حَصِينَةٍ وَرَأَيْتُ بَقَرًا يُنْحَرُ فَأَوَّلْتُ أَنَّ الدِّرْعَ الْمَدِينَةُ وَأَنَّ الْبَقَرَ نَفَرٌ وَاللَّهِ خَيْرٌ وَلَوْ أَقَمْنَا بِالْمَدِينَةِ فَإِذَا دَخَلُوا عَلَيْنَا قَاتَلْنَاهُمْ فَقَالُوا وَاللَّهِ مَا دُخِلَتْ عَلَيْنَا فِي الْجَاهِلِيَّةِ أَفَتُدْخَلُ عَلَيْنَا فِي الْإِسْلَامِ قَالَ فَشَأْنَكُمْ إِذًا وَقَالَتْ الْأَنْصَارُ لِبَعْضٍ رَدَدْنَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأْيَهُ فَجَاءُوا فَقَالُوا يَا رَسُولَ اللَّهِ شَأْنُكَ فَقَالَ الْآنَ إِنَّهُ لَيْسَ لِنَبِيٍّ إِذَا لَبِسَ لَأْمَتَهُ أَنْ يَضَعَهُ حَتَّى يُقَاتِلَ","id":"Telah mengabarkan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Abu Az Zubair] dari [Jabir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku bermimpi seakan saya memakai baju besi yang kuat dan aku juga bermimpi melihat seekor sapi yang disembelih, aku artikan baju besi yang kuat adalah Madinah, sedang makna sapi, demi Allah itu adalah sebuah kebaikan, jika saja kita bermukim di Madinah, lalu mereka (menyerang) kita disana, niscaya kita akan memerangi mereka.\" Para sahabat berkata; \"Wahai Rasulullah, demi Allah kami belum pernah diserang di kota Madinah semasa Jahiliyyah, bagaimana bisa kita diserang pada masa Islam?\" Beliau bersabda: \"Terserah kalian, kalau begitu.\" Lalu orang-orang Anshar berkata; \"Kami telah menolak pendapat Nabi shallallahu'alaihi wasallam', \" Akhirnya mereka datang dan berkata; \"Wahai Rasulullah, kalau begitu terserah anda.\" Beliau bersabda: \"Tidak layak bagi seorang Nabi jika telah memakai baju besi, lalu melepasnya kembali sampai ia berperang.\""},"1712":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ حَدَّثَنَا ابْنُ أَبِي الزِّنَادِ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رَأَيْتُ فِي الْمَنَامِ امْرَأَةً سَوْدَاءَ ثَائِرَةَ الشَّعْرِ تَفِلَةً أُخْرِجَتْ مِنْ الْمَدِينَةِ فَأُسْكِنَتْ مَهْيَعَةَ فَأَوَّلْتُهَا وَبَاءَ الْمَدِينَةِ يَنْقُلُهَا اللَّهُ إِلَى مَهْيَعَةَ","id":"Telah mengabarkan kepadaku [Sulaiman bin Daud Al Hasyimi] telah menceritakan kepada kami [Ibnu Abu Az Zinad] dari [Musa bin 'Uqbah] dari [Salim bin Abdullah] dari [Ayahnya] ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku bermimpi melihat seorang wanita hitam yang berambut acak-acakan tanpa memakai minyak wangi, ia dikeluarkan dari Madinah dan ditempatkan di Mahya'ah (yaitu Juhfah). Maka aku menafsirkannya suatu penyakit yang ada di Madinah, lalu Allah pindahkan ke Mahya'ah.\""},"1713":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا يَحْيَى بْنُ عَبْدِ الرَّحْمَنِ حَدَّثَنَا عَبِيدَةُ بْنُ الْأَسْوَدِ عَنْ مُجَالِدٍ عَنْ عَامِرٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ يَوْمًا مِنْ الْأَيَّامِ إِنِّي رَأَيْتُ فِي الْمَنَامِ أَنَّ رَجُلًا أَتَانِي بِكُتْلَةٍ مِنْ تَمْرٍ فَأَكَلْتُهَا فَوَجَدْتُ فِيهَا نَوَاةً فَآذَتْنِي حِينَ مَضَغْتُهَا ثُمَّ أَعْطَانِي كُتْلَةً أُخْرَى فَقُلْتُ إِنَّ الَّذِي أَعْطَيْتَنِي وَجَدْتُ فِيهَا نَوَاةً آذَتْنِي فَأَكَلْتُهَا فَقَالَ أَبُو بَكْرٍ نَامَتْ عَيْنُكَ يَا رَسُولَ اللَّهِ هَذِهِ السَّرِيَّةُ الَّتِي بَعَثْتَ بِهَا غَنِمُوا مَرَّتَيْنِ كِلْتَاهُمَا وَجَدُوا رَجُلًا يَنْشُدُ ذِمَّتَكَ فَقُلْتُ لِمُجَالِدٍ مَا يَنْشُدُ ذِمَّتَكَ قَالَ يَقُولُ لَا إِلَهَ إِلَّا اللَّهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Yahya bin Abdurrahman] telah menceritakan kepada kami ['Ubaidah bin Al Aswad] dari [Mujalid] dari ['Amir] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, bahwa suatu hari beliau bersabda: \"Aku bermimpi bahwa seorang laki-laki datang kepadaku dengan membawa sepotong kurma, kemudian aku memakannya lalu mendapatkan biji, laki-laki itu menggangguku ketika aku mengunyahnya. Kemudian ia memberiku sepotong yang lain, lalu aku katakan; \"Sesungguhnya yang engkau berikan kepadaku, telah aku dapatkan padanya biji yang menggangguku, lalu aku memakannya.\" Abu Bakr berkata; \"Semoga anda mendapatkan kelapangan dan kesejahteraan wahai Rasulullah, ini adalah pasukan yang engkau kirim memperoleh rampasan perang dua kali, keduanya mereka dapati seorang laki-laki yang meminta perlindunganmu.\" Kemudian aku katakan kepada Mujahid; \"Apakah maksud meminta perlindunganmu?\" Ia berkata; \"Mengucapkan LAA ILAAHA ILLALLAAH (tidak ada ilah yang berhak disembah selain Allah).\""},"1714":{"ar":" أَخْبَرَنَا عُبَيْدُ بْنُ يَعِيشَ حَدَّثَنَا يُونُسُ هُوَ ابْنُ بُكَيْرٍ أَخْبَرَنَا ابْنُ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرِو بْنِ عَطَاءٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَتْ امْرَأَةٌ مِنْ أَهْلِ الْمَدِينَةِ لَهَا زَوْجٌ تَاجِرٌ يَخْتَلِفُ فَكَانَتْ تَرَى رُؤْيَا كُلَّمَا غَابَ عَنْهَا زَوْجُهَا وَقَلَّمَا يَغِيبُ إِلَّا تَرَكَهَا حَامِلًا فَتَأْتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَقُولُ إِنَّ زَوْجِي خَرَجَ تَاجِرًا فَتَرَكَنِي حَامِلًا فَرَأَيْتُ فِيمَا يَرَى النَّائِمُ أَنَّ سَارِيَةَ بَيْتِي انْكَسَرَتْ وَأَنِّي وَلَدْتُ غُلَامًا أَعْوَرَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرٌ يَرْجِعُ زَوْجُكِ عَلَيْكِ إِنْ شَاءَ اللَّهُ تَعَالَى صَالِحًا وَتَلِدِينَ غُلَامًا بَرًّا فَكَانَتْ تَرَاهَا مَرَّتَيْنِ أَوْ ثَلَاثًا كُلُّ ذَلِكَ تَأْتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَيَقُولُ ذَلِكَ لَهَا فَيَرْجِعُ زَوْجُهَا وَتَلِدُ غُلَامًا فَجَاءَتْ يَوْمًا كَمَا كَانَتْ تَأْتِيهِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَائِبٌ وَقَدْ رَأَتْ تِلْكَ الرُّؤْيَا فَقُلْتُ لَهَا عَمَّ تَسْأَلِينَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَمَةَ اللَّهِ فَقَالَتْ رُؤْيَا كُنْتُ أُرَاهَا فَآتِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْأَلُهُ عَنْهَا فَيَقُولُ خَيْرًا فَيَكُونُ كَمَا قَالَ فَقُلْتُ فَأَخْبِرِينِي مَا هِيَ قَالَتْ حَتَّى يَأْتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَعْرِضَهَا عَلَيْهِ كَمَا كُنْتُ أَعْرِضُ فَوَاللَّهِ مَا تَرَكْتُهَا حَتَّى أَخْبَرَتْنِي فَقُلْتُ وَاللَّهِ لَئِنْ صَدَقَتْ رُؤْيَاكِ لَيَمُوتَنَّ زَوْجُكِ وَتَلِدِينَ غُلَامًا فَاجِرًا فَقَعَدَتْ تَبْكِي وَقَالَتْ مَا لِي حِينَ عَرَضْتُ عَلَيْكِ رُؤْيَايَ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ تَبْكِي فَقَالَ لَهَا مَا لَهَا يَا عَائِشَةُ فَأَخْبَرْتُهُ الْخَبَرَ وَمَا تَأَوَّلْتُ لَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْ يَا عَائِشَةُ إِذَا عَبَرْتُمْ لِلْمُسْلِمِ الرُّؤْيَا فَاعْبُرُوهَا عَلَى الْخَيْرِ فَإِنَّ الرُّؤْيَا تَكُونُ عَلَى مَا يَعْبُرُهَا صَاحِبُهَا فَمَاتَ وَاللَّهِ زَوْجُهَا وَلَا أُرَاهَا إِلَّا وَلَدَتْ غُلَامًا فَاجِرًا","id":"Telah mengabarkan kepada kami ['Ubaid bin Ya'isy], telah menceritakan kepada kami [Yunus yaitu Ibnu Bukair], telah mengabarkan kepada kami [Ibnu Ishaq] dari [Muhammad bin 'Amr bin 'Atha`] dari [Sulaiman bin Yasar] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; \"Seorang wanita dari penduduk Madinah memiliki suami seorang pedagang. Wanita itu juga pernah bermimpi. Setiap kali suaminya pergi, suaminya tidak pernah meninggalkannya kecuali dalam keadaan hamil. Kemudian wanita itu datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Sesungguhnya suamiku keluar berdagang dan meninggalkanku dalam keadaan hamil, kemudian aku bermimpi seperti orang tidur yang bermimpi, bahwa tiang rumahku patah dan saya melahirkan anak yang buta.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah kebaikan, suamimu akan kembali kepadamu dengan izin Allah ta'ala dalam keadaan baik, dan engkau akan melahirkan anak yang berbakti.\" Wanita tersebut bermimpi hingga dua atau tiga kali, setiap ia bermimpi, ia langsung datang menemui Rasulullah shallallahu 'alaihi wasallam, beliau pun mengatakan hal yang sama kepada wanita itu. Setelah itu suaminya kembali dan wanita itu melahirkan anak laki-laki, Suatu hari wanita itu datang sebagaimana dahulu ia datang, sementara Rasulullah shallallahu 'alaihi wasallam tidak berada di tempat. Sementara dirinya telah mengalami mimpi itu, kemudian aku katakan kepadanya; \"Apa yang pernah engkau tanyakan kepada Rasulullah shallallahu 'alaihi wasallam wahai hamba Allah?\" Wanita itu menjawab; \"Mimpi yang diperlihatkan kepadaku, kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya kepada beliau mengenai mimpi tersebut, beliau bersabda: \"Baik.\" Ternyata mimpi itu telah terjadi seperti yang telah beliau ucapkan.\" Aku bertanya; \"Beritahukan kepadaku apa mimpi itu?\" Wanita itu menjawab; \"Nanti setelah Rasulullah shallallahu 'alaihi wasallam datang, hingga aku dapat menyampaikannya kepada beliau sebagaimana dahulu pernah aku sampaikan.\" Demi Allah aku masih tetap menungguinya hingga ia memberitahukan kepadaku. Lalu aku katakan; \"Demi Allah, seandainya mimpimu itu benar niscaya suamimu akan meninggal dan engkau melahirkan anak yang durhaka.\" Lalu wanita tersebut duduk sambil menangis, dan berkata; \"Kenapa aku mendapatkan hal ini ketika menyampaikan mimpiku kepadamu?\" Kemudian Rasulullah shallallahu 'alaihi wasallam masuk, sementara wanita itu masih saja menangis. Beliau bertanya: \"Ada apa dengannya wahai Aisyah?\" Aku memberitahukan berita tersebut kepada beliau, dan apa yang aku tafsirkan kepadanya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tahanlah perkataan itu wahai Aisyah! Apabila engkau menafsirkan (mimpi) seorang muslim untuk muslim lainnya, maka tafsirkanlah dengan kebaikan, karena sesungguhnya mimpi akan terjadi sesuai yang ditafsirkan orang yang menafsirkannya.\" Demi Allah, setelah itu suaminya meninggal dan tidaklah diperlihatkan kepadaku kecuali ia melahirkan anak yang durhaka.\""},"1715":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الْمُغَلِّسِ عَنْ أَبِي نَجِيحٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَدَرَ عَلَى أَنْ يَنْكِحَ فَلَمْ يَنْكِحْ فَلَيْسَ مِنَّا","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Abu Al Mughallis] dari [Abu Najih] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa mampu menikah namun dia tidak menikah, maka dia bukan dari golongan kami.\""},"1716":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ عُمَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ قَالَ قَالَ عَبْدُ اللَّهِ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَابٌ لَيْسَ لَنَا شَيْءٌ فَقَالَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّ الصَّوْمَ لَهُ وِجَاءٌ","id":"Telah mengabarkan keapda kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari ['Umarah] dari [Abdurrahman bin Yazid], ia berkata; [Abdullah] berkata; kami pernah bersama Rasulullah shallallahu 'alaihi wasallam, kami adalah para pemuda yang tidak memiliki sesuatupun, kemudian beliau bersabda: \"Wahai para pemuda, barangsiapa diantara kalian yang mampu menikah, hendaknya ia menikah, sesungguhnya hal itu lebih menundukkan pandangan dan lebih menjaga kemaluan, dan barangsiapa yang tidak mampu, hendaknya ia berpuasa, sesungguhnya berpuasa adalah benteng baginya.\""},"1717":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ قَالَ لَقِيَهُ عُثْمَانُ وَأَنَا مَعَهُ فَقَالَ لَهُ يَا أَبَا عَبْدِ الرَّحْمَنِ هَلْ لَكَ فِي جَارِيَةٍ بِكْرٍ تُذَكِّرُكَ فَقَالَ لَئِنْ قُلْتَ ذَاكَ فَقَدْ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَا مَعْشَرَ الشَّبَابِ مَنْ كَانَ يَسْتَطِيعُ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ فَلْيَصُمْ فَإِنَّ الصَّوْمَ لَهُ وِجَاءٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] ia berkata; Utsman pernah bertemu dengannya, sementara aku bersamanya, lalu Utsman berkata; \"Wahai Abu Abdurrahman, apakah engkau mau menikah dengan wanita yang masih perawan dan dapat mengingatkan dirimu?\" Abdullah berkata; \"Jika engkau mengatakan demikian, maka sungguh aku telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai para pemuda, barangsiapa diantara kalian yang mampu menikah, hendaknya ia menikah, sesungguhnya hal itu lebih menundukkan pandangan dan lebih menjaga kemaluan, barang siapa yang tidak mampu, maka hendaknya ia berpuasa, sesungguhnya berpuasa adalah benteng baginya.\""},"1718":{"ar":" أَخْبَرَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ أَنَّهُ سَمِعَ سَعْدَ بْنَ أَبِي وَقَّاصٍ يَقُولُ لَقَدْ رَدَّ ذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُثْمَانَ وَلَوْ أَجَازَ لَهُ التَّبَتُّلَ لَاخْتَصَيْنَا","id":"Telah mengabarkan kepada kami [Abu Al Yaman] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku [Sa'id bin Al Musayyab] bahwa ia mendengar [Sa'd bin Abu Waqqash] berkata; \"Sungguh Rasulullah shallallahu 'alaihi wasallam telah menolak Utsman (bin Mazh'un) untuk hidup membujang, seandainya beliau memperbolehkan baginya hidup membujang, niscaya kami telah mengebiri.\""},"1719":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ حَدَّثَنَا الْأَشْعَثُ بْنُ عَبْدِ الْمَلِكِ عَنْ الْحَسَنِ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَ قَالَتْ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ التَّبَتُّلِ","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami [Hammad bin Mas'adah] telah menceritakan kepada kami [Al Asy'ats bin Abdul Malik] dari [Al Hasan] dari [Sa'd bin Hisyam] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam melarang hidup membujang.\""},"1720":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يَزِيدَ الْحِزَامِيُّ حَدَّثَنَا يُونُسُ بْنُ بُكَيْرٍ حَدَّثَنِي ابْنُ إِسْحَقَ حَدَّثَنِي الزُّهْرِيُّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ لَمَّا كَانَ مِنْ أَمْرِ عُثْمَانَ بْنِ مَظْعُونٍ الَّذِي كَانَ مِنْ تَرْكِ النِّسَاءِ بَعَثَ إِلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا عُثْمَانُ إِنِّي لَمْ أُومَرْ بِالرَّهْبَانِيَّةِ أَرَغِبْتَ عَنْ سُنَّتِي قَالَ لَا يَا رَسُولَ اللَّهِ قَالَ إِنَّ مِنْ سُنَّتِي أَنْ أُصَلِّيَ وَأَنَامَ وَأَصُومَ وَأَطْعَمَ وَأَنْكِحَ وَأُطَلِّقَ فَمَنْ رَغِبَ عَنْ سُنَّتِي فَلَيْسَ مِنِّي يَا عُثْمَانُ إِنَّ لِأَهْلِكَ عَلَيْكَ حَقًّا وَلِعَيْنِكَ عَلَيْكَ حَقًّا قَالَ سَعْدٌ فَوَاللَّهِ لَقَدْ كَانَ أَجْمَعَ رِجَالٌ مِنْ الْمُسْلِمِينَ عَلَى أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ هُوَ أَقَرَّ عُثْمَانَ عَلَى مَا هُوَ عَلَيْهِ أَنْ نَخْتَصِيَ فَنَتَبَتَّلَ","id":"Telah menceritakan kepada kami [Muhammad bin Zaid Al Hizami] telah menceritakan kepada kami [Yunus bin Bukair] telah menceritakan kepadaku [Ibnu Ishaq] telah menceritakan kepadaku [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Sa'd bin Abu Waqqash] ia berkata; Ketika terjadi permasalahan Utsman bin Mazh'un yaitu ketika ia tidak ingin menikahi wanita, maka Rasulullah shallallahu 'alaihi wasallam mengirim utusan kepadanya untuk mengatakan: \"Wahai Utsman, sesungguhnya aku tidak diutus dengan membawa ajaran untuk tidak beristeri dan mengurung diri dalam tempat ibadah. Apakah engkau tidak suka terhadap sunahku?\" Ia berkata; \"Tidak wahai Rasulullah.\" Beliau bersabda: \"Sesungguhnya diantara sunahku adalah melakukan shalat dan tidur, berpuasa dan makan, menikah dan menceraikan. Barangsiapa tidak menyukai sunahku, maka bukan dari gologanku. Wahai Utsman, sesungguhnya keluargamu memiliki hak atas dirimu, matamu memiliki hak atas dirimu.\" Sa'd berkata; \"Demi Allah, kaum Muslimin telah bersepakat, apabila Rasulullah shallallahu 'alaihi wasallam menetapkan Utsman dalam kondisinya (tidak menikah), niascaya kami telah mengebiri dan tidak menikah.\""},"1721":{"ar":" أَخْبَرَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُنْكَحُ النِّسَاءُ لِأَرْبَعٍ لِلدِّينِ وَالْجَمَالِ وَالْمَالِ وَالْحَسَبِ فَعَلَيْكَ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Shadaqah bin Al Fadhl] telah mengabarkan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah] dari [Sa'id bin Abu Sa'id] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Wanita dinikahi karena empat hal, yaitu; karena agamanya, kecantikannya, hartanya dan keturunannya. Maka carilah yang baik agamanya, niscaya engkau akan beruntung.\" Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] dari [Ali bin Mushir] dari [Abdul Malik] dari ['Atha`] dari [Jabir] dari Nabi shallallahu 'alaihi wasallam dengan hadits ini."},"1722":{"ar":" أَخْبَرَنَا قَبِيصَةُ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمٍ الْأَحْوَلِ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ أَنَّهُ خَطَبَ امْرَأَةً مِنْ الْأَنْصَارِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَانْظُرْ إِلَيْهَا فَإِنَّهُ أَجْدَرُ أَنْ يُؤْدَمَ بَيْنَكُمَا","id":"Telah mengabarkan kepada kami [Qabishah] telah menceritakan kepada kami [Sufyan] dari ['Ashim Al Ahwal] dari [Bakr bin Abdullah Al Muzani] dari [Al Mughirah bin Syu'bah] bahwa ia pernah melamar seorang wanita Anshar, Maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Pergi dan lihatlah dia, karena hal itu lebih melanggengkan diantara kalian berdua.\""},"1723":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ الْعَبْدِيُّ الْبَصْرِيُّ أَخْبَرَنَا سُفْيَانُ عَنْ يُونُسَ عَنْ الْحَسَنِ قَالَ سَمِعْتُهُ يَقُولُ قَدِمَ عَقِيلُ بْنُ أَبِي طَالِبٍ الْبَصْرَةَ فَتَزَوَّجَ امْرَأَةً مِنْ بَنِي جُشَمٍ فَقَالُوا لَهُ بِالرِّفَاءِ وَالْبَنِينَ فَقَالَ لَا تَقُولُوا ذَلِكَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَانَا عَنْ ذَلِكَ وَأَمَرَنَا أَنْ نَقُولَ بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir Al 'Abdi Al Bashri] telah mengabarkan kepada kami [Sufyan] dari [Yunus] dari [Al Hasan] ia berkata; Aku mendengar dia berkata; ['Aqil bin Abu Thalib] datang ke Bashrah kemudian menikahi seorang wanita dari Bani Jusyam, Orang-orang pun mengatakan kepadanya; \"Selamat sejahtera.\" Al Hasan berkata; \"Janganlah kalian mengatakan hal itu, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang kami mengatakan seperti itu, beliau memerintahkan kami suapya mengatakan; \"BAARAKALLAHU LAKA WA BAARAKA 'ALAIKA (semoga Allah memberkahimu dan senantiasa memberkahimu).\""},"1724":{"ar":" حَدَّثَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَانَ إِذَا رَفَّأَ لِإِنْسَانٍ قَالَ بَارَكَ اللَّهُ لَكَ وَبَارَكَ عَلَيْكَ وَجَمَعَ بَيْنَكُمَا فِي خَيْرٍ","id":"Telah menceritakan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz] dari [Suhail] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bahwa jika beliau mengucapkan selamat kepada seseorang, maka beliau mengatakan: \"BAARAKALLAHU LAKA WA WABAARAKA 'ALAIKUM WA JAMA'A BAINAKUMA FI KHAIR (Semoga Allah memberi berkah kepada kamu disaat senang dan susah, serta mengumpulkan kalian dalam kebaikan.\""},"1725":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ أَنْ يَخْطُبَ الرَّجُلُ عَلَى خِطْبَةِ أَخِيهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Suhail bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang seorang laki-laki meminang (wanita) yang telah dipinang saudaranya."},"1726":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ قَالَ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْطُبُ أَحَدُكُمْ عَلَى خِطْبَةِ أَخِيهِ وَلَا يَبِيعُ عَلَى بَيْعِ أَخِيهِ حَتَّى يَأْذَنَ لَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] dari ['Ubaidullah] ia berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah salah seorang diantara kalian meminang (wanita) yang telah dipinang saudaranya, dan janganlah menjual (barang) yang telah dibeli saudaranya, hingga saudaranya memberikan izin.\""},"1727":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّهَا حَدَّثَتْهُ وَكَتَبَهُ مِنْهَا كِتَابًا أَنَّهَا كَانَتْ تَحْتَ رَجُلٍ مِنْ قُرَيْشٍ مِنْ بَنِي مَخْزُومٍ فَطَلَّقَهَا الْبَتَّةَ فَأَرْسَلَتْ إِلَى أَهْلِهِ تَبْتَغِي مِنْهُمْ النَّفَقَةَ فَقَالُوا لَيْسَ لَكِ نَفَقَةٌ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَيْسَ لَكِ نَفَقَةٌ وَعَلَيْكِ الْعِدَّةُ وَانْتَقِلِي إِلَى بَيْتِ أُمِّ شَرِيكٍ وَلَا تُفَوِّتِينَا بِنَفْسِكِ ثُمَّ قَالَ إِنَّ أُمَّ شَرِيكٍ امْرَأَةٌ يَدْخُلُ عَلَيْهَا إِخْوَانُهَا مِنْ الْمُهَاجِرِينَ وَلَكِنْ انْتَقِلِي إِلَى بَيْتِ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ رَجُلٌ أَعْمَى إِنْ وَضَعْتِ ثِيَابَكِ لَمْ يَرَ شَيْئًا وَلَا تُفَوِّتِينَا بِنَفْسِكِ فَانْطَلَقَتْ إِلَى بَيْتِ ابْنِ أُمِّ مَكْتُومٍ فَلَمَّا حَلَّتْ ذَكَرَتْ أَنَّ مُعَاوِيَةَ وَأَبَا جَهْمٍ خَطَبَاهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مُعَاوِيَةُ فَرَجُلٌ لَا مَالَ لَهُ وَأَمَّا أَبُو جَهْمٍ فَلَا يَضَعُ عَصَاهُ عَنْ عَاتِقِهِ فَأَيْنَ أَنْتُمْ مِنْ أُسَامَةَ فَكَأَنَّ أَهْلَهَا كَرِهُوا ذَلِكَ فَقَالَتْ وَاللَّهِ لَا أَنْكِحُ إِلَّا الَّذِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَكَحَتْ أُسَامَةَ قَالَ مُحَمَّدُ بْنُ عَمْرٍو قَالَ مُحَمَّدُ بْنُ إِبْرَاهِيمَ يَا فَاطِمَةُ اتَّقِي اللَّهَ فَقَدْ عَلِمْتِ فِي أَيِّ شَيْءٍ كَانَ هَذَا قَالَ وَقَالَ ابْنُ عَبَّاسٍ قَالَ اللَّهُ تَعَالَى { لَا تُخْرِجُوهُنَّ مِنْ بُيُوتِهِنَّ وَلَا يَخْرُجْنَ إِلَّا أَنْ يَأْتِينَ بِفَاحِشَةٍ مُبَيِّنَةٍ } وَالْفَاحِشَةُ أَنْ تَبْذُوَ عَلَى أَهْلِهَا فَإِذَا فَعَلَتْ ذَلِكَ فَقَدْ حَلَّ لَهُمْ أَنْ يُخْرِجُوهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Fathimah binti Qais] bahwa ia menceritakan kepadanya; \"Abu Salamah pernah mendapatkan surat darinya bahwa dirinya dahulu pernah menjadi isteri seorang laki-laki Quraisy dari Bani Makhzum, kemudian ia mencerainya sekaligus. Kemudian Fathimah mengirimkan utusan kepada keluarga suaminya menuntut nafkah dari mereka. Namun mereka mengatakan; \"Engkau tidak lagi mendapatkan nafkah.\" Ketika hal tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Egkau tidak lagi mendapatkan nafkah, dan harus menunggu masa iddah, pindahlah ke rumah Ummu Syarik, dan janganlah kamu mengabaikan kami supaya dapat memberitahukan mengenai dirimu.\" Kemudian beliau bersabda: \"Sesungguhnya Ummu Syarik adalah seorang wanita yang sering dikunjungi saudara-saudaranya dari kalangan muhajirin, oleh karena itu pindahlah ke rumah Ibnu Ummi Maktum. Karena ia seorang lelaki buta, apabila engkau menanggalkan pakaianmu, maka ia tidak akan melihat sesuatupun. Dan janganlah engkau mengabaikan kami supaya kami dapat memberitakan mengenai dirimu.\" Kemudian ia pergi ke rumah Ibnu Ummi Maktum, setelah masa 'iddahnya selesai, ia menyebutkan bahwa Mu'awiyah dan Abu Jahm telah melamarnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mu'awiyah adalah laki-laki yang tidak memiliki harta, sementara Abu Jahm adalah seseorang yang tidak dapat meletakkan tongkatnya dari pundak. Bagaimana pendapatmu dengan Usamah?\" namun sepertinya keluarga Fathimah tidak menyukai hal itu. Tapi ia berkata; \"Demi Allah, aku tidak akan menikah kecuali dengan orang yang telah dikatakan Rasulullah shallallahu 'alaihi wasallam.\" Kemudian ia menikah dengan Usamah. Muhammad bin 'Amr berkata; Muhammad bin Ibrahim mengatakan (dengan redaksi); \"Wahai Fathimah, bertakwalah kepada Allah. Sungguh kalian telah mengetahui mengenai hal ini.\" Ibnu Abbas berkata; Allah Ta'ala berfirman: Janganlah kamu keluarkan mereka dari rumah mereka dan janganlah mereka (diizinkan) ke luar kecuali mereka mengerjakan perbuatan keji yang terang.\" QS Ath Thallaq; 1. Perbuatan faisyah adalah berbuat keji kepada keluarganya, apabila ia melakukan hal itu, maka telah halal bagi mereka untuk mengeluarkannya.\""},"1728":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا دَاوُدُ يَعْنِي ابْنَ أَبِي هِنْدٍ حَدَّثَنَا عَامِرٌ حَدَّثَنَا أَبُو هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا وَالْعَمَّةُ عَلَى ابْنَةِ أَخِيهَا أَوْ الْمَرْأَةُ عَلَى خَالَتِهَا أَوْ الْخَالَةُ عَلَى بِنْتِ أُخْتِهَا وَلَا تُنْكَحُ الصُّغْرَى عَلَى الْكُبْرَى وَلَا الْكُبْرَى عَلَى الصُّغْرَى","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Daud yaitu Ibnu Abu Hindun] telah menceritakan kepada kami ['Amir] telah menceritakan kepada kami [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang seorang wanita dinikahi sebagai madu bagi bibinya (dari pihak ayah) dan bibi (dari pihak ayah) menjadi madu bagi anak saudaranya, atau seorang wanita menjadi madu bagi bibinya (dari pihak ibu) atau seorang bibi (dari pihak ibu) menjadi madu bagi anak saudara perempuannya, dan tidak boleh adik perempuan dinikahi sebagai madu bagi kakak perempuannya dan seorang kakak perempuan menjadi madu bagi adik peremuannya.\""},"1729":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى أَنْ يُجْمَعَ بَيْنَ الْمَرْأَةِ وَعَمَّتِهَا وَالْمَرْأَةِ وَخَالَتِهَا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang seorang wanita dimadu dengan bibinya (dari pihak ayah) dan seorang wanita dimadu dengan bibinya (dari pihak ibu).\""},"1730":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشِّغَارِ قَالَ مَالِكٌ وَالشِّغَارُ أَنْ يُزَوِّجَ الرَّجُلُ الْآخَرَ ابْنَتَهُ عَلَى أَنْ يُزَوِّجَهُ الْآخَرُ ابْنَتَهُ بِغَيْرِ صَدَاقٍ قِيلَ لِأَبِي مُحَمَّدٍ تَرَى بَيْنَهُمَا نِكَاحًا قَالَ لَا يُعْجِبُنِي","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang (nikah) syighar.\" Malik berkata; syighar adalah seorang laki-laki menikahkan orang lain dengan putrinya dengan syarat orang tersebut menikahkannya dengan putrinya tanpa ada mahar.\" Abu Muhammad ditanya; \"Apakah anda melihat diantara mereka terjadi pernikahan?\" Ia berkata; \"Hal itu tidak membuatku heran.\""},"1731":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ إِبْرَاهِيمَ بْنِ عُمَرَ بْنِ كَيْسَانَ عَنْ أَبِيهِ عَنْ وَهْبِ بْنِ أَبِي مُغِيثٍ حَدَّثَتْنِي أَسْمَاءُ بِنْتُ أَبِي بَكْرٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَنْكِحُوا الصَّالِحِينَ وَالصَّالِحَاتِ قَالَ أَبُو مُحَمَّد وَسَقَطَ عَلَيَّ مِنْ الْحَدِيثِ فَمَا تَبِعَهُمْ بَعْدُ فَحَسَنٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibrahim bin Umar bin Kaisan] dari [bapaknya] dari [Wahb bin Abu Mughits] telah menceritakan kepadaku [Asma` binti Abu Bakr] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Nikahkanlah laki-laki yang shalih dengan wanita yang Shalihah.\" Abu Muhammad berkata; (sebagian) Hadits tersebut gugur dariku, dan apa yang diiringkan kepada mereka adalah baik."},"1732":{"ar":" أَخْبَرَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا إِسْرَائِيلُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا نِكَاحَ إِلَّا بِوَلِيٍّ","id":"Telah mengabarkan kepadaku [Malik bin Isma'il] telah menceritakan kepada kami [Isra`il] dari [Abu Ishaq] dari [Abu Burdah] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak sah pernikahan tanpa seorang wali.\""},"1733":{"ar":" حَدَّثَنَا عَلِيُّ بْنُ حُجْرٍ أَخْبَرَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا نِكَاحَ إِلَّا بِوَلِيٍّ","id":"Telah menceritakan kepada kami [Ali bin Hujr] telah mengceritakan kepada kami [Syarik] dari [Abu Ishaq] dari [Abu Burdah] dari [Abu Musa] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak sah pernikahan kecuali dengan seorang wali.\""},"1734":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ سُلَيْمَانَ بْنِ مُوسَى عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ نُكِحَتْ بِغَيْرِ إِذْنِ وَلِيِّهَا فَنِكَاحُهَا بَاطِلٌ فَنِكَاحُهَا بَاطِلٌ فَنِكَاحُهَا بَاطِلٌ فَإِنْ اشْتَجَرُوا قَالَ أَبُو عَاصِمٍ وَقَالَ مَرَّةً فَإِنْ تَشَاجَرُوا فَالسُّلْطَانُ وَلِيُّ مَنْ لَا وَلِيَّ لَهُ فَإِنْ أَصَابَهَا فَلَهَا الْمَهْرُ بِمَا اسْتَحَلَّ مِنْ فَرْجِهَا قَالَ أَبُو عَاصِمٍ أَمْلَاهُ عَلَيَّ سَنَةَ سِتٍّ وَأَرْبَعِينَ وَمِائَةٍ","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Sulaiman bin Musa] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda; \"Siapapun wanita yang dinikahkan tanpa seizin walinya, maka nikahnya tidak sah, nikahnya tidak sah, nikahnya tidak sah, walaupun mereka berseteru.\" Abu 'Ashim berkata; Dan sesekali beliau bersabda: \"Apabila mereka saling berseteru, maka penguasa adalah wali bagi orang yang tidak memiliki wali, apabila telah digauli, maka wanita tersebut mendapatkan maharnya karena ia telah menghalalkan farjinya.\" Abu 'Ashim berkata; Ibnu Juraij mendektekannya kepadaku pada tahun seratus empat puluh enam."},"1735":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ حَدَّثَنِي أَبُو بُرْدَةَ بْنُ أَبِي مُوسَى عَنْ أَبِي مُوسَى قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسْتَأْمَرُ الْيَتِيمَةُ فِي نَفْسِهَا فَإِنْ سَكَتَتْ فَقَدْ أَذِنَتْ وَإِنْ أَبَتْ لَمْ تُكْرَهْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Yunus bin Abu Ishaq] telah menceritakan kepadaku [Abu Burdah bin Abu Musa] dari [Abu Musa], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak perempuan yatim dimintai pendapatnya terhadap dirinya, apabila ia diam, maka sungguh ia telah mengizinkan dan apabila ia menolak maka tidak boleh dipaksa.\""},"1736":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنِي يَحْيَى عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُنْكَحُ الثَّيِّبُ حَتَّى تُسْتَأْمَرَ وَلَا تُنْكَحُ الْبِكْرُ حَتَّى تُسْتَأْذَنَ وَإِذْنُهَا الصُّمُوتُ أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ حَدَّثَهُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepadaku [Yahya] dari [Abu Salamah] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda tidak dinikahkan hingga dimintai pendapatnya, dan seorang gadis tidak dinikahkan hingga dimintai izinnya dan izinnya adalah diam.\" Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salamah] bahwa [Abu Hurairah] menceritakan kepadanya dari Rasulullah shallallahu 'alaihi wasallam dengan hadits ini."},"1737":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَيِّمُ أَحَقُّ بِنَفْسِهَا مِنْ وَلِيِّهَا وَالْب��كْرُ تُسْتَأْذَنُ فِي نَفْسِهَا وَإِذْنُهَا صُمَاتُهَا","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdullah bin Al Fadhl] dari [Nafi' bin Jubair bin Muth'im] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita janda lebih berhak terhadap dirinya daripada walinya, dan seorang gadis dimintai izin terhadap dirinya, dan izinnya adalah diam.\""},"1738":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ عِيسَى حَدَّثَنِي مَالِكٌ أَوَّلُ شَيْءٍ سَأَلْتُهُ عَنْهُ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْفَضْلِ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسْتَأْذَنُ الْبِكْرُ وَإِذْنُهَا صُمَاتُهَا","id":"Telah menceritakan kepada kami [Ishaq bin Isa] telah menceritakan kepadaku [Malik] pertama kali yang saya tanyakan kepadanya adalah ia berkata; telah menceritakan kepada kami [Abdullah bin Al Fadhl] dari [Nafi' bin Jubair] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang gadis diminta izin, dan izinnya adalah diam.\""},"1739":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ الرَّحْمَنِ بْنِ مَوْهَبٍ أَخْبَرَنَا نَافِعُ بْنُ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَيِّمُ أَمْلَكُ بِأَمْرِهَا مِنْ وَلِيِّهَا وَالْبِكْرُ تُسْتَأْمَرُ فِي نَفْسِهَا وَصَمْتُهَا إِقْرَارُهَا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepadaku ['Ubaidullah bin Abdurrahman bin Mauhib] telah mengabarkan kepada kami [Nafi' bin Jubair bin Muth'im] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda lebih berkuasa terpadap urusannya daripada walinya, dan seorang gadis dimintai pendapatnya mengenai dirinya, dan diamnya adalah tanda setujunya.\""},"1740":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ مُحَمَّدٍ أَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ يَزِيدَ وَمُجَمِّعَ بْنَ يَزِيدَ الْأَنْصَارِيَّيْنِ حَدَّثَاهُ أَنَّ رَجُلًا مِنْهُمْ مِنْ الْأَنْصَارِ يُدْعَى خِذَامًا أَنْكَحَ بِنْتًا لَهُ فَكَرِهَتْ نِكَاحَ أَبِيهَا فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَرَدَّ عَنْهَا نِكَاحَ أَبِيهَا فَنَكَحَتْ أَبَا لُبَابَةَ بْنَ عَبْدِ الْمُنْذِرِ فَذَكَرَ يَحْيَى أَنَّهُ بَلَغَهُ أَنَّهَا كَانَتْ ثَيِّبًا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya bin Sa'id] bahwa ia mendengar [Al Qasim bin Muhammad] bahwa ia mendengar [Abdurrahman bin Yazid] dan [Mujammi' bin Yazid Al Anshari] mereka berdua telah menceritakan kepadanya, bahwa seorang laki-laki dari Anshar yang disebut Khidzam pernah menikahkan putrinya, ternyata putrinya tidak senang dengan pernikahan ayahnya, lantas putrinya datang menemui Rasulullah shallallahu 'alaihi wasallam dan menceritakan hal tersebut kepada beliau. Beliau pun membatalkan pernikahan ayahnya, kemudian beliau menikah dengan Abu Lubabah bin Abdul Mundzir.\" Yahya menyebutkan; telah sampai kepadanya bahwa wanita tersebut adalah seorang janda."},"1741":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ وُمُجَمِّعٍ ابْنَيْ يَزِيدَ ابْنِ جَارِيَةَ أَنَّ خَنْسَاءَ بِنْتَ خِذَامٍ زَوَّجَهَا أَبُوهَا وَهِيَ ثَيِّبٌ فَكَرِهَتْ ذَلِكَ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ نِكَاحَهَا","id":"Telah mengabarkan kepada [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari [Abdurrahman] dan [Mujammi'] keduanya anak Yazid bin Jariyah, bahwa Khansa` binti Khidzam telah dinikahkan oleh ayahnya, ia adalah seorang janda, ternyata Khansa' tidak senang dengan hal itu. Lalu ia datang kepada Rasulullah shallallahu 'alaihi wasallam, akhirnya beliau pun membatalkan pernikahannya.\""},"1742":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَوْ سَمُرَةَ بْنِ جُنْدُبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ زَوَّجَهَا وَلِيَّانِ لَهَا فَهِيَ لِلْأَوَّلِ مِنْهُمَا وَأَيُّمَا رَجُلٍ بَاعَ بَيْعًا مِنْ رَجُلَيْنِ فَهُوَ لِلْأَوَّلِ مِنْهُمَا حَدَّثَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ أَخْبَرَنَا قَتَادَةُ عَنْ الْحَسَنِ عَنْ سَمُرَةَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari ['Uqbah bin 'Amir] atau [Samurah bin Jundub] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun wanita yang dinikahkan oleh dua orang wali, maka wanita itu untuk wali yang pertama dari keduanya. Dan siapapun laki-laki yang menjual barang dagangannya kepada dua orang, maka barang tersebut untuk orang yang pertama dari keduanya.\" Telah menceritakan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah mengabarkan kepada kami [Qatadah] dari [Al Hasan] dari [Samurah] dari Rasulullah shallallahu 'alaihi wasallam sama seperti hadits di atas."},"1743":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ عَبْدِ الْعَزِيزِ بْنِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ عَنْ الرَّبِيعِ بْنِ سَبْرَةَ أَنَّ أَبَاهُ حَدَّثَهُ أَنَّهُمْ سَارُوا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حِجَّةِ الْوَدَاعِ فَقَالَ اسْتَمْتِعُوا مِنْ هَذِهِ النِّسَاءِ وَالِاسْتِمْتَاعُ عِنْدَنَا التَّزْوِيجُ فَعَرَضْنَا ذَلِكَ عَلَى النِّسَاءِ فَأَبَيْنَ أَنْ لَا نَضْرِبَ بَيْنَنَا وَبَيْنَهُنَّ أَجَلًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ افْعَلُوا فَخَرَجْتُ أَنَا وَابْنُ عَمٍّ لِي مَعَهُ بُرْدٌ وَمَعِي بُرْدٌ وَبُرْدُهُ أَجْوَدُ مِنْ بُرْدِي وَأَنَا أَشَبُّ مِنْهُ فَأَتَيْنَا عَلَى امْرَأَةٍ فَأَعْجَبَهَا شَبَابِي وَأَعْجَبَهَا بُرْدُهُ فَقَالَتْ بُرْدٌ كَبُرْدٍ وَكَانَ الْأَجَلُ بَيْنِي وَبَيْنَهَا عَشْرًا فَبِتُّ عِنْدَهَا تِلْكَ اللَّيْلَةَ ثُمَّ غَدَوْتُ فَإِذَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَائِمٌ بَيْنَ الرُّكْنِ وَالْبَابِ فَقَالَ يَا أَيُّهَا النَّاسُ إِنِّي قَدْ كُنْتُ أَذِنْتُ لَكُمْ فِي الِاسْتِمْتَاعِ مِنْ النِّسَاءِ أَلَا وَإِنَّ اللَّهَ قَدْ حَرَّمَهُ إِلَى يَوْمِ الْقِيَامَةِ فَمَنْ كَانَ عِنْدَهُ مِنْهُنَّ شَيْءٌ فَلْيُخَلِّ سَبِيلَهَا وَلَا تَأْخُذُوا مِمَّا آتَيْتُمُوهُنَّ شَيْئًا","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Abdul Aziz bin Umar bin Abdul Aziz] dari [Ar Rabi' bin Sabrah] bahwa [Ayahnya] telah menceritakan kepadanya, bahwa orang-orang pernah berjalan bersama Rasulullah shallallahu 'alaihi wasallam ketika haji wada', kemudian beliau bersabda: \"Bersenang-senanglah dengan para wanita ini! \" Dan bersenang-senang menurut kami adalah menikahkan (dengan waktu yang ditentukan), kemudian kami menawarkan hal tersebut kepada para wanita, ternyata mereka menolak untuk tidak diberi tempo antara kami dan mereka. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lakukanlah.\" Kemudian aku keluar bersama anak pamanku, ia membawa burdah (kain yang dipakai untuk menyelimuti badan) dan aku membawa burdah dan burdahnya lebih baik dari burdahku, namun aku lebih muda darinya. Kemudian kami mendatangi seorang wanita, ternyata wanita itu kagum dengan kemudaanku, namun ia kagum dengan kain anak pamanku. Wanita itu berkata; \"Kain burdah seperti kain yang lain.\" Sementara tempo antara diriku dengan dirinya selama sepuluh hari. Kemudian aku bermalam di sisinya pada malam itu. Pada pagi harinya, aku pergi, ternyata Rasulullah shallallahu 'alaihi wasallam sedang berdiri diantara rukun dan pintu Ka'bah. Lalu beliau bersabda: \"Wahai sekalian manusia, sesungguhnya dahulu aku telah mengizinkan kalian untuk menikahi para wanita secara mut'ah. Ketahuilah bahwa Allah telah mengharamkannya hingga Hari Kiamat. Barangsiapa memiliki sesuatu dari mereka, hendaknya ia melepaskannya, dan janganlah mengambil sesuatupun dari apa yang kalian berikan kepada mereka.\" "},"1744":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ الرَّبِيعِ بْنِ سَبْرَةَ الْجُهَنِيِّ عَنْ أَبِيهِ قَالَ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ نِكَاحِ الْمُتْعَةِ عَامَ الْفَتْحِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Ar Rabi' bin Sabrah Al Juhani] dari [Ayahnya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam telah melarang nikah mut'ah pada saat penaklukan kota Makkah.\""},"1745":{"ar":" حَدَّثَنَا مُحَمَّدٌ حَدَّثَنِي ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ الْحَسَنِ وَعَبْدِ اللَّهِ عَنْ أَبِيهِمَا قَالَ سَمِعْتُ عَلِيًّا يَقُولُ لِابْنِ عَبَّاسٍ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الْمُتْعَةِ مُتْعَةِ النِّسَاءِ وَعَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ عَامَ خَيْبَرَ","id":"Telah menceritakan kepada kami [Muhammad] telah menceritakan kepadaku [Ibnu 'Uyainah] dari [Az Zuhri] dari [Al Hasan] dan [Abdullah] dari [ayah mereka berdua], ia berkata; aku mendengar [Ali] berkata kepada Ibnu Abbas; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah melarang mut'ah yaitu menikahi wanita secara mut'ah, dan daging keledai jinak ketika perang Khaibar.\""},"1746":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ أَيُّوبَ بْنِ مُوسَى عَنْ نُبَيْهِ بْنِ وَهْبٍ عَنْ أَبَانَ بْنِ عُثْمَانَ عَنْ عُثْمَانَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُحْرِمُ لَا يَنْكِحُ وَلَا يُنْكِحُ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Ayyub bin Musa] dari [Nubaih bin Wahb] dari [Aban bin Utsman] dari [Utsman] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang yang berihram tidak boleh menikah dan menikahkan.\""},"1747":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ هُوَ ابْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ قَالَ سَأَلْتُ عَائِشَةَ كَمْ كَانَ صَدَاقُ أَزْوَاجِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ صَدَاقُهُ لِأَزْوَاجِهِ اثْنَتَيْ عَشْرَةَ أُوقِيَّةً وَنَشًّا وَقَالَتْ أَتَدْرِي مَا النَّشُّ قَالَ قُلْتُ لَا قَالَتْ نِصْفُ أُوقِيَّةٍ فَهَذَا صَدَاقُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِأَزْوَاجِهِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Abdul Aziz yaitu Ibnu Muhammad] dari [Yazid bin Abdullah] dari [Muhammad bin Ibrahim] dari [Abu Salamah], ia berkata; Aku bertanya kepada ['Aisyah]; \"Berapakah mahar para isteri Rasulullah shallallahu 'alaihi wasallam?, \" 'Aisyah berkata; \"Mahar para isteri beliau adalah dua belas 'uqiyah dan nasy.\" Aisyah melanjutkan; \"Tahukah kamu apakah nasy itu?, \" Aku menjawab; \"Tidak.\" Aisyah berkata; \"Setengah 'Uqiyah. Ini adalah mahar Rasulullah shallallahu 'alaihi wasallam untuk para isterinya.\""},"1748":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ ابْنِ سِيرِينَ عَنْ أَبِي الْعَجْفَاءِ السُّلَمِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ خَطَبَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ أَلَا لَا تُغَالُوا فِي صُدُقِ النِّسَاءِ فَإِنَّهَا لَوْ كَانَتْ مَكْرُمَةً فِي الدُّنْيَا أَوْ تَقْوَى عِنْدَ اللَّهِ كَانَ أَوْلَاكُمْ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصْدَقَ امْرَأَةً مِنْ نِسَائِهِ وَلَا أُصْدِقَتْ امْرَأَةٌ مِنْ بَنَاتِهِ فَوْقَ اثْنَتَيْ عَشْرَةَ أُوقِيَّةً أَلَا وَإِنَّ أَحَدَكُمْ لَيُغَالِي بِصَدَاقِ امْرَأَتِهِ حَتَّى يَبْقَى لَهَا فِي نَفْسِهِ عَدَاوَةٌ حَتَّى يَقُولَ كَلِفْتُ إِلَيْكِ عَلَقَ الْقِرْبَةِ أَوْ عَرَقَ الْقِرْبَةِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari [Manshur bin Zadzan] dari [Ibnu Sirin] dari [Abu Al 'Ajfa` As Sulami], ia berkata; Aku mendengar [Umar bin Al Khathab] berkhutbah, ia memuji Allah, kemudian berkata; \"Ketahuilah, janganlah kalian berlebihan dalam mahar wanita, apabila berlebihan dalam mahar merupakan bentuk kemuliaan di dunia atau ketakwaan di sisi Allah, niscaya yang paling pertama kali melakukannya adalah Rasulullah shallallahu 'alaihi wasallam. Tidaklah beliau memberikan mahar kepada seorangpun dari para isterinya dan tidak seorangpun dari anak-anak wanitanya yang diberi mahar di atas dua belas 'uqiyah. Sungguh salah seorang diantara kalian berlebihan dalam mahar isterinya, hingga tinggallah dalam dirinya permusuhan kepada isterinya, sampai dirinya mengatakan; \"Aku telah menanggung segala sesuatu hingga tali geriba, atau hingga berkeringat seperti geriba berkeringat.\""},"1749":{"ar":" حَدَّثَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ أَتَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّهَا وَهَبَتْ نَفْسَهَا لِلَّهِ وَلِرَسُولِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لِي فِي النِّسَاءِ مِنْ حَاجَةٍ فَقَالَ رَجُلٌ زَوِّجْنِيهَا فَقَالَ أَعْطِهَا ثَوْبًا فَقَالَ لَا أَجِدُ قَالَ أَعْطِهَا وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَاعْتَلَّ لَهُ فَقَالَ مَا مَعَكَ مِنْ الْقُرْآنِ قَالَ كَذَا وَكَذَا قَالَ فَقَدْ زَوَّجْتُكَهَا عَلَى مَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah menceritakan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Hammad bin Zaid] dari [Abu Hazim] dari [Sahl bin Sa'd] ia berkata; \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam lalu berkata; \"Sesungguhnya dirinya telah menghibahkan dirinya untuk Allah dan RasulNya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda; \"Aku tidak memiliki kebutuhan kepada wanita.\" Lantas seorang laki-laki berkata; \"Nikahkanlah aku dengannya.\" Beliau pun bersabda; \"Berilah pakaian (kepada calon isterimu sebagai mahar -pent).\" Laki-laki itu berkata; \"Aku tidak memilikinya.\" Beliau bersabda: \"Berikan kepada (calon isterimu) walaupun hanya cincin dari besi.\" Laki-laki it uterus mengelak. Akhirnya beliau bersabda: \"Apakah kamu hafal Al Qur'an?\" lalu laki-laki itu mengatakan demikian dan demikian. Beliau bersabda: \"Sungguh aku telah menikahkanmu dengan wanita tersebut dengan mahar apa yang kamu hafal dari Al Qur'an.\""},"1750":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ وَحَجَّاجٌ قَالَا حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ أَبَا عُبَيْدَةَ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ قَالَ عَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خُطْبَةَ الْحَاجَةِ الْحَمْدُ لِلَّهِ أَوْ إِنَّ الْحَمْدَ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ فَلَا هَادِيَ لَهُ أَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ ثُمَّ يَقْرَأُ ثَلَاثَ آيَاتٍ { يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ حَقَّ تُقَاتِهِ وَلَا تَمُوتُنَّ إِلَّا وَأَنْتُمْ مُسْلِمُونَ } { يَا أَيُّهَا النَّاسُ اتَّقُوا رَبَّكُمْ الَّذِي خَلَقَكُمْ مِنْ نَفْسٍ وَاحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا } { يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَقُولُوا قَوْلًا سَدِيدًا يُصْلِحْ لَكُمْ أَعْمَالَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَمَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ فَازَ فَوْزًا عَظِيمًا } ثُمَّ يَتَكَلَّمُ بِحَاجَتِهِ","id":"Telah menceritakan kepada kami [Abu Al Walid] dan [Hajjaj] keduanya berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah memberitakan kepada kami [Abu Ishaq] ia berkata; Aku mendengar [Abu 'Ubaidah] menceritakan dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan kepada kami khutbah hajah, yaitu; \"Al HAMDULILLAAHI atau INNAL HAMDA LILLAAHI NAHMADUHU WA NASTA'IINUHU WA NASTAGHFIRUHU WA NA'UUDZU BILLAAHI MIN SYURUURI ANFUSINAA, MAN YAHDIHILLAAHU FALAA MUDHILLA LAHU WA MAN YUDHLIL FALAA HAADIYA LAHU. ASYHADU AN LAA ILAAHA ILLALLAAH WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU (segala puji bagi Allah, atau sesungguhnya segala puji bagi Allah, kita memujiNya, memohon pertolongan, serta ampunan kepadaNya, dan kita berlindung kepada Allah dari keburukan diri kita, barangsiapa yang Allah beri petunjuk maka tidak ada yang dapat menyesatkannya, dan barangsiapa yang Allah sesatkan maka tidak ada yang dapat memberinya petunjuk. Aku bersaksi bahwa tidak ada tuhan yang berhak disembah kecuali Allah, dan aku bersaksi bahwa Mummad adalah hamba dan utusanNya.. Kemudian membaca tiga ayat, yaitu; Hai orang-orang yang beriman, bertakwalah kepada Allah sebenar-benar takwa kepada-Nya; dan janganlah sekali-kali kamu mati melainkan dalam keadaan beragama Islam. QS Ali Imran; 102. Hai sekalian manusia, bertakwalah kepada Tuhan-mu yang telah menciptakan kamu dari seorang diri, dan dari padanya, Allah menciptakan isterinya.\" QS An Nisa`; 1. Hai orang-orang yang beriman, bertakwalah kamu kepada Allah dan katakanlah perkataan yang benar, niscaya Allah memperbaiki bagimu amalan-amalanmu dan mengampuni bagimu dosa-dosamu. Dan barangsiapa mentaati Allah dan Rasul-Nya, maka sesungguhnya ia telah mendapat kemenangan yang besar. QS Al Ahzab; 70-71. Kemudian mengatakan kebutuhannya."},"1751":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ عَبْدِ الْحَمِيدِ بْنِ جَعْفَرٍ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَقَّ الشُّرُوطِ أَنْ تُوفُوا بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Abdul Hamid bin Ja'far] dari [Yazid bin Abu Habib] dari [Martsad bin Abdullah] dari ['Uqbah bin 'Amir] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Sesungguhnya syarat yang paling berhak untuk kalian tunaikan adalah yang kalian gunakan untuk menghalalkan kemaluan.\""},"1752":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَى عَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ صُفْرَةً فَقَالَ مَا هَذِهِ الصُّفْرَةُ قَالَ تَزَوَّجْتُ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ مِنْ ذَهَبٍ قَالَ بَارَكَ اللَّهُ لَكَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam melihat bekas warna kuning (minyak) pada Abdurrahman bin 'Auf, lalu Abdurrahman berkata; Aku telah menikahi seorang wanita dengan mahar emas sebesar satu biji kurma. Beliau mengucapkan; \"BAARAKALLAAHU LAKA (Semoga Allah memberikan keberkahan atasmu) rayakanlah walaupun hanya dengan seekor kambing.\""},"1753":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا دُعِيَ أَحَدُكُمْ إِلَى وَلِيمَةٍ فَلْيُجِبْ قَالَ أَبُو مُحَمَّد يَنْبَغِي أَنْ يُجِيبَ وَلَيْسَ الْأَكْلُ عَلَيْهِ بِوَاجِبٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian diundang ke pesta (pernikahan), hendaknya ia memenuhi undangan tersebut.\" Abu Muhammad berkata; \"Selayaknya ia memenuhi undangan tersebut, sementara makan bukanlah sesuatu yang wajib.\""},"1754":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ النَّضْرِ بْنِ أَنَسٍ عَنْ بَشِيرِ بْنِ نَهِيكٍ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَتْ لَهُ امْرَأَتَانِ فَمَالَ إِلَى إِحْدَاهُمَا جَاءَ يَوْمَ الْقِيَامَةِ وَشِقُّهُ مَائِلٌ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [An Nadhr bin Anas] dari [Basyir bin Nahik] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa memiliki dua orang isteri, kemudian ia cenderung kepada salah seorang dari keduanya, maka ia akan datang pada Hari Kiamat dalam keadaan sisi sebelahnya miring.\""},"1755":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْخَطْمِيِّ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقْسِمُ فَيَعْدِلُ وَيَقُولُ اللَّهُمَّ هَذِهِ قِسْمَتِي فِيمَا أَمْلِكُ فَلَا تَلُمْنِي فِيمَا تَمْلِكُ وَلَا أَمْلِكُ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Abu Qilabah] dari [Abdullah bin Yazid Al Khathmi] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam membagi serta bersikap adil (terhadap para isterinya), dan beliau mengatakan: \"Ya Allah, ini adalah pembagianku yang aku mampu, maka janganlah Engkau cela aku dalam perkara yang Engkau mampu dan tidak aku mampui.\""},"1756":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ يُونُسَ بْنِ يَزِيدَ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا سَافَرَ أَقْرَعَ بَيْنَ نِسَائِهِ فَأَيَّتُهُنَّ خَرَجَ سَهْمُهَا خَرَجَ بِهَا مَعَهُ","id":"Telah mengabarkan kepada kami [Isma'il] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Yunus bin Yazid] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak bepergian, beliau selalu mengundi diantara para isterinya, siapa diantara mereka yang keluar undiannya, maka beliau pergi bersamanya.\""},"1757":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَا��َ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْبِكْرِ سَبْعٌ وَلِلثَّيِّبِ ثَلَاثٌ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Muhammad bin Ishaq] dari [Ayyub] dari [Abu Qilabah] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Gadis mendapatkan tujuh hari dan janda mendapatkan tiga hari.\""},"1758":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ أَبِي شَيْبَةَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ سُفْيَانَ عَنْ مُحَمَّدِ بْنِ أَبِي بَكْرٍ عَنْ عَبْدِ الْمَلِكِ بْنِ أَبِي بَكْرِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ الْحَارِثِ بْنِ هِشَامٍ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَمَّا تَزَوَّجَ أُمَّ سَلَمَةَ أَقَامَ عِنْدَهَا ثَلَاثًا وَقَالَ إِنَّهُ لَيْسَ بِكِ عَلَى أَهْلِكِ هَوَانٌ إِنْ شِئْتِ سَبَّعْتُ لَكِ وَإِنْ سَبَّعْتُ لَكِ سَبَّعْتُ لِسَائِرِ نِسَائِي","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abu Syaibah] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Sufyan] dari [Muhammad bin Abu Bakr] dari [Abdul Malik bin Abu Bakr bin Abdurrahman bin Al Harits bin Hisyam] dari [Ayahnya] dari [Ummu Salamah] bahwa ketika Rasulullah shallallahu 'alaihi wasallam menikahi Ummu Salamah, beliau tinggal di rumahnya selama tiga hari. Beliau bersabda: \"Sesungguhnya tidak ada kehinaan padamu atas keluargamu, apabila engkau mau, maka aku akan memberikan tujuh hari dan memberikan tujuh hari untuk isteri-isteriku yang lain.\""},"1759":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ تَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَوَّالٍ وَأُدْخِلْتُ عَلَيْهِ فِي شَوَّالٍ فَأَيُّ نِسَائِهِ كَانَ أَحْظَى عِنْدَهُ مِنِّي قَالَ وَكَانَتْ تَسْتَحِبُّ أَنْ تُدْخِلَ عَلَى النِّسَاءِ فِي شَوَّالٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Isma'il bin Umayyah] dari [Abdullah bin 'Urwah] dari ['Urwah] dari ['Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku pada Bulan Syawal, dan aku berumah tangga pada bulan Syawal. Siapakah diantara isteri beliau yang lebih mendapatkan bagian di sisinya daripada diriku?, \" 'Urwah berkata; \"Beliau sangat senang bila berumah tangga dengan para isterinya (yang baru) di Bulan Syawal."},"1760":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ سَالِمٍ عَنْ كُرَيْبٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَمْنَعُ أَحَدَكُمْ أَنْ يَقُولَ حِينَ يُجَامِعُ أَهْلَهُ بِسْمِ اللَّهِ اللَّهُمَّ جَنِّبْنَا الشَّيْطَانَ وَجَنِّبْ الشَّيْطَانَ مَا رَزَقْتَنَا فَإِنْ قَضَى اللَّهُ وَلَدًا لَمْ يَضُرَّهُ الشَّيْطَانُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Isra`il] dari [Manshur] dari [Salim] dari [Kuraib] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah yang menghalangi salah seorang dari kalian ketika menggauli isterinya untuk mengucapkan; BISMILLAAH, ALLAAHUMMA JANNIBNASY SYAITHAAN WA JANNIB ASY SYAITHAANA MAA RAZAQTANAA (Dengan nama Allah, ya Allah, jauhkanlah kami dari syetan dan jauhkanlah syetan dari anak yang Engkau rizkikan kepada kami). Apabila Allah menetapkan untuk memberikan anak kepadanya, maka syetan tidak akan mampu membahayakannya.\""},"1761":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ الْوَلِيدِ بْنِ كَثِيرٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ الْحُصَيْنِ عَنْ عَبْدِ الْمَلِكِ بْنِ عَمْرِو بْنِ قَيْسٍ الْخَطْمِيِّ عَنْ هَرَمِيِّ بْنِ عَبْدِ اللَّهِ قَالَ سَمِعْتُ خُزَيْمَةَ بْنَ ثَابِتٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِنَّ اللَّهَ لَا يَسْتَحْيِي مِنْ الْحَقِّ لَا تَأْتُوا النِّسَاءَ فِي أَعْجَازِهِنَّ","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Usamah] dari [Al Walid bin Katsir] dari ['Ubaidullah bin Abdullah bin Al Hushain] dari [Abdul Malik bin 'Amr bin Qais Al Khathmi] dari [Harami bin Abdullah] ia berkata; Aku mendengar [Khuzaimah bin Tsabit] berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidak malu dari kebenaran, janganlah kalian mendatangi para wanita dari duburnya.\""},"1762":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ الْيَهُودَ قَالُوا لِلْمُسْلِمِينَ مَنْ أَتَى امْرَأَتَهُ وَهِيَ مُدْبِرَةٌ جَاءَ وَلَدُهُ أَحْوَلَ فَأَنْزَلَ اللَّهُ تَعَالَى { نِسَاؤُكُمْ حَرْثٌ لَكُمْ فَأْتُوا حَرْثَكُمْ أَنَّى شِئْتُمْ }","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah] bahwa orang-orang Yahudi berkata kepada kaum Muslimin; \"Barangsiapa mendatangi isterinya dari arah belakang, maka anaknya akan terlahir dalam keadaan juling.\" Maka Allah Ta'ala menurunkan ayat Isteri-isterimu adalah (seperti) Tanah tempat kamu bercocok tanam, maka datangilah tanah tempat bercocok-tanammu itu bagaimana saja kamu kehendaki.\" QS Al Baqarah; 223."},"1763":{"ar":" أَخْبَرَنَا قَبِيصَةُ أَخْبَرَنَا سُفْيَانُ عَنْ أَبِي إِسْحَقَ عَنْ عَبْدِ اللَّهِ بْنِ حَلَّامٍ عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ قَالَ رَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةً فَأَعْجَبَتْهُ فَأَتَى سَوْدَةَ وَهِيَ تَصْنَعُ طِيبًا وَعِنْدَهَا نِسَاءٌ فَأَخْلَيْنَهُ فَقَضَى حَاجَتَهُ ثُمَّ قَالَ أَيُّمَا رَجُلٍ رَأَى امْرَأَةً تُعْجِبُهُ فَلْيَقُمْ إِلَى أَهْلِهِ فَإِنَّ مَعَهَا مِثْلَ الَّذِي مَعَهَا","id":"Telah mengabarkan kepada kami [Qabishah] telah mengabarkan kepada kami [Sufyan] dari [Abu Ishaq] dari [Abdullah bin Hallam] dari [Abdullah bin Mas'ud] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melihat seorang wanita yang membuat beliau terpesona, kemudian beliau langsung mendatangi Saudah, sementara dirinya sedang membuat minyak wangi, dan ia bersama beberapa orang wanita, kemudian mereka meninggalkan beliau bersamanya hingga beliau dapat memenuhi hajatnya. Kemudian beliau bersabda: \"Siapapun laki-laki yang melihat seorang wanita yang membuatnya terpesona, hendaknya ia segera mendatangi isterinya, sesungguhnya isterinya memiliki apa yang di miliki oleh wanita tersebut.\""},"1764":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُطِيعٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا سَيَّارٌ عَنْ الشَّعْبِيِّ حَدَّثَنَا جَابِرُ بْنُ عَبْدِ اللَّهِ قَالَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَفَرٍ فَلَمَّا قَفَلْنَا تَعَجَّلْتُ فَلَحِقَنِي رَاكِبٌ قَالَ فَالْتَفَتُّ فَإِذَا أَنَا بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِي مَا أَعْجَلَكَ يَا جَابِرُ قَالَ إِنِّي حَدِيثُ عَهْدٍ بِعُرْسٍ قَالَ أَفَبِكْرًا تَزَوَّجْتَهَا أَمْ ثَيِّبًا قَالَ قُلْتُ بَلْ ثَيِّبًا قَالَ فَهَلَّا بِكْرًا تُلَاعِبُهَا وَتُلَاعِبُكَ قَالَ ثُمَّ قَالَ لِي إِذَا قَدِمْتَ فَالْكَيْسَ الْكَيْسَ قَالَ فَلَمَّا قَدِمْنَا ذَهَبْنَا نَدْخُلُ قَالَ أَمْهِلُوا حَتَّى نَدْخُلَ لَيْلًا أَيْ عِشَاءً لِكَيْ تَمْتَشِطَ الشَّعِثَةُ وَتَسْتَحِدَّ الْمُغِيبَةُ","id":"Telah mengabarkan kepada kami [Abdullah bin Muthi'] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Sayyar] dari [Asy Sya'bi] telah menceritakan kepada kami [Jabir bin Abdullah] ia berkata; kami bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu perjalanan, tatkala kami kambali (dari perjalanan), aku terburu-buru kemudian seseorang yang menunggang kendaraan menyusulku dan berbicara, kemudian aku menoleh, ternyata aku dengan Rasulullah shallallahu 'alaihi wasallam, beliau bersabda kepadaku: \"Apa yang menyebabkanmu terburu-buru wahai Jabir?\" Jabir menjawab; \"Sesungguhnya aku baru menikah.\" Beliau bertanya: \"Apakah engkau menikahi gadis atau janda?\" Jabir berkata; Aku menjawab; \"Janda.\" Beliau bersabda: \"Tidakkah engkau menikahi seorang gadis, sehingga engkau dapat bercumbu dengannya dan dia bercumbu denganmu?\" Jabir berkata; kemudian beliau bersabda kepadaku: \"Berharaplah mendapatkan anak, berharaplah mendapatkan anak.\" Jabir berkata; Tatkala kami tiba (di Madinah), kami pun pergi dan segera hendak masuk rumah. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pelan-pelanlah, hingga kita masuk pada malam hari yaitu pada waktu Isya` agar wanita yang rambutnya berantakan menyisir rambutnya dan dan mereka bisa mempersiapkan dirinya.\""},"1765":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ نَوْفَلٍ الْأَسَدِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ جُدَامَةَ بِنْتِ وَهْبٍ الْأَسَدِيَّةِ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ حَتَّى ذَكَرْتُ أَنَّ فَارِسَ وَالرُّومَ يَصْنَعُونَ ذَلِكَ فَلَا يَضُرُّ أَوْلَادَهُمْ قَالَ أَبُو مُحَمَّد الْغِيلَةُ أَنْ يُجَامِعَهَا وَهِيَ تُرْضِعُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Malik] dari [Muhammad bin Abdurrahman bin Naufal Al Asadi] dari ['Urwah] dari [Aisyah] dari [Judamah binti Wahb Al Asadiyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh aku pernah berkeinginan melarang ghilah (menggauli wanita yang tengah menyusui), hingga aku ingat bahwa orang-orang Persia dan Romawi melakukan hal itu namun tidak membahayakan anak-anak mereka.\" Abu Muhammad berkata; ghilah adalah menggauli wanita dalam keadaan menyusui."},"1766":{"ar":" حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ مَا ضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَادِمًا قَطُّ وَلَا ضَرَبَ بِيَدِهِ شَيْئًا قَطُّ إِلَّا أَنْ يُجَاهِدَ فِي سَبِيلِ اللَّهِ","id":"Telah menceritakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam tidak pernah memukul pembantu sama sekali, dan tidak pernah memukul sesuatu dengan tangannya sama sekali kecuali ketika berjihad di jalan Allah.\""},"1767":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ أَحْمَدَ بْنِ أَبِي خَلَفٍ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ إِيَاسِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي ذُبَابٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَضْرِبُوا إِمَاءَ اللَّهِ فَجَاءَ عُمَرُ بْنُ الْخَطَّابِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَدْ ذَئِرْنَ عَلَى أَزْوَاجِهِنَّ فَرَخَّصَ فِي ضَرْبِهِنَّ فَأَطَافَ بِآلِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءٌ كَثِيرٌ يَشْكُونَ أَزْوَاجَهُنَّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ طَافَ بِآلِ مُحَمَّدٍ نِسَاءٌ كَثِيرٌ يَشْكُونَ أَزْوَاجَهُنَّ لَيْسَ أُولَئِكَ بِخِيَارِكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad bin Abu Khalaf] telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Iyas bin Abdullah bin Abu Dzubab] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah kalian memukul hamba wanita Allah.\" Kemudian Umar bin Al Khathab datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Sungguh mereka telah berani kepada suami mereka.\" Lalu beliau memberikan keringanan untuk memukul mereka. Ternyata banyak wanita yang mengelilingi keluarga Rasulullah shallallahu 'alaihi wasallam, mereka mengeluhkan suami-suami mereka. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Sungguh banyak wanita yang mengelilingi keluarga Muhammad, mereka mengeluhkan para suami mereka, padahal mereka bukanlah orang-orang terbaik kalian.\""},"1768":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ زَمَعَةَ قَالَ خَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ النَّاسَ يَوْمًا فَوَعَظَهُمْ فِي النِّسَاءِ ��َقَالَ مَا بَالُ الرَّجُلِ يَجْلِدُ امْرَأَتَهُ جَلْدَ الْعَبْدِ وَلَعَلَّهُ يُضَاجِعُهَا فِي آخِرِ يَوْمِهِ","id":"Telah mengabakan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari [Abdullah bin Zama'ah], ia berkata; Suatu hari Rasulullah shallallahu 'alaihi wasallam khutbah dihadapan manusia. Beliau menasehati mereka terhadap para isteri. Beliau bersabda: \"Bagaimana seorang laki-laki mencambuk isterinya seperti mencambuk seorang budak, padahal kemungkinan ia akan menggaulinya pada akhir hari.\""},"1769":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا عَبْدُ الْوَارِثِ حَدَّثَنَا الْجُرَيْرِيُّ عَنْ أَبِي الْعَلَاءِ عَنْ نُعَيْمِ بْنِ قَعْنَبٍ عَنْ أَبِي ذَرٍّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الْمَرْأَةَ خُلِقَتْ مِنْ ضِلَعٍ فَإِنْ تُقِمْهَا كَسَرْتَهَا فَدَارِهَا فَإِنَّ فِيهَا أَوَدًا وَبُلْغَةً","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Abdul Warits] telah menceritakan kepada kami [Al Jurairi] dari [Abu Al 'Ala`] dari [Nu'aim bin Qa'nab] dari [Abu Dzar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang wanita diciptakan dari tulang rusuk, apabila engkau meluruskannya maka engkau akan mematahkannya, maka bersikaplah lembut kepadanya, sesungguhnya padanya terdapat kebengkokan dan kehidupan yang sepadan.\""},"1770":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْمَرْأَةُ كَالضِّلَعِ إِنْ تُقِمْهَا تَكْسِرْهَا وَإِنْ تَسْتَمْتِعْ تَسْتَمْتِعْ وَفِيهَا عِوَجٌ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya seorang wanita itu seperti tulang rusuk, apabila engkau meluruskannya, maka engkau akan mematahkannya, dan apabila engkau bersenang-senang dengannya maka engkau dapat bersenang-senang dengannya sekalipun tetap bengkok.\""},"1771":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ عَنْ إِبْرَاهِيمَ بْنِ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي سَعِيدٍ قَالَ سَأَلَ رَجُلٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَزْلِ فَقَالَ أَوَ تَفْعَلُونَ ذَلِكَ فَلَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا فَإِنَّهُ لَيْسَ مِنْ نَسَمَةٍ قَضَى اللَّهُ تَعَالَى أَنْ تَكُونَ إِلَّا كَانَتْ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud Al Hasyimi] dari [Ibrahim bin Sa'd] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Sa'id] ia berkata; \"Seorang laki-laki bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai 'azl, beliau menjawab: \"Apakah kalian melakukan hal itu? Tidak, kalian tidak boleh melakukan, sesungguhnya tidak ada jiwa yang telah Allah Ta'ala tetapkan melainkan akan terwujud.\""},"1772":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بِشْرٍ يَرُدُّ الْحَدِيثَ إِلَى أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قُلْنَا يَا رَسُولَ اللَّهِ الرَّجُلُ تَكُونُ لَهُ الْجَارِيَةُ فَيُصِيبُ مِنْهَا وَيَكْرَهُ أَنْ تَحْمِلَ أَفَيَعْزِلُ عَنْهَا وَتَكُونُ عِنْدَهُ الْمَرْأَةُ تُرْضِعُ فَيُصِيبُ مِنْهَا وَيَكْرَهُ أَنْ تَحْمِلَ فَيَعْزِلُ عَنْهَا قَالَ لَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا فَإِنَّمَا هُوَ الْقَدَرُ قَالَ ابْنُ عَوْنٍ فَذَكَرْتُ ذَلِكَ لِلْحَسَنِ فَقَالَ وَاللَّهِ لَكَأَنَّ هَذَا زَجْرًا وَاللَّهِ لَكَأَنَّ هَذَا زَجْرًا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan keapada kami [Ibnu 'Aun] dari [Muhammad bin Sirin] dari [Abdurrahman bin Bisyr] ia merefrensikan hadits kepada [Abu Sa'id Al Khudri] ia berkata; \"Kami mengatakan; \"Wahai Rasulullah, seorang laki-laki memiliki budak wanita, kemudian ia menggaulinya dan tidak ingin budaknya hamil, apakah ia boleh melakukan 'azl? dia juga memiliki isteri yang sedang menyusui, kemudian ia menggaulinya dan tidak ingin ia mengandung, maka bolehkan ia melakukan 'azl?\" Beliau menjawab: \"Tidak, janganlah kalian melakukannya, sesungguhnya hal itu merupakan suatu ketetapan.\" Ibnu 'Aun mengatakan; kemudian aku menyebutkan hadits tersebut kepada Al Hasan, ia berkata; \"Demi Allah, seolah-olah hal ini merupakan hardikan, demi Allah seolah-olah ini merupakan suatu hardikan.\""},"1773":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ شَقِيقٍ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ أَحَدٌ أَغْيَرَ مِنْ اللَّهِ لِذَلِكَ حَرَّمَ الْفَوَاحِشَ وَلَيْسَ أَحَدٌ أَحَبُّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Syaqiq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada sesuatupun yang lebih besar kecemburuannya daripada Allah, oleh karena itu Allah mengharamkan perbuatan keji, dan tidak ada sesuatu pun yang lebih senang dipuji daripada Allah.\""},"1774":{"ar":" أَخْبَرَنَا أَبُو الْمُغِيرَةِ حَدَّثَنَا الْأَوْزَاعِيُّ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ حَدَّثَنِي ابْنُ جَابِرِ بْنِ عَتِيكٍ حَدَّثَنِي أَبِي أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مِنْ الْغَيْرَةِ مَا يُحِبُّ اللَّهُ وَمِنْهَا مَا يُبْغِضُ اللَّهُ فَالْغَيْرَةُ الَّتِي يُحِبُّ اللَّهُ الْغَيْرَةُ فِي الرِّيبَةِ وَالْغَيْرَةُ الَّتِي يُبْغِضُ اللَّهُ الْغَيْرَةُ فِي غَيْرِ رِيبَةٍ","id":"Telah mengabarkan kepada kami [Abu Al Mughirah] telah menceritakan kepada kami [Al Auza'i] telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Muhammad bin Ibrahim] telah menceritakan kepadaku [Ibnu Jabir bin 'Atik] telah menceritakan kepadaku [Ayahku] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Diantara rasa cemburu, ada sesuatu yang Allah cintai dan ada yang Allah benci. Rasa cemburu yang dicintai Allah adalah cemburu ketika terdapat keraguan dan cemburu yang Allah benci adalah cemburu ketika tidak terdapat keraguan.\""},"1775":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ وَرَّادٍ مَوْلَى الْمُغِيرَةِ عَنْ الْمُغِيرَةِ قَالَ بَلَغَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ سَعْدَ بْنَ عُبَادَةَ يَقُولُ لَوْ وَجَدْتُ مَعَهَا رَجُلًا لَضَرَبْتُهَا بِالسَّيْفِ غَيْرَ مُصْفَحٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَعْجَبُونَ مِنْ غَيْرَةِ سَعْدٍ أَنَا أَغَيْرُ مِنْ سَعْدٍ وَاللَّهُ أَغَيْرُ مِنِّي وَلِذَلِكَ حَرَّمَ الْفَوَاحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَلَا شَخْصَ أَغَيْرُ مِنْ اللَّهِ وَلَا أَحَبُّ إِلَيْهِ مِنْ الْمَعَاذِرِ وَلِذَلِكَ بَعَثَ النَّبِيِّينَ مُبَشِّرِينَ وَمُنْذِرِينَ وَلَا شَخْصَ أَحَبُّ إِلَيْهِ الْمَدْحُ مِنْ اللَّهِ وَلِذَلِكَ وَعَدَ الْجَنَّةَ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami ['Ubaidullah bin 'Amr] dari [Abdul Malik bin 'Umair] dari [Warrad] mantan budak Al Mughirah, dari [Al Mughirah] ia berkata; telah sampai kepada Rasulullah shallallahu 'alaihi wasallam bahwa Sa'd bin 'Ubadah pernah berkata; \"Seandainya aku mendapatkan bersamanya seorang laki-laki, niscaya aku penggal kepala wanita itu dengan pedang, tidak dengan sisi tumpul melainkan dengan sisi yang tajam.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian heran dengan kecemburuan Sa'd? Aku lebih cemburu daripada Sa'd, dan Allah lebih cemburu daripada diriku, oleh karena itu Allah mangharamkan perbuatan keji yang nampak maupun yang tersembunyi, dan tidak ada yang lebih besar cemburunya daripada Allah, dan tidak ada yang lebih Allah cintai daripada penyampaian alas an, oleh karena itu Allah mengutus para nabi yang memberikan kabar gembira dan peringatan, dan tidak ada yang paling senang kepada pujian daripada Allah, oleh karena itu Allah menjanjikan Surga.\""},"1776":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ أَخْبَرَنَا قَتَادَةُ عَنْ زُرَارَةَ بْنِ أَوْفَى الْعَامِرِيِّ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا بَاتَتْ الْمَرْأَةُ هَاجِرَةً لِفِرَاشِ زَوْجِهَا لَعَنَتْهَا الْمَلَائِكَةُ حَتَّى تَرْجِعَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] telah mengabarkan kepada kami [Qatadah] dari [Zurarah bin Aufa Al 'Amiri] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila seorang isteri enggan bermalam dengan meninggalkan kasur suaminya, maka Malaikat melaknatnya hingga ia kembali.\""},"1777":{"ar":" حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ أَنَّ عُوَيْمِرًا الْعَجْلَانِيَّ قَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَيَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَنْزَلَ اللَّهُ فِيكَ وَفِي صَاحِبَتِكَ فَاذْهَبْ فَأْتِ بِهَا قَالَ سَهْلٌ فَتَلَاعَنَا وَأَنَا مَعَ النَّاسِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغَا مِنْ تَلَاعُنِهِمَا قَالَ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَطَلَّقَهَا ثَلَاثًا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ابْنُ شِهَابٍ وَكَانَتْ تِلْكَ بَعْدُ سُنَّةَ الْمُتَلَاعِنَيْنِ حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ الْأَوْزَاعِيِّ عَنْ ابْنِ شِهَابٍ عَنْ سَهْلِ بْنِ سَعْدٍ أَنَّ عُوَيْمِرًا أَتَى عَاصِمَ بْنَ عَدِيٍّ وَكَانَ سَيِّدَ بَنِي عَجْلَانَ فَذَكَرَ مِثْلَهُ وَلَمْ يَذْكُرْ طَلَّقَهَا ثَلَاثًا","id":"Telah menceritakan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Sahl bin Sa'd] bahwa 'Uwaimir Al 'Ajlani berkata; \"Wahai Rasulullah, bagaimana pendapatmu mengenai seorang suami mendapati laki-laki lain tengah bersama isterinya, apakah suaminya membunuh laki-laki itu hingga orang-orang membunuh dirinya atau bagaimana ia berbuat?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah telah menurunkan wahyu mengenaimu dan mengenai isterimu, pergilah dan bawalah dia.\" Sahl berkata; \"Kemudian mereka berdua saling melaknat, sementara aku bersama orang-orang di sisi Rasulullah shallallahu 'alaihi wasallam. Tatkala mereka selesai saling melaknat, 'Uwaimir berkata; aku berdusta terhadapnya wahai Rasulullah, apabila aku mempertahankannya, kemudian ia mencerainya tiga kali sebelum Rasulullah shallallahu 'alaihi wasallam memerintahkannya.\" Ibnu Syihab berkata; \"Setelah itu, perkara tersebut menjadi sunnah orang yang saling melaknat (melakukan li'an).\" Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Al Auza'i] dari [Ibnu Syihab] dari [Sahl bin Sa'd] bahwa 'Uwaimir datang kepada 'Ashim bin 'Adi dan ia adalah pemimpin Bani 'Ajlan,..\" lalu Sahl menyebutkan hadits seperti di atas, namun tidak menyebutkan; \"'Uwaimir mencerainya tiga kali.\""},"1778":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُ سُئِلْتُ عَنْ الْمُتَلَاعِنَيْنِ فِي إِمَارَةِ مُصْعَبِ بْنِ الزُّبَيْرِ أَيُفَرَّقُ بَيْنَهُمَا فَمَا دَرَيْتُ مَا أَقُولُ قَالَ فَقُمْتُ حَتَّى أَتَيْتُ مَنْزِلَ عَبْدِ اللَّهِ بْنِ عُمَرَ فَقُلْتُ لِلْغُلَامِ اسْتَأْذِنْ لِي عَلَيْهِ فَقَالَ إِنَّهُ قَائِلٌ لَا تَسْتَطِيعُ أَنْ تَدْخُلَ عَلَيْهِ قَالَ فَسَمِعَ ابْنُ عُمَرَ صَوْتِي فَقَالَ ابْنُ جُبَيْرٍ فَقُلْتُ نَعَمْ فَقَالَ ادْخُلْ فَمَا جَاءَ بِكَ هَذِهِ السَّاعَةَ إِلَّا حَاجَةٌ قَالَ فَدَخَلْتُ عَلَيْهِ فَوَجَدْتُهُ وَهُوَ مُفْتَرِشٌ بَرْذَعَةَ رَحْلِهِ مُتَوَسِّدٌ مِرْفَقَةً أَوْ قَالَ نُمْرُقَةً شَكَّ عَبْدُ اللَّهِ حَشْوُهَا لِيفٌ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ الْمُتَلَاعِنَانِ أَيُفَرَّقُ بَيْنَهُمَا قَالَ سُبْحَانَ اللَّهِ نَعَمْ إِنَّ أَوَّلَ مَنْ سَأَلَ عَنْ ذَلِكَ فُلَانٌ فَقَالَ يَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْكَ أَرَأَيْتَ لَوْ أَنَّ أَحَدَنَا رَأَى امْرَأَتَهُ عَلَى فَاحِشَةٍ كَيْفَ يَصْنَعُ إِنْ سَكَتَ سَكَتَ عَلَى أَمْرٍ عَظِيمٍ وَإِنْ تَكَلَّمَ فَمِثْلُ ذَلِكَ قَالَ فَسَكَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمْ يُجِبْهُ فَقَامَ لِحَاجَتِهِ فَلَمَّا كَانَ بَعْدَ ذَلِكَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ الَّذِي سَأَلْتُكَ عَنْهُ قَدْ ابْتُلِيتُ بِهِ قَالَ فَأَنْزَلَ اللَّهُ تَعَالَى هَؤُلَاءِ الْآيَاتِ الَّتِي فِي سُورَةِ النُّورِ { وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ } حَتَّى خَتَمَ هَؤُلَاءِ الْآيَاتِ قَالَ فَدَعَا الرَّجُلَ فَتَلَاهُنَّ عَلَيْهِ وَذَكَّرَهُ بِاللَّهِ وَأَخْبَرَهُ أَنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ فَقَالَ مَا كَذَبْتُ عَلَيْهَا ثُمَّ دَعَا الْمَرَأَةَ فَوَعَظَهَا وَذَكَّرَهَا وَأَخْبَرَهَا أَنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ فَقَالَتْ وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنَّهُ لَكَاذِبٌ فَدَعَا الرَّجُلَ فَشَهِدَ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الصَّادِقِينَ { وَالْخَامِسَةُ أَنَّ لَعْنَةَ اللَّهِ عَلَيْهِ إِنْ كَانَ مِنْ الْكَاذِبِينَ } ثُمَّ أُتِيَ بِالْمَرْأَةِ فَشَهِدَتْ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الْكَاذِبِينَ { وَالْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ } ثُمَّ فَرَّقَ بَيْنَهُمَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Abdul Malik bin Sulaiman] ia berkata; aku mendengar [Sa'id bin Jubair] berkata; aku ditanya mengenai dua orang yang saling melakukan li'an pada masa kepemimpinan Mush'ab bin Az Zubair, apakah keduanya dipisahkan?\" Aku tidak tahu apa yang akan aku katakan. Kemudian aku bangkit hingga datang ke rumah [Abdullah bin Umar], aku katakan kepada seorang budak; \"Mintakan aku izin untuk menemuinya! \" Budak itu menjawab; \"Sesungguhnya ia berkata; \"Engkau tidak dapat menemuinya.\" Ketika Ibnu Umar mendengar suaraku, ia berkata; \"Apakah engkau Ibnu Jubair?\" Aku menjawab; \"Ya, benar.\" Ibnu Umar berkata; \"Masuklah, tidaklah engkau datang pada saat-saat demikian ini kecuali ada suatu keperluan.\" Kemudian aku menemuinya dan mendapatinya tengah menghamparkan alas pelana kendaraannya bersandarkan bantal -Abdullah ragu dengan redaksi haditsnya- yang berisi serabut. Kemudian aku berkata; \"Wahai Abu Abdurrahman, apakah dua orang yang saling melakukan li'an dipisahkan antara mereka?\" Ibnu Umar berkata; \"Subhanallah, ya. Sesungguhnya orang pertama yang bertanya mengenai hal itu adalah Fulan, lalu ia berkata; \"Wahai Rasulullah, semoga Allah melimpahkan shalawat dan salam kepadamu, bagaimana pendapat anda apabila salah seorang diantara kami melihat isterinya melakukan perbuatan keji, bagaimana ia harus perbuat? Apabila ia diam maka ia diam terhadap perkara yang besar, namun apabila ia berbicara, maka seperti itu juga.\" Rasulullah shallallahu 'alaihi wasallam diam dan tidak menjawab, lalu beliau bangkit untuk suatu keperluan. Sesaat kemudian orang itu datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, sesungguhnya yang aku tanyakan kepadamu telah menimpa diriku.\" Ibnu Umar melanjutkan; \"Kemudian Allah Ta'ala menurunkan ayat yang ada dalam surat An Nur: Dan orang-orang yang menuduh isterinya (berzina) \" QS An Nur; 6 hingga selesai. Ibnu Umar melanjutkan; Setelah itu beliau memanggil laki-laki tersebut dan membacakan ayat tersebut kepadanya, beliau mengingatkannya kepada Allah dan mengabarkan kepadanya bahwa adzab dunia lebih ringan daripada adzab akherat. Lalu ia berkata; \"Aku tidak berdusta kepadanya.\" Kemudian beliau memanggil wanita tersebut (isterinya), menasehatinya serta mengingatkannya dan mengabarkan kepadanya bahwa adzab dunia lebih ringan daripada adzab akherat.\" Wanita tersebut (isterinya) berkata; \"Demi Dzat yang mengutusmu dengan kebenaran, sesungguhnya ia telah berdusta.\" Beliau akhirnya memanggil laki-laki tersebut, lalu ia bersumpah empat kali dengan nama Allah bahwa ia merupakan diantara orang-orang yang benar, dan yang kelima bahwa laknat Allah akan menimpa kepadanya apabila merupakan diantara orang-orang yang berdusta, kemudian wanita tersebut didatangkan lalu ia bersumpah empat kali dengan nama Allah, bahwa ia termasuk diantara orang-orang yang dusta, dan kelima kalinya bahwa kemurkaan Allah akan menimpa kepadanya apabila ia merupakan diantara orang-orang yang benar. Kemudian beliau memisahkan mereka berdua.\""},"1779":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنِي مَالِكٌ قَالَ سَمِعْتُ نَافِعًا عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ قَالَ فَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْمُتَلَاعِنَيْنِ وَأَلْحَقَ الْوَلَدَ بِأُمِّهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepadaku [Malik], ia berkata; aku mendengar [Nafi'] dari [Abdullah bin Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memisahkan antara dua orang yang melakukan li'an, dan menisbatkan anak kepada ibunya.\""},"1780":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا الْحَسَنُ بْنُ صَالِحٍ عَنْ عَبْدِ اللَّهِ بْنِ مُحَمَّدِ بْنِ عَقِيلٍ قَالَ سَمِعْتُ جَابِرًا يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا عَبْدٍ تَزَوَّجَ بِغَيْرِ إِذْنِ مَوَالِيهِ أَوْ أَهْلِهِ فَهُوَ عَاهِرٌ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Al Hasan bin Shalih] dari [Abdullah bin Muhammad bin 'Uqail], ia berkata; aku mendengar [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun seorang budak yang menikah tanpa seizing tuannya atau keluarganya maka ia adalah pezina.\""},"1781":{"ar":" حَدَّثَنَا مَالِكُ بْنُ إِسْمَعِيلَ حَدَّثَنَا مِنْدَلُ بْنُ عَلِيٍّ عَنْ ابْنِ جُرَيْجٍ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا عَبْدٍ تَزَوَّجَ بِغَيْرِ إِذْنِ مَوَالِيهِ فَهُوَ زَانٍ","id":"Telah menceritakan kepada kami [Malik bin Isma'il] telah menceritakan kepada kami [Mindal bin Ali] dari [Ibnu Juraij] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Siapapun seorang budak yang menikah tanpa seizing tuannya, maka ia adalah pezina.\""},"1782":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ يَرْفَعُهُ قَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] dari [Ibnu Al Musayyab] dari [Abu Hurairah] dan -ia memarfu'kannya- ia berkata; \"Anak adalah untuk pemilik ranjang dan tidak ada hak bagi pelaku zina (yang menzinahi ibunya -pent).\""},"1783":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِلْفِرَاشِ","id":"Telah menceritakan kepada kami [Abdullah bin Maslamah] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak adalah untuk pemilik ranjang.\""},"1784":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ نَافِعٍ حَدَّثَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ كَانَ عُتْبَةُ بْنُ أَبِي وَقَّاصٍ عَهِدَ إِلَى أَخِيهِ سَعْدِ بْنِ أَبِي وَقَّاصٍ أَنْ يَقْبِضَ إِلَيْهِ ابْنَ وَلِيدَةِ زَمْعَةَ فَقَالَ عُتْبَةُ إِنَّهُ ابْنِي فَلَمَّا قَدِمَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمَنَ الْفَتْحِ أَخَذَ سَعْدُ بْنُ أَبِي وَقَّاصٍ ابْنَ وَلِيدَةِ زَمْعَةَ فَإِذَا هُوَ أَشْبَهُ النَّاسِ بِعُتْبَةَ بْنِ أَبِي وَقَّاصٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ لَكَ يَا عَبْدُ بْنَ زَمْعَةَ مِنْ أَجْلِ أَنَّهُ وُلِدَ عَلَى فِرَاشِ أَبِيهِ وَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْتَجِبِي مِنْهُ يَا سَوْدَةُ بِنْتَ زَمْعَةَ مِمَّا رَأَى مِنْ شَبَهِهِ بِعُتْبَةَ بْنِ أَبِي وَقَّاصٍ وَسَوْدَةُ بِنْتُ زَمْعَةَ","id":"Telah menceritakan kepada kami [Al Hakam bin Nafi'] telah menceritakan kepada kami [Syu'aib] dari [Az Zuhri] telah mengabarkan kepadaku ['Urwah] dari ['Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; 'Utbah bin Abu Waqqash telah berwasiat kepada Sa'd bin Abu Waqqash agar mengambilkan anak sahaya wanita Zam'ah. 'Utbah berkata; \"Sesungguhnya ia adalah anakku.\" Tatkala Nabi shallallahu 'alaihi wasallam dating, yaitu katika penaklukan Makkah, Sa'd bin Abu Waqqash mengambil anak sahaya wanita Zam'ah. Ternyata anaknya mirip dengan 'Utbah bin Abu Waqqash. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Ia milikmu wahai 'Abdu bin Zam'ah, karena ia terlahir di atas kasur ayahmu.\" Nabi shallallahu 'alaihi wasallam berkata: \"Berhijablah darinya wahai Saudah binti Zam'ah.\" Karena beliau melihat kemiripannya dengan 'Utbah bin Abu Waqqash dan Saudah binti Zam'ah.\""},"1785":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يَزِيدُ بْنُ عَبْدِ اللَّهِ عَنْ عَبْدِ اللَّهِ بْنِ يُونُسَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ أَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ أُنْزِلَتْ آيَةُ الْمُلَاعَنَةِ أَيُّمَا امْرَأَةٍ أَدْخَلَتْ عَلَى قَوْمٍ نَسَبًا لَيْسَ مِنْهُمْ فَلَيْسَتْ مِنْ اللَّهِ فِي شَيْءٍ وَلَمْ يُدْخِلْهَا اللَّهُ جَنَّتَهُ وَأَيُّمَا رَجُلٍ جَحَدَ وَلَدَهُ وَهُوَ يَنْظُرُ إِلَيْهِ احْتَجَبَ اللَّهُ مِنْهُ وَفَضَحَهُ عَلَى رُءُوسِ الْأَوَّلِينَ وَالْآخِرِينَ قَالَ عَبْدُ اللَّهِ قَالَ مُحَمَّدُ بْنُ كَعْبٍ الْقُرَظِيُّ وَسَعِيدٌ يُحَدِّثَهُ هَذَا وَقَدْ بَلَغَنِي هَذَا الْحَدِيثُ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yazid bin Abdullah] dari [Abdullah bin Yunus] dari [Sa'id bin Abu Sa'id] dari [Abu Hurairah] bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika turun ayat li'an: \"Siapapun seorang wanita yang menasabkan (anaknya) kepada suatu kaum, sementara (anaknya) bukan dari mereka, maka ia bukan termasuk golongan Allah sama sekali, dan Allah tidak akan memasukkannya ke dalam Surga. Dan siapapun laki-laki yang mengingkari anaknya padahal ia tahu bahwa itu adalah anaknya, maka Allah akan menutup diri darinya, dan Allah akan mempermalukannya dihadapan para manusia yang pertama dan yang terakhir.\" [Abdullah] berkata; [Muhammad bin Ka'b Al Qurazhi] berkata; Sa'id telah menceritkan hal ini kepadanya. Hadits ini juga telah sampai kepadaku dari Rasulullah shallallahu 'alaihi wasallam."},"1786":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ الرَّقِّيُّ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ يَزِيدَ بْنِ الْبَرَاءِ عَنْ أَبِيهِ قَالَ لَقِيتُ عَمِّي وَمَعَهُ رَايَةٌ فَقُلْتُ أَيْنَ تُرِيدُ فَقَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ نَكَحَ امْرَأَةَ أَبِيهِ فَأَمَرَنِي أَنْ أَضْرِبَ عُنُقَهُ وَآخُذَ مَالَهُ","id":"Telah menceritakan kepada kami [Abdullah bin Ja'far Ar Raqqi] telah menceritakan kepada kami ['Ubaidullah bin 'Amr] dari [Zaid] dari ['Adi bin Tsabit] dari [Yazid bin Al Bara`] dari [Ayahnya] ia berkata; Aku berjumpa dengan [pamanku], katika itu ia membawa bendera. Lalu aku berkata; \"Engkau hendak kemana?\" pamanku berkata; \"Aku telah diutus Rasulullah shallallahu 'alaihi wasallam untuk datang kepada seorang laki-laki yang menikahi isteri ayahnya, dan beliau memerintahkanku agar memenggal kepalanya dan mengambil hartanya.\""},"1787":{"ar":" حَدَّثَنِي مُعَلَّى بْنُ أَسَدٍ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ مُحَمَّدِ بْنِ أَبِي مُوسَى عَنْ رَجُلٍ مِنْ الْأَنْصَارِ يُسَمَّى زِيَادًا قَالَ قُلْتُ لِأُبَيِّ بْنِ كَعْبٍ أَرَأَيْتَ لَوْ أَنَّ أَزْوَاجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتْنَ كَانَ يَحِلُّ لَهُ أَنْ يَتَزَوَّجَ قَالَ نَعَمْ إِنَّمَا أَحَلَّ اللَّهُ لَهُ ضَرْبًا مِنْ النِّسَاءِ وَوَصَفَ لَهُ صِفَةً فَقَالَ { لَا يَحِلُّ لَكَ النِّسَاءُ مِنْ بَعْدُ } مِنْ بَعْدِ هَذِهِ الصِّفَةِ","id":"Telah menceritakan kepadaku [Mu'alla bin Asad] ia berkata; telah menceritakan kepada kami [Wuhaib] dari [Daud bin Abu Hindun] dari [Muhammad bin Abu Musa] dari seorang laki-laki dari kalangan Anshar yang bernama [Ziyad] ia berkata; aku berkata kepada [Ubay bin Ka'b]; \"Bagaimana pendapatmu seandainya para isteri Nabi shallallahu 'alaihi wasallam meninggal, apakah boleh beliau menikah lagi?\" Ubay menjawab; \"Ya, sesungguhnya Allah menghalalkan baginya menikahi para wanita.\" Ubay menjelaskan kepadanya lalu berkata; Tidak halal bagimu mengawini perempuan-perempuan sesudah itu. QS Al Ahzab; 52. yaitu setelah ada keterangan ini. "},"1788":{"ar":" أَخْبَرَنَا الْمُعَلَّى حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ قَالَتْ مَا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحَلَّ اللَّهُ لَهُ أَنْ يَتَزَوَّجَ مِنْ النِّسَاءِ مَا شَاءَ","id":"Telah mengabarkan kepada kami [Al Mu'alla] dari [Wuhaib] dari [Ibnu Juraij] dari ['Atha`] dari ['Ubaid bin 'Umair] dari ['Aisyah] ia berkata; \"Tidaklah Rasulullah shallallahu 'alaihi wasallam meninggal hingga Allah menghalalkan baginya untuk menikahi wanita yang beliau kehendaki.\""},"1789":{"ar":" حَدَّثَنَا مُسَدَّدٌ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ شُعَيْبِ بْنِ الْحَبْحَابِ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَجَعَلَ عِتْقَهَا صَدَاقَهَا","id":"Telah menceritakan kepada kami [Musaddad] telah menceritakan kepada kami [Hammad bin Zaid] dari [Syu'aib bin Al Habhab] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam memerdekakan Shafiyah dan menjadikan pembebasannya sebagai maharnya.\""},"1790":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَتَزَوَّجَهَا وَجَعَلَ عِتْقَهَا صَدَاقَهَا","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam memerdekakan Shafiyah dan menjadikan pembebasannya sebagai maharnya.\""},"1791":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ حَدَّثَنَا هُشَيْمٌ عَنْ صَالِحِ بْنِ صَالِحِ بْنِ حَيٍّ الْهَمْدَانِيِّ قَالَ كُنْتُ عِنْدَ الشَّعْبِيِّ فَأَتَاهُ رَجُلٌ مِنْ أَهْلِ خُرَاسَانَ فَقَالَ يَا أَبَا عَمْرٍو إِنَّ مَنْ قِبَلَنَا مِنْ أَهْلِ خُرَاسَانَ يَقُولُونَ فِي الرَّجُلِ إِذَا أَعْتَقَ أَمَتَهُ ثُمَّ تَزَوَّجَهَا فَهُوَ كَالرَّاكِبِ بَدَنَتَهُ فَقَالَ الشَّعْبِيُّ حَدَّثَنِي أَبُو بُرْدَةَ بْنُ أَبِي مُوسَى عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ يُؤْتَوْنَ أَجْرَهُمْ مَرَّتَيْنِ رَجُلٌ مِنْ أَهْلِ الْكِتَابِ آمَنَ بِنَبِيِّهِ ثُمَّ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَآمَنَ بِهِ وَاتَّبَعَهُ وَعَبْدٌ مَمْلُوكٌ أَدَّى حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِ فَلَهُ أَجْرَانِ وَرَجُلٌ كَانَتْ لَهُ أَمَةٌ فَغَذَّاهَا فَأَحْسَنَ غِذَاءَهَا وَأَدَّبَهَا فَأَحْسَنَ تَأْدِيبَهَا فَأَعْتَقَهَا وَتَزَوَّجَهَا فَلَهُ أَجْرَانِ ثُمَّ قَالَ لِلرَّجُلِ خُذْ هَذَا الْحَدِيثَ بِغَيْرِ شَيْءٍ فَقَدْ كَانَ يُرْحَلُ فِيمَا دُونَ هَذَا إِلَى الْمَدِينَةِ قَالَ هُشَيْمٌ أَفَادُونِي بِالْبَصْرَةِ فَأَتَيْتُهُ فَسَأَلْتُهُ عَنْهُ أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ عَنْ شُعْبَةَ عَنْ صَالِحِ بْنِ حَيٍّ عَنْ الشَّعْبِيِّ عَنْ أَبِي بُرْدَةَ عَنْ أَبِيهِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَ هَذَا الْحَدِيثِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah menceritakan kepada kami [Husyaim] dari [Shalih bin Shalih bin Hay Al Hamdani] ia berkata; aku pernah bersama [Asy Sya'bi], kemudian seorang laki-laki dari penduduk Khurasan datang kepadanya dan berkata; \"Wahai Abu 'Amru, sesungguhnya orang-orang dibelakang kami dari kalangan penduduk Khurasan berkata mengenai seorang laki-laki yang memerdekakan budak wanitanya kemudian menikahinya seperti orang yang menggauli untanya.\" Kemudian [Asy Sya'bi] berkata; telah menceritakan kepadaku [Abu Burdah bin Musa] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga orang yang diberi pahala dua kali, yaitu; laki-laki dari ahli kitab yang beriman kepada nabinya kemudian menjumpai Nabi shallallahu 'alaihi wasallam dan beriman kepadanya serta mengikutinya, seorang budak yang menunaikan hak Allah dan hak tuannya, maka ia mendapatkan dua pahala, serta seorang laki-laki yang memiliki budak wanita kemudian memberinya makan dengan baik dan mendidiknya dengan baik, kemudian membebaskannya serta menikahinya, maka baginya dua pahala.\" Kemudian ia berkata kepada orang tersebut; \"Ambillah hadits ini tanpa imbalan apapun. Sungguh ia telah melakukan perjalanan kurang dari jarak ini menuju Madinah.\" Husyaim berkata; Mereka telah memberikan faedah kepadaku di Bashrah, kemudian aku datang kepadanya dan bertanya mengenai hal itu. Telah mengabarkan kepada kami [Sahl bin Hammad] dari [Syu'bah] dari [Shalih Hay] dari [Asy Sya'bi] dari [Abu Burdah] dari [Ayahnya] dari Nabi shallallahu 'alaihi wasallam seperti hadits ini."},"1792":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ فِي رَجُلٍ تَزَوَّجَ امْرَأَةً وَلَمْ يَكُنْ فَرَضَ لَهَا شَيْئًا وَلَمْ يَدْخُلْ بِهَا وَمَاتَ عَنْهَا قَالَ فِيهَا لَهَا صَدَاقُ نِسَائِهَا وَعَلَيْهَا الْعِدَّةُ وَلَهَا الْمِيرَاثُ قَالَ مَعْقِلٌ الْأَشْجَعِيُّ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بِرْوَعَ بِنْتِ وَاشِقٍ امْرَأَةٍ مِنْ بَنِي رُوَاسٍ بِمِثْلِ مَا قَضَيْتَ قَالَ فَفَرِحَ بِذَلِكَ قَالَ مُحَمَّدٌ وَسُفْيَانُ نَأْخُذُ بِهَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] mengenai seorang laki-laki yang menikahi seorang wanita dan ia belum menetapkan sesuatupun sebagai maharnya, serta belum menggaulinya, ternyata suaminya meninggal. Abdullah berkata; Dalam masalah itu, wanita tersebut mendapatkan mahar layaknya wanita lain, dan ia juga harus melakukan 'iddah dan mendapatkan warisan.\" [Ma'qil Al Asyja'i] berkata; Rasulullah shallallahu 'alaihi wasallam telah menetapkan kepada Barwa' binti Wasyiq yaitu seorang wanita dari Bani Ruwas, seperti yang telah engkau putuskan. 'Alqamah berkata; kemudian ia senang dengan hal itu. Muhammad dan Sufyan berkata; kami mengambil pendapat ini."},"1793":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ أَنَّهَا كَانَتْ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَيْتِ حَفْصَةَ فَسَمِعَتْ صَوْتَ إِنْسَانٍ قَالَتْ قُلْتُ يَا رَسُولَ اللَّهِ سَمِعْتُ صَوْتَ إِنْسَانٍ فِي بَيْتِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرَاهُ فُلَانًا لِعَمِّ حَفْصَةَ مِنْ الرَّضَاعَةِ قَالَتْ عَائِشَةُ يَا رَسُولَ اللَّهِ وَلَوْ كَانَ فُلَانٌ حَيًّا لِعَمِّهَا مِنْ الرَّضَاعَةِ دَخَلَ عَلَيَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ الْوِلَادَةِ","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami [Rauh] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakr bin 'Amr bin Hazm] dari ['Amrah] dari ['Aisyah] bahwa dirinya bersama Nabi shallallahu 'alaihi wasallam di rumah Hafshah, kemudian ia mendengar suara orang. Aisyah berkata; lalu aku berkata; \"Wahai Rasulullah, au mendengar suara seseorang di dalam rumahmu.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Aku lira ia adalah Fulan, paman Hafshah sepersusuan.\" 'Aisyah berkata; \"Wahai Rasulullah, apabila Fulan masih hidup (ia menyebutkan paman sepersusuannya), bolehkah ia menemuiku?\" Beliau bersabda: \"Ya, sesuatu yang haram karena faktor persusuan adalah haram pula karena kelahiran.\""},"1794":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ قَالَ أَخْبَرَتْنِي عَائِشَةُ أَنَّ عَمَّهَا أَخَا أَبِي الْقُعَيْسِ جَاءَ يَسْتَأْذِنُ عَلَيْهَا بَعْدَمَا ضُرِبَ الْحِجَابُ فَأَبَتْ أَنْ تَأْذَنَ لَهُ حَتَّى يَأْتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَسْتَأْذِنَهُ فَلَمَّا جَاءَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَكَرَتْ ذَلِكَ لَهُ فَقَالَتْ جَاءَ عَمِّي أَخُو أَبِي الْقُعَيْسِ فَرَدَدْتُهُ حَتَّى أَسْتَأْذِنَكَ قَالَ أَوَ لَيْسَ بِعَمِّكِ قَالَتْ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ فَقَالَ إِنَّهُ عَمُّكِ فَلْيَلِجْ عَلَيْكِ قَالَ وَكَانَتْ عَائِشَةُ تَقُولُ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ الْوِلَادَةِ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] ia berkata; telah mengabarkan kepadaku ['Aisyah] bahwa pamannya yaitu saudara Abu Al Qu'ais datang meminta izin untuk menemuinya setelah turunnya ayat hijab, kemudian 'Aisyah menolak untuk mengizinkannya hingga Rasulullah shallallahu 'alaihi wasallam datang dan meminta izin kepada beliau, setelah Nabi shallallahu 'alaihi wasallam datang, 'Aisyah menyebutkan hal itu kepada beliau dan berkata; \"Pamanku yaitu saudara Abu Al Qu'ais datang, namun aku menolaknya hingga ia meminta izin kepada anda.\" Beliau bersabda: \"Bukankah ia pamanmu?\" Aisyah menjawab; \"Sesungguhnya yang menyusuiku adalah seorang wanita dan tidak disusui orang laki-laki.\" Beliau bersabda: \"Sesungguhnya ia adalah pamanmu, maka ia boleh masuk menemuimu.\" 'Urwah berkata; 'Aisyah melanjutkan; \"Sesungguhnya persusuan itu mengharamkan apa yang diharamkan peranakan.\""},"1795":{"ar":" أَخْبَرَنَا صَدَقَةُ بْنُ الْفَضْلِ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ مَالِكٍ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَحْرُمُ مِنْ الرَّضَاعَةِ مَا يَحْرُمُ مِنْ الْوِلَادَةِ قَالَ مَالِكٌ وَحَدَّثَنِي عَبْدُ اللَّهِ بْنُ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Shadaqah bin Al Fadhl] telah menceritakan kepada kami [Yahya bin Sa'id] dari [Malik] telah menceritakan kepadaku [Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari ['Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Persusuan itu mengharamkan apa yang diharamkan peranakan.\" Dan telah menceritakan kepadaku [Abdullah bin Abu Bakr] dari ['Amrah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam seperti itu."},"1796":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحَرِّمُ الْمَصَّةُ وَالْمَصَّتَانِ","id":"Telah menceritakan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Satu hisapan dan dua hisapan tidaklah menyebabkannya mahram.\""},"1797":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ عَنْ أُمِّ الْفَضْلِ أَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي قَدْ تَزَوَّجْتُ امْرَأَةً وَعِنْدِي أُخْرَى فَزَعَمَتْ الْأُولَى أَنَّهَا أَرْضَعَتْ الْحُدْثَى فَقَالَ لَا تُحَرِّمُ الْإِمْلَاجَةُ وَلَا الْإِمْلَاجَتَانِ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Al Khalil] dari [Abdullah bin Al Harits] dari [Ummu Al Fadhl] bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, sesungguhnya aku telah menikahi seorang wanita, dan aku memiliki isteri yang lain, kemudian isteri yang pertama mengaku telah menyusui isteri yang baru.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu atau dua hisapan tidaklah menyebabkannya mahram.\""},"1798":{"ar":" أَخْبَرَنَا إِسْحَقُ أَخْبَرَنَا رَوْحٌ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْ نَزَلَ الْقُرْآنُ بِعَشْرِ رَضَعَاتٍ مَعْلُومَاتٍ يُحَرِّمْنَ ثُمَّ نُسِخْنَ بِخَمْسٍ مَعْلُومَاتٍ فَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُنَّ مِمَّا يُقْرَأُ مِنْ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Ishaq] telah mengabarkan kepada kami [Rauh] telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakr] dari ['Amrah] dari ['Aisyah] ia berkata; \"Al Qur'an turun mengenai susuan yang dapat menyebabkan menjadi muhrim ialah sepuluh kali penyusuan, kemudian hal itu dinasakh (dihapus) dengan lima kali penyusuan saja. Lalu Rasulullah shallallahu 'alaihi wasallam wafat, sementara ayat-ayat Al Qur'an masih tetap di baca seperti itu.\""},"1799":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدَةُ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ حَجَّاجِ بْنِ حَجَّاجٍ الْأَسْلَمِيِّ عَنْ أَبِيهِ أَنَّهُ قَالَ يَا رَسُولَ اللَّهِ مَا يُذْهِبُ عَنِّي مَذَمَّةَ الرَّضَاعِ قَالَ الْغُرَّةُ الْعَبْدُ أَوْ الْأَمَةُ","id":"Telah menceritakan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami ['Abdah] dari [Hisyam] dari [Ayahnya] dari [Hajjaj bin Hajjaj Al Aslami] dari [Ayahnya] bahwa ia berkata; \"Wahai Rasulullah, apakah yang dapat menghilangkan dariku hak yang disebabkan karena penyusuan?\" Beliau menjawab: \"Denda yaitu budak laki-laki atau perempuan.\""},"1800":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُقْبَةُ بْنُ الْحَارِثِ ثُمَّ قَالَ لَمْ يُحَدِّثْنِيهِ وَلَكِنْ سَمِعْتُهُ يُحَدِّثُ الْقَوْمَ قَالَ تَزَوَّجْتُ بِنْتَ أَبِي إِهَابٍ فَجَاءَتْ أَمَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي أَرْضَعْتُكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَأَعْرَضَ عَنِّي قَالَ أَبُو عَاصِمٍ قَالَ فِي الثَّالِثَةِ أَوْ الرَّابِعَةِ قَالَ كَيْفَ وَقَدْ قِيلَ وَنَهَاهُ عَنْهَا قَالَ أَبُو عَاصِمٍ وَقَالَ عُمَرُ بْنُ سَعِيدِ بْنِ أَبِي حُسَيْنٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ فَكَيْفَ وَقَدْ قِيلَ وَلَمْ يَقُلْ نَهَاهُ عَنْهَا قَالَ أَبُو مُحَمَّد كَذَا عِنْدَنَا","id":"Telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Abu Mulaikah] ia berkata; telah menceritakan kepadaku ['Uqbah bin Al Harits], -Ibnu Abu Mulaikah berkata; 'Uqbah tidak menceritakannya kepadaku, akan tetapi aku mendengar ia menceritakan kepada beberapa orang- ia berkata; aku menikahi putrid Abu Ihab, kemudian seorang budak wanita hitam datang dan berkata; \"Sesungguhnya aku telah menyusui kalian berdua.\" Lalu aku datang kepada Nabi shallallahu 'alaihi wasallam dan menyebutkan hal itu kepada beliau. Maka beliau berpaling dariku.\" Abu 'Ashim berkata; \"Ketiga atau keempat kalinya beliau bersabda: \"Bagaimana lagi, padahal itu telah dikatakan! \" Lalu beliau melarangnya (menikahi) wanita tersebut.\" [Abu 'Ashim] berkata; [Umar bin Sa'id bin Abu Husain] berkata dari [Ibnu Abu Mulaikah]; \"Bagaimana lagi, padahal itu telah dikatakan! \" Dan Umar bin Sa'id tidak menyebutkan; \"Kemudian beliau melarang (menikahi) wanita tersebut).\" Abu Muhammad berkata; \"Demikianlah yang ada pada kami.\""},"1801":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ أَشْعَثَ بْنِ سُلَيْمٍ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيْهَا وَعِنْدَهَا رَجُلٌ فَتَغَيَّرَ وَجْهُهُ وَكَأَنَّهُ كَرِهَ ذَلِكَ فَقُلْتُ إِنَّهُ أَخِي مِنْ الرَّضَاعَةِ فَقَالَ انْظُرْنَ مَا إِخْوَانُكُنَّ فَإِنَّمَا الرَّضَاعَةُ مِنْ الْمَجَاعَةِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari [Asy'ats bin Sulaim] dari [Ayahnya] dari [Masruq] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam menemuinya, sementara di sampingnya terdapat seorang laki-laki, maka wajah beliau berubah sepertinya beliau tidak senang dengan hal itu. kemudian aku berkata; \"Sesungguhnya dia saudara sepersusuanlu.\" Beliau bersabda: \"Lihatlah, siapakah saudara-saudara kalian, sesungguhnya penyusuan itu karena lapar.\""},"1802":{"ar":" أَخْبَرَنَا أَبُو الْيَمَانِ الْحَكَمُ بْنُ نَافِعٍ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْ جَاءَتْ سَهْلَةُ بِنْتُ سُهَيْلِ بْنِ عَمْرٍو وَكَانَتْ تَحْتَ أَبِي حُذَيْفَةَ بْنِ عُتْبَةَ بْنِ رَبِيعَةَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ سَالِمًا مَوْلَى أَبِي حُذَيْفَةَ يَدْخُلُ عَلَيْنَا وَأَنَا فُضُلٌ وَإِنَّمَا نَرَاهُ وَلَدًا وَكَانَ أَبُو حُذَيْفَةَ تَبَنَّاهُ كَمَا تَبَنَّى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَأَنْزَلَ اللَّهُ تَعَالَى { ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِنْدَ اللَّهِ } فَأَمَرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ أَنْ تُرْضِعَ سَالِمًا قَالَ أَبُو مُحَمَّد هَذَا لِسَالِمٍ خَاصَّةً","id":"Telah mengabarkan kepada kami [Abu Al Yaman Al Hakam bin Nafi'] telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] ia berkata; [Sahlah binti Suhail bin 'Amr] -ia adalah isteri Abu Hudzaifah bin 'Utbah bin Rabi'ah- datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Sesungguhnya Salim mantan budak Abu Hudzaifah sering menemui kami, sementara aku memakai baju rumah (yang kelihat sebagian tubuhnya -pent), sementara kami mengangkat sebagai anak. Dan Abu Hudzaifah juga mengangkatnya sebagai anak sebagaimana Nabi shallallahu 'alaihi wasallam menganggap Zaid sebagai anak. Kemudian Allah Ta'ala menurunkan ayat: \" Panggilah mereka (anak-anak angkat itu) dengan (memakai) nama bapak-bapak mereka; itulah yang lebih adil pada sisi Allah.\" QS Al Ahzab; 5. Kemudian Nabi shallallahu 'alaihi wasallam memerintahkannya untuk menyusui Salim. Abu Muhammad berkata; \"Ini khusus untuk Salim.\""},"1803":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي قَيْسٍ عَنْ الْهُزَيْلِ عَنْ عَبْدِ اللَّهِ قَالَ لَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُحِلَّ وَالْمُحَلَّلَ لَهُ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Abu Qais] dari [Al Hudzail] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat muhilla dan muhallal lahu.\" "},"1804":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ أَخْبَرَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ هِنْدًا أُمَّ مُعَاوِيَةَ امْرَأَةَ أَبِي سُفْيَانَ أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ أَبَا سُفْيَانَ رَجُلٌ شَحِيحٌ وَإِنَّهُ لَا يُعْطِينِي مَا يَكْفِينِي وَبَنِيَّ إِلَّا مَا أَخَذْتُ مِنْهُ وَهُوَ لَا يَعْلَمُ فَهَلْ عَلَيَّ فِي ذَلِكَ جُنَاحٌ فَقَالَ خُذِي مَا يَكْفِيكِ وَوَلَدَكِ بِالْمَعْرُوفِ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah mengabarkan kepada kami [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] bahwa Hindun ibu Mu'awiyah, isteri Abu Sufyan datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, sesungguhnya Abu Sufyan adalah orang yang pelit, dan ia tidak memberiku apa yang cukup untukku dan anakku kecuali yang aku ambil darinya, sementara ia tidak mengetahui. Apakah dalam hal itu aku mendapatkan dosa?\" Beliau bersabda: \"Ambillah apa yang cukup bagimu dan anakmu dengan cara yang baik.\""},"1805":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُكُمْ خَيْرُكُمْ لِأَهْلِهِ وَإِذَا مَاتَ صَاحِبُكُمْ فَدَعُوهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik kalian adalah orang yang baik kepada keluarganya, apabila sahabat kalian meninggal, maka biarkanlah (jangan mengungkit-ungkit kejelekannya).\""},"1806":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ خَلِيلٍ أَخْبَرَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ تَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِنْتُ سِتِّ سِنِينَ فَقَدِمْنَا الْمَدِينَةَ فَنَزَلْنَا فِي بَنِي الْحَارِثِ بْنِ الْخَزْرَجِ فَوُعِكْتُ فَتَمَرَّقَ رَأْسِي فَأَوْفَى جُمَيْمَةً فَأَتَتْنِي أُمُّ رُومَانَ وَإِنِّي لَفِي أُرْجُوحَةٍ وَمَعِي صَوَاحِبَاتٌ لِي فَصَرَخَتْ بِي فَأَتَيْتُهَا وَمَا أَدْرِي مَا تُرِيدُ فَأَخَذَتْ بِيَدِي حَتَّى أَوْقَفَتْنِي عَلَى بَابِ الدَّارِ وَإِنِّي لَأَنْهَجُ حَتَّى سَكَنَ بَعْضُ نَفَسِي ثُمَّ أَخَذَتْ شَيْئًا مِنْ مَاءٍ فَمَسَحَتْ بِهِ وَجْهِي وَرَأْسِي ثُمَّ أَدْخَلَتْنِي الدَّارَ فَإِذَا نِسْوَةٌ مِنْ الْأَنْصَارِ فِي الْبَيْتِ فَقُلْنَ عَلَى الْخَيْرِ وَالْبَرَكَةِ وَعَلَى خَيْرِ طَائِرٍ فَأَسْلَمَتْنِي إِلَيْهِنَّ فَأَصْلَحْنَ مِنْ شَأْنِي فَلَمْ يَرُعْنِي إِلَّا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضُحًى فَأَسْلَمَتْنِي إِلَيْهِ وَأَنَا يَوْمَئِذٍ بِنْتُ تِسْعِ سِنِينَ","id":"Telah mengabarkan kepada kami [Isma'il bin Khalil] telah mengabarkan kepada kami [Ali bin Mushir] dari [Hisyam] dari [Ayahnya] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku, sementara aku masih berumur enam tahun, kemudian kami datang ke Madinah dan singgah di Bani Al Harits bin Al Khazraj, aku terserang demam hingga menyebabkan rambut kepalaku rontok, lalu Ummu Ruman datang menemiku, katika aku tengah berada dibandulan bersama teman-temanku. Kemudian ia memanggilu dan mendatangiku, aku tidak tahu apa yang dia inginkan. Lalu dia menggandeng tanganku hingga memberhentikanku di depan pintu rumah, sementara diriku masih tersengal-sengal. Setelah aku tenang kembali, Ummu Ruman mengambil sedikit air dan mengusap wajah dan kepalaku. Kemudian ia memasukkanku ke dalam rumah, ternyata di rumah terdapat beberapa orang wanita Anshar. Mereka berkata; \"Semoga dalam keadaan baik dan berkah, dan semoga mendapatkan nasib yang baik.\" Kemudian ia menyerahkanku kepada mereka, lalu mereka membenahi keadaanku dan tidak ada yang membuatkan perhatian kecuali kehadiran Rasulullah shallallahu 'alaihi wasallam pada waktu Dhuha. Kemudian Ummu Ruman menyerahkanku kepada beliau sementara aku masih berumur enam tahun.\""},"1807":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْهُ أَنْ يُرَاجِعَهَا وَيُمْسِكَهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ ثُمَّ تَطْهُرَ ثُمَّ إِنْ شَاءَ أَمْسَكَ وَإِنْ شَاءَ طَلَّقَ قَبْلَ أَنْ يَمَسَّ فَتِلْكَ الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ أَنْ يُطَلَّقَ لَهَا النِّسَاءُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa dia menceraikan isterinya ketika haid. Kemudian Umar memberitahukan hal itu kepada Nabi shallallahu 'alaihi wasallam, beliau berkata: \"Perintahkan supaya dia kembali, dan merujiknya hingga isterinya suci kemudian haid, kemudian suci, setelah itu jika berkehendak, maka dia boleh menahannya dan jika berkehendak, maka dia boleh mencerai sebelum menggaulinya. Itulah 'iddah yang Allah perintahkan agar wanita dicerai karenanya.\""},"1808":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى أَخْبَرَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ سَمِعْتُ سَالِمًا يَذْكُرُ عَنْ ابْنِ عُمَرَ أَنَّ عُمَرَ قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ طَلَّقَ ابْنُ عُمَرَ امْرَأَتَهُ فَقَالَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُطَلِّقْهَا وَهِيَ طَاهِرٌ قَالَ أَبُو مُحَمَّد رَوَاهُ ابْنُ الْمُبَارَكِ وَوَكِيعٌ أَوْ حَامِلٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] telah mengabarkan kepada kami [Sufyan] dari [Muhammad bin Abdurrahman] ia berkata; aku mendengar [Salim] menyebutkankan dari [Ibnu Umar] bahwa [Umar] berkata kepada Nabi shallallahu 'alaihi wasallam ketika Ibnu Umar menceraikan isterinya. Beliau bersabda: \"Perintahkan supaya dia kembali kepada isterinya, setelah itu dia boleh mencerainya ketika isterinya suci.\" Abu Muhammad berkata; [Ibnu Al Mubarak] serta [Waki'] meriwayatkan; \"Atau dalam keadaan hamil.\""},"1809":{"ar":" حَدَّثَنَا إِسْمَعِيلُ بْنُ خَلِيلٍ وَإِسْمَعِيلُ بْنُ أَبَانَ قَالَا حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ صَالِحِ بْنِ صَالِحٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ عُمَرَ قَالَ طَلَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَفْصَةَ ثُمَّ رَاجَعَهَا","id":"Telah menceritakan kepada kami [Isma'il bin Khalil] dan [Isma'il bin Aban] keduanya berkata; telah menceritakan kepada kami [Yahya bin Abu Zaidah] dari [Shalih bin Shalih] dari [Salamah bin Kuhail] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Umar], ia berkata; \"Rasulullah shallallahu 'alaihi wasallam pernah mencerai Hafshah kemudian merujuknya.\""},"1810":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ سُلَيْمَانَ عَنْ هُشَيْمٍ عَنْ حُمَيْدٍ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ طَلَّقَ حَفْصَةَ ثُمَّ رَاجَعَهَا قَالَ أَبُو مُحَمَّد كَأَنَّ عَلِيَّ بْنَ الْمَدِينِيِّ أَنْكَرَ هَذَا الْحَدِيثَ وَقَالَ لَيْسَ عِنْدَنَا هَذَا الْحَدِيثُ بِالْبَصْرَةِ عَنْ حُمَيْدٍ","id":"Telah mengabarkan kepada kami [Sa'id bin Sulaiman] dari [Husyaim] dari [Humaid] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah mencerai Hafshah kemudian merujuknya.\" Abu Muhammad berkata; \"Seolah-olah Ali bin Al Madini mengingkari hadits ini dan berkata; \"Kami tidak memiliki hadits ini di Bashrah (yang diriwayatkan) dari Humaid.\""},"1811":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ الْحَكَمُ قَالَ لِي يَحْيَى بْنُ حَمْزَةَ أَفْصِلُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ أَنْ لَا يَمَسَّ الْقُرْآنَ إِلَّا طَاهِرٌ وَلَا طَلَاقَ قَبْلَ إِمْلَاكٍ وَلَا عَتَاقَ حَتَّى يَبْتَاعَ قِيلَ لِأَبِي مُحَمَّدٍ مَنْ سُلَيْمَانُ قَالَ أَحْسَبُ كَاتِبًا مِنْ كُتَّابِ عُمَرَ بْنِ عَبْدِ الْعَزِيزِ","id":"Telah menghabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [Kakeknya] ia berkata; [Al Hakam] berkata; [Yahya bin Hamzah] berkata kepadaku; \"Aku menerangkan bahwa Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepada penduduk Yaman bahwa tidak boleh menyentuh Al Qur'an kecuali orang yang suci, tidak boleh mencerai sebelum menikah dan tidak dapat membebaskan kecuali setelah membeli.\" Abu Muhammad ditanya; \"Siapakah Sulaiman itu?\" Dia menjawab; \"Aku kira ia adalah sekretaris diantara sekretaris Umar bin Abdul Aziz.\""},"1812":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ قَالَ سَمِعْتُ عُرْوَةَ بْنَ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْ جَاءَتْ امْرَأَةُ رِفَاعَةَ الْقُرَظِيِّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ أَبُو بَكْرٍ وَخَالِدُ بْنُ سَعِيدِ بْنِ الْعَاصِ عَلَى الْبَابِ يَنْتَظِرُ أَنْ يُؤْذَنَ لَهُ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ عِنْدَ رِفَاعَةَ فَطَلَّقَنِي فَبَتَّ طَلَاقِي قَالَ أَتُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُ فَنَادَى خَالِدُ بْنُ سَعِيدٍ أَبَا بَكْرٍ أَلَا تَرَى مَا تَجْهَرُ بِهِ هَذِهِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Ibnu 'Uyainah] dari [Az Zuhri] ia berkata; aku mendengar ['Urwah bin Az Zubair] dari ['Aisyah] ia berkata; isteri Rifa'ah Al Qurazhi datang kepada Rasulullah shallallahu 'alaihi wasallam, sedangkan Abu Bakr berada di sisi beliau, sementara Khalid bin Sa'id bin Al 'Ash berada di depan pintu, menunggu hingga di izinkan untuk menemui Rasulullah shallallahu 'alaihi wasallam, kemudian isteri Rifa'ah berkata; \"Wahai Rasulullah, sesungguhnya dahulu aku hidup bersama Rifa'ah, kemudian ia menceraiku dengan talak tiga. Beliau bersabda: \"Apakah engkau ingin kembali kepada Rifa'ah? Tidak boleh, hingga ia (suami yang baru) mencicipi madumu dan engkau mencicipi madunya.\" Kemudian Khalid bin Sa'id memanggil Abu Bakr, ia berkata; \"Tidakkah engkau melihat wanita ini berkata kasar di sisi Rasulullah shallallahu 'alaihi wasallam?.\""},"1813":{"ar":" حَدَّثَنَا فَرْوَةُ بْنُ أَبِي الْمَغْرَاءِ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ طَلَّقَ رِفَاعَةُ رَجُلٌ مِنْ بَنِي قُرَيْظَةَ امْرَأَتَهُ فَتَزَوَّجَهَا عَبْدُ الرَّحْمَنِ بْنُ الزُّبَيْرِ فَدَخَلَتْ عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنْ مَعَهُ إِلَّا مِثْلُ هُدْبَتِي هَذِهِ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ أَوْ قَالَ تَذُوقِي عُسَيْلَتَهُ","id":"Telah menceritakan kepada kami [Farwah bin Abu Al Maghra`] telah menceritakan kepada kami [Ali bin Mushir] dari [Hisyam bin 'Urwah] dari [Ayahnya] dari ['Aisyah], ia berkata; Rifa'ah seorang laki-laki dari Bani Quraizhah telah mencerai isterinya, kemudian Abdurrahman bin Az Zubair menikahi mantan isteri Rifa'ah, lalu wanita (mantan isteri Rifa'ah) menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, ia (Abdurrahman bin Zubair) tidak memiliki kemampuan kecuali seperti ujung kainku ini.\" Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Kemungkinan engkau ingin kembali kepada Rifa'ah. Tidak, hingga ia merasakan madumu atau engkau merasakan madunya.\""},"1814":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ قَالَ سَأَلْتُ عَائِشَةَ عَنْ الْخِيَرَةِ فَقَالَتْ قَدْ خَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفَكَانَ طَلَاقًا","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Asy Sya'bi] dari [Masruq] ia berkata; aku bertanya kepada ['Aisyah] mengenai khiyarah, 'Aisyah menjawab; \"Rasulullah shallallahu 'alaihi wasallam telah memberikan pilihan kepada kami, namun hal itu tidak dianggap sebagai bentuk talak.\" "},"1815":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي أَسْمَاءَ عَنْ ثَوْبَانَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّمَا امْرَأَةٍ سَأَلَتْ زَوْجَهَا الطَّلَاقَ مِنْ غَيْرِ بَأْسٍ فَحَرَامٌ عَلَيْهَا رَائِحَةُ الْجَنَّةِ","id":"Telah menceritakan kepada kami [Muhammad bin Al Fadhl] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Asma`] dari [Tsauban], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapapun wanita yang meminta cerai suaminya, bukan karena sesuatu yang menyusahkan, maka haram baginya bau Surga.\""},"1816":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ أَنَّ عَمْرَةَ أَخْبَرَتْهُ أَنَّ حَبِيبَةَ بِنْتَ سَهْلٍ تَزَوَّجَهَا ثَابِتُ بْنُ قَيْسِ بْنِ شَمَّاسٍ فَذَكَرَتْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ هَمَّ أَنْ يَتَزَوَّجَهَا وَكَانَتْ جَارَةً لَهُ وَأَنَّ ثَابِتًا ضَرَبَهَا فَأَصْبَحَتْ عَلَى بَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْغَلَسِ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ فَرَأَى إِنْسَانًا فَقَالَ مَنْ هَذَا قَالَتْ أَنَا حَبِيبَةُ بِنْتُ سَهْلٍ فَقَالَ مَا شَأْنُكِ قَالَتْ لَا أَنَا وَلَا ثَابِتٌ فَأَتَى ثَابِتٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ رَسُولُ اللَّهِ خُذْ مِنْهَا وَخَلِّ سَبِيلَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ عِنْدِي كُلُّ شَيْءٍ أَعْطَانِيهِ فَأَخَذَ مِنْهَا وَقَعَدَتْ عِنْدَ أَهْلِهَا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya yaitu Ibnu Sa'id] bahwa ['Amrah] telah menceritakan bahwa [Habibah binti Sahl] telah dinikahi Tsabit bin Qais bin Syammas, kemudian ia menyebutkan bahwa Rasulullah shallallahu 'alaihi wasallam dahulu berkeinginan untuk menikahinya, dia adalah tetangga beliau. Suatu ketika Tsabit memukulnya, dan di waktu fajar, ia berada di depan pintu Rasulullah shallallahu 'alaihi wasallam dalam kegelapan, Ketika Rasulullah shallallahu 'alaihi wasallam keluar dan melihat ada seseorang, beliau bersabda bersabda; \"Siapakah ini?\" Habibah menjawab; \"Aku Habibah binti Sahl.\" Beliau bersabda; \"Apa keperluanmu?, \" Habibah berkata; \"Tidak mungkin aku dan Tsabit berkumpul.\" Kemudian Tsabit datang kepada Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Ambillah dari isterimu dan lepaskanlah dia.\" Habibah berkata; \"Wahai Rasulullah, segala yang ia berikan, ada padaku.\" Kemudian Tsabit mengambil darinya, lalu Habibah tinggal bersama keluarganya.\""},"1817":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ الزُّبَيْرِ بْنِ سَعِيدٍ رَجُلٍ مِنْ بَنِي عَبْدِ الْمُطَّلِبِ قَالَ بَلَغَنِي حَدِيثٌ عَنْ عَبْدِ اللَّهِ بْنِ عَلِيِّ بْنِ يَزِيدَ بْنِ رُكَانَةَ وَهُوَ فِي قَرْيَةٍ لَهُ فَأَتَيْتُهُ فَسَأَلْتُهُ فَقَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي أَنَّهُ طَلَّقَ امْرَأَتَهُ الْبَتَّةَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ مَا أَرَدْتَ فَقَالَ وَاحِدَةً قَالَ آللَّهِ قَالَ آللَّهِ قَالَ هُوَ مَا نَوَيْتَ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Jarir bin Hazim] dari [Az Zubair bin Sa'id] seorang laki-laki dari Bani Abdul Muththalib, ia berkata; [telah sampai kepadaku] suatu hadits dari [Abdullah bin Ali bin Yazid bin Rukanah] sementara dirinya berada di desanya, kemudian aku datang kepadanya, ia pun berkata; telah menceritakan kepadaku [Ayahku] dari [kakekku] bahwa ia telah menceraikan isterinya sama sekali (talak tiga), kemudian dia datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan hal itu. Beliau lalu bertanya: \"Apa yang engkau inginkan?\" dia berkata; \"Cerai satu kali.\" Beliau bersabda: \"Demi Allah?\" Ia berkata; \"Demi Allah.\" Beliau berkata: \"Hal itu seperti apa yang engkau niatkan.\""},"1818":{"ar":" حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ سَلَمَةَ بْنِ صَخْرٍ الْبَيَاضِيِّ قَالَ كُنْتُ امْرَأً أُصِيبُ مِنْ النِّسَاءِ مَا لَا يُصِيبُ غَيْرِي فَلَمَّا دَخَلَ شَهْرُ رَمَضَانَ خِفْتُ أَنْ أُصِيبَ فِي لَيْلِي شَيْئًا فَيَتَتَابَعَ بِي ذَلِكَ إِلَى أَنْ أُصْبِحَ قَالَ فَتَظَاهَرْتُ إِلَى أَنْ يَنْسَلِخَ فَبَيْنَا هِيَ لَيْلَةً تَخْدُمُنِي إِذْ تَكَشَّفَ لِي مِنْهَا شَيْءٌ فَمَا لَبِثْتُ أَنْ نَزَوْتُ عَلَيْهَا فَلَمَّا أَصْبَحْتُ خَرَجْتُ إِلَى قَوْمِي فَأَخْبَرْتُهُمْ وَقُلْتُ امْشُوا مَعِي إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا لَا وَاللَّهِ لَا نَمْشِي مَعَكَ مَا نَأْمَنُ أَنْ يَنْزِلَ فِيكَ الْقُرْآنُ أَوْ أَنْ يَكُونَ فِيكَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَقَالَةٌ يَلْزَمُنَا عَارُهَا وَلَنُسْلِمَنَّكَ بِجَرِيرَتِكَ فَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَصَصْتُ عَلَيْهِ خَبَرِي فَقَالَ يَا سَلَمَةُ أَنْتَ بِذَاكَ قُلْتُ أَنَا بِذَاكَ قَالَ يَا سَلَمَةُ أَنْتَ بِذَاكَ قُلْتُ أَنَا بِذَاكَ قَالَ يَا سَلَمَةُ أَنْتَ بِذَاكَ قُلْتُ أَنَا بِذَاكَ وَهَا أَنَا صَابِرٌ نَفْسِي فَاحْكُمْ فِيَّ مَا أَرَاكَ اللَّهُ قَالَ فَأَعْتِقْ رَقَبَةً قَالَ فَضَرَبْتُ صَفْحَةَ رَقَبَتِي فَقُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا أَصْبَحْتُ أَمْلِكُ رَقَبَةً غَيْرَهَا قَالَ فَصُمْ شَهْرَيْنِ مُتَتَابِعَيْنِ قُلْتُ وَهَلْ أَصَابَنِي الَّذِي أَصَابَنِي إِلَّا فِي الصِّيَامِ قَالَ فَأَطْعِمْ وَسْقًا مِنْ تَمْرٍ سِتِّينَ مِسْكِينًا فَقُلْتُ وَالَّذِي بَعَثَكَ بِالْحَقِّ لَقَدْ بِتْنَا لَيْلَتَنَا وَحْشَى مَا لَنَا طَعَامٌ قَالَ فَانْطَلِقْ إِلَى صَاحِبِ صَدَقَةِ بَنِي زُرَيْقٍ فَلْيَدْفَعْهَا إِلَيْكَ وَأَطْعِمْ سِتِّينَ مِسْكِينًا وَسْقًا مِنْ تَمْرٍ وَكُلْ بَقِيَّتَهُ أَنْتَ وَعِيَالُكَ قَالَ فَأَتَيْتُ قَوْمِي فَقُلْتُ وَجَدْتُ عِنْدَكُمْ الضِّيقَ وَسُوءَ الرَّأْيِ وَوَجَدْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ السَّعَةَ وَحُسْنَ الرَّأْيِ وَقَدْ أَمَرَ لِي بِصَدَقَتِكُمْ","id":"Telah menceritakan kepada kami [Zakariya bin 'Adi] telah menceritakan kepada kami [Abdullah bin Idris] dari [Muhammad bin Ishaq] dari [Muhammad bin 'Amr] dari [Sulaiman bin Yasar] dari [Salamah bin Shakhr Al Bayadhi] ia berkata; \"Aku dahulu adalah orang yang sering menggauli isteri tidak seperti orang lain yang menggauli isterinya. Tatkala masuk Bulan Ramadhan, aku sedikit khawatir melakukan jima' pada malam hariku, sehingga hal itu berlanjut hingga pagi hari. Maka aku menzhihar isteriku hingga berlalunya bulan Ramadhan. Pada dustu malam, ia membantuku, tiba-tiba tersingkap sesuatu darinya, tidak lama kemudian aku pun menggaulinya. Pada pagi harinya, aku keluar menuju kepada kaumku dan mengabarkan hal itu kepada mereka, aku berkata; \"Pergilah kalian bersamaku menemui Rasulullah shallallahu 'alaihi wasallam! \" Mereka mengatakan; \"Tidak, demi Allah, kami tidak akan pergi bersamamu. Kami khawatir turun Al Qur'an mengenai dirimu atau terdapat perkataan Rasulullah shallallahu 'alaihi wasallam mengenai dirimu yang aibnya mengenai kami. Sungguh kami menyerahkanmu dengan dosamu sendiri.\" Akhirnya aku pergi menemui Rasulullah shallallahu 'alaihi wasallam dan menceritakan kepada beliau berita mengenaiku. Beliau bersabda: \"Wahai Salamah, apakah engkau melakukan hal ini?\" Aku berkata; \"Aku telah melakukan hal ini.\" Beliau bersabda: \"Wahai Salamah, apakah engkau melakukan hal ini?\" aku menjawab; \"Aku telah melakukan hal ini.\" Beliau bersabda: \"Wahai Salamah, apakah engkau melakukan hal ini?\" Aku menjawab; \"Aku telah melakukan hal ini. Inilah aku yang telah bersabar terhadap diriku, maka putuskanlah terhadap diriku apa yang telah Allah perlihatkan kepada dirimu.\" Beliau bersabda: \"Bebaskanlah budak.\" Salamah berkata; \"Aku menepuk leher belakangku dan berkata; \"Demi Dzat yang mengutusmu dengan kebenaran, tidaklah aku dipagi hari memiliki budak selain dirinya.\" Beliau bersabda: \"Berpuasalah dua bulan berturut-turut! \" Aku berkata; \"Tidaklah aku tertimpa sesuatu yang menimpaku, kecuali ketika aku berpuasa.\" Beliau bersabda: \"Berilah makan satu wasaq kurma enam puluh orang miskin.\" Lalu aku berkata; \"Demi Dzat yang mengutusmu dengan kebenaran, sungguh kami bermalam dalam keadaan tidak memiliki makanan.\" Beliau bersabda: \"Pergilah kepada penjaga Shadaqah Bani Zuraiq, hendaknya ia memberikan kepadamu dan berilah makan enam puluh orang miskin satu wasaq kurma, dan makanlah sisanya bersama keluargamu.\" Salamah berkata; \"Kemudian aku mendatangi kaumku dan berkata; \"Aku dapatkan di sisi kalian kesempitan serta pendapat yang buruk, dan aku dapatkan di sisi Rasulullah shallallahu 'alaihi wasallam kelapangan dan pendapat yang baik, beliau telah memerintahkan agar aku diberi shadaqah kalian.\""},"1819":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّ زَوْجَهَا طَلَّقَهَا ثَلَاثًا فَلَمْ يَجْعَلْ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَفَقَةً وَلَا سُكْنَى قَالَ سَلَمَةُ فَذَكَرْتُ ذَلِكَ لِإِبْرَاهِيمَ فَقَالَ قَالَ عُمَرُ بْنُ الْخَطَّابِ لَا نَدَعُ كِتَابَ رَبِّنَا وَسُنَّةَ نَبِيِّهِ بِقَوْلِ امْرَأَةٍ فَجَعَلَ لَهَا السُّكْنَى وَالنَّفَقَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Salamah bin Kuhail] dari [Asy Sya'bi] dari [Fathimah binti Qais] bahwa suaminya telah mencerainya tiga kali dan Nabi shallallahu 'alaihi wasallam tidak memberikan nafkah untuknya dan tidak pula tempat tinggal.\" Salamah berkata; \"Kemudian aku sebutkan hal itu kepada Ibrahim. Dia berkata; \"Umar bin Al Khathab berkata; \"Kami tidak akan meninggalkan Kitab Rabb kami dan Sunnah Nabi kami karena perkataan seorang wanita. Dan ia tetap (berkewajiban) memberikan tempat tinggal dan nafkah.\""},"1820":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ قَيْسٍ أَنَّ زَوْجَهَا طَلَّقَهَا ثَلَاثًا فَأَمَرَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَعْتَدَّ عِنْدَ ابْنِ عَمِّهَا ابْنِ أُمِّ مَكْتُومٍ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Zakariya] dari [Amir] telah menceritakan kepadaku [Fathimah binti Qais] bahwa suaminya telah menceraikannya tiga kali, kemudian Nabi shallallahu 'alaihi wasallam memerintahakannya agar ber'iddah di rumah Ibnu Ummi Maktum."},"1821":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ عَنْ الْأَشْعَثِ عَنْ الْحَكَمِ وَحَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عُمَرَ قَالَ لَا نَدَعُ كِتَابَ رَبِّنَا وَسُنَّةَ نَبِيِّهِ بِقَوْلِ امْرَأَةٍ الْمُطَلَّقَةُ ثَلَاثًا لَهَا السُّكْنَى وَالنَّفَقَةُ أَخْبَرَنَا طَلْقُ بْنُ غَنَّامٍ عَنْ حَفْصِ بْنِ غِيَاثٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عُمَرَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] telah menceritakan kepada kami [Hafsh bin Ghiyats] dari [Al Asy'ats] dari [Al Hakam] serta [Hammad] dari [Ibrahim] dari [Al Aswad] dari [Umar], ia berkata; \"Kami tidak akan meninggalkan Kitab Rabb kami dan Sunnah NabiNya Karena perkataan seorang wanita. Wanita yang dicerai tiga kali, baginya mendapatkan tempat tinggal dan nafkah.\" Telah mengabarkan kepada kami [Thalq bin Ghannam] dari [Hafsh bin Ghiyats] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Umar] seperti hadits di atas."},"1822":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا حَفْصٌ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ قَالَ قَالَ عُمَرُ لَا نُجِيزُ قَوْلَ امْرَأَةٍ فِي دِينِ اللَّهِ الْمُطَلَّقَةُ ثَلَاثًا لَهَا السُّكْنَى وَالنَّفَقَةُ قَالَ أَبُو مُحَمَّد لَا أَرَى السُّكْنَى وَالنَّفَقَةَ لِلْمُطَلَّقَةِ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad], ia berkata; telah menceritakan kepada kami [Hafsh] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] Ia berkata; [Umar] berkata; \"Kami tidak memperkenankan perkataan seorang wanita dalam agama Allah. Wanita yang dicerai tiga kali, baginya mendapatkan tempat tinggal dan nafkah.\" Abu Muhammad berkata; \"Aku tidak berpendapat tempat tinggal dan nafkah untuk wanita yang dicerai.\""},"1823":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى بْنُ سَعِيدٍ أَنَّ سُلَيْمَانَ بْنَ يَسَارٍ أَخْبَرَهُ أَنَّ أَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ أَخْبَرَهُ أَنَّهُ اجْتَمَعَ هُوَ وَابْنُ عَبَّاسٍ عِنْدَ أَبِي هُرَيْرَةَ فَذَكَرُوا الرَّجُلَ يُتَوَفَّى عَنْ الْمَرْأَةِ فَتَلِدُ بَعْدَهُ بِلَيَالٍ قَلَائِلَ فَقَالَ ابْنُ عَبَّاسٍ حِلُّهَا آخِرُ الْأَجَلَيْنِ وَقَالَ أَبُو سَلَمَةَ إِذَا وَضَعَتْ فَقَدْ حَلَّتْ فَتَرَاجَعَا فِي ذَلِكَ بَيْنَهُمَا فَقَالَ أَبُو هُرَيْرَةَ أَنَا مَعَ ابْنِ أَخِي يَعْنِي أَبَا سَلَمَةَ فَبَعَثُوا كُرَيْبًا مَوْلَى ابْنِ عَبَّاسٍ إِلَى أُمِّ سَلَمَةَ فَسَأَلَهَا فَذَكَرَتْ أُمُّ سَلَمَةَ أَنَّ سُبَيْعَةَ بِنْتَ الْحَارِثِ الْأَسْلَمِيَّةَ مَاتَ عَنْهَا زَوْجُهَا فَنَفِسَتْ بَعْدَهُ بِلَيَالٍ وَأَنَّ رَجُلًا مِنْ بَنِي عَبْدِ الدَّارِ يُكْنَى أَبَا السَّنَابِلِ خَطَبَهَا وَأَخْبَرَهَا أَنَّهَا قَدْ حَلَّتْ فَأَرَادَتْ أَنْ تَتَزَوَّجَ غَيْرَهُ فَقَالَ لَهَا أَبُو السَّنَابِلِ فَإِنَّكِ لَمْ تَحِلِّينَ فَذَكَرَتْ سُبَيْعَةُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا أَنْ تَتَزَوَّجَ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya bin Sa'id] bahwa [Sulaiman bin Yasar] telah mengabarkan kepadanya, bahwa [Abu Salamah bin Abdurrahman] telah mengabarkan kepadanya, bahwa ia dan [Ibnu Abbas] berkumpul di sisi [Abu Hurairah], kemudian mereka menyebutkan seorang laki-laki mati meninggalkan seorang isteri, beberapa malam setelahnya, isterinya melahirkan. Ibnu Abbas berkata; \"Kehalalannya adalah yang paling akhir diantara dua waktu.\" Sementara Abu Salamah berkata; \"Apabila ia melahirkan, maka ia telah halal.\" Dalam hal, mereka berdua saling mendiskusikan. Abu Hurairah berkata; (Dalam masalah ini) aku sependapat dengan anak saudaraku yaitu Abu Salamah.\" Kemudian mereka mengutus [Kuraib] mantan budak Ibnu Abbas kepada Ummu Salamah, lalu ia bertanya kepadanya. [Ummu Salamah] menyebutkan bahwa Subai'ah binti Al Harits Al Aslamiyah ditinggal mati suaminya. Kemudian ia menjalani nifas beberapa malam setelahnya, lalu seorang laki-laki dari Bani Abdud Dar yang dijuluki Abu As Sanabil meminangnya dan mengabarkan kepadanya bahwa ia telah halal. Ternyata Subai'ah ingin menikah dengan selain Abu As Sanabil, Abu As Sanabil berkata kepadanya; \"Sesungguhnya engkau belum halal.\" Kemudian Subai'ah menceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau memerintahkannya supaya menikah.\""},"1824":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ كُرَيْبٍ عَنْ أُمِّ سَلَمَةَ قَالَتْ تُوُفِّيَ زَوْجُ سُبَيْعَةَ بِنْتِ الْحَارِثِ فَوَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِأَيَّامٍ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَتَزَوَّجَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Sulaiman bin Yasar] dari [Kuraib] dari [Ummu Salamah], ia berkata; \"Suami Subai'ah binti Al Harits telah meninggal, selang beberapa malam setelah suaminya meninggal, ia melahirkan, maka Rasulullah shallallahu 'alaihi wasallam memerintahkannya supaya menikah.\""},"1825":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ عُمَرَ الزَّهْرَانِيُّ حَدَّثَنَا أَبُو الْأَحْوَصِ حَدَّثَنَا مَنْصُورٌ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ أَبِي السَّنَابِلِ قَالَ وَضَعَتْ سُبَيْعَةُ بِنْتُ الْحَارِثِ حَمْلَهَا بَعْدَ وَفَاةِ زَوْجِهَا بِبِضْعٍ وَعِشْرِينَ لَيْلَةً فَلَمَّا تَعَلَّتْ مِنْ نِفَاسِهَا تَشَوَّفَتْ فَعِيبَ ذَلِكَ عَلَيْهَا فَذُكِرَ أَمْرُهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ تَفْعَلْ فَقَدْ انْقَضَى أَجَلُهَا","id":"Telah mengabarkan kepada kami [Bisyr bin Umar Az Zahrani] telah menceritakan kepada kami [Abu Al Ahwash] telah menceritakan kepada kami [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Abu As Sanabil] ia berkata; \"Subai'ah binti Al Harits telah melahirkan dua puluh tiga malam setelah suaminya meninggal. Tatkala ia telah suci dari nifasnya, ia menghias diri. Ternyata dirinya dicela karena hal itu, ketika perkaranya diberitahukan kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Apabila ia melakukan, maka sungguh telah selesai masa (iddah) nya.\""},"1826":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ أَنَّ سُبَيْعَةَ وَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِأَيَّامٍ فَتَشَوَّفَتْ فَعَابَ أَبُو السَّنَابِلِ فَسَأَلَتْ أَوْ ذَكَرَتْ أَمْرَهَا لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا أَنْ تَتَزَوَّجَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari [Al Aswad] bahwa Subai'ah telah melahirkan beberapa hari setelah suaminya wafat. Kemudian dirinya berhias, ternyata dirinya dicela oleh Abu As Sanabil. Lantas Suba'iah mengadukan atau menyebutkan perkaranya kepada Rasulullah shallallahu 'alaihi wasallam, ternyata beliau memerintahkannya supaya menikah lagi."},"1827":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَوْ تُؤْمِنُ بِاللَّهِ أَنْ تَحِدَّ عَلَى أَحَدٍ فَوْقَ ثَلَاثَةِ أَيَّامٍ إِلَّا عَلَى زَوْجِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sulaiman bin Katsir] dari [Az Zuhri] dari ['Urwah] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari Akhir atau beriman kepada Allah, berkabung kepada seseorang di atas tiga hari kecuali terhadap suaminya.\""},"1828":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدِ بْنِ نَافِعٍ قَالَ سَمِعْتُ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ تُحَدِّثُ عَنْ أُمِّ حَبِيبَةَ بِنْتِ أَبِي سُفْيَانَ أَنَّ أَخًا لَهَا مَاتَ أَوْ حَمِيمًا لَهَا فَعَمَدَتْ إِلَى صُفْرَةٍ فَجَعَلَتْ تَمْسَحُ يَدَيْهَا وَقَالَتْ إِنَّمَا أَفْعَلُ هَذَا لِأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تَحِدَّ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجِهَا فَإِنَّهَا تَحِدُّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ أَخْبَرَنَا شُعْبَةُ عَنْ حُمَيْدِ بْنِ نَافِعٍ قَالَ سَمِعْتُ زَيْنَبَ بِنْتَ أُمِّ سَلَمَةَ تُحَدِّثُ عَنْ أُمِّهَا أَوْ امْرَأَةٍ مِنْ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Humaid bin Nafi'], ia berkata; aku mendengar [Zainab binti Abu Salamah] menceritakan dari [Ummu Habibah binti Abu Sufyan] bahwa saudaranya -atau sahabatnya, - kemudian ia mengambil minyak wangi berwarna kuning dan mengusapkan ke kedua tangannya, dia berkata; \"Sesungguhnya aku melakukan hal ini karena Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan hari Akhir untuk berkabung melebihi tiga hari, kecuali terhadap suaminya, maka ia berkabung empat bulan sepuluh hari.\" Telah mengabarkan kepada kami [Syu'bah] dari [Humaid bin Nafi'], ia berkata; aku mendengar [Zainab binti Ummu Salamah] menceritakan dari [ibunya] dari para isteri Nabi shallallahu 'alaihi wasallam seperti itu.\""},"1829":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا زَائِدَةُ عَنْ هِشَامِ بْنِ حَسَّانَ عَنْ حَفْصَةَ بِنْتِ سِيرِينَ عَنْ أُمِّ عَطِيَّةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَحِدُّ الْمَرْأَةُ فَوْقَ ثَلَاثَةِ أَيَّامٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تَحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا لَا تَلْبَسُ ثَوْبًا مَصْبُوغًا إِلَّا ثَوْبَ عَصْبٍ وَلَا تَكْتَحِلُ وَلَا تَمَسُّ طِيبًا إِلَّا فِي أَدْنَى طُهْرِهَا إِذَا اغْتَسَلَتْ مِنْ مَحِيضِهَا نُبْذَةً مِنْ كُسْتٍ وَأَظْفَارٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Zaidah] dari [Hisyam bin Hassan] dari [Hafshah binti Sirin] dari [Ummu 'Athiyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak boleh seorang wanita berkabung melebihi tiga hari, kecuali terhadap suaminya, maka ia berkabung selama empat bulan sepuluh hari, dan tidak boleh menggunkan pakaian yang berwarna warni, melainkan hanya memakai pakaian yang kasar (kain beludru), dan tidak boleh menggunakan celak mata, dan tidak boleh memakai wewangian kecuali jika masa iddahnya telah habis, maka diperbolehkan baginya memakai qusth dan adzfar (sejenis pohon yang harum baunya).\""},"1830":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا مَالِكٌ عَنْ سَعْدِ بْنِ إِسْحَقَ بْنِ كَعْبِ بْنِ عُجْرَةَ عَنْ عَمَّتِهِ زَيْنَبَ بِنْتِ كَعْبِ بْنِ عُجْرَةَ أَنَّ الْفُرَيْعَةَ بِنْتَ مَالِكٍ أَخْبَرَتْهَا أَنَّهَا سَأَلَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَأْذَنَ لَهَا أَنْ تَرْجِعَ إِلَى أَهْلِهَا فَإِنَّ زَوْجِي قَدْ خَرَجَ فِي طَلَبِ أَعْبُدٍ لَهُ أَبَقُوا فَأَدْرَكَهُمْ حَتَّى إِذَا كَانَ بِطَرَفِ الْقَدُومِ قَتَلُوهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْكُثِي فِي بَيْتِكِ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ فَقُلْتُ إِنَّهُ لَمْ يَدَعْنِي فِي بَيْتٍ أَمْلِكُهُ وَلَا نَفَقَةٍ فَقَالَ امْكُثِي حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ فَاعْتَدَّتْ فِيهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا قَالَتْ فَلَمَّا كَانَ عُثْمَانُ أَرْسَلَ إِلَيَّ فَسَأَلَنِي عَنْ ذَلِكَ فَأَخْبَرْتُهُ فَاتَّبَعَ ذَلِكَ وَقَضَى بِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Malik] dari [Sa'd bin Ishaq bin Ka'b bin 'Ujrah] dari bibinya [Zainab binti Ka'an bin Ujrah] bahwa [Al Furai'ah binti Malik], ia telah mengabarkan kepadanya, bahwa ia pernah meminta kepada Rasulullah shallallahu 'alaihi wasallam agar memberinya izin untuk kembali kepada keluarganya. Ia berkata; \"Sesungguhnya suamiku keluar untuk mencari budak-budaknya yang kabur, kemudian ia mendapatkan mereka hingga setelah berada di Tharaf Al Qadum, budak-budaknya membunuhnya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tinggallah di rumahmu hingga 'iddahmu habis sampai batas waktunya.\" Aku berkata; \"Sesungguhnya suamiku tidak meninggalkanku di rumah yang aku miliki, tidak pula ada nafkah.\" Beliau bersabda: \"Tinggallah hingga 'iddah sampai batas waktunya.\" Kemudian ia menjalani 'iddah selama empat bulan sepuluh hari. Furai'ah berkata; Tatkala Utsman mengirim surat kepadaku dan bertanya mengenai hal itu, maka aku mengabarkan kepadanya, setelah itu Utsman mengikuti dan memberikan keputusan dengannya.\""},"1831":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَ طُلِّقَتْ خَالَتِي فَأَرَادَتْ أَنْ تَجُدَّ نَخْلًا لَهَا فَقَالَ لَهَا رَجُلٌ لَيْسَ لَكِ أَنْ تَخْرُجِي قَالَتْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ اخْرُجِي فَجُدِّي نَخْلَكِ فَلَعَلَّكِ أَنْ تَصَدَّقِي أَوْ تَصْنَعِي مَعْرُوفًا","id":"Telah mengabarkan kepada kami ['Ashim] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], ia berkata; bibiku telah dicerai dan ia hendak menebang pohon kurma miliknya, lantas seseorang berkata; \"Engkau tidak boleh keluar.\" Bibiku berkata; kemudian aku mendatangi Nabi shallallahu 'alaihi wasallam dan menceritakan hal itu kepada beliau. Beliau bersabda: \"Keluarlah dan potonglah pohon kurmamu, kemungkinan engkau akan bersedekah atau melakukan sesuatu yang terpuji.\""},"1832":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ أَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ فَأَرَادَ مَوَالِيهَا أَنْ يَشْتَرِطُوا وَلَاءَهَا فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ فَاشْتَرَتْهَا فَأَعْتَقَتْهَا وَخَيَّرَهَا مِنْ زَوْجِهَا وَكَانَ حُرًّا وَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِلَحْمٍ فَقَالَ مِنْ أَيْنَ هَذَا قِيلَ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] bahwa ia ingin membeli Barirah, ternyata tuannya memberikan syarat perwaliannya harus milik mereka. 'Aisyah pun mengadukan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lalu bersabda: \"Belilah dia, sesungguhnya perwalian adalah milik orang yang memerdekakan.\" Kemudian 'Aisyah membelinya dan membebaskannya. Dan beliau juga pernah memberikan pilihan kepadanya atas suaminya yang juga orang merdeka. Dan Nabi shallallahu 'alaihi wasallam pernah diberi daging, kemudian beliau bertanya: \"Dari mana daging ini?\" Dijawab; \"ini adalah daging yang disedekahkan kepada Barirah.\" Lalu beliau bersabda: \"Baginya adalah sedekah dan bagi kami adalah hadiah.\""},"1833":{"ar":" أَخْبَرَنَا إِسْمَعِيلُ بْنُ خَلِيلٍ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْ دَخَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ فَقَرَّبْتُ إِلَيْهِ طَعَامًا لَيْسَ فِيهِ لَحْمٌ فَقَالَ أَلَمْ أَرَ لَكُمْ قِدْرًا مَنْصُوبَةً قُلْتُ يَا رَسُولَ اللَّهِ هَذَا لَحْمٌ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَأَهْدَتْ لَنَا قَالَ هُوَ عَلَيْهَا صَدَقَةٌ وَهُوَ لَنَا مِنْهَا هَدِيَّةٌ وَكَانَ لَ��َا زَوْجٌ فَلَمَّا عُتِقَتْ خُيِّرَتْ","id":"Telah mengabarkan kepada kami [Isma'il bin Khalil] telah menceritakan kepada kami [Ali bin Mushir] telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari ['Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku, lalu aku dekatkan makanan yang tidak ada dagingnya, lalu beliau bersabda: \"Bukankah tadi aku melihat kalian memasak (daging) di kuwali?\" Maka saya katakan; \"Wahai Rasulullah, ini adalah daging yang disedekahkan kepada Barirah, dan ia hadiahkan kepada kita.\" Beliau bersabda: \"Daging itu adalah sedekah baginya dan menjadi hadiah bagi kita.\" Dan Barirah dahulunya memiliki suami, kemudian setelah ia di bebaskan, maka ia diberikan pilihan (antara meneruskan atau berpisah).\""},"1834":{"ar":" أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ الضَّحَّاكِ عَنْ الْمُغِيرَةِ بْنِ عَبْدِ الرَّحْمَنِ الْمَخْزُومِيِّ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ أَنَّ بَرِيرَةَ حِينَ أَعْتَقَتْهَا عَائِشَةُ كَانَ زَوْجُهَا عَبْدًا فَجَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحُضُّهَا عَلَيْهِ فَجَعَلَتْ تَقُولُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَيْسَ لِي أَنْ أُفَارِقَهُ قَالَ بَلَى قَالَتْ فَقَدْ فَارَقْتُهُ","id":"Telah mengabarkan kepada kami [Abdurrahman bin Adh Dhahhak] dari [Al Mughirah bin Abdurrahman Al Makhzumi] dari [Hisyam bin 'Urwah] dari [Abdurrahman bin Al Qasim] dari [Ayahnya] dari ['Aisyah] bahwa ketika Barirah dibebaskan oleh 'Aisyah, sementara suaminya masih berstatuskan budak, kemudian Rasulullah shallallahu 'alaihi wasallam menganjurkannya agar berbuat baik terhadapnya, maka Barirah berkata kepada Rasulullah shallallahu 'alaihi wasallam; \"Bukankah aku boleh berpisah dengannya?\" Beliau menjawab: \"Benar.\" Ia berkata; \"Sungguh aku telah berpisah darinya.\""},"1835":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا خَالِدُ بْنُ عَبْدِ اللَّهِ عَنْ خَالِدٍ يَعْنِي الْحَذَّاءَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ زَوْجَ بَرِيرَةَ كَانَ عَبْدًا يُقَالُ لَهُ مُغِيثٌ كَأَنِّي أَنْظُرُ إِلَيْهِ يَطُوفُ خَلْفَهَا يَبْكِي وَدُمُوعُهُ تَسِيلُ عَلَى لِحْيَتِهِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْعَبَّاسِ يَا عَبَّاسُ أَلَا تَعْجَبُ مِنْ شِدَّةِ حُبِّ مُغِيثٍ بَرِيرَةَ وَمِنْ شِدَّةِ بُغْضِ بَرِيرَةَ مُغِيثًا فَقَالَ لَهَا لَوْ رَاجَعْتِيهِ فَإِنَّهُ أَبُو وَلَدِكِ فَقَالَتْ يَا رَسُولَ اللَّهِ أَتَأْمُرُنِي قَالَ إِنَّمَا أَنَا شَافِعٌ قَالَتْ لَا حَاجَةَ لِي فِيهِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Khalid bin Abdullah] dari [Khalid yaitu Al Hadzdza`] dari [Ikrimah] dari [Ibnu Abbas] bahwa suami Barirah adalah seorang budak yang bernama Mughits, sepertinya aku melihat dia mengikuti di belakang Barirah dalam keadaan menangis dan air matanya mengalir hingga membasahi jenggotnya. Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepada Al Abbas: \"Wahai Abbas, tidakkah engkau kagum dengan besarnya kecintaan Mughits kepada Barirah dan besarnya kebencian Barirah kepada Mughits?\" Kemudian beliau bersabda kepada Barirah: \"Seandainya engkau kembali kepadanya, sesungguhnya ia adalah ayah dari anakmu.\" Lalu Barirah berkata; \"Wahai Rasulullah, apakah anda memerintahkanku?\" Beliau menjawab: \"Sesungguhnya aku sebagai perantara.\" Ia berkata; \"Aku tidak butuh kepadanya.\""},"1836":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي زِيَادُ بْنُ سَعْدٍ عَنْ هِلَالِ بْنِ أُسَامَةَ عَنْ أَبِي مَيْمُونَةَ سُلَيْمَانَ مَوْلًى لِأَهْلِ الْمَدِينَةِ قَالَ كُنْتُ عِنْدَ أَبِي هُرَيْرَةَ فَجَاءَتْهُ امْرَأَةٌ فَقَالَتْ إِنَّ زَوْجِي يُرِيدُ أَنْ يَذْهَبَ بِوَلَدِي فَقَالَ أَبُو هُرَيْرَةَ كُنْتُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَتْهُ امْرَأَةٌ فَقَالَتْ إِنَّ زَوْجِي يُرِيدُ أَنْ يَذْهَبَ بِوَلَدِي أَوْ بِابْنِي وَقَدْ نَفَعَنِي وَسَقَانِي مِنْ بِئْرِ أَبِي عِنَبَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اسْتَهِمَا أَوْ قَالَ تَسَاهَمَا أَبُو عَاصِمٍ الشَّاكُّ فَجَاءَ زَوْجُهَا فَقَالَ مَنْ يُخَاصِمُنِي فِي وَلَدِي أَوْ فِي ابْنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا غُلَامُ هَذَا أَبُوكَ وَهَذِهِ أُمُّكَ فَخُذْ بِيَدِ أَيِّهِمَا شِئْتَ وَقَدْ قَالَ أَبُو عَاصِمٍ فَاتْبَعْ أَيَّهُمَا شِئْتَ فَأَخَذَ بِيَدِ أُمِّهِ فَانْطَلَقَتْ بِهِ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij], ia berkata; telah mengabarkan kepadaku [Ziyad bin Sa'd] dari [Hilal bin Usamah] dari [Abu Maimunah Sulaiman] mantan budak penduduk Madinah, ia berkata; aku pernah berada di rumah Abu Hurairah, kemudian seorang wanita datang kepadanya dan berkata; \"Sesungguhnya suamiku ingin pergi membawa anakku.\" [Abu Hurairah] lalu berkata; \"Aku pernah bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba seorang wanita datang kepada beliau sambil berkata; \"Sesungguhnya suamiku ingin pergi membawa anakku -atau putraku- sementara anakku telah memberi manfaat kepadaku dan selalu mengambilkan air dari sumur Abu 'Inabah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam berkata: \"Hendaknya kalian berdua mengadakan undian.\" -Atau beliau mengatakan: \"Hendaknya kalian saling mengundi.\" Abu 'Ashim ragu mengenai redaksi haditsnya- Kemudian suaminya datang dan berkata; \"Siapakah yang akan melawanku terhadap anakku?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai anak kecil, ini adalah ayahmu dan ini adalah ibumu, peganglah tangan salah seorang diantara mereka berdua yang engkau kehendaki! \" Anak tersebut akhirnya memegang tangan ibunya, lalu wanita itu pergi dengan anaknya.\""},"1837":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ أَخْبَرَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي مُظَاهِرٌ وَهُوَ ابْنُ أَسْلَمَ أَنَّهُ سَمِعَ الْقَاسِمَ بْنَ مُحَمَّدٍ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِلْأَمَةِ تَطْلِيقَتَانِ وَقُرْؤُهَا حَيْضَتَانِ قَالَ أَبُو عَاصِمٍ سَمِعْتُهُ مِنْ مُظَاهِرٍ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah mengabarkan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Muzhahir yaitu Ibnu Aslam] bahwa ia mendengar [Al Qasim bin Muhammad] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Seorang budak memiliki dua kali cerai, dan quru`nya (masa iddahnya) adalah dua kali haid.\" [Abu 'Ashim] berkata; aku mendengarnya dari [Muzhahir]."},"1838":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا شَرِيكٌ عَنْ قَيْسِ بْنِ وَهْبٍ عَنْ أَبِي الْوَدَّاكِ عَنْ أَبِي سَعِيدٍ وَرَفَعَهُ أَنَّهُ قَالَ فِي سَبَايَا أَوْطَاسٍ لَا تُوطَأُ حَامِلٌ حَتَّى تَضَعَ حَمْلَهَا وَلَا غَيْرُ ذَاتِ حَمْلٍ حَتَّى تَحِيضَ حَيْضَةً","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Syarik] dari [Qais bin Wahb] dari [Abu Al Waddak] dari [Abu Sa'id] -dia telah merafa'kannya- dia berkata mengenai para tawanan wanita Authas; \"Wanita hamil tidak boleh digauli hingga ia melahirkan kandungannya, sedangkan yang tidak hamil, hingga ia mengalami haid satu kali.\""},"1839":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا حَمَّادٌ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثَةٍ عَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الصَّغِيرِ حَتَّى يَحْتَلِمَ وَعَنْ الْمَجْنُونِ حَتَّى يَعْقِلَ وَقَدْ قَالَ حَمَّادٌ أَيْضًا وَعَنْ الْمَعْتُوهِ حَتَّى يَعْقِلَ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Hammad] dari [Ibrahim] dari [Al Aswad] dari ['Aisyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Pena diangkat dari tiga orang, yaitu; orang yang tidur hingga terbangun, orang yang masih kecil hingga ia dapat bermimpi (baligh), dan dari orang yang gila hingga berakal.\" Hammad berkata; \"Juga dari orang yang kurang akal hingga ia berakal.\""},"1840":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ عَنْ عُثْمَانَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ دَمُ امْرِئٍ مُسْلِمٍ إِلَّا بِإِحْدَى ثَلَاثٍ بِكُفْرٍ بَعْدَ إِيمَانٍ أَوْ بِزِنًى بَعْدَ إِحْصَانٍ أَوْ يَقْتُلُ نَفْسًا بِغَيْرِ نَفْسٍ فَيُقْتَلُ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Abu Umamah bin Sahl bin Hani] dari [Utsman], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang muslim kecuali dengan tiga perkara, yaitu; kafir setelah beriman (murtad), berzina setelah menikah, atau membunuh jiwa bukan karena hak, sehingga ia dibunuh.\""},"1841":{"ar":" حَدَّثَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ دَمُ رَجُلٍ يَشْهَدُ أَنَّ لَا إِلَهَ إِلَّا اللَّهُ وَأَنِّي رَسُولُ اللَّهِ إِلَّا أَحَدَ ثَلَاثَةِ نَفَرٍ النَّفْسُ بِالنَّفْسِ وَالثَّيِّبُ الزَّانِي وَالتَّارِكُ لِدِينِهِ الْمُفَارِقُ لِلْجَمَاعَةِ","id":"Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seorang wanita yang bersaksi bahwa tidak ada Ilah yang berhak disembah melainkan Allah dan aku adalah Rasulullah, kecuali salah satu dari tiga orang ini, yaitu; jiwa dibalas dengan jiwa (qishahs), janda yang berzina, orang yang meninggalkan agamanya dan memisahkan diri dari jama'ah kaum muslimin.\""},"1842":{"ar":" أَخْبَرَنَا سَعْدُ بْنُ حَفْصٍ حَدَّثَنَا شَيْبَانُ عَنْ أَشْعَثَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ كَانَ صَفْوَانُ بْنُ أُمَيَّةَ نَائِمًا فِي الْمَسْجِدِ فَأَتَاهُ رَجُلٌ وَهُوَ نَائِمٌ فَاسْتَلَّ رِدَاءَهُ مِنْ تَحْتِ رَأْسِهِ فَنَبِهَ بِهِ فَلَحِقَهُ فَأَخَذَهُ فَانْطَلَقَ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ كُنْتُ نَائِمًا فِي الْمَسْجِدِ فَأَتَانِي هَذَا فَاسْتَلَّ رِدَائِي مِنْ تَحْتِ رَأْسِي فَلَحِقْتُهُ فَأَخَذْتُهُ فَأَمَرَ بِقَطْعِهِ فَقَالَ لَهُ صَفْوَانُ يَا رَسُولَ اللَّهِ إِنَّ رِدَائِي لَمْ يَبْلُغْ أَنْ يُقْطَعَ فِيهِ هَذَا قَالَ فَهَلَّا قَبْلَ أَنْ تَأْتِيَنِي بِهِ","id":"Telah mengabarkan kepada kami [Sa'd bin Hafsh] telah menceritakan kepada kami [Syaiban] dari [Asy'ats] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; Shafwan bin Umayyah pernah tidur di masjid, kemudian seorang laki-laki datang kepadanya sementara ia masih tidur, aki-laki itu lalu mengambil selendangnya dari bawah kepalanya. Katika terjaga, dia langsung mengejar laki-laki itu dan berhasil menangkapnya, setelah itu dia membawanya menghadap kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Wahai Rasulullah, tadi aku tidur di masjid, kemudian orang ini mendatangiku dan mengambil selendangku dari bawah kepalaku. Lalu aku mengejarnya dan berhasil menangkapnya.\" Kemudian beliau memerintahkan agar tangan laki-laki itu dipotong. Ternyata Shafwan berkata; \"Wahai Rasulullah, sesungguhnya tidak sampai harus dipotong tangannya karena selendangku.\" Beliau bersabda: \"Seandainya kamu mengatakannya sebelum kamu membawanya kepadaku.\""},"1843":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ الْهَاشِمِيُّ أَخْبَرَنَا إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُقْطَعُ الْيَدُ فِي رُبْعِ دِينَارٍ فَصَاعِدًا","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud Al Hasyimi] telah mengabarkan kepada kami [Ibrahim bin Sa'd] dari [Az Zuhri] dari ['Amrah binti Abdurrahman] dari ['Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tangan dipotong karena mengambil sesuatu yang nilainya seperempat dinar atau lebih.\""},"1844":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ أَيُّوبَ وَإِسْمَعِيلَ بْنِ أُمَيَّةَ وَعُبَيْدِ اللَّهِ وَمُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ قَطَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مِجَنٍّ قِيمَتُهُ ثَلَاثَةُ دَرَاهِمَ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Ayyub] dan [Isma'il bin Umayyah] dan ['Ubaidullah] serta [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam memotong tangan pencuri tameng yang nilainya sebesar tiga dirham.\""},"1845":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ أَنَّ قُرَيْشًا أَهَمَّهُمْ شَأْنُ الْمَرْأَةِ الْمَخْزُومِيَّةِ الَّتِي سَرَقَتْ فَقَالُوا مَنْ يُكَلِّمُ فِيهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالُوا وَمَنْ يَجْتَرِئُ عَلَيْهِ إِلَّا أُسَامَةُ بْنُ زَيْدٍ حِبُّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَلَّمَهُ أُسَامَةُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَشْفَعُ فِي حَدٍّ مِنْ حُدُودِ اللَّهِ ثُمَّ قَامَ فَاخْتَطَبَ فَقَالَ إِنَّمَا هَلَكَ الَّذِينَ قَبْلَكُمْ أَنَّهُمْ كَانُوا إِذَا سَرَقَ فِيهِمْ الشَّرِيفُ تَرَكُوهُ وَإِذَا سَرَقَ فِيهِمْ الضَّعِيفُ أَقَامُوا عَلَيْهِ الْحَدَّ وَايْمُ اللَّهِ لَوْ أَنَّ فَاطِمَةَ بِنْتَ مُحَمَّدٍ سَرَقَتْ لَقَطَعْتُ يَدَهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Aisyah] bahwa orang-orang Quraisy disibukkan oleh perkara wanita Makhzum yang mencuri, kemudian mereka berkata; \"Siapakah yang akan menjadi jubir kepada Rasulullah shallallahu 'alaihi wasallam mengenai wanita tersebut?\" Orang-orang yang lain mengatakan; \"Sepertinya tidak ada yang berani kecuali Usamah bin Zaid, orang yang dicintai Rasulullah shallallahu 'alaihi wasallam.\" Kemudian Usamah berbicara kepada beliau. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau akan memberikan pertolongan dalam perkara had diantara had-had Allah?\" kemudian beliau berdiri dan berkhutbah, beliau bersabda: 'Sesungguhnya orang-orang sebelum kalian binasa, bahwa jika terdapat orang mulia diantara mereka mencuri, maka mereka membiarkannya dan jika terdapat orang yang lemah diantara mereka mencuri, maka mereka menegakkan hukuman atasnya. Demi Allah apabila Fathimah binti Muhammad mencuri, niscaya aku akan potong tangannya.\""},"1846":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَبِي الْمُنْذِرِ مَوْلَى أَبِي ذَرٍّ عَنْ أَبِي أُمَيَّةَ الْمَخْزُومِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِسَارِقٍ اعْتَرَفَ اعْتِرَافًا لَمْ يُوجَدْ مَعَهُ مَتَاعٌ فَقَالَ مَا إِخَالُكَ سَرَقْتَ قَالَ بَلَى قَالَ مَا إِخَالُكَ سَرَقْتَ قَالَ بَلَى قَالَ فَاذْهَبُوا فَاقْطَعُوا يَدَهُ ثُمَّ جِيئُوا بِهِ فَقَطَعُوا يَدَهُ ثُمَّ جَاءُوا بِهِ فَقَالَ اسْتَغْفِرْ اللَّهَ وَتُبْ إِلَيْهِ فَقَالَ أَسْتَغْفِرُ اللَّهَ وَأَتُوبُ إِلَيْهِ فَقَالَ اللَّهُمَّ تُبْ عَلَيْهِ اللَّهُمَّ تُبْ عَلَيْهِ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ishaq bin Abdullah bin Abu Thalhah] dari [Abu Al Mundzir] mantan budak Abu Dzar dari [Abu Umayyah Al Makhzumi] bahwa seorang pencuri yang mengaku telah mencuri dihadapakan kepada Rasulullah shallallahu 'alaihi wasallam, namun tidak didapatkan barang padanya. Kemudian beliau bersabda: \"Aku tidak menyangka engkau mencuri.\" Ia berkata; \"Benar.\" Beliau bersabda: \"Aku tidak menyangka engkau mencuri.\" Ia berkata; \"Benar.\" Beliau bersabda (kepada para sahabatnya): \"Pergilah kalian dan potonglah tangannya, setelah itu bawalah dia kemari.\" Kemudian mereka memotongnya setelah itu mereka membawanya (menghadap beliau), lalu beliau bersabda kepadanya: \"Mohonlah ampunan kepada Allah dan bertaubatlah kepadaNya.\" Orang itu pun mengatakan; \"Aku mohon ampun kepada Allah dan bertaubat kepadaNya.\" Beliau bersabda: \"Ya Allah, terimalah taubatnya, ya Allah, terimalah taubatnya.\""},"1847":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ أَنَّ مُحَمَّدَ بْنَ يَحْيَى بْنِ حَبَّانَ أَخْبَرَهُ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Yahya yaitu Ibnu Sa'id] bahwa [Muhammad bin Yahya bin Habban] telah mengabarkan kepadanya dari [Rafi' bin Khadij] ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada had potong tangan karena mengambil buah dan mayang (kurma).\""},"1848":{"ar":" حَدَّثَنَا الْحُسَيْنُ بْنُ مَنْصُورٍ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَجُلٍ مِنْ قَوْمِهِ عَنْ رَافِعِ بْنِ خَدِيجٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ","id":"Telah menceritakan kepada kami [Al Husain bin Manshur] telah menceritakan kepada kami [Abu Usamah] dari [Yahya bin Sa'id] dari [Muhammad bin Yahnya bin Hibban] dari [seorang laki-laki] dari kaumnya dari [Rafi' bin Khadij] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Tidak ada had potong tangan karena mengambil buah dan mayang (kurma).\""},"1849":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ عَمِّهِ وَاسِعِ بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepada kami [Waki'] dari [Sufyan] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari pamannya yaitu [Wasi' bin Habban] dari [Rafi' bin Khadij], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada had potong tangan karena mengambil buah dan mayang (kurma).\" Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Rafi' bin Khadij] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1850":{"ar":" أَخْبَرَنَا إِسْحَقُ حَدَّثَنَا جَرِيرٌ وَالثَّقَفِيُّ عَنْ يَحْيَى بْنِ سَعِيدٍ أَخْبَرَنِي مُحَمَّدُ بْنُ يَحْيَى بْنِ حَبَّانَ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي ثَمَرٍ وَلَا كَثَرٍ قَالَ وَهُوَ شَحْمُ النَّخْلِ وَالْكَثَرُ الْجُمَّارُ","id":"Telah mengabarkan kepada kami [Ishaq] telah menceritakan kepadaku [Jarir] serta [Ats Tsaqafi] dari [Yahya bin Sa'id] telah mengabarkan kepadaku [Muhammad bin Yahya bin Habban] dari [Rafi' bin Khadij], ia berkata; Aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada had potong tangan karena mengambil buah dan mayang (kurma).\" Rafi' berkata; \"Yaitu kurma yang paling lunak, sedangkan katsar adalah mayang (kurma).\""},"1851":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَبِي مَيْمُونٍ عَنْ رَافِعِ بْنِ خَدِيجٍ قَالَ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا قَطْعَ فِي كَثَرٍ قَالَ أَبُو مُحَمَّد الْقَوْلُ مَا قَالَ أَبُو أُسَامَةَ","id":"Telah mengabarkan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Abu Maimun] dari [Rafi' bin Khadij] ia berkata; aku mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada had potong tangan karena mengambil mayang (kurma).\" Abu Muhammad berkata; \"Perkataan yang benar adalah yang dikatakan oleh Abu Usamah.\""},"1852":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ قَالَ قَالَ أَبُو الزُّبَيْرِ قَالَ جَابِرٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ عَلَى الْمُنْتَهِبِ وَلَا عَلَى الْمُخْتَلِسِ وَلَا عَلَى الْخَائِنِ قَطْعٌ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] ia berkata; [Abu Az Zubair] berkata; [Jabir] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang merampas dan yang menggelapkan harta serta orang yang berkhianat tidak dipotong tangannya.\""},"1853":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُتِيَ بِرَجُلٍ قَدْ شَرِبَ خَمْرًا فَضَرَبَهُ بِجَرِيدَتَيْنِ ثُمَّ فَعَلَ أَبُو بَكْرٍ مِثْلَ ذَلِكَ فَلَمَّا كَانَ عُمَرُ اسْتَشَارَ النَّاسَ فَقَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ أَخَفُّ الْحُدُودِ ثَمَانِينَ قَالَ فَفَعَلَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] bahwa seorang laki-laki yang meminum khamer dihadapkan kepada Nabi shallallahu 'alaihi wasallam, kemudian beliau mencambuknya dengan dua pelepah kurma, Abu Bakr juga melakukan seperti itu. Setelah Umar berkuasa, maka ia meminta pendapat orang-orang, kemudian Abdurrahman bin 'Auf berkata; \"Had (hukuman) yang paling ringan adalah delapan puluh kali cambukan.\" Anas berkata; \"Kemudian Umar melakukannya hal itu.\""},"1854":{"ar":" حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ أَخْبَرَنَا عَبْدُ الْعَزِيزِ بْنُ الْمُخْتَارِ حَدَّثَنَا عَبْدُ اللَّهِ الدَّانَاجُ حَدَّثَنَا حُضَيْنُ بْنُ الْمُنْذِرِ الرَّقَاشِيُّ قَالَ شَهِدْتُ عُثْمَانَ بْنَ عَفَّانَ وَأُتِيَ بِالْوَلِيدِ بْنِ عُقْبَةَ فَقَالَ عَلِيٌّ جَلَدَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعِينَ وَجَلَدَ أَبُو بَكْرٍ أَرْبَعِينَ وَعُمَرُ ثَمَانِينَ وَكُلٌّ سُنَّةٌ","id":"Telah menceritakan kepada kami [Muslim bin Ibrahim] telah mengabarkan kepada kami [Abdul Aziz bin Al Mukhtar] telah menceritakan kepada kami [Abdullah Ad Danaj] telah menceritakan kepada kami [Hudhain bin Al Mundzir Ar Raqasyi], ia berkata; aku menyaksikan Utsman bin 'Affan dan dihadapkan kepadanya Al Walid bin 'Uqbah, kemudian [Ali] berkata; \"Nabi shallallahu 'alaihi wasallam pernah mencambuknya empat puluh kali dan Abu Bakr juga empat puluh kali sementara Umar delapan puluh kali, dan semuanya adalah sunnah.\""},"1855":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ هُوَ ابْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ عُتْبَةَ بْنِ عُرْوَةَ بْنِ مَسْعُودٍ الثَّقَفِيُّ عَنْ عَمْرِو بْنِ الشَّرِيدِ عَنْ أَبِيهِ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ إِذَا شَرِبَ أَحَدُكُمْ فَاضْرِبُوهُ ثُمَّ إِنْ عَادَ فَاضْرِبُوهُ ثُمَّ إِنْ عَادَ فَاضْرِبُوهُ ثُمَّ إِنْ عَادَ الرَّابِعَةَ فَاقْتُلُوهُ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'] telah menceritakan kepada kami [Muhammad yaitu Ibnu Ishaq] telah menceritakan kepada kami [Abdullah bin 'Utbah bin 'Urwah bin Mas'ud Ats Tsaqafi] dari ['Amr bin Asy Syarid] dari [Ayahnya] ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila salah seorang dari kalian minum khamer, maka cambuklah dia, apabila ia mengulangi, maka cambuklah dia, apabila ia masih mengulangi, maka cambuklah dia, dan apabila ia tetap mengulangi yang keempat kalinya, maka bunuhlah dia.\""},"1856":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا سَعِيدٌ هُوَ ابْنُ أَبِي أَيُّوبَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الرَّحْمَنِ هُوَ ابْنُ جَابِرٍ عَنْ أَبِي بُرْدَةَ بْنِ نِيَارٍ قَالَ سَم��عْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِأَحَدٍ أَنْ يَضْرِبَ أَحَدًا فَوْقَ عَشَرَةِ أَسْوَاطٍ إِلَّا فِي حَدٍّ مِنْ حُدُودِ اللَّهِ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyaj] dari [Sulaiman bin Yasar] dari [Abdurrahman yaitu Ibnu Jabir] dari [Abu Burdah bin Niyar], ia berkata; Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seseorang untuk mencambuk orang lain lebih dari sepuluh kali, kecuali dalam hukuman diantara hukuman-hukuman (yang ditetapkan) Allah.\""},"1857":{"ar":" أَخْبَرَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ أَخْبَرَنِي ابْنُ شِهَابٍ عَنْ أَبِي سَلَمَةَ عَنْ جَابِرٍ أَنَّ رَجُلًا مِنْ أَسْلَمَ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَدَّثَهُ أَنَّهُ زَنَى فَشَهِدَ عَلَى نَفْسِهِ أَنَّهُ زَنَى أَرْبَعًا فَأَمَرَ بِرَجْمِهِ وَكَانَ قَدْ أُحْصِنَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Syihab] dari [Abu Salamah] dari [Jabir] bahwa seorang laki-laki dari Aslam datang kepada Nabi shallallahu 'alaihi wasallam, dia lalu menceritakan kepadanya bahwa dia telah berzina. Kemudian ia bersumpah atas dirinya sebanyak empat kali bahwa dirinya telah berzina. Kemudian beliau memerintahkan agar laki-laki itu dirajam, sementara laki-laki itu adalah orang yang telah menikah.\""},"1858":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ سِمَاكٍ أَنَّهُ سَمِعَ جَابِرَ بْنَ سَمُرَةَ يَقُولُ أُتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمَاعِزِ بْنِ مَالِكٍ رَجُلٍ قَصِيرٍ فِي إِزَارٍ مَا عَلَيْهِ رِدَاءٌ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُتَّكِئٌ عَلَى وِسَادَةٍ عَلَى يَسَارِهِ فَكَلَّمَهُ فَمَا أَدْرِي مَا يُكَلِّمُهُ بِهِ وَأَنَا بَعِيدٌ مِنْهُ بَيْنِي وَبَيْنَهُ الْقَوْمُ ثُمَّ قَالَ اذْهَبُوا بِهِ فَارْجُمُوهُ ثُمَّ قَالَ رُدُّوهُ فَكَلَّمَهُ أَيْضًا وَأَنَا أَسْمَعُ غَيْرَ أَنَّ بَيْنِي وَبَيْنَهُ الْقَوْمَ فَقَالَ اذْهَبُوا بِهِ فَارْجُمُوهُ ثُمَّ قَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَطَبَ وَأَنَا أَسْمَعُهُ ثُمَّ قَالَ كُلَّمَا نَفَرْنَا فِي سَبِيلِ اللَّهِ خَلَفَ أَحَدُهُمْ لَهُ نَبِيبٌ كَنَبِيبِ التَّيْسِ يَمْنَحُ إِحْدَاهُنَّ الْكُثْبَةَ مِنْ اللَّبَنِ وَاللَّهِ لَا أَقْدِرُ عَلَى أَحَدٍ مِنْهُمْ إِلَّا نَكَّلْتُ بِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Isra`il] dari [Simak] bahwa ia mendengar [Jabir bin Samurah] berkata; Ma'iz bin Malik seorang yang memiliki kain sarung yang pendek dan tidak memakai selendang dihadapkan kepada Nabi shallallahu 'alaihi wasallam, sementara Rasulullah shallallahu 'alaihi wasallam bersandar pada bantal di sisi kirinya. Kemudian beliau berbicara kepadanya, aku tidak tahu apa yang beliau bicarakan, sementara aku jauh darinya, sebab antara diriku dan dirinya terdapat beberapa orang. Kemudian beliau bersabda: \"Bawalah dia pergi dan rajamlah dia! \" Kemudian beliau bersabda: \"Suruhlah dia kembali! \" Kemudian beliau berbicara kepadanya dan aku sempat mendengar, hanya saja antara diriku dan dirinya terdapat beberapa orang, kemudian beliau bersabda: \"Bawalah dia pergi dan rajamlah dia! \" Kemudian Nabi shallallahu 'alaihi wasallam berdiri dan berkhutbah, sementara aku mendengarnya, beliau bersabda: \"Setiap kali kita hendak pergi di jalan Allah, masih saja salah seorang dari mereka tidak ikut serta, lalu dia memberikan sesuatu (kepada istrinya -pent) seperti suara kambing pejantan yang sedang terbakar nafsu birahi, Demi Allah, sekiranya saya di berikan kemungkinan, niscaya saya akan memberikan hukuman kepadanya sebagai suatu pelajaran.\""},"1859":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ أَبِي هُرَيْرَةَ وَزَيْدِ بْنِ خَالِدٍ وَشِبْلٍ قَالُوا جَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَنْشُدُكَ اللَّهَ إِلَّا قَضَيْتَ بَيْنَنَا بِكِتَابِ اللَّهِ فَقَالَ خَصْمُهُ وَكَانَ أَفْقَهَ مِنْهُ صَدَقَ اقْضِ بَيْنَنَا بِكِتَابِ اللَّهِ وَأْذَنْ لِي يَا رَسُولَ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْ فَقَالَ إِنَّ ابْنِي كَانَ عَسِيفًا عَلَى أَهْلِ هَذَا فَزَنَى بِامْرَأَتِهِ فَافْتَدَيْتُ مِنْهُ بِمِائَةِ شَاةٍ وَخَادِمٍ وَإِنِّي سَأَلْتُ رِجَالًا مِنْ أَهْلِ الْعِلْمِ فَأَخْبَرُونِي أَنَّ عَلَى ابْنِي جَلْدَ مِائَةٍ وَتَغْرِيبَ عَامٍ وَأَنَّ عَلَى امْرَأَةِ هَذَا الرَّجْمَ فَقَالَ وَالَّذِي نَفْسِي بِيَدِهِ لَأَقْضِيَنَّ بَيْنَكُمَا بِكِتَابِ اللَّهِ الْمِائَةُ شَاةٍ وَالْخَادِمُ رَدٌّ عَلَيْكَ وَعَلَى ابْنِكَ جَلْدُ مِائَةٍ وَتَغْرِيبُ عَامٍ وَيَا أُنَيْسُ اغْدُ عَلَى امْرَأَةِ هَذَا فَسَلْهَا فَإِنْ اعْتَرَفَتْ فَارْجُمْهَا فَاعْتَرَفَتْ فَرَجَمَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Abu Hurairah] serta [Zaid bin Khalid] dan [Syibl] mereka berkata; \"Seorang laki-laki datang kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; \"Aku bersumpah kepadamu atas nama Allah, putuskanlah perkara diantara kami dengan Kitabullah.\" Kemudian lawannya yang lebih faham daripada dirinya berkata; \"Ia benar, berilah keputusan diantara kami dengan Kitabullah, dan izinkan kami berbicara wahai Rasulullah! \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Katakanlah! \" ia berkata; \"Sesungguhnya anakku adalah pelayan untuk melayani keperluan isteri orang ini. Ternyata ia berzina dengan isterinya itu, kemudian aku menebus darinya dengan seratus ekor unta serta seorang budak. Dan aku bertanya kepada orang-orang yang berilmu, lalu mereka memberitahukan kepadaku bahwa anakku mendapat hukuman cambuk seratus kali dan di asingkan selama satu tahun, sementara isteri orang ini mendapat hukuman rajam.\" Beliau bersabda: \"Demi Dzat yang jiwaku ada di tanganNya. Sungguh aku akan memberikan keputusan dengan Kitabullah. Seratus ekor kambing dan seorang budak dikembalikan kepadamu, dan anakmu mendapatkan hukuman cambuk seratus kali dan di asingkan selama satu tahun. Wahai Unais, pergilah kepada isteri orang ini, dan tanyakan kepadanya! Apabila ia mengaku, maka rajamlah dia.\" Wanita itupun mengakui perbuatannya, maka Unais merajamnya."},"1860":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدٌ هُوَ ابْنُ إِسْحَقَ بْنِ يَسَارٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ التَّيْمِيُّ عَنْ أَبِي الْهَيْثَمِ بْنِ نَصْرِ بْنِ دَهْرٍ الْأَسْلَمِيِّ عَنْ أَبِيهِ قَالَ كُنْتُ فِيمَنْ رَجَمَهُ قَالَ أَبُو مُحَمَّد يَعْنِي مَاعِزَ بْنَ مَالِكٍ فَلَمَّا وَجَدَ مَسَّ الْحِجَارَةِ جَزِعَ جَزَعًا شَدِيدًا قَالَ فَذَكَرْنَا ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَهَلَّا تَرَكْتُمُوهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad bin Ishaq bin Yasar] telah menceritakan kepada kami [Muhammad bin Ibrahim At Taimi] dari [Abu Al Haitsami bin Nashr bin Dahr Al Aslami] dari [Ayahnya] ia berkata; aku termasuk diantara orang yang merajamnya. -Abu Muhammad berkata; yaitu Ma'iz bin Malik- Tatkala dia merasakan lemparan bebatuan, dia sangat gelisah. Nashr bin Dahr Al Aslami berkata; Kemudian kami menyebutkan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. Lalu beliau bersabda: \"Tidakkah kalian meninggalkannya?\""},"1861":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عِيسَى حَدَّثَنَا يَحْيَى بْنُ أَبِي زَائِدَةَ عَنْ دَاوُدَ عَنْ أَبِي نَضْرَةَ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْطَلِقُوا بِمَاعِزِ بْنِ مَالِكٍ فَارْجُمُوهُ فَانْطَلَقْنَا بِهِ إِلَى بَقِيعِ الْغَرْقَدِ فَوَاللَّهِ مَا أَوْثَقْنَاهُ وَلَا حَفَرْنَا لَهُ وَلَكِنْ قَامَ فَرَمَيْنَاهُ بِالْعِظَامِ وَالْخَزَفِ وَالْجَنْدَلِ","id":"Telah mengabarkan kepada kami [Muhammad bin Isa] telah menceritakan kepada kami [Yahya bin Abu Zaidah] dari [Daud] dari [Abu Nadhrah] dari [Abu Sa'id Al Khudri] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergilah kepada Ma'iz bin Malik, dan rajamlah dia.\" Kemudian kami membawanya pergi ke Baqi' yang banyak pohon Gharqadnya. Demi Allah, kami tidak mengikatnya dan tidak pula menguburnya, akan tetapi ia berdiri, kemudian kami melemparinya dengan tulang, potongan bejana serta bebatuan.\""},"1862":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرُ بْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَهُ رَجُلٌ يُقَالُ لَهُ مَاعِزُ بْنُ مَالِكٍ فَاعْتَرَفَ عِنْدَهُ بِالزِّنَا فَرَدَّهُ ثَلَاثَ مَرَّاتٍ ثُمَّ جَاءَ الرَّابِعَةَ فَاعْتَرَفَ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحُفِرَ لَهُ حُفْرَةٌ فَجُعِلَ فِيهَا إِلَى صَدْرِهِ وَأَمَرَ النَّاسَ أَنْ يَرْجُمُوهُ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir bin Al Muhajir] telah menceritakan kepadaku [Abdullah bin Buraidah] dari [Ayahnya] ia berkata; kami pernah duduk-duduk bersama Nabi shallallahu 'alaihi wasallam, kemudian seorang laki-laki yang bernama Ma'iz bin Malik datang kepada beliau dan mengaku bahwa dirinya telah berzina. Namun beliau berpaling darinya sebanyak tiga kali. Akan tetapi dia tetap datang keempat kalinya sambil mengakui perbuatannya. Akhirnya Nabi shallallahu 'alaihi wasallam memerintahkan agar dibuatkan lubang untuknya, kemudian dia diletakkan pada lobang tersebut hingga dada, dan beliau memerintahkan orang-orang agar melemparinya (dengan batu).\""},"1863":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا زُهَيْرٌ حَدَّثَنَا مُوسَى بْنُ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ الْيَهُودَ جَاءُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرَجُلٍ مِنْهُمْ وَامْرَأَةٍ قَدْ زَنَيَا فَقَالَ كَيْفَ تَفْعَلُونَ بِمَنْ زَنَى مِنْكُمْ قَالُوا لَا نَجِدُ فِيهَا شَيْئًا فَقَالَ لَهُمْ عَبْدُ اللَّهِ بْنُ سَلَامٍ كَذَبْتُمْ فِي التَّوْرَاةِ الرَّجْمُ { فَأْتُوا بِالتَّوْرَاةِ فَاتْلُوهَا إِنْ كُنْتُمْ صَادِقِينَ } فَجَاءُوا بِالتَّوْرَاةِ فَوَضَعَ مِدْرَاسُهَا الَّذِي يَدْرُسُهَا مِنْهُمْ كَفَّهُ عَلَى آيَةِ الرَّجْمِ فَقَالَ مَا هَذِهِ فَلَمَّا رَأَوْا ذَلِكَ قَالُوا هِيَ آيَةُ الرَّجْمِ فَأَمَرَ بِهِمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُجِمَا قَرِيبًا مِنْ حَيْثُ تُوضَعُ الْجَنَائِزُ عِنْدَ الْمَسْجِدِ قَالَ عَبْدُ اللَّهِ فَرَأَيْتُ صَاحِبَهَا يَجْنَأُ عَلَيْهَا يَقِيهَا الْحِجَارَةَ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Zuhair] telah menceritakan kepada kami [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] bahwa orang-orang Yahudi datang kepada Rasulullah shallallahu 'alaihi wasallam dengan membawa seorang laki-laki dan perempuan dari kalangan mereka yang berzina. Kemudian beliau bersabda: \"Bagaimana kalian berbuat terhadap orang yang berzina dari kalangan kalian?\" Mereka mengatakan; \"Kami tidak mendapatkan dalam Taurat sesuatupun. Kemudian Abdullah bin Salam berkata kepada mereka; \"Kalian telah berdusta. Dalam taurat terdapat rajam. Datangkanlah Taurat kemudian bacalah, apabila kalian adalah orang-orang yang benar.\" Kemudian mereka mendatangkan Taurat, sementara orang yang mempelajari Taurat dari kalangan mereka meletakkan telapak tangannya pada ayat mengenai rajam. Beliau bertanya; \"Apa ini?\" Tatkala mereka melihat hal itu, mereka berkata; \"Itu adalah ayat rajam.\" Rasulullah shallallahu 'alaihi wasallam pun memerintahkan supaya keduanya dirajam, akhirnya keduanya di rajam dekat dari tempat diletakkannya beberapa jenazah di Masjid. Abdullah berkata; \"Aku melihat laki-laki itu membungkuk diatas wanita tersebut untuk melindunginya dari bebatuan.\""},"1864":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ عُمَرُ إِنَّ اللَّهَ تَعَالَى بَعَثَ مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْحَقِّ وَأَنْزَلَ عَلَيْهِ الْكِتَابَ وَكَانَ فِيمَا أَنْزَلَ آيَةُ الرَّجْمِ فَقَرَأْنَاهَا وَوَعَيْنَاهَا وَعَقَلْنَاهَا وَرَجَمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَجَمْنَا بَعْدَهُ فَأَخْشَى إِنْ طَالَ بِالنَّاسِ زَمَانٌ أَنْ يَقُولَ الْقَائِلُ لَا نَجِدُ حَدَّ آيَةِ الرَّجْمِ فِي كِتَابِ اللَّهِ وَالرَّجْمُ فِي كِتَابِ اللَّهِ حَقٌّ عَلَى مَنْ زَنَى مِنْ الرِّجَالِ وَالنِّسَاءِ إِذَا أُحْصِنَ إِذَا قَامَتْ عَلَيْهِ الْبَيِّنَةُ أَوْ كَانَ الْحَبَلُ أَوْ الِاعْتِرَافُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Ibnu Abbas], ia berkata; [Umar] berkata; Sesungguhnya Allah Ta'ala telah mengutus Muhammad shallallahu 'alaihi wasallam dengan membawa kebenaran, dan telah menurunkan kepadanya Al Qur'an. Diantara yang Allah turunkan adalah ayat mengenai rajam. Kemudian kami membacanya dan menghafal serta memahaminya. Rasulullah shallallahu 'alaihi wasallam pernah merajam dan kamipun merajam setelah beliau (wafat). Lalu aku khawatir apabila zaman telah berlalu bagi manusia, maka seseorang akan berkata; \"Kami tidak mendapatkan ayat rajam dalam Kitabullah, sementara rajam dalam Kitabullah adalah benar, yaitu bagi laki-laki dan perempuan yang telah menikah, dan telah cukup bukti atau hamil atau mengaku telah berzina.\""},"1865":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ حَدَّثَنَا الْعَقَدِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ يُحَدِّثُ عَنْ كَثِيرِ بْنِ الصَّلْتِ عَنْ زَيْدِ بْنِ ثَابِتٍ قَالَ أَشْهَدُ لَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الشَّيْخُ وَالشَّيْخَةُ إِذَا زَنَيَا فَارْجُمُوهُمَا الْبَتَّةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i] telah menceritakan kepada kami [Al 'Aqadi] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Yunus bin Jubair] ia menceritakan dari [Katsir bin Ash Shalt] dari [Zaid bin Tsabit], ia berkata; aku bersaksi telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang laki-laki dan perempuan tua apabila berzina, maka rajamlah dia.\""},"1866":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا بَشِيرُ بْنُ الْمُهَاجِرِ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كُنْتُ جَالِسًا عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَتْهُ امْرَأَةٌ مِنْ بَنِي غَامِدٍ فَقَالَتْ يَا نَبِيَّ اللَّهِ إِنِّي قَدْ زَنَيْتُ وَإِنِّي أُرِيدُ أَنْ تُطَهِّرَنِي فَقَالَ لَهَا ارْجِعِي فَلَمَّا كَانَ مِنْ الْغَدِ أَتَتْهُ أَيْضًا فَاعْتَرَفَتْ عِنْدَهُ بِالزِّنَا فَقَالَتْ يَا نَبِيَّ اللَّهِ طَهِّرْنِي فَلَعَلَّكَ أَنْ تَرْدُدَنِي كَمَا رَدَدْتَ مَاعِزَ بْنَ مَالِكٍ فَوَاللَّهِ إِنِّي لَحُبْلَى فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْجِعِي حَتَّى تَلِدِي فَلَمَّا وَلَدَتْ جَاءَتْ بِالصَّبِيِّ تَحْمِلُهُ فِي خِرْقَةٍ فَقَالَتْ يَا نَبِيَّ اللَّهِ هَذَا قَدْ وَلَدْتُ قَالَ فَاذْهَبِي فَأَرْضِعِيهِ ثُمَّ افْطِمِيهِ فَلَمَّا فَطَمَتْهُ جَاءَتْ بِالصَّبِيِّ فِي يَدِهِ كِسْرَةُ خُبْزٍ فَقَالَتْ يَا نَبِيَّ اللَّهِ قَدْ فَطَمْتُهُ فَأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالصَّبِيِّ فَدُفِعَ إِلَى رَجُلٍ مِنْ الْمُسْلِمِينَ وَأَمَرَ بِهَا فَحُفِرَ لَهَا حُفْرَةٌ فَجُعِلَتْ فِيهَا إِلَى صَدْرِهَا ثُمَّ أَمَرَ النَّاسَ أَنْ يَرْجُمُوهَا فَأَقْبَلَ خَالِدُ بْنُ الْوَلِيدِ بِحَجَرٍ فَرَمَى رَأْسَهَا فَتَلَطَّخَ الدَّمُ عَلَى وَجْنَةِ خَالِدِ بْنِ الْوَلِيدِ فَسَبَّهَا فَسَمِعَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبَّهُ إِيَّاهَا فَقَالَ مَهْ يَا خَالِدُ لَا تَسُبَّهَا فَوَالَّذِي نَفْسِي بِيَدِهِ لَقَدْ تَابَتْ تَوْبَةً لَوْ تَابَهَا صَاحِبُ مَكْسٍ لَغُفِرَ لَهُ فَأَمَرَ بِهَا فَصُلِّيَ عَلَيْهَا وَدُفِنَتْ","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Basyir bin Al Muhajir] telah menceritakan kepadaku [Abdullah bin Buraidah] dari [Ayahnya] ia berkata; aku duduk di sisi Nabi shallallahu 'alaihi wasallam, tiba-tiba seorang wanita dari Bani Ghamid datang kepada beliau sambil berkata; \"Wahai Nabiyullah, sesungguhnya aku telah berzina, dan aku ingin membersihkan diri.\" Beliau bersabda kepadanya; \"Kembalilah.\" Dihari berikutnya, wanita itu datang lagi sambil mengaku telah berzina, katanya; \"Wahai Nabiyullah, sucikanlah diriku, sepertinya engaku hendak menolakku sebagaimana menolak (pengakuan) Ma'iz bin Malik, demi Allah, sesungguhnya diriku telah hamil (dari perzinahan tersebut).\" Maka Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Kembalilah hingga engkau melahirkan.\" Setelah melahirkan, wanita itu datang membawa seorang bayi yang ia gendong dalam sepotong kain, wanita itu berkata; \"Wahai Nabiyullah, kini aku telah melahirkan.\" Beliau bersabda: \"Pergilah dan susui anak itu hingga kamu menyapihnya! \" Tatkala wanita itu selesai menyapih, ia datang dan di tangan anak tersebut terdapat potongan roti. Lalu ia berkata; \"Wahai Nabiyullah, sungguh aku telah menyapihnya.\" Lalu Nabi shallallahu 'alaihi wasallam memerintahkan agar anak tersebut diserahkan kepada seseorang dari kalangan muslimin, lalu beliau memerintahkan supaya wanita itu dibuatkan lubang, akhirnya ia diletakkan di dalam lubang tersebut hingga dada. Lalu beliau memerintahkan orang-orang agar melemparinya. Sesaat kemudian Khalid bin Al Walid datang dengan batu, lalu ia melempar kepala wanita tersebut hingga darah terpancar ke pelipis Khaid bin Al Walid, ia langsung mengumpatnya. Mendengar umpatan itu Nabi shallallahu 'alaihi wasallam bersabda: \"Tahanlah, wahai Khalid, janganlah engkau mengumpatnya. Demi Dzat yang jiwanya ada di tanganNya. Sungguh ia telah bertaubat dengan taubat yang seandainya pemungut pajak, memungut pajak tidak sesuai dengan syari'at (Islam), niscaya pemungut pajak akan mendapatkan ampunan.\" Kemudian beliau memerintahkan agar wanita tersebut dishalatkan dan dikubur."},"1867":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ امْرَأَةً مِنْ جُهَيْنَةَ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ حُبْلَى مِنْ الزِّنَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ حَدًّا فَأَقِمْهُ عَلَيَّ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلِيَّهَا فَقَالَ اذْهَبْ فَأَحْسِنْ إِلَيْهَا فَإِذَا وَضَعَتْ حَمْلَهَا فَأْتِنِي بِهَا فَفَعَلَ فَأَمَرَ بِهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشُكَّتْ عَلَيْهَا ثِيَابُهَا ثُمَّ أَمَرَ بِهَا فَرُجِمَتْ ثُمَّ صَلَّى عَلَيْهَا فَقَالَ عُمَرُ يَا رَسُولَ اللَّهِ أَتُصَلِّي عَلَيْهَا وَقَدْ زَنَتْ فَقَالَ لَقَدْ تَابَتْ تَوْبَةً لَوْ قُسِمَتْ بَيْنَ سَبْعِينَ مِنْ أَهْلِ الْمَدِينَةِ لَوَسِعَتْهُمْ وَهَلْ وَجَدْتَ أَفْضَلَ مِنْ أَنْ جَادَتْ بِنَفْسِهَا لِلَّهِ عَزَّ وَجَلَّ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] bahwa seoerang wanita dari Juhainah datang kepada Nabi shallallahu 'alaihi wasallam dalam keadaan hamil karena berzina, dia berkata; \"Wahai Rasulullah, sesungguhnya aku telah melanggar hukum, oleh karena itu tegakkanlah hukuman kepadaku!.\" Rasulullah shallallahu 'alaihi wasallam memanggil walinya dan berkata: \"Pergilah dan uruslah dia dengan baik, apabila telah melahirkan, bawalah ia kepadaku.\" Walinya pun melakukan perintah beliau, setelah itu Rasulullah shallallahu 'alaihi wasallam memerintahkan supaya pakain wanita tersebut diikatkan ke badannya, beliau akhirnya memerintahkan agar wanita tersebut dirajam. Setelah itu beliau menshalatkan jenazah wanita tersebut, Umar berkata; \"Wahai Rasulullah, apakah engkau menshalatkannya, sementara dirinya telah berzina?\" Beliau bersabda: \"Sungguh dirinya telah bertaubat dengan taubat yang seandainya di bagikan diantara tujuh puluh penduduk Madinah, niscaya akan mencukupi mereka semua. Apakah engkau mendapatkan taubat yang lebih baik dari seseorang yang menyerahkan dirinya kepada Allah 'azza wajalla?.\""},"1868":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ وَأَبِي هُرَيْرَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الْأَمَةِ تَزْنِي وَلَمْ تُحْصَنْ فَقَالَ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا ثُمَّ إِنْ زَنَتْ فَاجْلِدُوهَا قَالَ مَا أَدْرِي فِي الثَّالِثَةِ أَوْ فِي الرَّابِعَةِ فَبِيعُوهَا وَلَوْ بِضَفِيرٍ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah bin 'Utbah] dari [Zaid bin Khalid Al Juhani] serta [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam ditanya mengenai seorang budak wanita yang berzina dan belum menikah. Beliau bersabda; \"Apabila ia berzina, maka cambuklah dia, jika masih berzina, maka cambuklah dia, jika masih berzina, maka cambuklah dia.\" Abu Hurairah berkata; Aku tidak tahu beliau mengatakan yang ketiga kali atau keempat kalinya: \"Kemudian juallah dia walaupun hanya senilai tali pelana.\""},"1869":{"ar":" أَخْبَرَنَا بِشْرُ بْنُ عُمَرَ الزَّهْرَانِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خُذُوا عَنِّي خُذُوا عَنِّي قَدْ جَعَلَ اللَّهُ لَهُنَّ سَبِيلًا الْبِكْرُ بِالْبِكْرِ وَالثَّيِّبُ بِالثَّيِّبِ الْبِكْرُ جَلْدُ مِائَةٍ وَنَفْيُ سَنَةٍ وَالثَّيِّبُ جَلْدُ مِائَةٍ وَالرَّجْمُ أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا هُشَيْمٌ عَنْ مَنْصُورٍ عَنْ الْحَسَنِ عَنْ حِطَّانَ بْنِ عَبْدِ اللَّهِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنَحْوِهِ","id":"Telah mengabarkan kepada kami [Bisyr bin Umar Az Zahrani] telah menceritakan kepada kami [Hammad bin Salamah] dari [Qatadah] dari [Al Hasan] dari [Haththan bin Abdullah] dari ['Ubadah bin Ash Shamit] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ikutilah semua ajaranku, ikutilah semua ajaranku, sungguh Allah telah menetapkan hukuman bagi seorang wanita, hukuman bagi seorang perawan sesuai hukumannya bagi seorang perawan yaitu di cambuk seratus kali dan di asingkan selama setahun, sedangkan seseorang yang telah menikah, hukumannya juga sesuai dengan orang yang telah menikah yaitu di dera seratus kali dan di rajam.\" Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Husyaim] dari [Manshur] dari [Al Hasan] dari [Hiththan bin Abdullah] dari ['Ubadah bin Ash Shamit] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1870":{"ar":" أَخْبَرَنَا يَحْيَى بْنُ حَمَّادٍ حَدَّثَنَا أَبَانُ بْنُ يَزِيدَ عَنْ قَتَادَةَ قَالَ كَتَبَ إِلَيَّ خَالِدُ بْنُ عُرْفُطَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ أَنَّ غُلَامًا كَانَ يُنْبَزُ فُرْفُورًا فَوَقَعَ عَلَى جَارِيَةِ امْرَأَتِهِ فَرُفِعَ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ فَقَالَ لَأَقْضِيَنَّ فِيهِ بِقَضَاءٍ شَافٍ إِنْ كَانَتْ أَحَلَّتْهَا لَهُ جَلَدْتُهُ مِائَةً وَإِنْ كَانَتْ لَمْ تُحِلَّهَا لَهُ رَجَمْتُهُ فَقِيلَ لَهَا زَوْجُكِ فَقَالَتْ إِنِّي قَدْ أَحْلَلْتُهَا لَهُ فَضَرَبَهُ مِائَةً قَالَ يَحْيَى هُوَ مَرْفُوعٌ حَدَّثَنَا صَدَقَةُ بْنُ الْفَضْلِ أَخْبَرَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ أَبِي بِشْرٍ عَنْ خَالِدِ بْنِ عُرْفُطَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Yahya bin Hammad] telah menceritakan kepada kami [Aban bin Yazid] dari [Qatadah] ia berkata; [Khalid bin 'Urfuthah] telah menulis surat kepadaku, dari [Habib bin Salim] bahwa seorang pemuda berjulukan Furfur telah menggauli budak wanita isterinya, Ketika hal itu dilaporkan kepada [An Nu'man bin Basyir], dia berkata; \"Sungguh aku akan memberikan keputusan mengenai pemuda tersebut dengan keputusan yang mencakup. Apabila isterinya telah menghalalkan budak tersebut untuknya, maka aku akan mencambuknya sebanyak seratus kali, dan apabila isterinya tidak menghalalkan budak tersebut untuknya, maka aku akan merajamnya.\" Lalu dikatakan kepada isterinya; \"Suamimu tergantung kepadamu.\" Isterinya berkata; \"Aku telah menghalalkan budak itu baginya.\" Kemudian An Nu'man mencambuknya seratus kali.\" Yahya berkata; \"Hadits tersebut marfu'.\" Telah menceritakan kepada kami [Shadaqah bin Al Fadhl] telah mengabarkan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Abu Bisyr] dari [Khalid bin 'Urfuthah] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1871":{"ar":" أَخْبَرَنَا مَرْوَانُ بْنُ مُحَمَّدٍ الدِّمَشْقِيُّ حَدَّثَنَا ابْنُ وَهْبٍ عَنْ أُسَامَةَ بْنِ زَيْدٍ عَنْ مُحَمَّدِ بْنِ الْمُنَكْدِرِ عَنْ ابْنِ خُزَيْمَةَ بْنِ ثَابِتٍ عَنْ أَبِيهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أُقِيمَ عَلَيْهِ حَدٌّ غُفِرَ لَهُ ذَلِكَ الذَّنْبُ","id":"Telah mengabarkan kepada kami [Marwan bin Muhammad Ad Dimasyqi] telah menceritakan kepada kami [Ibnu Wahb] dari [Usamah bin Zaid] dari [Muhammad bin Al Munkadir] dari [Ibnu Khuzaimah bin Tsabit] dari [Ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa dirinya dijatuhi hukuman terhadap (dosa yang ia perbuat), maka dosanya tersebut akan diampuni.\""},"1872":{"ar":" أَخْبَرَنَا سَهْلُ بْنُ حَمَّادٍ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ امْرَأَةً نَذَرَتْ أَنْ تَحُجَّ فَمَاتَتْ فَجَاءَ أَخُوهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ عَنْ ذَلِكَ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ كَانَ عَلَيْهَا دَيْنٌ كُنْتَ قَاضِيَهُ قَالَ نَعَمْ قَالَ فَاقْضُوا اللَّهَ فَاللَّهُ أَحَقُّ بِالْوَفَاءِ","id":"Telah mengabarkan kepada kami [Sahl bin Hammad] telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa seorang wanita bernadzar untuk melakukan haji, ternyata ia meninggal (sebelum berhaji), kemudian saudara laki-lakinya datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya mengenai hal itu, beliau bersabda: \"Apabila saudaramu memiliki hutang, apakah engkau akan membayarnya?\" laki-laki itu menjawab; \"Ya.\" Beliau bersabda: \"Bayarlah hutang kepada Allah, sebab Dia lebih berhak untuk ditunaikan hutang-Nya.\""},"1873":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا حَفْصٌ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ نَذْرًا فِي الْجَاهِلِيَّةِ ثُمَّ جَاءَ الْإِسْلَامُ قَالَ فِ بِنَذْرِكَ ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Hafsh] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] dari [Umar] ia berkata; \"Wahai Rasulullah, sesungguhnya aku telah bernadzar pada masa Jahiliyah, kemudian Islam datang.\" Beliau bersabda: \"Laksanakanlah nadzarmu.\""},"1874":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ زَحْرٍ عَنْ أَبِي سَعِيدٍ الرُّعَيْنِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مَالِكٍ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ قَالَ نَذَرَتْ أُخْتِي أَنْ تَحُجَّ لِلَّهِ مَاشِيَةً غَيْرَ مُخْتَمِرَةٍ فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْ أُخْتَكَ فَلْتَخْتَمِرْ وَلْتَرْكَبْ وَلْتَصُمْ ثَلَاثَةَ أَيَّامٍ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Yahya bin Sa'id] dari ['Ubaidullah bin Zahr] dari [Abu Sa'id Ar Ru'aini] dari [Abdullah bin Malik] dari ['Uqbah bin 'Amir Al Juhani], ia berkata; \"Saudara perempuanku pernah bernadzar pergi haji karena Allah dengan berjalan kaki dan tidak memakai penutup kepala. Setelah aku menceritakan hal itu kepada Rasulullah shallallahu 'alaihi wasallam. beliau bersabda: \"Perintahkanlah kepada sadara perempuanmu agar menutup kepala dan naik kendaraan serta berpuasa tiga hari.\""},"1875":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ أَخْبَرَنِي قَتَادَةُ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ أُخْتَ عُقْبَةَ نَذَرَتْ أَنْ تَمْشِيَ إِلَى الْبَيْتِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ لَغَنِيٌّ عَنْ نَذْرِ أُخْتِكَ لِتَرْكَبْ وَلْتُهْدِ هَدْيًا","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammam] telah mengabarkan kepadaku [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] bahwa saudara perempuan 'Uqbah bernadzar berjalan menuju Ka'bah. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah tidak butuh kepada nadzar saudarimu, suruhlah ia naik kendaraan dan menyembelih kurban.\""},"1876":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ مَنْصُورٍ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ عَمْرِو بْنِ أَبِي عَمْرٍو عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْرَكَ شَيْخًا يَمْشِي بَيْنَ ابْنَيْهِ فَقَالَ مَا شَأْنُ هَذَا الشَّيْخِ فَقَالَ ابْنَاهُ نَذَرَ أَنْ يَمْشِيَ فَقَالَ ارْكَبْ فَإِنَّ اللَّهَ غَنِيٌّ عَنْكَ وَعَنْ نَذْرِكَ","id":"Telah menceritakan kepada kami [Sa'id bin Manshur] telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari ['Amr bin Abu 'Amr] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menjumpai laki-laki tua yang berjalan sambil dipapah diantara dua orang, kemudian beliau bersabda: \"Ada apa dengan orang tua ini?\" Kedua anaknya menjawab; \"Ia bernadzar untuk berjalan menuju Ka'bah.\" Beliau bersabda: \"Suruhlah ia naik kendaraan, sesungguhnya Allah tidak butuh kepadamu dan kepada nadzarmu.\""},"1877":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ أَيُّوبَ عَنْ أَبِي قِلَابَةَ عَنْ أَبِي الْمُهَلَّبِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا وَفَاءَ لِنَذْرٍ فِي مَعْصِيَةِ اللَّهِ وَلَا فِيمَا لَا يَمْلِكُ ابْنُ آدَمَ","id":"Telah mengabarkan kepada kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Hammad bin Zaid] dari [Ayyub] dari [Abu Qilabah] dari [Abu Al Muhallab] dari [Imran bin Hushain] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak wajib menunaikan nadzar dalam rangka bermaksiat kepada Allah, dan apa yang tidak dimiliki oleh manusia.\""},"1878":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ طَلْحَةَ بْنِ عَبْدِ الْمَلِكِ الْأَيْلِيِّ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ نَذَرَ أَنْ يَطِيعَ اللَّهَ فَلْيُطِعْهُ وَمَنْ نَذَرَ أَنْ يَعْصِيَ اللَّهَ فَلَا يَعْصِهِ","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Thalhah bin Abdul Malik Al 'Aili] dari [Al Qasim bin Muhammad] dari ['Aisyah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bernadzar untuk mentaati Allah, hendaknya ia mentaati-Nya dan barangsiapa bernadzar untuk bermaksiat kepada Allah, janganlah ia bermaksiat kepadaNya.\""},"1879":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَبِيبِ بْنِ أَبِي بَقِيَّةَ الْمُعَلِّمِ عَنْ عَطَاءِ بْنِ أَبِي رَبَاحٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنِّي نَذَرْتُ إِنْ فَتَحَ اللَّهُ عَلَيْكَ أَنْ أُصَلِّيَ فِي بَيْتِ الْمَقْدِسِ فَقَالَ صَلِّ هَا هُنَا فَأَعَادَ عَلَيْهِ ثَلَاثَ مَرَّاتٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَأْنُكَ إِذَنْ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Habib bin Abu Baqiyyah Al Mu'allim] dari ['Atha` bin Abu Rabah] dari [Jabir bin Abdullah] bahwa seorang laki-laki berkata; \"Wahai Rasulullah, sesungguhnya aku telah bernadzar, apabila Allah memberikan kemenangan kepadamu, maka aku akan melakukan shalat di Baitul Maqdis. Beliau bersabda: \"Shalatlah di sini.\" Jabir mengulanginya sebanyak tiga kali, akhirnya Nabi shallallahu 'alaihi wasallam bersabda: \"Terserah kamu, kalau demikian.\""},"1880":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَوْنٍ أَخْبَرَنَا أَبُو عَوَانَةَ عَنْ مَنْصُورٍ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ ابْنِ عُمَرَ قَالَ قَالَ رَسُولُ اللَّهِ إِنَّ النَّذْرَ لَا يَرُدُّ شَيْئًا وَإِنَّمَا يُسْتَخْرَجُ بِهِ مِنْ الشَّحِيحِ","id":"Telah mengabarkan kepada kami ['Amr bin 'Aun] telah mengabarkan kepada kami [Abu 'Awanah] dari [Manshur] dari [Abdullah bin Murrah] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya nadzar tidak dapat menolak sesuatupun, sesungguhnya itu dikeluarkan dari orang yang pelit.\""},"1881":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا مَالِكُ بْنُ أَنَسٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَدْرَكَ عُمَرَ بْنَ الْخَطَّابِ وَهُوَ يَسِيرُ فِي رَكْبٍ وَهُوَ يَحْلِفُ بِأَبِيهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يَنْهَاكُمْ أَنْ تَحْلِفُوا بِآبَائِكُمْ فَمَنْ كَانَ حَالِفًا فَلْيَحْلِفْ بِاللَّهِ أَوْ لِيَصْمُتْ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Malik Anas] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mendapati Umar bin Al Khathab berjalan di atas tunggangannya tengah bersumpah dengan nenek moyangnya. Nmaka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah melarang kalian bersumpah dengan nama bapak-bapak kalian. Barangsiapa bersumpah, hendaknya ia bersumpah dengan nama Allah atau ia diam.\""},"1882":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ ثُمَّ قَالَ إِنْ شَاءَ اللَّهُ فَقَدْ اسْتَثْنَى","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Ayyub] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barangsiapa bersumpah kemudian berkata; \"Jika Allah menghendaki, \" maka ia telah mengucapkan pengecualian.\""},"1883":{"ar":" أَخْبَرَنَا حَجَّاجٌ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا أَيُّوبُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ حَلَفَ عَلَى يَمِينٍ ثُمَّ قَالَ إِنْ شَاءَ اللَّهُ فَهُوَ بِالْخِيَارِ إِنْ شَاءَ فَعَلَ وَإِنْ شَاءَ لَمْ يَفْعَلْ","id":"Telah mengabarkan kepada kami [Hajjaj] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Ayyub] dari [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah, kemudian mengucapkan insya Allah, maka ia memiliki pilihan, apabila berkehendak, maka ia melakukannya dan apabila berkehendak, maka ia bolehtidak melakukannya.\""},"1884":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي اللَّيْثُ حَدَّثَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لِأَبِي بَكْرٍ لَا تُقْسِمْ قَالَ أَبُو مُحَمَّد الْحَدِيثُ فِيهِ طُولٌ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepada kami [Al Laits] telah menceritakan kepadaku [Yunus] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda kepada Abu Bakr: \"Janganlah engkau bersumpah.\" Abu Muhammad berkata; \"Hadits ini panjang.\""},"1885":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا شُعْبَةُ عَنْ عَمْرٍو هُوَ ابْنُ مُرَّةَ قَالَ سَمِعْتُ رَجُلًا يُقَالُ لَهُ عَبْدُ اللَّهِ بْنُ عَمْرٍو زَمَنَ الْجَمَاجِمِ يُحَدِّثُ قَالَ سَأَلَ رَجُلٌ عَدِيَّ بْنَ حَاتِمٍ فَحَلَفَ أَنْ لَا يُعْطِيَهُ شَيْئًا ثُمَّ قَالَ لَوْلَا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ حَلَفَ عَلَى يَمِينٍ فَرَأَى غَيْرَهَا خَيْرًا مِنْهَا فَلْيَأْتِ الَّذِي هُوَ خَيْرٌ وَلْيُكَفِّرْ عَنْ يَمِينِهِ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Syu'bah] dari ['Amr yaitu Ibnu Hubairah], ia berkata; aku mendengar seorang laki-laki yang bernama [Abdullah bin 'Amr] pada masa tejadinya perang Al Jamajim berkata; \"Seseorang meminta sesuatu kepada ['Adi bin Hatim], namun 'Adi bersumpah untuk tidak akan memberikan sesuatupun. Kemudian ia berkata; \"Seandainya aku tidak mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa bersumpah, kemudian ia melihat ada sesuatu yang lebih baik darinya, hendaknya ia melakukan yang lebih baik dan membayar kafarah sumpahnya.\""},"1886":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْفَضْلِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ حَدَّثَنَا الْحَسَنُ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ سَمُرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا عَبْدَ الرَّحْمَنِ بْنَ سَمُرَةَ لَا تَسْأَلْ الْإِمَارَةَ فَإِنَّكَ إِنْ أُعْطِيتَهَا عَنْ مَسْأَلَةٍ وُكِلْتَ إِلَيْهَا وَإِنْ أُعْطِيتَهَا مِنْ غَيْرِ مَسْأَلَةٍ أُعِنْتَ عَلَيْهَا فَإِذَا حَلَفْتَ عَلَى يَمِينٍ فَرَأَيْتَ غَيْرَهَا خَيْرًا مِنْهَا فَكَفِّرْ عَنْ يَمِينِكَ وَأْتِ الَّذِي هُوَ خَيْرٌ أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا سُفْيَانُ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ سَمُرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَ الْحَدِيثِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Fadhl] telah menceritakan kepada kami [Jarir bin Hazim] telah menceritakan kepada kami [Al Hasan] telah menceritakan kepada kami [Abdurrahman bin Samurah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Abdurrahman bin Samurah, janganlah engkau meminta jabatan, sesungguhnya bila engkau diberi jabatan karena meminta, engkau akan diterlantarkan, namun apabila engkau diberi jabatan dengan tanpa meminta, maka engkau akan ditolong dalam menjalankannya. Dan jika engkau bersumpah, lantas engkau melihat sesuatu yang lebih baik, maka bayarlah kafarah sumpahmu, dan lakukan yang lebih baik.\" Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Sufyan] dari [Yunus] dari [Al Hasan] dari [Abdurrahman bin Samurah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda:....\" kemudian ia menyebutkan hadits seperti di atas."},"1887":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ الطَّيَالِسِيُّ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الشَّرِيدِ قَالَ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ عَلَى أُمِّي رَقَبَةً وَإِنَّ عِنْدِي جَارِيَةً سَوْدَاءَ نُوبِيَّةً أَفَتُجْزِئُ عَنْهَا قَالَ ادْعُ بِهَا فَقَالَ أَتَشْهَدِينَ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَتْ نَعَمْ قَالَ أَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Telah mengabarkan kepada kami [Abu Al Walid Ath Thayalisi] telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin 'Amr] dari [Abu Salamah] dari [Asy Syarid] ia berkata; aku mendatangi Nabi shallallahu 'alaihi wasallam dan berkata; \"Sesungguhnya ibuku kewajiban membebaskan budak, sementara aku memiliki budak wanita berkulit hitam, apakah sah untuknya?\" Beliau menjawab: \"Panggillah dia! \" kemudian beliau berkata: \"Apakah engkau bersaksi bahwa tidak ada Tuhan yang berhak disembah kecuali Allah?\" Budak itu menjawab; \"Ya.\" Beliau bersabda: \"Bebaskan dia, sesungguhnya ia adalah wanita mukminah.\""},"1888":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا هُشَيْمٌ أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَمِينُكَ عَلَى مَا صَدَّقَكَ بِهِ صَاحِبُكَ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami [Husyaim] telah mengabarkan kepada kami [Abdullah bin Abu Shalih] dari [Ayahnya] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sumpahmu adalah sesuatu yang dapat meyakinkan sahabatmu.\""},"1889":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ قَالَ كَانَتْ يَمِينُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الَّتِي يَحْلِفُ بِهَا لَا وَمُقَلِّبِ الْقُلُوبِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Musa bin 'Uqbah] dari [Salim] dari [Ibnu Umar] ia berkata; sumpah Rasulullah shallallahu 'alaihi wasallam yang beliau ucapkan adalah: \"Tidak, demi Dzat yang membolak-balikkan hati.\""},"1890":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْحَقَ عَنْ الْحَارِثِ بْنِ فُضَيْلٍ عَنْ سُفْيَانَ بْنِ أَبِي الْعَوْجَاءِ السُّلَمِيِّ عَنْ أَبِي شُرَيْحٍ الْخُزَاعِيِّ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ أُصِيبَ بِدَمٍ أَوْ خَبْلٍ وَالْخَبْلُ الْجُرْحُ فَهُوَ بِالْخِيَارِ بَيْنَ إِحْدَى ثَلَاثٍ فَإِنْ أَرَادَ الرَّابِعَةَ فَخُذُوا عَلَى يَدَيْهِ بَيْنَ أَنْ يَقْتَصَّ أَوْ يَعْفُوَ أَوْ يَأْخُذَ الْعَقْلَ فَإِنْ أَخَذَ مِنْ ذَلِكَ شَيْئًا ثُمَّ عَدَا بَعْدَ ذَلِكَ فَلَهُ النَّارُ خَالِدًا فِيهَا مُخَلَّدًا","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Muhammad bin Ishaq] dari [Al Harits bin Fudhail] dari [Sufyan bin Abu Al 'Auja` As Sulami] dari [Abu Syuraih Al Khuza'i] ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa diuji dengan terbunuhnya jiwa, atau khabl -khabl adalah luka- maka baginya hak untuk memilih salah satu dari tiga hal, apabila ia menginginkan tambahan yang keempat, maka cegahlah dia. Yaitu antara membalas, atau memaafkan, atau mengambil diat. Apabila ia telah mengambil salah satu dari ketiga hal itu, kemudian melampaui batas setelah itu, maka baginya Neraka, ia kekal di dalamnya.\""},"1891":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَكَانَ فِي كِتَابِهِ أَنَّ مَنْ اعْتَبَطَ مُؤْمِنًا قَتْلًا عَنْ بَيِّنَةٍ فَإِنَّهُ قَوَدُ يَدِهِ إِلَّا أَنْ يَرْضَى أَوْلِيَاءُ الْمَقْتُولِ قَالَ أَبُو مُحَمَّد اعْتَبَطَ قَتَلَ مِنْ غَيْرِ عِلَّةٍ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepada penduduk Yaman, dan diantara isi suratnya adalah: \"Barangsiapa membunuh seorang mukmin secara lalim dengan tanpa bukti yang jelas, maka ia mendapatkan balasan, kecuali apabila para wali orang yang dibunuh merasa rela.\" Abu Muhammad berkata; \"I'tabatha adalah membunuh tanpa alasan yang hak.\""},"1892":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنَا بُشَيْرُ بْنُ يَسَارٍ عَنْ سَهْلِ بْنِ أَبِي حَثْمَةَ قَالَ خَرَجَ عَبْدُ اللَّهِ بْنُ سَهْلٍ أَحَدُ بَنِي حَارِثَةَ إِلَى خَيْبَرَ مَعَ نَفَرٍ مِنْ قَوْمِهِ يُرِيدُونَ الْمِيرَةَ بِخَيْبَرَ قَالَ فَعُدِيَ عَلَى عَبْدِ اللَّهِ فَقُتِلَ فَتُلَّتْ عُنُقُهُ حَتَّى نُخِعَ ثُمَّ طُرِحَ فِي مَنْهَلٍ مِنْ مَنَاهِلِ خَيْبَرَ فَاسْتُصْرِخَ عَلَيْهِ أَصْحَابُهُ فَاسْتَخْرَجُوهُ فَغَيَّبُوهُ ثُمَّ قَدِمُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَدِينَةَ فَتَقَدَّمَ أَخُوهُ عَبْدُ الرَّحْمَنِ بْنُ سَهْلٍ وَكَانَ ذَا قِدَمٍ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَابْنَا عَمِّهِ مَعَهُ حُوَيِّصَةُ بْنُ مَسْعُودٍ وَمُحَيِّصَةُ فَتَكَلَّمَ عَبْدُ الرَّحْمَنِ وَكَانَ أَحْدَثَهُمْ سِنًّا وَهُوَ صَاحِبُ الدَّمِ وَذَا قَدَمٍ فِي الْقَوْمِ فَلَمَّا تَكَلَّمَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْكُبْرَ الْكُبْرَ قَالَ فَاسْتَأْخَرَ فَتَكَلَّمَ حُوَيِّصَةُ وَمُحَيِّصَةُ ثُمَّ هُوَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسَمُّونَ قَاتِلَكُمْ ثُمَّ تَحْلِفُونَ عَلَيْهِ خَمْسِينَ يَمِينًا ثُمَّ نُسَلِّمُهُ إِلَيْكُمْ قَالُوا يَا رَسُولَ اللَّهِ مَا كُنَّا لِنَحْلِفَ عَلَى مَا لَا نَعْلَمُ مَا نَدْرِي مَنْ قَتَلَهُ إِلَّا أَنَّ يَهُودَ عَدُوُّنَا وَبَيْنَ أَظْهُرِهِمْ قُتِلَ قَالَ فَيَحْلِفُونَ لَكُمْ بِاللَّهِ إِنَّهُمْ لَبُرَءَاءُ مِنْ دَمِ صَاحِبِكُمْ ثُمَّ يَبْرَءُونَ مِنْهُ قَالُوا مَا كُنَّا لِنَقْبَلَ أَيْمَانَ يَهُودَ مَا فِيهِمْ أَكْبَرُ مِنْ أَنْ يَحْلِفُوا عَلَى إِثْمٍ قَالَ فَوَدَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ عِنْدِهِ بِمِائَةِ نَاقَةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad bin Ishaq] telah menceritakan kepada kami [Busyair bin Yasar] dari [Sahl bin Abu Hatsmah] ia berkata; Abdullah bin Sahl -salah seorang Bani Haritsah- keluar menuju Khaibar bersama beberapa orang dari kaumnya. Mereka hendak mengambil kurma di Khaibar. Sahl bin Abu Hatsmah berkata; \"Kemudian Abdullah bin Sahl dibunuh dan lehernya dipotong dan dicampakkan ke dalam satu sumur di Khaibar. Kemudian para sahabatnya berteriak meminta tolong, setelah mereka mengeluarkan jasadnya dan menguburkannya, mereka datang menemui Rasulullah shallallahu 'alaihi wasallam di Madinah, lalu saudaranya yaitu Abdurrahman bin Sahl -ia telah lama bersama Rasulullah shallallahu 'alaihi wasallam bersama- bersama dua orang anak pamannya yaitu Huwayyishah dan Muhayyishah menemui beliau, Abdurrahman angkat bicara - ia adalah orang yang paling muda diantara mereka, orang yang memiliki hak terhadap darah tersebut dan orang yang masuk Islam lebih dulu daripada mereka- Tatkala ia berbicara, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya orang yang lebih tua yang angkat bicara lebih dulu, Hendaknya orang yang lebih tua yang angkat bicara lebih dulu, \" Sahl bin Abu Hatsmah berkata; \"Kemudian Abdurrahman mundur dan Huwayyishah serta Muhayyishah berbicara, setelah itu ia angkat bicara. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah kalian dapat menyebutkan orang yang membunuh, kemudian kalian bersumpah atasnya sebanyak lima puluh kali, maka kami menyerahkan orang tersebut kepada kalian.\" Mereka berkata; \"Wahai Rasulullah, kami tidak dapat bersumpah terhadap sesuatu yang tidak kami ketahui, kami tidak mengerti siapa yang membunuhnya. Hanya saja orang-orang Yahudi adalah musuh kita, dan orang yang berada di antara mereka akan ia bunuh. Beliau bersabda: \"Apakah mereka bersumpah untuk kalian dengan nama Allah sehingga mereka bebas dari darah sahabat kalian?\" Mereka berkata; \"Sumpah orang-orang Yahudi, tidak ada sesuatu yang lebih besar bagi mereka daripada mereka harus bersumpah atas perbuatan dosa.\" Sahl bin Abu Hatsmah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam menebusnya dengan seratus ekor unta milik beliau."},"1893":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَكَانَ فِي كِتَابِهِ أَنَّ الرَّجُلَ يُقْتَلُ بِالْمَرْأَةِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat kepada penduduk Yaman, diantara isi suratnya adalah bahwa orang laki-laki dibunuh apabila membunuh wanita."},"1894":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا هَمَّامٌ حَدَّثَنَا قَتَادَةُ عَنْ أَنَسٍ أَنَّ جَارِيَةً رُضَّ رَأْسُهَا بَيْنَ حَجَرَيْنِ فَقِيلَ لَهَا مَنْ فَعَلَ بِكِ هَذَا أَفُلَانٌ أَفُلَانٌ حَتَّى سُمِّيَ الْيَهُودِيُّ فَأَوْمَأَتْ بِرَأْسِهَا فَبُعِثَ إِلَيْهِ فَجِيءَ بِهِ فَاعْتَرَفَ فَأَمَرَ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرُضَّ رَأْسُهُ بَيْنَ حَجَرَيْنِ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Hammam] telah menceritakan kepada kami [Qatadah] dari [Anas] bahwa seorang wanita dijepit kepalanya diantara dua bongkah batu. Kemudian ia ditanya; \"Siapakah yang melakukan hal ini kepadamu? Apakah Fulan? Apakah Fulan?, \" Hingga disebutkan seorang Yahudi, wanita itu pun menganggukkan kepalanya. Lalu seorang utusan dikirim untuk menemui orang Yahudi itu, lalu ia didatangkan. Setelah Yahudi itu mengaku, maka Nabi shallallahu 'alaihi wasallam memerintahkan supaya kepalanya dijepit di antara dua bongkah batu.\""},"1895":{"ar":" أَخْبَرَنَا إِسْحَقُ أَخْبَرَنَا جَرِيرٌ عَنْ مُطَرِّفٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي جُحَيْفَةَ قَالَ قُلْتُ لِعَلِيٍّ يَا أَمِيرَ الْمُؤْمِنِينَ هَلْ عَلِمْتَ شَيْئًا مِنْ الْوَحْيِ إِلَّا مَا فِي كِتَابِ اللَّهِ تَعَالَى قَالَ لَا وَالَّذِي فَلَقَ الْحَبَّةَ وَبَرَأَ النَّسَمَةَ مَا أَعْلَمُهُ إِلَّا فَهْمًا يُعْطِيهِ اللَّهُ الرَّجُلَ فِي الْقُرْآنِ وَمَا فِي الصَّحِيفَةِ قُلْتُ وَمَا فِي الصَّحِيفَةِ قَالَ الْعَقْلُ وَفِكَاكُ الْأَسِيرِ وَلَا يُقْتَلُ مُسْلِمٌ بِمُشْرِكٍ","id":"Telah mengabarkan kepada kami [Ishaq] telah mengabarkan kepada kami [Jarir] dari [Mutharrif] dari [Asy Sya'bi] dari [Abu Juhaifah] ia berkata; aku berkata kepada [Ali]; \"Wahai amirul mukminin, apakah anda mengetahui sesuatu dari wahyu selain yang ada dalam Kitabullah Ta'ala?\" Dia menjawab; \"Tidak, demi Dzat yang menumbuhkan biji, dan menciptakan jiwa, kecuali pemahaman yang Allah berikan kepada seseorang mengenai Al Qur'an, dan apa yang ada dalam lembaran ini.\" Aku berkata; \"Apa yang ada dalam lembaran tersebut?, \" Dia berkata; \"Isinya adalah diyat, pembebasan tawanan, dan seorang muslim tidak dibunuh lantaran (membunuh) orang musyrik.\""},"1896":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَونٍ عَنْ إِسْمَعِيلَ بْنِ مُسْلِمٍ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُقَامُ الْحُدُودُ فِي الْمَسَاجِدِ وَلَا يُقَادُ بِالْوَلَدِ الْوَالِدُ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Isma'il bin Muslim] dari ['Amr bin Dinar] dari [Thawus] dari [Ibnu Abbas] ia berkata; Nabi shallallahu 'alaihi wasallam bersabda: \"Hukuman had tidak boleh ditegakkan di dalam masjid, dan tidak ada qishash orang tua terhadap anaknya.\""},"1897":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ سَعِيدٍ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ قَتَلَ عَبْدَهُ قَتَلْنَاهُ وَمَنْ جَدَعَهُ جَدَعْنَاهُ قَالَ ثُمَّ نَسِيَ الْحَسَنُ هَذَا الْحَدِيثَ وَكَانَ يَقُولُ لَا يُقْتَلُ حُرٌّ بِعَبْدٍ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundub] bahwa Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membunuh seorang budak, maka kami akan membunuhnya, dan barangsiapa memotong hidungnya, maka kami akan memotong hidungnya.\" Perawi berkata; kemudian Al Hasan lupa hadits ini, dahulu ia mengatakan; \"Orang yang meredeka tidak dibunuh lantara (membunuh) seorang budak.\""},"1898":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ الْهَمْدَانِيُّ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ عَوْفٍ عَنْ حَمْزَةَ أَبِي عُمَرَ عَنْ عَلْقَمَةَ بْنِ وَائِلٍ الْحَضْرَمِيِّ عَنْ أَبِيهِ وَائِلِ بْنِ حُجْرٍ قَالَ شَهِدْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُتِيَ بِالرَّجُلِ الْقَاتِلِ يُقَادُ فِي نِسْعَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِوَلِيِّ الْمَقْتُولِ أَتَعْفُو قَالَ لَا قَالَ فَتَأْخُذُ الدِّيَةَ قَالَ لَا قَالَ فَتَقْتُلُهُ قَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّكَ إِنْ عَفَوْتَ عَنْهُ فَإِنَّهُ يَبُوءُ بِإِثْمِكَ وَإِثْمِ صَاحِبِكَ قَالَ فَتَرَكَهُ قَالَ فَأَنَا رَأَيْتُهُ يَجُرُّ نِسْعَتَهُ قَدْ عَفَا عَنْهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah Al Hamdani] telah menceritakan kepada kami [Abu Usamah] dari ['Auf] dari [Hamzah Abu Umar] dari ['Alqamah bin Wa`il Al Hadhrami] dari ayahnya yaitu [Wa`il bin Hujr] ia berkata; \"Aku menyaksikan Nabi shallallahu 'alaihi wasallam ketika didatangkan seorang pembunuh yang dituntun oleh keluarga terbunuh dalam keadaan terikat. Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya kepada wali korban itu: \"Apakah engkau mema'afkan?\" Ia berkata; \"Tidak.\" Beliau bersabda: \"Apakah engkau meminta tebusan?\" Ia berkata; \"Tidak.\" Beliau bersabda: \"Apakah engkau akan membunuhnya?\" Ia berkata; \"Ya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sekiranya engkau memaafkannya, maka ia akan membawa dosamu dan dosa sahabatmu.\" Wa`il bin Hujr berkata; \"Kemudian wali korban membiarkannya. Wa`il berkata; \"Setelah itu aku melihat orang yang membunuh menarik tali kekangnya dan wali orang yang dibunuh tersebut telah mema'afkannya.\""},"1899":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ حَدَّثَنَا شُعْبَةُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْكَبَائِرُ الْإِشْرَاكُ بِاللَّهِ وَعُقُوقُ الْوَالِدَيْنِ وَقَتْلُ النَّفْسِ شُعْبَةُ الشَّاكُّ أَوْ الْيَمِينُ الْغَمُوسُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basyar] telah menceritakan kepada kami [Muhammad bin Ja'far] telah menceritakan kepada kami [Syu'bah] dari [Firas] dari [Asy Sya'bi] dari [Abdullah bin 'Amr] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Dosa-dosa besar adalah mensekutukan Allah, durhaka kepada kedua orang tua, dan membunuh jiwa.\" -Syu'bah ragu dengan redaksi haditsnya- Atau sumpah palsu.\""},"1900":{"ar":" حَدَّثَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي قِلَابَةَ عَنْ ثَابِتِ بْنِ الضَّحَّاكِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَعْنُ الْمُؤْمِنِ كَقَتْلِهِ وَمَنْ قَتَلَ نَفْسَهُ بِشَيْءٍ فِي الدُّنْيَا عُذِّبَ بِهِ يَوْمَ الْقِيَامَةِ","id":"Telah menceritakan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Qilabah] dari [Tsabit bin Adh Dhahhak] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Melaknat seorang mukmin seperti membunuhnya, barangsiapa bunuh diri dengan sesuatu di Dunia, maka ia disiksa dengan alat tersebut pada Hari Kiamat.\""},"1901":{"ar":" حَدَّثَنَا يَعْلَى بْنُ عُبَيْدٍ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَتَلَ نَفْسَهُ بِحَدِيدَةٍ فَحَدِيدَتُهُ فِي يَدِهِ يَتَوَجَّأُ بِهَا فِي بَطْنِهِ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ قَتَلَ نَفْسَهُ بِسُمٍّ فَسُمُّهُ فِي يَدِهِ يَتَحَسَّاهُ فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا وَمَنْ تَرَدَّى مِنْ جَبَلٍ فَقَتَلَ نَفْسَهُ فَهُوَ يَتَرَدَّى فِي نَارِ جَهَنَّمَ خَالِدًا مُخَلَّدًا فِيهَا أَبَدًا","id":"Telah menceritakan kepada kami [Ya'la bin 'Ubaid] telah menceritakan kepada kami [Al A'masy] dari [Abu Shalih] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dan barangsiapa bunuh diri dengan (menusuk dirinya dengan) besi, maka besi itu akan ada di tangannya, dan ia akan menghujamkan ke perutnya di neraka jahannam, ia kekal dan abadi di dalamnya selama-lamanya. Barangsiapa menegak racun, hingga meninggal dunia, maka racun tersebut akan berada di tangannya, dan ia akan menegaknya di neraka jahannam, ia kekal serta abadi di dalamnya selama-lamanya. Barangsiapa menjatuhkan diri dari gunung, hingga mmebunuh jiwanya (bunuh diri), maka ia akan jatuh ke neraka jahannam, ia kekal serta abadi di dalamnya selama-lamanya.\""},"1902":{"ar":" حَدَّثَنَا مُعَاذُ بْنُ هَانِئٍ حَدَّثَنَا مُحَمَّدُ بْنُ مُسْلِمٍ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَ قَتَلَ رَجُلٌ رَجُلًا عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَعَلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَتَهُ اثْنَيْ عَشَرَ أَلْفًا فَذَلِكَ قَوْلُهُ { وَمَا نَقَمُوا إِلَّا أَنْ أَغْنَاهُمْ اللَّهُ وَرَسُولُهُ مِنْ فَضْلِهِ } بِأَخْذِهِمْ الدِّيَةَ","id":"Telah menceritakan kepada kami [Mu'adz bin Hani`] telah menceritakan kepada kami [Muhammad bin Muslim] telah menceritakan kepada kami ['Amr bin Dinar] dari [Ikrimah] dari [Ibnu Abbas], ia berkata; \"Seorang laki-laki membunuh laki-laki lain pada masa Rasulullah shallallahu 'alaihi wasallam. Kemudian Nabi shallallahu 'alaihi wasallam menetapkan bahwa diyatnya dua belas ribu. Yang demikian itu adalah firman Allah Dan mereka tidak mencela (Allah dan Rasul-Nya), kecuali karena Allah dan Rasul-Nya telah melimpahkan karunia-Nya kepada mereka. QS At Taubah; 74, Yaitu dalam masalah pengambilan diyat."},"1903":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَعَلَى أَهْلِ الذَّهَبِ أَلْفُ دِينَارٍ","id":"Telah menceritakan kepada kami [Al Hakam] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] ia berkata; telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amar bin Hazm] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam telah menulis surat kepada penduduk Yaman: \".... dan atas para pemilik emas seribu dinar.\""},"1904":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ مِنْ مُحَمَّدٍ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شُرَحْبِيلَ بْنِ عَبْدِ كُلَالٍ وَالْحَارِثِ بْنِ عَبْدِ كُلَالٍ وَنُعَيْمِ بْنِ عَبْدِ كُلَالٍ قِيَلِ ذِي رُعَيْنٍ وَمَعَافِرَ وَهَمَدَانَ فَكَانَ فِي كِتَابِهِ وَإِنَّ فِي النَّفْسِ الدِّيَةَ مِائَةٌ مِنْ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amru bin Hazm] dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menulis (surat) kepada penduduk Yaman: \"BISMILLAAHIR RAHMAANIR RAHIIM dari Muhmammad seorang Nabi shallallahu 'alaihi wasallam, kepada Syurahbil bin Abdu Kulal dan Al Harits bin Abdul Kulal serta Nu'aim bin Abdul Kulal di Qail Ru'ain, Ma'afir dan Hamadan..\" -Dan diantara isi surat tersebut adalah- \".... bahwa untuk jiwa, diyatnya seratus ekor unta.\""},"1905":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَكَانَ فِي كِتَابِهِ وَفِي الْأَنْفِ إِذَا أُوعِبَ جَدْعُهُ الدِّيَةُ وَفِي اللِّسَانِ الدِّيَةُ وَفِي الشَّفَتَيْنِ الدِّيَةُ وَفِي الْبَيْضَتَيْنِ الدِّيَةُ وَفِي الذَّكَرِ الدِّيَةُ وَفِي الصُّلْبِ الدِّيَةُ وَفِي الْعَيْنَيْنِ الدِّيَةُ وَفِي الرِّجْلِ الْوَاحِدَةِ نِصْفُ الدِّيَةِ وَفِي الْمَأْمُومَةِ ثُلُثُ الدِّيَةِ وَفِي الْجَائِفَةِ ثُلُثُ الدِّيَةِ وَفِي الْمُنَقِّلَةِ خَمْسَ عَشَرَةَ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menulis surat kepada penduduk Yaman, dan diantara isi suratnya adalah, \".....untuk hidung apabila dipotong, semuanya adalah satu diyat, untuk lidah satu diyat, untuk dua bibir satu diyat, dua buah pelir satu diyat, penis satu diyat, tulang belakang satu diyat, dua mata satu diyat, satu kaki setengah diyat, luka yang sampai kepada otak, sepertiga diyat, luka dalam sepertiga diyat, tulang retak dan bergeser lima belas unta.\""},"1906":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ حَجَّاجٍ عَنْ زَيْدِ بْنِ جُبَيْرٍ عَنْ خِشْفِ بْنِ مَالِكٍ عَنْ عَبْدِ اللَّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَعَلَ الدِّيَةَ فِي الْخَطَإِ أَخْمَاسًا","id":"Telah mengabarkan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hajjaj] dari [Zaid bin Jubair] dari [Khisyf bin Malik] dari [Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam menjadikan diyat karena tidak disengaja adalah akhmas.\" "},"1907":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ عَنْ أَبِيهِ عَنْ قَتَادَةَ عَنْ أَبِي نَضْرَةَ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ عَبْدًا لِأُنَاسٍ فُقَرَاءَ قَطَعَ يَدَ غُلَامٍ لِأُنَاسٍ أَغْنِيَاءَ فَأَتَى أَهْلُهُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ لِأُنَاسٍ فُقَرَاءَ فَلَمْ يَجْعَلْ عَلَيْهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i] telah menceritakan kepadaku [Mu'adz bin Hisyam] dari [Ayahnya] dari [Qatadah] dari [Abu Nadhrah] dari [Imran bin Hushain] bahwa seorang budak orang fakir telah memotong tangan budak orang kaya, kemudian pemiliknya datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; \"Wahai Rasulullah, sesungguhnya budak itu milik orang-orang fakir. Kemudian Nabi shallallahu 'alaihi wasallam tidak memberikan padanya sesuatupun.\""},"1908":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ غَالِبٍ التَّمَّارِ عَنْ مَسْرُوقِ بْنِ أَوْسٍ عَنْ أَبِي مُوسَى الْأَشْعَرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَصَابِعُ سَوَاءٌ قَالَ فَقُلْتُ عَشْرٌ عَشْرٌ قَالَ نَعَمْ","id":"Telah menceritakan kepada kami [Nu'aim] telah menceritakan kepada kami [Syu'bah] dari [Ghalib At Tammar] dari [Masruq bin Aus] dari [Abu Musa Al Asy'ari] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Ini dan ini adalah sama.\" Kemudian aku berkata; \"Sepuluh, sepuluh?.\" Beliau bersabda: \"Ya.\""},"1909":{"ar":" حَدَّثَنَا أَبُو نُعَيْمٍ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ هَذَا وَهَذَا سَوَاءٌ وَقَالَ بِخِنْصِرِهِ وَإِبْهَامِهِ","id":"Telah menceritakan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Ikrimah] dari [Ibnu Abbas] dari [Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Ini dan ini adalah sama.\" Beliau memberi isyarat dengan menunjukkan jari kelingking dan ibu jari beliau.\""},"1910":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ حَدَّثَنِي أَبُو بَكْرِ بْنُ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَفِي كُلِّ إِصْبَعٍ مِنْ أَصَابِعِ الْيَدِ وَالرِّجْلِ عَشْرٌ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] telah menceritakan kepadaku [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat kepada penduduk Yaman, \".... dan untuk setiap jari dari jari-jari tangan dan kaki sepuluh unta.\""},"1911":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ حَدَّثَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ مَطَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْمَوَاضِحِ خَمْسًا خَمْسًا مِنْ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah menceritakan kepada kami ['Abdah] dari [Sa'id] dari [Mathar] dari ['Amr bin Syu'aib] dari [Ayahnya] dari [Kakeknya], ia berkata; Rasulullah shallallahu 'alaihi wasallam memutuskan untuk luka dalam hingga terlihat tulangnya adalah denda lima, yaitu lima ekor unta.\""},"1912":{"ar":" حَدَّثَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَفِي كُلِّ إِصْبَعٍ مِنْ أَصَابِعِ الْيَدِ وَالرِّجْلِ عَشْرٌ مِنْ الْإِبِلِ وَفِي الْمُوضِحَةِ خَمْسٌ مِنْ الْإِبِلِ","id":"Telah menceritakan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam menulis surat kepada penduduk Yaman: \"...dan untuk setiap jari diantara jari-jari tangan dan kaki (dendanya adalah) sepuluh ekor unta dan untuk luka dalam hingga terlihat tulangnya adalah lima ekor unta.\""},"1913":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ مُحَمَّدٍ أَخْبَرَنَا عَبْدَةُ عَنْ سَعِيدٍ عَنْ مَطَرٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْأَسْنَانِ خَمْسًا خَمْسًا مِنْ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Utsman bin Muhammad] telah mengabarkan kepada kami ['Abdah] dari [Sa'id] dari [Mathar] dari ['Amr bin Syu'aib] dari [Ayahnya] dari [Kakeknya] ia berkata; \"Rasulullah shallallahu 'alaihi wasallam memutuskan untuk gigi (dendanya adalah) lima, yaitu lima ekor unta.\""},"1914":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ مُوسَى حَدَّثَنَا يَحْيَى بْنُ حَمْزَةَ عَنْ سُلَيْمَانَ بْنِ دَاوُدَ حَدَّثَنِي الزُّهْرِيُّ عَنْ أَبِي بَكْرِ بْنِ مُحَمَّدِ بْنِ عَمْرِو بْنِ حَزْمٍ عَنْ أَبِيهِ عَنْ جَدِّهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَتَبَ إِلَى أَهْلِ الْيَمَنِ وَفِي السِّنِّ خَمْسٌ مِنْ الْإِبِلِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Musa] telah menceritakan kepada kami [Yahya bin Hamzah] dari [Sulaiman bin Daud] telah menceritakan kepadaku [Az Zuhri] dari [Abu Bakr bin Muhammad bin 'Amr bin Hazm] dari [Ayahnya] dari [Kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam pernah menulis surat kepada penduduk Yaman: \"...untuk gigi (dendanya) lima ekor unta.\""},"1915":{"ar":" حَدَّثَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ قَالَ قَتَادَةُ أَخْبَرَنِي قَالَ سَمِعْتُ زُرَارَةَ بْنَ أَوْفَى عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ رَجُلًا عَضَّ يَدَ رَجُلٍ قَالَ فَنَزَعَ يَدَهُ فَوَقَعَتْ ثَنِيَّتَاهُ فَاخْتَصَمُوا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَعَضُّ أَحَدُكُمْ أَخَاهُ كَمَا يَعَضُّ الْفَحْلُ لَا دِيَةَ لَكَ","id":"Telah menceritakan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah]. - [Qatadah] mengatakan; telah mengabarkan kepadaku- ia berkata; aku mendengar [Zurarah bin Aufa] dari ['Imran bin Hushain] bahwa seorang laki-laki menggigit tangan laki-laki lain, kemudian laki-laki tersebut menarik tangannya hingga dua gigi seri (orang yang menggigit) tanggal, mereka akhirnya mempermasalahkan kepada Rasulullah shallallahu 'alaihi wasallam. Beliau bersabda: \"Salah seorang diantara kalian menggigit saudaranya seperti kuda pejantan menggigit, engkau tidak mendapatkan diyat.\""},"1916":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْعَجْمَاءُ جُرْحُهَا جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah menceritakan kepada kami [Muhammad bin 'Amr] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Binatang ternak yang mencelakakan tidak ada kewajiban diyat, sumur yang mencelakai juga tak ada kewajiban diyat, Pertambangan (yang mencelakai juga) tak ada kewajiban diyat, dan harta karun zakatnya seperlima.\""},"1917":{"ar":" أَخْبَرَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جُرْحُ الْعَجْمَاءِ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَالْمَعْدِنُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah mengabarkan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Sa'id bin Al Musayyab] dan [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Binatang ternak yang mencelakakan tidak ada kewajiban diyat, sumur yang mencelakai juga tak ada kewajiban diyat, Pertambangan (yang mencelakai juga) tak ada kewajiban diyat, dan harta karun zakatnya seperlima.\""},"1918":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمَعْدِنُ جُبَارٌ وَالسَّائِمَةُ جُبَارٌ وَالْبِئْرُ جُبَارٌ وَفِي الرِّكَازِ الْخُمُسُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Pertambangan (yang mencelakai) tidak ada kewajiban diyat, binatang ternak yang mencelakakan tidak ada kewajiban diyat, sumur yang mencelakai juga tak ada kewajiban diyat, dan harta karun zakatnya seperlima.\""},"1919":{"ar":" حَدَّثَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عُبَيْدِ بْنِ نُضَيْلَةَ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّ امْرَأَتَيْنِ كَانَتَا تَحْتَ رَجُلٍ فَتَغَايَرَتَا فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِعَمُودٍ فَقَتَلَتْهَا وَمَا فِي بَطْنِهَا فَاخْتَصَمَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى فِيهِ غُرَّةً وَجَعَلَهَا عَلَى عَاقِلَةِ الْمَرْأَةِ","id":"Telah menceritakan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] dari [Manshur] dari [Ibrahim] dari ['Ubaid bin Nudhailah] dari [Al Mughirah bin Syu'bah] dari Nabi shallallahu 'alaihi wasallam bahwa dua isteri dari seorang laki-laki saling menaruh rasa cemburu, kemudian salah seorang darinya memukul isterinya yang lain dengan tiang hingga membunuhnya dan membunuh janin yang ada dalam perutnya. Kemudian mereka mempermasalahkan kepada Rasulullah shallallahu 'alaihi wasallam, beliau lalu memutuskan diyat janin tersebut adalah seorang budak, dan beliau membebankannya kepada wali wanita tersebut.\""},"1920":{"ar":" حَدَّثَنَا أَبُو عَاصِمٍ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَمْرٍو هُوَ ابْنُ دِينَارٍ عَنْ طَاوُسٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ عُمَرَ نَشَدَ النَّاسَ قَضَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الْجَنِينِ فَقَامَ حَمَلُ بْنُ مَالِكِ بْنِ النَّابِغَةِ فَقَالَ كُنْتُ بَيْنَ امْرَأَتَيْنِ فَضَرَبَتْ إِحْدَاهُمَا الْأُخْرَى بِمِسْطَحٍ فَقَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي جَنِينِهَا بِغُرّ��ةٍ وَأَنْ تُقْتَلَ بِهَا","id":"Telah menceritakan kepada kami [Abu 'Ashim] telah menceritakan kepada kami [Ibnu Juraij] dari ['Amr yaitu Ibnu Dinar] dari [Thawus] dari [Ibnu Abbas] bahwa Umar bertanya kepada orang-orang mengenai keputusan Rasulullah shallallahu 'alaihi wasallam tentang janin. Maka [Hamal bin Malik bin An Nabighah] berdiri dan berkata; \"Aku pernah berada diantara dua orang wanita, salah seorang diantara mereka memukul yang lainnya menggunakan tiang, kemudian Rasulullah shallallahu 'alaihi wasallam memutuskan diyat untuk janinnya adalah seorang budak, dan wanita tersebut dibunuh karena ia telah membunuh wanita yang lain.\""},"1921":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ أَنَّ امْرَأَتَيْنِ مِنْ هُذَيْلٍ اقْتَتَلَتَا فَرَمَتْ إِحْدَاهُمَا الْأُخْرَى بِحَجَرٍ فَقَتَلَتْهَا وَمَا فِي بَطْنِهَا فَاخْتَصَمُوا فِي الدِّيَةِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَضَى أَنَّ دِيَةَ جَنِينِهَا غُرَّةُ عَبْدٍ أَوْ وَلِيدَةٍ وَقَضَى بِدِيَتِهَا عَلَى عَاقِلَتِهَا وَوَرِثَتْهَا وَرَثَتُهَا وَلَدُهَا وَمَنْ مَعَهَا فَقَالَ حَمَلُ بْنُ النَّابِغَةِ الْهُذَلِيُّ كَيْفَ أُغَرَّمُ مَنْ لَا شَرِبَ وَلَا أَكَلَ وَلَا نَطَقَ وَلَا اسْتَهَلَّ فَمِثْلُ ذَلِكَ يُطَلُّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا هُوَ مِنْ إِخْوَانِ الْكُهَّانِ مِنْ أَجْلِ سَجْعِهِ الَّذِي سَجَعَ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] serta [Abu Salamah] dari [Abu Hurairah] bahwa dua orang wanita dari Hudzail berkelahi, kemudian salah seorang dari mereka melempar wanita lain menggunakan batu hingga membunuhnya serta (membunuh) janin yang ada dalam perutnya. Kemudian mereka mempermasalahkan diyahtnya kepada Rasulullah shallallahu 'alaihi wasallam. Akhirnya beliau memutuskan bahwa diyat janinnya adalah seorang budak laki-laki atau perempuan dan beliau memutuskan diyatnya ditanggung oleh para walinya, dan wanita yang terbunuh diwarisi oleh para pewarisnya yaitu anaknya dan yang bersama dengannya. Lantas Hamal bin An Nabighah Al Hudzali berkata; \"Bagaimana aku menanggung denda orang yang belum makan dan minum?, tidak berbicara serta menangis? (Bukankah) yang seperti ini (termasuk) sesuatu yang dibatalkan?\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya (bayi) ini termasuk di antara saudara dukun karena kalimat sajak yang ia ucapkan.\""},"1922":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا شُعْبَةُ عَنْ أَيُّوبَ عَنْ الْقَاسِمِ بْنِ رَبِيعَةَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِيَةُ قَتِيلِ الْخَطَإِ شِبْهِ الْعَمْدِ وَمَا كَانَ بِالسَّوْطِ وَالْعَصَا مِنْهَا أَرْبَعُونَ فِي بُطُونِهَا أَوْلَادُهَا","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Syu'bah] dari [Ayyub] dari [Al Qasim bin Rabi'ah] dari [Abdullah bin 'Amr], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang terbunuh karena tidak sengaja adalah mirip dengan orang yang terbunuh karena disiksa dengan cambuk, atau tongkat, diyatnya adalah seratus unta, empat puluh di antaranya sedang bunting.\""},"1923":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ السَّاعِدِيِّ أَخْبَرَهُ أَنَّ رَجُلًا اطَّلَعَ مِنْ جُحْرٍ فِي حُجْرَةِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِدْرًى يُخَلِّلُ بِهَا رَأْسَهُ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَوْ أَعْلَمُ أَنَّكَ تَنْظُرُنِي لَطَعَنْتُ بِهَا فِي عَيْنَيْكَ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا جُعِلَ الْإِذْنُ مِنْ أَجْلِ النَّظَرِ","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Al Auza'i] dari [Az Zuhri] dari [Sahl bin Sa'd As Sa'idi] telah mengabarkan kepada kami, bahwa seorang laki-laki mengintip dari lubang kamar Nabi shallallahu 'alaihi wasallam, ketika itu Rasulullah shallallahu 'alaihi wasallam sedang membawa sisir untuk menggaruk kepalanya, tatkala Rasulullah shallallahu 'alaihi wasallam melihatnya, beliau bersabda: \"Jika aku mengetahui kamu mengintipku, sungguh aku akan menusukkan ini ke matamu, sesungguhnya diberlakukannya meminta izin itu karena pandangan.\""},"1924":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ بَيْنَمَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي حُجْرَةٍ وَمَعَهُ مِدْرًى يَحُكُّ بِهِ رَأْسَهُ اطَّلَعَ إِلَيْهِ رَجُلٌ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ أَعْلَمُ أَنَّكَ تَنْظُرُ لَقُمْتُ حَتَّى أَطْعَنَ بِهِ عَيْنَيْكَ إِنَّمَا جُعِلَ الْإِذْنُ مِنْ أَجْلِ النَّظَرِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Ibnu Abu Dzi`b] dari [Az Zuhri] dari [Sahl bin Sa'd], ia berkata; \"Ketika Rasulullah shallallahu 'alaihi wasallam berada dalam kamar, sementara beliau membawa sisir untuk menggaruk kepalanya, seorang laki-laki mengintip beliau, maka Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Seandainya aku mengetahui engkau mengintip, niscaya aku berdiri hingga menusuk matamu, sesungguhnya diberlakukannya meminta izin karena pandangan.\""},"1925":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ مُطِيعٍ عَنْ مُطِيعٍ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ فَتْحِ مَكَّةَ لَا يُقْتَلُ قُرَشِيٌّ صَبْرًا بَعْدَ هَذَا الْيَوْمِ إِلَى يَوْمِ الْقِيَامَةِ حَدَّثَنَا يَعْلَى حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ قَالَ قَالَ عَبْدُ اللَّهِ بْنُ مُطِيعٍ سَمِعْتُ مُطِيعًا يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ نَحْوَهُ قَالَ أَبُو مُحَمَّد فَسَّرُوا ذَلِكَ أَنْ لَا يُقْتَلَ قُرَشِيٌّ عَلَى الْكُفْرِ يَعْنِي لَا يَكُونُ هَذَا أَنْ يَكْفُرَ قُرَشِيٌّ بَعْدَ ذَلِكَ الْيَوْمِ فَأَمَّا فِي الْقَوَدِ فَيُقْتَلُ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] dari [Zakariya] dari [Asy Sya'bi] dari [Abdullah bin Muthi'] dari [Muthi'], ia berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada saat penaklukan kota Makkah: \"Orang-orang Quraisy tidak akan di bunuh dengan cara di ikat dan di lempari batu sampai mati setelah hari ini, hingga hari kiamat.\" Telah menceritakan kepada kami [Ya'la] telah menceritakan kepada kami [Zakariya] dari ['Amir] ia berkata; [Abdullah bin Muthi'] berkata; Aku mendengar [Muthi'] berkata; aku mendengar Rasulullah shallallahu 'alaihi wasallam...\" kemudian ia menyebutkan sama seperti hadits di atas. Abu Muhammad berkata; mereka mentafsirkan hal itu, bahwa tidak ada seorang Quraisypun yang dibunuh dalam keadaan kafir, yaitu tidak ada seorang Quraisypun yang kafir setelah hari itu. Jika dalam masalah qishash, maka ia dibunuh dengan cara demikian."},"1926":{"ar":" أَخْبَرَنَا يُونُسُ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ يَعْنِي ابْنَ حَازِمٍ قَالَ سَمِعْتُ عَبْدَ الْمَلِكِ بْنَ عُمَيْرٍ حَدَّثَنِي إِيَادُ بْنُ لَقِيطٍ عَنْ أَبِي رِمْثَةَ قَالَ قَدِمْتُ الْمَدِينَةَ وَمَعِيَ ابْنٌ لِي وَلَمْ نَكُنْ رَأَيْنَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ فَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيْهِ ثَوْبَانِ أَخْضَرَانِ فَلَمَّا رَأَيْتُهُ عَرَفْتُهُ بِالصِّفَةِ فَأَتَيْتُهُ فَقَالَ مَنْ هَذَا الَّذِي مَعَكَ قُلْتُ ابْنِي وَرَبِّ الْكَعْبَةِ فَقَالَ ابْنُكَ فَقُلْتُ أَشْهَدُ بِهِ قَالَ فَإِنَّ ابْنَكَ هَذَا لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ","id":"Telah mengabarkan kepada kami [Yunus bin Muhammad] telah menceritakan kepada kami [Jarir yaitu Ibnu Hazim] ia berkata; aku mendengar [Abdul Malik bin 'Umair] berkata; telah menceritakan kepadaku [Iyad bin Laqith] dari [Abu Rimtsah], ia berkata; aku datang ke Madinah bersama anakku. Ternyata kami tidak menjumpai Rasulullah shallallahu 'alaihi wasallam, kemudian aku mendatangi beliau. Rasulullah shallallahu 'alaihi wasallam lalu keluar dengan memakai dua baju hijau, tatkala aku melihat beliau, maka aku mengetahuinya dengan suatu sifat (yang beliau miliki), aku pun menemuinya, beliau lalu bersabda: \"Siapakah yang bersamamu?\" Aku menjawab; \"Anakku, demi Rabb Pemilik Ka'bah.\" Beliau bertanya: \"Anakmu?\" Aku menjawab; \"Aku bersaksi dengannya. Beliau bersabda: \"Sesungguhnya dia tidak dihukum karena kejahatanmu dan engkau tidak dihukum karena kejahatannya.\""},"1927":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ إِيَادٍ حَدَّثَنَا إِيَادٌ عَنْ أَبِي رِمْثَةَ قَالَ انْطَلَقْتُ مَعَ أَبِي نَحْوَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لِأَبِي ابْنُكَ هَذَا فَقَالَ إِي وَرَبِّ الْكَعْبَةِ قَالَ حَقًّا قَالَ أَشْهَدُ بِهِ قَالَ فَتَبَسَّمَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ضَاحِكًا مِنْ ثَبَتِ شَبَهِي فِي أَبِي وَمِنْ حَلِفِ أَبِي عَلَيَّ فَقَالَ إِنَّ ابْنَكَ هَذَا لَا يَجْنِي عَلَيْكَ وَلَا تَجْنِي عَلَيْهِ قَالَ وَقَرَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ { وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَى }","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami ['Ubaidullah bin Iyad] telah menceritakan kepada kami [Iyad] dari [Abu Rimtsah], ia berkata; aku pergi bersama ayahku menemui Rasulullah shallallahu 'alaihi wasallam, kemudian beliau bersabda kepada ayahku: \"Apakah ini anakmu?\" Ayahku menjawab; \"Ya, demi Rabb Pemilik Ka'bah.\" Beliau bersabda: \"Apakah benar (ini anakmu)?\" Ayahku menjawab; \"Aku bersaksi dengannya.\" Abu Rimtsah berkata; Kemudian Rasulullah shallallahu 'alaihi wasallam tersenyum karena kemiripanku dengan ayahku dan karena sumpah ayahku atas diriku. Beliau lalu bersabda: \"Sesungguhnya anakmu ini tidak dihukum karena kejahatanmu dan engkau tidak dihukum karena kejahatannya.\" Abu Rimtsah berkata; Rasulullah shallallahu 'alaihi wasallam lalu membaca ayat: \" Dan seorang yang berdosa tidak akan memikul dosa orang lain.\" QS Al Isra`; 15."},"1928":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْأَوْزَاعِيِّ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ أَبِي سَلَمَةَ عَنْ عَبْدِ اللَّهِ بْنِ سَلَامٍ قَالَ قَعَدْنَا نَفَرٌ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَذَاكَرْنَا فَقُلْنَا لَوْ نَعْلَمُ أَيَّ الْأَعْمَالِ أَحَبَّ إِلَى اللَّهِ تَعَالَى لَعَمِلْنَاهُ فَأَنْزَلَ اللَّهُ تَعَالَى { سَبَّحَ لِلَّهِ مَا فِي السَّمَوَاتِ وَمَا فِي الْأَرْضِ وَهُوَ الْعَزِيزُ الْحَكِيمُ يَا أَيُّهَا الَّذِينَ آمَنُوا لِمَ تَقُولُونَ مَا لَا تَفْعَلُونَ كَبُرَ مَقْتًا } حَتَّى خَتَمَهَا قَالَ عَبْدُ اللَّهِ فَقَرَأَهَا عَلَيْنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى خَتَمَهَا قَالَ أَبُو سَلَمَةَ فَقَرَأَهَا عَلَيْنَا ابْنُ سَلَامٍ قَالَ يَحْيَى فَقَرَأَهَا عَلَيْنَا أَبُو سَلَمَةَ وَقَرَأَهَا عَلَيْنَا يَحْيَى وَقَرَأَهَا عَلَيْنَا الْأَوْزَاعِيُّ وَقَرَأَهَا عَلَيْنَا مُحَمَّدٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Katsir] dari [Al Auza'i] dari [Yahya bin Abu Katsir] dari [Abu Salamah] dari [Abdullah bin Salam], ia berkata; kami duduk-duduk bersama dengan beberapa orang sahabat Rasulullah shallallahu 'alaihi wasallam, kami saling menyebutkan sesuatu, lalu kami berkata; \"Seandainya kami mengetahui suatu amalan yang paling dicintai Allah Ta'ala, niscaya kami akan mengamalkannya.\" Setelah itu Allah Ta'ala menurunkan ayat: \" Telah bertasbih kepada Allah apa saja yang ada di langit dan apa saja yang ada di bumi; dan Dia-lah Yang Maha Perkasa lagi Maha Bijaksana. Wahai orang-orang yang beriman, kenapakah kamu mengatakan sesuatu yang tidak kamu kerjakan? Amat besar kebencian di sisi Allah.... QS As Shaf; 1-3, hingga selesai ayat. Abdullah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam membacakannya kepada kami hingga selesai. Abu Salamah berkata; \"Kemudian Ibnu Salam membacakannya kepada kami. Yahya berkata; Kemudian Abu Salamah membacakannya kepada kami dan Yahya pun membacanya kepada kami, dan Al Auza'i membacakannya kepada kami dan Muhammad membacakannya kepada kami.\""},"1929":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَكَفَّلَ اللَّهُ لِمَنْ خَرَجَ مِنْ بَيْتِهِ لَا يُخْرِجُهُ إِلَّا جِهَادٌ فِي سَبِيلِ اللَّهِ وَتَصْدِيقُ كَلِمَاتِهِ أَنْ يُدْخِلَهُ الْجَنَّةَ أَوْ يَرُدَّهُ إِلَى مَسْكَنِهِ الَّذِي خَرَجَ مِنْهُ مَعَ مَا نَالَ مِنْ أَجْرٍ أَوْ غَنِيمَةٍ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah menjamin bagi siapa yang berjihad di jalan-Nya, Dia tidak mengeluarkan orang itu kecuali untuk berjihad di jalan-Nya dan membenarkan kalimat-Nya untuk memasukkannya ke dalam surga atau mengembalikannya ke tempat tinggalnya ketika dia keluar, dengan membawa pulang pahala atau ghanimah\"."},"1930":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ عَنْ الْأَعْمَشِ عَنْ أَبِي سُفْيَانَ عَنْ جَابِرٍ قَالَ قِيلَ يَا رَسُولَ اللَّهِ أَيُّ الْجِهَادِ أَفْضَلُ قَالَ مَنْ عُقِرَ جَوَادُهُ وَأُهْرِيقَ دَمُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] telah menceritakan kepada kami [Malik bin Mighwal] dari [Al A'masy] dari [Abu Sufyan] dari [Jabir] ia berkata; (Rasulullah) ditanya; \"Wahai Rasulullah, jihad apakah yang paling utama?, \" Beliau menjawab: \"Orang yang kudanya disembih dan darahnya mengalir (hingga gugur).\""},"1931":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي إِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ ابْنِ شِهَابٍ عَنْ ابْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَ سُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ الْأَعْمَالِ أَفْضَلُ قَالَ إِيمَانٌ بِاللَّهِ وَرَسُولِهِ قَالَ قِيلَ ثُمَّ مَاذَا قَالَ ثُمَّ الْجِهَادُ فِي سَبِيلِ اللَّهِ قِيلَ ثُمَّ مَاذَا قَالَ ثُمَّ حَجٌّ مَبْرُورٌ","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Ibraihim bin Sa'd] dari [Ibnu Syihab] dari [Ibnu Al Musayyab] dari [Abu Hurairah] ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya; \"Amalan apakah yang paling utama?, \" Beliau bersabda: \"Beriman kepada Allah dan RasulNya.\" Abu Hurairah berkata; Beliau ditanya lagi; \"Kemudian apa?, \" Beliau menjawab: \"Kemudian berjuang di jalan Allah.\" Beliau ditanya lagi; \"Kemudian apa?, \" Beliau menjawab: \"Kemudian haji mabrur.\" "},"1932":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ مَالِكِ بْنِ يَخَامِرَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَاتَلَ فِي سَبِيلِ اللَّهِ فُوَاقَ نَاقَةٍ وَجَبَتْ لَهُ الْجَنَّةُ وَهُوَ قَدْرُ مَا تَدُرُّ حَلَبَهَا لِمَنْ حَلَبَهَا","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Baqiyyah] dari [Bahir] dari [Khalid bin Ma'dan] dari [Malik bin Yakhamir] dari [Mu'adz bin Jabal] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berperang di jalan Allah, seukuran lamanya waktu istirahat diantara dua kali memeras unta, maka wajib baginya Surga.\" Yaitu seukuran unta tersebut memancarkan perahannya bagi orang yang memerah susunya."},"1933":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ عَلِيٍّ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ سَعِيدِ بْنِ خَالِدٍ عَنْ إِسْمَعِيلَ بْنِ عَبْدِ الرَّحْمَنِ بْنِ أَبِي ذِئْبٍ عَنْ عَطَاءِ بْنِ يَسَارٍ عَنْ ابْنِ عَبَّاسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ عَلَيْهِمْ وَهُمْ جُلُوسٌ فَقَالَ أَلَا أُخْبِرُكُمْ بِخَيْرِ النَّاسِ مَنْزِلَةً قُلْنَا بَلَى قَالَ رَجُلٌ مُمْسِكٌ بِرَأْسِ فَرَسِهِ أَوْ قَالَ فَرَسٍ فِي سَبِيلِ اللَّهِ حَتَّى يَمُوتَ أَوْ يُقْتَلَ قَالَ فَأُخْبِرُكُمْ بِالَّذِي يَلِيهِ فَقُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ امْرُؤٌ مُعْتَزِلٌ فِي شِعْبٍ يُقِيمُ الصَّلَاةَ وَيُؤْتِي الزَّكَاةَ وَيَعْتَزِلُ شُرُورَ النَّاسِ قَالَ فَأُخْبِرُكُمْ بِشَرِّ النَّاسِ مَنْزِلَةً فَقُلْنَا نَعَمْ يَا رَسُولَ اللَّهِ قَالَ الَّذِي يُسْأَلُ بِاللَّهِ وَلَا يُعْطِي بِهِ","id":"Telah mengabarkan kepada kami ['Ashim bin Ali] telah menceritakan kepada kami [Ibnu Abu Dzi`b] dari [Sa'id bin Khalid] dari [Isma'il bin Abdurrahman bin Abu Dzi`b] dari ['Atha` bin Yasar] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam keluar menemui para sahabat, sementara mereka sedang duduk-duduk. Lalu beliau bersabda: \"Maukah aku beritahukan kepada kalian mengenai orang paling baik kedudukannya?\" Kami menjawab; \"Tentu.\" Beliau bersabda: \"Orang yang memegangi kepala kudanya -atau bersabda; kepala kuda- di jalan Allah kemudian meninggal atau terbunuh.\" Beliau bersabda: \"Maukah aku beritahukan kepada kalian mengenai (kedudukan) orang yang setelahnya.\" Maka kami menjawab; \"Ya wahai Rasulullah.\" Beliau bersabda: \"Orang yang mengisolir diri di lembah, ia mendirikan shalat, menunaikan zakat dan menjauhi kejahatan manusia.\" Beliau bersabda: \"Maukah aku beritahukan kepada kalian mengenai orang yang paling buruk kedudukannya.\" Kami menjawab; \"Tentu wahai Rasulullah.\" Beliau bersabda: \"Orang yang dimintai (sesuatu) atas nama Allah, namun ia tidak mau memberi karena-Nya.\""},"1934":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ صَالِحٍ حَدَّثَنِي يَحْيَى بْنُ أَيُّوبَ عَنْ هِشَامٍ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَقَامُ الرَّجُلِ فِي الصَّفِّ فِي سَبِيلِ اللَّهِ أَفْضَلُ مِنْ عِبَادَةِ الرَّجُلِ سِتِّينَ سَنَةً","id":"Telah mengabarkan kepada kami [Abdullah bin Shalih] telah menceritakan kepadaku [Yahya bin Ayyub] dari [Hisyam] dari [Al Hasan] dari ['Imran bin Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berdirinya seorang laki-laki di barisan (jihad) di jalan Allah, itu lebih baik daripada ibadahnya seseorang selama enam puluh tahun.\""},"1935":{"ar":" أَخْبَرَنَا الْقَاسِمُ بْنُ كَثِيرٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ شُرَيْحٍ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ سُلَيْمَانَ أَنَّ مَالِكَ بْنَ عَبْدِ اللَّهِ مَرَّ عَلَى حَبِيبِ بْنِ مَسْلَمَةَ أَوْ حَبِيبٌ مَرَّ عَلَى مَالِكٍ وَهُوَ يَقُودُ فَرَسًا يَمْشِي فَقَالَ ارْكَبْ حَمَلَكَ اللَّهُ فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اغْبَرَّتْ قَدَمَاهُ فِي سَبِيلِ اللَّهِ حَرَّمَهُ اللَّهُ عَلَى النَّارِ","id":"Telah mengabarkan kepada kami [Al Qasim bin Katsir], ia berkata; aku mendengar [Abdurrahman bin Syuraih] menceritakan dari [Abdullah bin Sulaiman] bahwa [Malik bin Abdullah] melewati [Habib bin Maslamah] -atau Habib melewati Malik- ketika ia menuntun kuda sambil berjalan. Kemudian Habib (atau Malik) berkata; tunggangilah, sebab Allah telah memberimu tunggangan. Lantas Habib (atau Malik) berkata; \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa kedua kakinya berdebu di jalan Allah, maka Allah mengharamkan Neraka untuknya.\""},"1936":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَغَدْوَةٌ فِي سَبِيلِ اللَّهِ أَوْ رَوْحَةٌ خَيْرٌ مِنْ الدُّنْيَا وَمَا فِيهَا","id":"Telah menceritakan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abu Hazim] dari [Sahl bin Sa'd], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh berpagi-pagi atau sore hari di jalan Allah itu lebih baik dari dunia seisinya.\""},"1937":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ النُّعْمَانِ بْنِ أَبِي عَيَّاشٍ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ عَبْدٍ يَصُومُ يَوْمًا فِي سَبِيلِ اللَّهِ ابْتِغَاءَ وَجْهِ اللَّهِ إِلَّا بَاعَدَ اللَّهُ بَيْنَ وَجْهِهِ وَبَيْنَ النَّارِ سَبْعِينَ خَرِيفًا","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Suhail bin Abu Shalih] dari [An Nu'man bin Abu 'Ayyasy] dari [Abu Sa'id Al Khudri] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seorang hamba berpuasa sehari di jalan Allah dengan mengharap wajah Allah, melainkan Allah akan menjauhkan jarak antara wajahnya dan Neraka sejauh tujuh puluh tahun.\""},"1938":{"ar":" أَخْبَرَنَا الْقَاسِمُ بْنُ كَثِيرٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ شُرَيْحٍ يُحَدِّثُ عَنْ أَبِي الصَّبَّاحِ مُحَمَّدِ بْنِ سُمَيْرٍ عَنْ أَبِي عَلِيٍّ الْهَمْدَانِيِّ عَنْ أَبِي رَيْحَانَةَ أَنَّهُ كَانَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةٍ فَسَمِعَهُ ذَاتَ لَيْلَةٍ وَهُوَ يَقُولُ حُرِّمَتْ النَّارُ عَلَى عَيْنٍ سَهِرَتْ فِي سَبِيلِ اللَّهِ وَحُرِّمَتْ النَّارُ عَلَى عَيْنٍ دَمَعَتْ مِنْ خَشْيَةِ اللَّهِ قَالَ وَقَالَ الثَّالِثَةَ فَنَسِيتُهَا قَالَ أَبُو شُرَيْحٍ سَمِعْتُ مَنْ يَقُولُ ذَاكَ حُرِّمَتْ النَّارُ عَلَى عَيْنٍ غَضَّتْ عَنْ مَحَارِمِ اللَّهِ أَوْ عَيْنٍ فُقِئَتْ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ","id":"Telah mengabarkan [Al Qasim bin Katsir] ia berkata; aku mendengar [Abdurrahman bin Syuraih] telah menceritakan kepada kami dari [Abu Ash Shabbah Muhammad bin Sumair] dari [Abu Ali Al Hamdani] dari [Abu Raihanah] bahwa ia pernah bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu ekspedisi, suatu malam, dia mendengar beliau bersabda: \"Telah diharamkan Neraka bagi mata yang begadang (untuk berjaga-jaga) di jalan Allah, dan telah diharamkan Neraka bagi mata yang menangis karena takut kepada Allah.\" Lalu beliau menyebutkan yang ketiga, namun aku lupa. Abu Syuraih berkata; Ku mendengar orang yang mengatakan hal itu, yaitu: \"Telah diharamkan Neraka bagi mata yang menahan dari melihat perkara-perkara yang diharamkan Allah, atau mata yang dicongkel di jalan Allah 'azza wajalla.\""},"1939":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ أَخْبَرَنَا ابْنُ الدَّرَاوَرْدِيِّ عَنْ صَالِحِ بْنِ مُحَمَّدِ بْنِ زَائِدَةَ قَالَ سَمِعْتُ عُمَرَ بْنَ عَبْدِ الْعَزِيزِ عَنْ عُقْبَةَ بْنِ عَامِرٍ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رَحِمَ اللَّهُ حَارِسَ الْحَرَسِ قَالَ عَبْد اللَّهِ وَعُمَرُ بْنُ عَبْدِ الْعَزِيزِ لَمْ يَلْقَ عُقْبَةَ بْنَ عَامِرٍ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah mengabarkan kepada kami [Ad Darawardi] dari [Shalih bin Muhammad bin Zaidah], ia berkata; aku mendengar [Umar bin Abdul Aziz] dari ['Uqbah bin 'Amir Al Juhani] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Semoga Allah merahmati orang yang menjaga para penjaga (orang yang menjaga kaum muslimin).\" Abdullah berkata; \"Umar bin Abdul Aziz belum pernah bertemu dengan 'Uqbah bin 'Amir."},"1940":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ قَالَ جَاءَ رَجُلٌ بِنَاقَةٍ مَخْطُومَةٍ فَقَالَ هَذِهِ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَكَ بِهَا يَوْمَ الْقِيَامَةِ سَبْعُ مِائَةِ نَاقَةٍ كُلُّهَا مَخْطُومَةٌ","id":"Telah menceritakan kepada kami [Abdullah bin Muhammad] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu 'Amr Asy Syaibani] dari [Abu Mas'ud Al Anshari], ia berkata; \"Seorang laki-laki datang sambil membawa unta yang telah dikekang. Laki-laki itu berkata; \"Unta ini diperuntukkan di jalan Allah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Karena unta tersebut, engkau mendapatkan tujuh ratus unta yang seluruhnya dikekang pada Hari Kiamat.\""},"1941":{"ar":" أَخْبَرَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا هِشَامٌ عَنْ الْحَسَنِ عَنْ صَعْصَعَةَ بْنِ مُعَاوِيَةَ قَالَ لَقِيتُ أَبَا ذَرٍّ وَهُوَ يَسُوقُ جَمَلًا أَوْ يَقُودُهُ فِي عُنُقِهِ قِرْبَةٌ فَقُلْتُ يَا أَبَا ذَرٍّ مَا مَالُكَ قَالَ لِي عَمَلِي فَقُلْتُ مَا مَالُكَ قَالَ لِي عَمَلِي قُلْتُ حَدِّثْنِي حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَا مِنْ مُسْلِمٍ أَنْفَقَ زَوْجَيْنِ مِنْ مَالٍ فِي سَبِيلِ اللَّهِ إِلَّا ابْتَدَرَتْهُ حَجَبَةُ الْجَنَّةِ قَالَ أَبُو مُحَمَّد هُوَ دِرْهَمَيْنِ أَوْ أَمَتَيْنِ أَوْ عَبْدَيْنِ أَوْ دَابَّتَيْنِ","id":"Telah mengabarkan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Hisyam] dari [Al Hasan] dari [Sha'sha'ah bin Mu'awiyah], ia berkata; aku bertemu [Abu Dzar], sementara dirinya sedang menuntun unta -atau menggiringnya- dan dilehernya tergantung geriba. Aku berkata; \"Wahai Abu Dzar, bagaimana engkau pergunakan hartamu?, \" dia menjawab; \"Hartaku! untuk bekal amalanku.\" Aku bertanya lagi; \"Bagaimana engkau pergunakan hartamu? Dia menjawab; \"Hartaku, untuk mengantarkan amalanku.\" Aku berkata; \"Ceritakanlah kepadaku suatu hadits yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam! \" Abu Dzar berkata; \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang muslim yang menginfakkan sepasang hartanya di jalan Allah, melainkan akan segera diambil penjaga Surga.\" Abu Muhammad berkata; sepasang harta tersebut seperti dua dirham, atau dua budak wanita atau laki-laki atau dua kendaraan (unta atau yang lainnya)."},"1942":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ الْمُقْرِئُ حَدَّثَنَا سَعِيدُ بْنُ أَبِي أَيُّوبَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ مَرْثَدِ بْنِ عَبْدِ اللَّهِ عَنْ عُقْبَةَ بْنِ عَامِرٍ أَنَّهُ تَلَا هَذِهِ الْآيَةَ { وَأَعِدُّوا لَهُمْ مَا اسْتَطَعْتُمْ مِنْ قُوَّةٍ } أَلَا إِنَّ الْقُوَّةَ الرَّمْيُ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid Al Muqri`] telah menceritakan kepada kami [Sa'id bin Abu Ayyub] telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Abu Al Khair Martsad bin Abdullah] dari ['Uqbah bin 'Amir] bahwa beliau pernah membaca ayat ini: \" Dan siapkanlah untuk menghadapi mereka kekuatan apa saja yang kamu sanggupi.\" QS Al Anfal; 60, ketahuilah sesungguhnya kekuatan itu adalah melempar.\""},"1943":{"ar":" أَخْبَرَنَا وَهْبُ بْنُ جَرِيرٍ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى عَنْ أَبِي سَلَّامٍ عَنْ عَبْدِ اللَّهِ بْنِ زَيْدٍ الْأَزْرَقِ عَنْ عُقْبَةَ بْنِ عَامِرٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُدْخِلُ الثَّلَاثَةَ بِالسَّهْمِ الْوَاحِدِ الْجَنَّةَ صَانِعَهُ يَحْتَسِبُ فِي صَنْعَتِهِ الْخَيْرَ وَالْمُمِدَّ بِهِ وَالرَّامِيَ بِهِ وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ارْمُوا وَارْكَبُوا وَلَأَنْ تَرْمُوا أَحَبُّ إِلَيَّ مِنْ أَنْ تَرْكَبُوا وَقَالَ كُلُّ شَيْءٍ يَلْهُو بِهِ الرَّجُلُ بَاطِلٌ إِلَّا رَمْيَ الرَّجُلِ بِقَوْسِهِ وَتَأْدِيبَهُ فَرَسَهُ وَمُلَاعَبَتَهُ أَهْلَهُ فَإِنَّهُنَّ مِنْ الْحَقِّ وَقَالَ مَنْ تَرَكَ الرَّمْيَ بَعْدَمَا عُلِّمَهُ فَقَدْ كَفَرَ الَّذِي عُلِّمَهُ","id":"Telah mengabarkan kepada kami [Wahb bin Jarir] telah menceritakan kepada kami [Hisyam] dari [Yahya] dari [Abu Salam] dari [Abdullah bin Zaid Al Azraq] dari ['Uqbah bin 'Amir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah 'azza wajalla memasukkan tiga orang ke dalam Surga karena anak panah, yaitu; pembuatnya yang mengharapkan kebaikan dalam membuatnya, orang yang mengambilkannya dan orang yang memanah degannya.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Panahlah dan naiklah kuda, sesungguhnya memanah lebih aku sukai daripada naik kuda.\" Dan beliau bersabda: \"Segala hiburan yang dilakukan seseorang adalah sia-sia kecuali seorang laki-laki yang memanah dengan busur, mengajari kudanya, serta mencandai isterinya. Sesungguhnya ketiga hal itu adalah benar.\" Beliau juga bersabda; \"Barangsiapa meninggalkan memanah setelah diajarkan kepadanya, sungguh ia telah ingkar terhadap sesuatu yang telah diajarkan kepadanya.\""},"1944":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الرَّقَاشِيُّ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ حَدَّثَنَا مُحَمَّدُ بْنُ إِسْحَقَ حَدَّثَنِي عَمِّي مُوسَى بْنُ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ أَبُو الْقَاسِمِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ مَجْرُوحٍ يُجْرَحُ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ إِلَّا بَعَثَهُ اللَّهُ عَزَّ وَجَلَّ يَوْمَ الْقِيَامَةِ وَجُرْحُهُ يَدْمَى الرِّيحُ رِيحُ الْمِسْكِ وَاللَّوْنُ لَوْنُ الدَّمِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Ar Raqasyi] telah menceritakan kepada kami [Yazid bin Zurai'] telah menceritakan kepada kami [Muhammad bin Ishaq] telah menceritakan kepadaku pamanku yaitu [Musa bin Yasar] dari [Abu Hurairah] ia berkata; Abu Al Qasim shallallahu 'alaihi wasallam bersabda; \"Tidaklah seseorang yang terluka di jalan Allah 'azza wajalla, melainkan Allah 'azza wajalla akan membangkitkannya pada hari Kiamat, sementara lukanya masih mengalir, dengan bau seperti bau kasturi dan warnanya seperti warna darah.\""},"1945":{"ar":" أَخْبَرَنَا الْقَاسِمُ بْنُ كَثِيرٍ قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ شُرَيْحٍ يُحَدِّثُ أَنَّهُ سَمِعَ سَهْلَ بْنَ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ يُحَدِّثُ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ اللَّهَ الشَّهَادَةَ صَادِقًا مِنْ قَلْبِهِ بَلَّغَهُ اللَّهُ مَنَازِلَ الشُّهَدَاءِ وَإِنْ مَاتَ عَلَى فِرَاشِهِ","id":"Telah mengabarkan kepada kami [Al Qasim bin Katsir], ia berkata; aku mendengar [Abdurrahman bin Syuraih] menceritakan, bahwa ia mendengar [Sahl bin Abu Umamah bin Sahl bin Hunaif] menceritakan dari [Ayahnya] dari [Kakeknya] ia berkata; Sesungguhnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa memohon mati syahid kepada Allah dengan sungguh-sungguh dari lubuk hatinya, maka Allah akan mengangkatnya sampai ke tingkatan para syuhada' walaupun ia mati di atas kasur.\""},"1946":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الرِّفَاعِيُّ حَدَّثَنَا صَفْوَانُ بْنُ عِيسَى عَنْ ابْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا يَجِدُ الشَّهِيدُ مِنْ أَلَمِ الْقَتْلِ إِلَّا كَمَا يَجِدُ أَحَدُكُمْ مِنْ أَلَمِ الْقَرْصَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Ar Rifa'i] telah menceritakan kepada kami [Shafwan bin Isa] dari [Ibnu 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang yang mati syahid merasakan rasa sakit karena terbunuh melainkan seperti seseorang diantara kalian merasakan rasa sakit karena dicubit.\""},"1947":{"ar":" أَخْبَرَنَا أَبُو عَلِيٍّ الْحَنَفِيُّ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ نَفْسٍ تَمُوتُ فَتَدْخُلُ الْجَنَّةَ فَتَوَدُّ أَنَّهَا رَجَعَتْ إِلَيْكُمْ وَلَهَا الدُّنْيَا وَمَا فِيهَا إِلَّا الشَّهِيدَ فَإِنَّهُ وَدَّ أَنَّهُ قُتِلَ كَذَا مَرَّةً لِمَا رَأَى مِنْ الثَّوَابِ","id":"Telah mengabarkan kepada kami [Abu Ali Al Hanafi] telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Anas] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah suatu jiwa yang mati lalu masuk Surga, kemudian ingin kembali kepada kalian dengan mendapatkan dunia seisinya, kecuali orang yang mati syahid. Sesungguhnya ia ingin terbunuh seperti ini lagi, karena melihat pahala orang yang mati syahid.\""},"1948":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ قَالَ سَأَلْنَا عَبْدَ اللَّهِ عَنْ أَرْوَاحِ الشُّهَدَاءِ وَلَوْلَا عَبْدُ اللَّهِ لَمْ يُحَدِّثْنَا أَحَدٌ قَالَ أَرْوَاحُ الشُّهَدَاءِ عِنْدَ اللَّهِ يَوْمَ الْقِيَامَةِ فِي حَوَاصِلِ طَيْرٍ خُضْرٍ لَهَا قَنَادِيلُ مُعَلَّقَةٌ بِالْعَرْشِ تَسْرَحُ فِي أَيِّ الْجَنَّةِ شَاءُوا ثُمَّ تَرْجِعُ إِلَى قَنَادِيلِهَا فَيُشْرِفُ عَلَيْهِمْ رَبُّهُمْ فَيَقُولُ أَلَكُمْ حَاجَةٌ تُرِيدُونَ شَيْئًا فَيَقُولُونَ لَا إِلَّا أَنْ نَرْجِعَ إِلَى الدُّنْيَا فَنُقْتَلَ مَرَّةً أُخْرَى","id":"Telah mengabarkan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Sulaiman] dari [Abdullah bin Murrah] dari [Masruq] ia berkata; kami bertanya kepada [Abdullah] mengenai ruh seorang syahid, seandainya bukan Abdullah maka tidak ada seorangpun yang menceritakan kepada kami. Ia berkata; \"Ruh para syuhada' berada di sisi Allah pada hari Kiamat, mereka berada rongga burung hijau yang memiliki sarang-sarang yang bergantungan di 'Arsy, burung-burung tersebut terbang di Surga sekehendak hati mereka, kemudian kembali ke sarang-sarangnya. Kemudian Rabb mereka menampakkan diri kepada mereka dan berfirman: \"Apakah kalian punya kebutuhan, kalian menginginkan sesuatu?\" Mereka mengatakan; \"Tidak, kecuali kami ingin kembali ke dunia dan terbunuh sekali lagi.\""},"1949":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُبَارَكِ حَدَّثَنَا مُعَاوِيَةُ بْنُ يَحْيَى هُوَ الصَّدَفِيُّ قَالَ حَدَّثَنَا صَفْوَانُ بْنُ عَمْرٍو عَنْ أَبِي الْمُثَنَّى الْأُمْلُوكِيِّ عَنْ عُتْبَةَ بْنِ عَبْدٍ السُّلَمِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَتْلَى ثَلَاثَةٌ مُؤْمِنٌ جَاهَدَ بِنَفْسِهِ وَمَالِهِ فِي سَبِيلِ اللَّهِ إِذَا لَقِيَ الْعَدُوَّ قَاتَلَ حَتَّى يُقْتَلَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ فَذَلِكَ الشَّهِيدُ الْمُمْتَحَنُ فِي خَيْمَةِ اللَّهِ تَحْتَ عَرْشِهِ لَا يَفْضُلُهُ النَّبِيُّونَ إِلَّا بِدَرَجَةِ النُّبُوَّةِ وَمُؤْمِنٌ خَلَطَ عَمَلًا صَالِحًا وَآخَرَ سَيِّئًا جَاهَدَ بِنَفْسِهِ وَمَالِهِ فِي سَبِيلِ اللَّهِ إِذَا لَقِيَ الْعَدُوَّ قَاتَلَ حَتَّى يُقْتَلَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِيهِ مُمَصْمِصَةٌ مَحَتْ ذُنُوبَهُ وَخَطَايَاهُ إِنَّ السَّيْفَ مَحَّاءٌ لِلْخَطَايَا وَأُدْخِلَ الْجَنَّةَ مِنْ أَيِّ أَبْوَابِ الْجَنَّةِ شَاءَ وَمُنَافِقٌ جَاهَدَ بِنَفْسِهِ وَمَالِهِ فَإِذَا لَقِيَ الْعَدُوَّ قَاتَلَ حَتَّى يُقْتَلَ فَذَاكَ فِي النَّارِ إِنَّ السَّيْفَ لَا يَمْحُو النِّفَاقَ قَالَ عَبْد اللَّهِ يُقَالُ لِلثَّوْبِ إِذَا غُسِلَ مُصْمِصَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mubarak] telah menceritakan kepada kami [Mu'awiyah bin Yahya yaitu Ash Shadafi], ia berkata; telah menceritakan kepada kami [Shafwan bin 'Amr] dari [Abu Al Mutsanna Al Umluki] dari ['Utbah bin 'Abd As Sulami], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang terbunuh (dalam peperangan) ada tiga macam, yaitu; orang mukmin yang berjihad dengan jiwa dan hartanya di jalan Allah, apabila ia bertemu dengan musuh, ia berperang hingga terbunuh.\" Nabi shallallahu 'alaihi wasallam berkata mengenai orang ini: \"Maka itulah orang yang syahid dan mendapatkan ujian, ia berada dalam kemah Allah di bawah 'Arsy, para nabi tidak lebih utama daripada mereka kecuali dengan derajat kenabian, dan seorang mukmin yang mencampurkan amalan shalih dan yang lainnya adalah amalan keburukan, ia berjihad dengan jiwa dan hartanya di jalan Allah. Apabila ia bertemu musuh, maka ia berperang hingga terbunuh.\" Nabi shallallahu 'alaihi wasallam bersabda mengenai orang ini: \"Satu gerakan telah menghapus dosa-dosa serta kesalahannya, sesungguhnya pedang menghapuskan kesalahan-kesalahannya. Dan ia dimasukkan di dalam Surga dari pintu Suga manapun yang ia kehendaki. Dan seorang munafik yang berjihad dengan jiwa dan hartanya, apabila ia bertemu musuh, maka ia berperang hingga terbunuh. Maka orang itu ada dalam Neraka. Sesungguhnya pedang tidak menghapuskan kemunafikannya.\" Abdullah berkata; Apabila baju telah dicuci, maka disebut mushmisha.\""},"1950":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ عَبْدِ الْمَجِيدِ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الْمَقْبُرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ فَخَطَبَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ ذَكَرَ الْجِهَادَ فَلَمْ يَدَعْ شَيْئًا أَفْضَلَ مِنْهُ إِلَّا الْفَرَائِضَ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ مَنْ قُتِلَ فِي سَبِيلِ اللَّهِ فَهَلْ ذَلِكَ مُكَفِّرٌ عَنْهُ خَطَايَاهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِذَا قُتِلَ صَابِرًا مُحْتَسِبًا مُقْبِلًا غَيْرَ مُدْبِرٍ إِلَّا الدَّيْنَ فَإِنَّهُ مَأْخُوذٌ بِهِ كَمَا زَعَمَ لِي جِبْرِيلُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Abdul Majid] telah menceritakan kepada kami [Ibnu Dzi`b] dari [Al Maqburi] dari [Abdullah bin Abu Qatadah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam berdiri dan berkhutbah. Setelah memuji Allah, beliau menyebutkan jihad dan tidak meninggalkan sesuatu yang lebih baik daripada jihad kecuali perkara-perkara yang wajib. Tiba-tiba seorang laki-laki berdiri seraya berkata; \"Wahai Rasulullah, bagaimana pendapat anda mengenai orang yang terbunuh di jalan Allah, apakah hal itu akan menghapuskan kesalahan-kesalahannya? Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, apabila ia terbunuh dalam keadaan bersabar, mengharap pahala dan maju tanpa mundur, kecuali hutang, sesungguhnya ia akan dihukum karena hutang tersebut, sebagaimana yang dikatakan Jibril kepadaku.\""},"1951":{"ar":" أَخْبَرَنَا يَزِيدُ بْنُ هَارُونَ أَخْبَرَنَا سُلَيْمَانُ هُوَ التَّيْمِيُّ عَنْ أَبِي عُثْمَانَ عَنْ عَامِرِ بْنِ مَالِكٍ عَنْ صَفْوَانَ بْنِ أُمَيَّةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الطَّاعُونُ شَهَادَةٌ وَالْغَرَقُ شَهَادَةٌ وَالْغَزْوُ شَهَادَةٌ وَالْبَطْنُ وَالنُّفَسَاءُ","id":"Telah mengabarkan kepada kami [Yazid bin Harun] telah mengabarkan kepada kami [Sulaiman yaitu At Taimi] dari [Abu Utsman] dari [Amir bin Malik] dari [Shafwan bin Umayyah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Orang yang mati karena penyakit lepra adalah syahid, orang yang tenggelam adalah syahid, orang yang mati dalam peperangan adalah syahid, orang yang mati karena sakit perut adalah syahid, dan orang yang mati karena nifas (setelah melahirkan) adalah syahid.\""},"1952":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ إِسْرَائِيلَ عَنْ مَنْصُورٍ عَنْ أَبِي بَكْرِ بْنِ حَفْصٍ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْقَتْلُ فِي سَبِيلِ اللَّهِ شَهَادَةٌ وَالطَّاعُونُ شَهَادَةٌ وَالْبَطْنُ شَهَادَةٌ وَالْمَرْأَةُ يَقْتُلُهَا وَلَدُهَا جُمْعًا شَهَادَةٌ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Isra`il] dari [Manshur] dari [Abu Bakr bin Hafsh] dari [Syurahbil bin As Simth] dari ['Ubadah bin Ash Shamit], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Terbunuh di jalan Allah adalah syahid, meninggal karena penyakit pes adalah syahid, mati karena sakit perut adalah syahid, wanita yang meninggal karena melahirkan anaknya adalah syahid.\""},"1953":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا إِسْمَعِيلُ عَنْ قَيْسٍ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَ كُنَّا نَغْزُو مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا لَنَا طَعَامٌ إِلَّا السَّمُرُ وَوَرَقُ الْحُبْلَةِ حَتَّى إِنَّ أَحَدَنَا لَيَضَعُ كَمَا تَضَعُ الشَّاةُ مَا لَهُ خِلْطٌ ثُمَّ أَصْبَحَتْ بَنُو أَسَدٍ يُعَزِّرُونِي لَقَدْ خِبْتُ إِذَنْ وَضَلَّ عَمَلِيَهْ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Isma'il] dari [Qais] dari [Sa'd bin Abu Waqqash], ia berkata; \"Kami pernah berperang bersama Rasulullah shallallahu 'alaihi wasallam, waktu itu kami tidak mendapatkan makanan kecuali hanya pohon Samur dan dedaunan hublah (sejenis pohon gurun yang berduri) hingga salah seorang diantara kami membuang hajat seperti kambing membuang kotoran tanpa melekat antara satu dengan yang lain, Keesokan harinya Bani Asad memuliakanku. (kalau begitu) sungguh aku telah merugi dan amalanku telah sesat, \""},"1954":{"ar":" أَخْبَرَنَا الْحَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا جَبَلَةُ بْنُ عَطِيَّةَ عَنْ يَحْيَى بْنِ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ عُبَادَةَ بْنِ الصَّامِتِ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ غَزَا فِي سَبِيلِ اللَّهِ وَهُوَ لَا يَنْوِي فِي غَزَاتِهِ إِلَّا عِقَالًا فَلَهُ مَا نَوَى","id":"Telah mengabarkan kepada kami [Al Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Jabalah bin 'Athiyyah] dari [Yahya bin Al Walid bin 'Ubadah bin Ash Shamit] dari ['Ubadah bin Ash Shamit] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa berperang di jalan Allah dan ketika berperang, ia tidak berniat kecuali hanya ingin mendapatkan tali kekang (unta), maka baginya apa yang ia niatkan.\""},"1955":{"ar":" أَخْبَرَنَا نُعَيْمُ بْنُ حَمَّادٍ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ أَبِي بَحْرِيَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْغَزْوُ غَزْوَانِ فَأَمَّا مَنْ غَزَا ابْتِغَاءَ وَجْهِ اللَّهِ وَأَطَاعَ الْإِمَامَ وَأَنْفَقَ الْكَرِيمَةَ وَيَاسَرَ الشَّرِيكَ وَاجْتَنَبَ الْفَسَادَ فَإِنَّ نَوْمَهُ وَنُبْهَهُ أَجْرٌ كُلُّهُ وَأَمَّا مَنْ غَزَا فَخْرًا وَرِيَاءً وَسُمْعَةً وَعَصَى الْإِمَامَ وَأَفْسَدَ فِي الْأَرْضِ فَإِنَّهُ لَا يَرْجِعُ بِالْكَفَافِ","id":"Telah mengabarkan kepada kami [Nu'aim bin Hammad] telah menceritakan kepada kami [Baqiyyah bin Al Walid] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Abu Bahriyyah] dari [Mu'adz bin Jabal] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berperang ada dua macam, adapun orang yang berperang dengan mengharapkan wajah Allah dan mentaati pemimpin serta menginfakkan harta berharga dan memberikan kemudahan bagi sahabatnya dengan menghidari kerusakan, sesungguhnya tidurnya, dan terjaganya semua adalah pahala. Adapun orang yang berperang dengan berbangga diri, agar dilihat dan di dengar, durhaka kepada pemimpin dan membuat kerusakan di muka bumi, maka ia tidak kembali dengan membawa balasan yang rendah (sedikit).\""},"1956":{"ar":" أَخْبَرَنَا الْحَكَمُ بْنُ الْمُبَارَكِ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ حَدَّثَنَا يَحْيَى بْنُ الْحَارِثِ عَنْ الْقَاسِمِ أَبِي عَبْدِ الرَّحْمَنِ عَنْ أَبِي أُمَامَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ لَمْ يَغْزُ أَوْ يُجَهِّزْ غَازِيًا أَوْ يَخْلُفْ غَازِيًا فِي أَهْلِهِ بِخَيْرٍ أَصَابَهُ اللَّهُ بِقَارِعَةٍ قَبْلَ يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Al Hakam bin Al Mubarak] telah menceritakan kepada kami [Al Walid bin Muslim] telah menceritakan kepada kami [Yahya bin Al Harits] dari [Al Qasim Abu Abdurrahman] dari [Abu Umamah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barangsiapa tidak berperang atau mempersiapkan orang yang berperang atau menggantikan orang yang berperang dalam menjaga keluarganya dengan baik, maka Allah akan menimpakan musibah yang membinasakannya sebelum hari Kiamat.\""},"1957":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا عَبْدُ الْمَلِكِ عَنْ عَطَاءٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ أَوْ خَلَفَ فِي أَهْلِهِ كَتَبَ اللَّهُ لَهُ مِثْلَ أَجْرِهِ إِلَّا أَنَّهُ لَا يَنْقُصُ مِنْ أَجْرِ الْغَازِي شَيْئًا","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Abdul Malik] dari ['Atha`] dari [Zaid bin Khalid Al Juhani] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa membekali orang yang berperang di jalan Allah atau menggantikannya menjaga keluarganya, maka Allah akan menetapkan baginya seperti pahala orang yang berperang tanpa mengurangi pahala orang yang berperang sedikitpun.\""},"1958":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ قَالَ أَنْبَأَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ يَقُولُ لَمَّا نَزَلَتْ هَذِهِ الْآيَةُ { لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ } دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا فَجَاءَ بِكَتِفٍ فَكَتَبَهَا وَشَكَا ابْنُ أُمِّ مَكْتُومٍ ضَرَارَتَهُ فَنَزَلَتْ { لَا يَسْتَوِي الْقَاعِدُونَ مِنْ الْمُؤْمِنِينَ غَيْرُ أُولِي الضَّرَرِ }","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah], ia berkata; telah memberitakan kepada kami [Abu Ishaq], ia berkata; aku mendengar [Al Bara`] berkata; \"Ketika turun ayat: \" Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang)...\" QS An Nisa`; 95. Rasulullah shallallahu 'alaihi wasallam memanggil Zaid, kemudian ia datang dengan membawa tulang pundak binatang, lalu Zaid menulis ayat tersebut. Sementara Ibnu Ummi Maktum dating mengadu akan kebutaannya. Kemudian turunlah ayat: \" Tidaklah sama antara mukmin yang duduk (yang tidak ikut berperang) yang tidak mempunyai 'uzur.\" QS An Nisa'; 95."},"1959":{"ar":" أَخْبَرَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَ حَدَّثَتْنِي أُمُّ حَرَامٍ بِنْتُ مِلْحَانَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي بَيْتِهَا يَوْمًا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ قَالَ أُرِيتُ قَوْمًا مِنْ أُمَّتِي يَرْكَبُونَ ظَهْرَ هَذَا الْبَحْرِ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْهُمْ ثُمَّ نَامَ أَيْضًا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ يَا رَسُولَ اللَّهِ مَا أَضْحَكَكَ قَالَ أُرِيتُ قَوْمًا مِنْ أُمَّتِي يَرْكَبُونَ هَذَا الْبَحْرَ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ قَالَ فَتَزَوَّجَهَا عُبَادَةُ بْنُ الصَّامِتِ فَغَزَا فِي الْبَحْرِ فَحَمَلَهَا مَعَهُ فَلَمَّا قَدِمُوا قُرِّبَتْ لَهَا بَغْلَةٌ لِتَرْكَبَهَا فَصَرَعَتْهَا فَدُقَّتْ عُنُقُهَا فَمَاتَتْ","id":"Telah mengabarkan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Hammad bin Zaid] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Anas bin Malik], ia berkata; telah menceritakan kepadaku [Ummu Haram binti Milhan] bahwa suatu hari Nabi shallallahu 'alaihi wasallam berada di rumahnya, tiba-tiba beliau bangun (tidur) sambil tertawa, lalu aku bertanya; \"Wahai Rasulullah, apakah yang membuatmu tertawa?\" Beliau bersabda: \"Diperlihatkan kepadaku suatu kaum dari umatku, mereka mengarungi lautan ini seperti para raja di atas singgasana.\" Aku berkata; \"Wahai Rasulullah, berdoalah kepada Allah supaya menjadikanku termasuk bagian dari mereka.\" Beliau bersabda: \"Engkau termasuk bagian dari mereka.\" Kemudian beliau tidur kembali, lalu terbangun sambil tertawa, aku bertanya; \"Wahai Rasulullah, apa yang membuatmu tertawa?\" Beliau bersabda: \"Diperlihatkan kepadaku suatu kaum dari umatku, mereka tengah mengarungi lautan ini bagaikan para raja di atas singgasana.\" Aku berkata; \"Wahai Rasulullah, berdoalah kepada supaya Allah menjadikanku termasuk bagian dari mereka.\" Beliau bersabda: \"Engkau termasuk dari kelompok pertama.\" Kemudian 'Ubadah bin Ash Shamit menikahinya, lalu ia membawa Ummu Haram ikut berperang di lautan. Tatkala mereka (kaum Muslimin) sampai tujuan, maka di dekatkan seekor Baghal kepada Ummu Haram untuk ditunggangi, ternyata bighal tersebut menjatuhkannya hingga menyebabkan lehernya patah dan iapun meninggal.\""},"1960":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْ غَزَوْتُ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَبْعَ غَزَوَاتٍ أُدَاوِي الْجَرِيحَ أَوْ الْجَرْحَى وَأَصْنَعُ لَهُمْ الطَّعَامَ وَأَخْلُفُهُمْ فِي رِحَالِهِمْ","id":"Telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Hisyam] dari [Hafshah] dari [Ummu 'Athiyyah], ia berkata; aku berperang bersama Nabi shallallahu 'alaihi wasallam sebanyak tujuh peperangan. Aku bertugas mengobati pasukan yang terluka serta membuatkan makanan untuk mereka dan menggantikan dipersinggahan mereka.\""},"1961":{"ar":" أَخْبَرَنَا أَبُو نُعَيْمٍ حَدَّثَنَا عَبْدُ الْوَاحِدِ بْنُ أَيْمَنَ قَالَ حَدَّثَنِي ابْنُ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا خَرَجَ أَقْرَعَ بَيْنَ نِسَائِهِ فَطَارَتْ الْقُرْعَةُ عَلَى عَائِشَةَ وَحَفْصَةَ فَخَرَجَتَا مَعَهُ جَمِيعًا","id":"Telah mengabarkan kepada kami [Abu Nu'aim] telah menceritakan kepada kami [Abdul Wahid bin Aiman], ia berkata; telah menceritakan kepadaku [Ibnu Abu Mulaikah] dari [Al Qasim bin Muhammad] dari [Aisyah], ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak keluar (bepergian) beliau mengundi diantara para isterinya. Ternyata undian jatuh kepada 'Aisyah dan Hafshah, maka keduanyapun turut keluar bersama beliau.\""},"1962":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ حَدَّثَنَا أَبُو عَقِيلٍ زُهْرَةُ بْنُ مَعْبَدٍ عَنْ أَبِي صَالِحٍ مَوْلَى عُثْمَانَ قَالَ سَمِعْتُ عُثْمَانَ عَلَى الْمِنْبَرِ وَهُوَ يَقُولُ إِنِّي كُنْتُ كَتَمْتُكُمْ حَدِيثًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَرَاهِيَةَ تَفَرُّقِكُمْ عَنِّي ثُمَّ بَدَا لِي أَنْ أُحَدِّثَكُمُوهُ لِيَخْتَارَ امْرُؤٌ لِنَفْسِهِ مَا بَدَا لَهُ إِنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ أَلْفِ يَوْمٍ فِيمَا سِوَاهُ مِنْ الْمَنَازِلِ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Laits bin Sa'd] telah menceritakan kepada kami [Abu 'Uqail Zuhrah bin Ma'bad] dari [Abu Shalih] mantan budak Utsman, ia berkata; Aku mendengar [Utsman] berkata di atas mimbar; \"Sesungguhnya aku pernah menyembunyikan satu hadits dari kalian yang aku dengar dari Rasulullah shallallahu 'alaihi wasallam, sebab aku tidak ingin kalian memisahkan diri dariku. Nampaknya sekarang aku ingin menceritakannya kepada kalian, supaya seseorang memilih untuk dirinya atas sesuatu yang ia inginkan. Sesungguhnya aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berjaga-jaga sehari di jalan Allah lebih baik daripada seribu hari ditempat lain.\""},"1963":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا ابْنُ لَهِيعَةَ عَنْ مِشْرَحٍ قَالَ سَمِعْتُ عُقْبَةَ بْنَ عَامِرٍ يَقُولُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ كُلُّ مَيِّتٍ يُخْتَمُ عَلَى عَمَلِهِ إِلَّا الْمُرَابِطَ فِي سَبِيلِ اللَّهِ فَإِنَّهُ يُجْرَى لَهُ عَمَلُهُ حَتَّى يُبْعَثَ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Ibnu Lahi'ah] dari [Misyrah] dia berkata; aku mendengar ['Uqbah bin 'Amir] dia berkata; \"Aku mendengar Rasulullah Shallallahu 'alaihi wasalllam bersabda: \"Setiap orang yang telah mati akan terputus amalnya kecuali orang yang pernah berjaga-jaga dijalan Allah, sesungguhnya amalnya akan tetap mengalir hingga dia dibangkitkan.\""},"1964":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا زَكَرِيَّا عَنْ عَامِرٍ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Zakariya] dari ['Amir] dari ['Urwah Al Bariqi], ia berkata; Rasulullah Shalallahu 'alaihi wasallam bersabda: \"Kuda yang tertambat pada jambulnya (yang disiapkan untuk berperang) senantiasa terdapat kebaikan hingga hari Kiamat.\""},"1965":{"ar":" أَخْبَرَنَا سَعِيدُ بْنُ الرَّبِيعِ حَدَّثَنَا شُعْبَةُ عَنْ حُصَيْنٍ وَعَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah mengabarkan kepada kami [Sa'id bin Ar Rabi'] telah menceritakan kepada kami [Syu'bah] dari [Hushain] dan [Abdullah bin Abu Safar] dari [Asy Sya'bi] dari ['Urwah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kuda yang tertambat pada jambulnya (yang disiapkan untuk berperang) sanantiasa terdapat kebaikan berupa pahala dan ghanimah hingga hari Kiamat.\""},"1966":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ الرَّحْمَنِ الدِّمَشْقِيُّ حَدَّثَنَا الْوَلِيدُ حَدَّثَنِي ابْنُ لَهِيعَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عُلَيِّ بْنِ رَبَاحٍ عَنْ أَبِي قَتَادَةَ الْأَنْصَارِيِّ أَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنِّي أُرِيدُ أَنْ أَشْتَرِيَ فَرَسًا فَأَيُّهَا أَشْتَرِي قَالَ اشْتَرِ أَدْهَمَ أَرْثَمَ مُحَجَّلَ طَلْقَ الْيَدِ الْيُمْنَى أَوْ مِنْ الْكُمْتِ عَلَى هَذِهِ الشِّيَةِ تَغْنَمْ وَتَسْلَمْ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdurrahman Ad Dimasyqi] telah menceritakan kepada kami [Al Walid] telah menceritakan kepadaku [Ibnu Lahi'ah] dari [Yazid bin Abu Habib] dari [Ali bin Rabah] dari [Abu Qatadah Al Anshari] bahwa seorang laki-laki berkata; \"Wahai Rasulullah, sesungguhnya aku ingin membeli seekor kuda, maka kuda bagaimanakah yang harus akuu beli? Beliau menjawab: \"Belilah kuda yang berwarna hitam, hidung dan bibir atasnya putih, dikaki terdapat warna putih, kaki depan yang kanan polos atau yang berwarna merah kehitaman, dengan tanda seperti ini, maka engkau akan mendapatkan keberuntungan dan selamat.\""},"1967":{"ar":" حَدَّثَنَا خَالِدُ بْنُ مَخْلَدٍ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُسَابِقُ بَيْنَ الْخَيْلِ الْمُضَمَّرَةِ مِنْ الْحَفْيَا إِلَى الثَّنِيَّةِ وَالَّتِي لَمْ تُضَمَّرْ مِنْ الثَّنِيَّةِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ وَأَنَّ ابْنَ عُمَرَ كَانَ فِيمَنْ سَابَقَ بِهَا","id":"Telah menceritakan kepada kami [Khalid bin Makhlad] telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah melombakan antara kuda yang khusus untuk pacuan dilepas dari Al Hafya` dan berakhir hingga Tsaniyah Al Wada`, dan melombakan antara kuda yang biasa (tidak dipersiapkan untuk pacuan) dilepas dari Ats Tsaniyah hingga masjid Bani Zuraiq, sedangkan Ibnu Umar termasuk diantara orang yang ikut pacuan."},"1968":{"ar":" أَخْبَرَنَا عَفَّانُ حَدَّثَنَا سَعِيدُ بْنُ زَيْدٍ حَدَّثَنِي الزُّبَيْرُ بْنُ الْخِرِّيتِ عَنْ أَبِي لَبِيدٍ قَالَ أُجْرِيَتْ الْخَيْلُ فِي زَمَنِ الْحَجَّاجِ وَالْحَكَمُ بْنُ أَيُّوبَ عَلَى الْبَصْرَةِ فَأَتَيْنَا الرِّهَانَ فَلَمَّا جَاءَتْ الْخَيْلُ قَالَ قُلْنَا لَوْ مِلْنَا إِلَى أَنَسِ بْنِ مَالِكٍ فَسَأَلْنَاهُ أَكَانُوا يُرَاهِنُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فَأَتَيْنَاهُ وَهُوَ فِي قَصْرِهِ فِي الزَّاوِيَةِ فَسَأَلْنَاهُ فَقُلْنَا يَا أَبَا حَمْزَةَ أَكُنْتُمْ تُرَاهِنُونَ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُرَاهِنُ قَالَ نَعَمْ لَقَدْ رَاهَنَ عَلَى فَرَسٍ لَهُ يُقَالُ لَهُ سَبْحَةُ فَسَبَقَ النَّاسَ فَانْهَشَّ لِذَلِكَ وَأَعْجَبَهُ قَالَ أَبُو مُحَمَّد انْهَشَّ يَعْنِي أَعْجَبَهُ","id":"Telah mengabarkan kepada kami ['Affan] telah menceritakan kepada kami [Sa'id bin Zaid] telah Pada zaman Al Hajjaj menceritakan kepadaku [Az Zubair bin Al Khirrit] dari [Abu Labid], ia berkata; \"Pernah diadakan lomba pacuan kuda pada zaman Al Hajjaj, yaitu ketika Al Hakam bin Ayyub menjadi wali Bashrah. Kemudian kami lomba pacuan, tatkala seekor kuda telah tiba, kami berkata; \"Sekiranya kita pergi menemui [Anas bin Malik] dan bertanya kepadanya, apakah dahulu orang-orang melakukan lomba pacuan kuda pada zaman Rasulullah shallallahu 'alaihi wasallam, hal itu akan menjadi lebih baik.\" Maka kami datang menemui Anas, sementara ia tengah berada dalam rumahnya di Az Zawiyah. Kemudian kami bertanya kepadanya, kami berkata; \"Wahai Abu Hamzah, apakah dahulu kalian pernah melakukan lomba pacuan pada zaman Rasulullah shallallahu 'alaihi wasallam? Apakah Rasulullah shallallahu 'alaihi wasallam pernah ikut lomba pacuan?\" Ia menjawab; \"Ya, sungguh beliau pernah ikut lomba pacuan kudanya yang diberi nama Sabhah, dan kuda tersebut berhasil mendahului orang-orang, maka beliau senang dan kagum terhadapnya.\""},"1969":{"ar":" أَخْبَرَنَا عَمْرُو بْنُ عَاصِمٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ جَاهِدُوا الْمُشْرِكِينَ بِأَمْوَالِكُمْ وَأَنْفُسِكُمْ وَأَلْسِنَتِكُمْ","id":"Telah mengabarkan kepada kami ['Amr bin 'Ashim] telah menceritakan kepada kami [Hammad bin Salamah] telah menceritakan kepada kami [Humaid] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perangilah orang-orang musyrik dengan harta, jiwa dan lisan kalian.\""},"1970":{"ar":" أَخْبَرَنَا جَعْفَرُ بْنُ عَوْنٍ حَدَّثَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَيْسِ بْنِ أَبِي حَازِمٍ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ قَوْمٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى النَّاسِ حَتَّى يَأْتِيَ أَمْرُ اللَّهِ وَهُمْ ظَاهِرُونَ","id":"Telah mengabarkan kepada kami [Ja'far bin 'Aun] telah menceritakan kepada kami [Isma'il bin Abu Khalid] dari [Qais bin Abu Hazim] dari [Al Mughirah bin Syu'bah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Akan selalu ada sekelompok kaum dari umatku yang senantiasa menang di atas manusia hingga datang perkara Allah, sementara mereka dalam keadaan menang.\""},"1971":{"ar":" أَخْبَرَنَا أَبُو بَكْرِ بْنُ بَشَّارٍ حَدَّثَنَا أَبُو دَاوُدَ الطَّيَالِسِيُّ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ سُلَيْمَانَ بْنِ الرَّبِيعِ عَنْ عُمَرَ بْنِ الْخَطَّابِ قَالَ سَمِعْتُهُ يَقُولُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَزَالُ نَاسٌ مِنْ أُمَّتِي ظَاهِرِينَ عَلَى الْحَقِّ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Basyar] telah menceritakan kepada kami [Abu Daud Ath Thayalisi] telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Abdullah bin Buraidah] dari [Sulaiman bin Ar Rabi'] dari [Umar bin Al Khathab], ia berkata; aku mendengarnya berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Senantiasa akan ada sekelopok orang dari umatku yang berada diatas kebenaran.\""},"1972":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ بْنِ قَعْنَبٍ حَدَّثَنَا سُلَيْمَانُ هُوَ ابْنُ الْمُغِيرَةِ عَنْ حُمَيْدِ بْنِ هِلَالٍ عَنْ عَبْدِ اللَّهِ بْنِ الصَّامِتِ عَنْ أَبِي ذَرٍّ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ بَعْدِي مِنْ أُمَّتِي قَوْمًا يَقْرَءُونَ الْقُرْآنَ لَا يُجَاوِزُ حَلَاقِيمَهُمْ يَخْرُجُونَ مِنْ الدِّينِ كَمَا يَخْرُجُ السَّهْمُ مِنْ الرَّمِيَّةِ ثُمَّ لَا يَعُودُونَ فِيهِ هُمْ شَرُّ الْخَلْقِ وَالْخَلِيقَةِ قَالَ سُلَيْمَانُ قَالَ حُمَيْدٌ قَالَ عَبْدُ اللَّهِ بْنُ الصَّامِتِ فَلَقِيتُ رَافِعًا أَخَا الْحَكَمِ بْنِ عَمْرٍو الْغِفَارِيِّ فَحَدَّثْتُهُ هَذَا الْحَدِيثَ قَالَ رَافِعٌ وَأَنَا أَيْضًا سَمِعْتُهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Abdullah bin Maslamah bin Qa'nab] telah menceritakan kepada kami [Sulaiman yaitu Ibnu Al Mughirah] dari [Humaid bin Hilal] dari [Abdullah bin Ash Shamit] dari [Abu Dzar], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh sepeninggalku akan ada sekelompok kaum dari umatku yang membaca Al Qur'an tidak melebihi kerongkongan mereka. Mereka keluar dari agama seperti keluarnya anak panah dari busurnya. Kemudian mereka tidak kembali kepadanya (Islam), mereka adalah seburuk-buruk ciptaan.\" Sulaiman berkata; Humaid berkata; [Abdullah bin Ash Shamit] berkata; kemudian aku bertemu dengan Rafi' saudara Al Hakam bin 'Amr Al Ghifari, kemudian aku menceritakan hadits ini kepadanya. [Rafi'] berkata; \"Dan aku juga mendengarnya dari Rasulullah shallallahu 'alaihi wasallam.\""},"1973":{"ar":" حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ شُعْبَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عُمَارَةَ بْنِ حَدِيدٍ عَنْ صَخْرٍ الْغَامِدِيِّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اللَّهُمَّ بَارِكْ لِأُمَّتِي فِي بُكُورِهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا بَعَثَ سَرِيَّةً بَعَثَهَا مِنْ أَوَّلِ النَّهَارِ قَالَ فَكَانَ هَذَا الرَّجُلُ رَجُلًا تَاجِرًا فَكَانَ يَبْعَثُ غِلْمَانَهُ مِنْ أَوَّلِ النَّهَارِ فَكَثُرَ مَالُهُ","id":"Telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Syu'bah] dari [Ya'la bin 'Atha`] dari ['Umarah bin Hadid] dari [Shakhr Al Ghamidi] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berkahilah umatku dipagi harinya.\" Apabila Rasulullah shallallahu 'alaihi wasallam mengirim suatu pasukan, maka beliau mengirimnya diawal siang. Shakhr berkata; \"Seorang pedagang pernah mengutus budaknya (pergi) diawal siang, ternyata ia memperoleh harta yang melimpah."},"1974":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ أَخْبَرَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبٍ عَنْ أَبِيهِ قَالَ لَقَلَّمَا كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْرُجُ إِذَا أَرَادَ سَفَرًا إِلَّا يَوْمَ الْخَمِيسِ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah mengabarkan kepada kami [Yunus] dari [Az Zuhri] dari [Abdurrahman bin Ka'b] dari [Ayahnya], ia berkata; \"Sungguh jarang sekali Rasulullah shallallahu 'alaihi wasallam keluar bepergian kecuali pada hari Kamis.\""},"1975":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا حَيْوَةُ وَابْنُ لَهِيعَةَ قَالَا حَدَّثَنَا شُرَحْبِيلُ بْنُ شَرِيكٍ أَنَّهُ سَمِعَ أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَيْرُ الْأَصْحَابِ عِنْدَ اللَّهِ خَيْرُهُمْ لِصَاحِبِهِ وَخَيْرُ الْجِيرَانِ عِنْدَ اللَّهِ خَيْرُهُمْ لِجَارِهِ","id":"Telah menceritakan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Haiwah] dan [Ibnu Lahi'ah] keduanya berkata; telah menceritakan kepada kami [Syurahbil bin Syarik] bahwa ia mendengar [Abu Abdurrahman Al Hubuli] menceritakan dari [Abdullah bin 'Amr bin Al 'Ash] dari Rasulullah shallallahu 'alaihi wasallam beliau bersabda: \"Sebaik-baik sahabat di sisi Allah adalah yang paling baik kepada sahabatnya, dan sebaik-baik tetangga di sisi Allah adalah yang paling baik terhadap tetangganya.\" "},"1976":{"ar":" حَدَّثَنَا مُحَمَّدُ بْنُ الصَّلْتِ حَدَّثَنَا حِبَّانُ بْنُ عَلِيٍّ عَنْ يُونُسَ وَعُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَيْرُ الْأَصْحَابِ أَرْبَعَةٌ وَخَيْرُ الْجُيُوشِ أَرْبَعَةُ آلَافٍ وَخَيْرُ السَّرَايَا أَرْبَعُ مِائَةٍ وَمَا بَلَغَ اثْنَا عَشَرَ أَلْفًا فَصَبَرُوا وَصَدَقُوا فَغُلِبُوا مِنْ قِلَّةٍ","id":"Telah menceritakan kepada kami [Muhammad bin Ash Shalt] telah menceritakan kepada kami [Hibban bin Ali] dari [Yunus] serta ['Uqail] dari [Ibnu Syihab] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sebaik-baik sahabat adalah empat orang, dan sebaik-baik pasukan adalah empat ribu, dan sebaik-baik satuan pasukan adalah empat ratus dan tidaklah mereka mencapai dua belas ribu, lalu bersabar dan jujur maka mereka tidak akan terkalahkan.\""},"1977":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَّرَ رَجُلًا عَلَى سَرِيَّةٍ أَوْصَاهُ فِي خَاصَّةِ نَفْسِهِ بِتَقْوَى اللَّهِ وَبِمَنْ مَعَهُ مِنْ الْمُسْلِمِينَ خَيْرًا وَقَالَ اغْزُوا بِسْمِ اللَّهِ وَفِي سَبِيلِ اللَّهِ قَاتِلُوا مَنْ كَفَرَ بِاللَّهِ اغْزُوا وَلَا تَغْدِرُوا وَلَا تَغُلُّوا وَلَا تُمَثِّلُوا وَلَا تَقْتُلُوا وَلِيدًا","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] ia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam mengangkat seseorang sebagai pemimpin ekspedisi, beliau mewasiatkan kepadanya secara khusus agar bertakwa kepada Allah dan berbuat baik kepada orang-orang muslim yang bersamanya. Beliau bersabda: \"Berperanglah dengan nama Allah, dan di jalan Allah. Perangilah orang kafir kepada Allah, berperanglah kalian dan janganlah mundur, jangan mencuri rampasan perang, jangan mencincang dan jangan membunuh anak kecil.\""},"1978":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ يَزِيدَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ زِيَادٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍو أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَتَمَنَّوْا لِقَاءَ الْعَدُوِّ وَسَلُوا اللَّهَ الْعَافِيَةَ فَإِنْ لَقِيتُمُوهُمْ فَاثْبُتُوا وَأَكْثِرُوا ذِكْرَ اللَّهِ فَإِنْ أَجْلَبُوا وَضَجُّوا فَعَلَيْكُمْ بِالصَّمْتِ","id":"Telah mengabarkan kepada kami [Abdullah bin Yazid] telah menceritakan kepada kami [Abdurrahman bin Yazid] dari [Abdullah bin Yazid] dari [Abdullah bin 'Amr] bahwa Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah kalian berangan-angan bertemu dengan musuh, dan mohonlah keselamatan kepada Allah, apabila kalian bertemu dengan musuh, maka teguhkanlah dan perbanyaklah berdzikir kepada Allah, apabila mereka berteriak dan membuat gaduh, maka kalian harus diam.\""},"1979":{"ar":" أَخْبَرَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ أَبِي لَيْلَى عَنْ صُهَيْبٍ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَدْعُو أَيَّامَ حُنَيْنٍ اللَّهُمَّ بِكَ أُحَاوِلُ وَبِكَ أُصَاوِلُ وَبِكَ أُقَاتِلُ","id":"Telah mengabarkan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Abdurrahman bin Abu Laila] dari [Shuhaib] bahwa Rasulullah shallallahu 'alaihi wasallam berdoa pada saat perang Hunain: \"Ya Allah, dengan-Mu aku berusaha, dengan-Mu kami menyerbu, dan dengan-Mu aku menyerang.\""},"1980":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَمَّرَ رَجُلًا عَلَى سَرِيَّةٍ أَوْصَاهُ إِذَا لَقِيتَ عَدُوَّكَ مِنْ الْمُشْرِكِينَ فَادْعُهُمْ إِلَى إِحْدَى ثَلَاثِ خِلَالٍ أَوْ خِصَالٍ فَأَيَّتُهُمْ مَا أَجَابُوكَ إِلَيْهَا فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ثُمَّ ادْعُهُمْ إِلَى الْإِسْلَامِ فَإِنْ هُمْ أَجَابُوكَ فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ ثُمَّ ادْعُهُمْ إِلَى التَّحَوُّلِ مِنْ دَارِهِمْ إِلَى دَارِ الْمُهَاجِرِينَ وَأَخْبِرْهُمْ إِنْ هُمْ فَعَلُوا أَنَّ لَهُمْ مَا لِلْمُهَاجِرِينَ وَأَنَّ عَلَيْهِمْ مَا عَلَى الْمُهَاجِرِينَ فَإِنْ هُمْ أَبَوْا فَأَخْبِرْهُمْ أَنَّهُمْ يَكُونُونَ كَأَعْرَابِ الْمُسْلِمِينَ يَجْرِي عَلَيْهِمْ حُكْمُ اللَّهِ الَّذِي يَجْرِي عَلَى الْمُؤْمِنِينَ وَلَيْسَ لَهُمْ فِي الْفَيْءِ وَالْغَنِيمَةِ نَصِيبٌ إِلَّا أَنْ يُجَاهِدُوا مَعَ الْمُسْلِمِينَ فَإِنْ هُمْ أَبَوْا أَنْ يَدْخُلُوا فِي الْإِسْلَامِ فَسَلْهُمْ إِعْطَاءَ الْجِزْيَةِ فَإِنْ فَعَلُوا فَاقْبَلْ مِنْهُمْ وَكُفَّ عَنْهُمْ فَإِنْ هُمْ أَبَوْا فَاسْتَعِنْ بِاللَّهِ وَقَاتِلْهُمْ وَإِنْ حَاصَرْتَ أَهْلَ حِصْنٍ فَإِنْ أَرَادُوكَ أَنْ تَجْعَلَ لَهُمْ ذِمَّةَ اللَّهِ وَذِمَّةَ نَبِيِّهِ فَلَا تَجْعَلْ لَهُمْ ذِمَّةَ اللَّهِ وَلَا ذِمَّةَ نَبِيِّهِ وَلَكِنْ اجْعَلْ لَهُمْ ذِمَّتَكَ وَذِمَّةَ أَبِيكَ وَذِمَّةَ أَصْحَابِكَ فَإِنَّكُمْ إِنْ تُخْفِرُوا بِذِمَّتِكُمْ وَذِمَّةِ آبَائِكُمْ أَهْوَنُ عَلَيْكُمْ مِنْ أَنْ تُخْفِرُوا ذِمَّةَ اللَّهِ وَذِمَّةَ رَسُولِهِ وَإِنْ حَاصَرْتَ حِصْنًا فَأَرَادُوكَ أَنْ يَنْزِلُوا عَلَى حُكْمِ اللَّهِ فَلَا تُنْزِلْهُمْ عَلَى حُكْمِ اللَّهِ وَلَكِنْ أَنْزِلْهُمْ عَلَى حُكْمِكَ فَإِنَّكَ لَا تَدْرِي أَتُصِيبُ حُكْمَ اللَّهِ فِيهِمْ أَمْ لَا ثُمَّ اقْضِ فِيهِمْ بِمَا شِئْتَ قَالَ عَلْقَمَةُ فَحَدَّثْتُ بِهِ مُقَاتِلَ بْنَ حَيَّانَ فَقَالَ حَدَّثَنِي مُسْلِمُ بْنُ هَيْصَمٍ عَنْ النُّعْمَانِ بْنِ مُقَرِّنٍ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [Ayahnya] ia berkata; Apabila Rasulullah shallallahu 'alaihi wasallam mengangkat seseorang sebagai pemimpin ekspedisi, beliau akan berwasiat kepadanya: \"Apabila engkau berjumpa dengan musuh dari kaum musyrikin, maka ajaklah mereka kepada salah satu tiga perkara, yaitu; Siapapun diantara mereka yang memenuhi seruanmu untuk melakukannya maka terimalah mereka, dan tahanlah untuk tidak menyerang mereka, kemudian ajaklah mereka kepada Islam. Apabila mereka memenuhi seruanmu maka terimalah dan tahanlah untuk tidak menyerang mereka, kemudian ajaklah mereka agar berpindah dari negeri mereka menuju negeri hijrah, dan beritahukan kepada mereka, apabila mereka melakukan hal itu maka bagi mereka apa yang menjadi hak orang-orang muhajirin dan apa yang menjadi kewajiban mereka adalah yang menjadi kewajiban orang-orang muhajirin. Apabila mereka menolak maka beritahukan kepada mereka bahwa mereka seperti orang-orang badui muslim yang diberlakukan atas mereka hukum Allah sebagaimana yang berlaku terhadap orang-orang mukmin dan mereka tidak memiliki bagian fai` dan rampasan perang kecuali mereka berjihad bersama orang-orang muslim. Dan apabila mereka menolak untuk masuk Islam, maka mintalah mereka supaya membayar Jizyah, apabila mereka melakukan hal itu, maka terimalah mereka dan tahanlah untuk tidak menyerang mereka, apabila mereka menolak, maka mintalah pertolongan Allah dan perangilah mereka. Apabila engkau mengepung penghuni benteng, kemudian mereka ingin agar engkau memberikan kepada mereka perlindungan Allah dan perlindungan NabiNya, maka janganlah engkau memberikan kepada mereka perlindungan Allah dan perlindungan NabiNya, akan tetapi berikan kepada mereka perlindunganmu, perlindungan ayahmu dan perlindungan para sahabamu. Karena apabila engkau salah dalam memberikan perlindungan kalian serta bapak-bapak kalian, hal itu lebih ringan daripada kalian salah dalam memberikan perlindungan Allah dan RasulNya. Apabila engkau mengepung benteng dan mereka hendak memutuskan (perkara) dengan hukum Allah, maka janganlah engkau memutuskan (perkara) mereka dengan hukum Allah, akan tetapi putusilah mereka dengan hukummu. Karena engkau tidak mengetahui apakah engkau sesuai dengan hukum Allah mengenai mereka atau tidak. Kemudian berilah keputusan mengenai mereka sesuai kehendakmu.\" ['Alqamah] berkata; kemudian aku menceritakannya kepada [Muqatil bin Hayyan] lalu ia berkata; telah menceritkan kepadaku [Muslim bin Haisham] dari [An Nu'man bin Muqarrin] dari Nabi shallallahu 'alaihi wasallam seperti hadits di atas."},"1981":{"ar":" أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى عَنْ سُفْيَانَ عَنْ ابْنِ أَبِي نَجِيحٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَ مَا قَاتَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَوْمًا حَتَّى دَعَاهُمْ قَالَ عَبْد اللَّهِ سُفْيَانُ لَمْ يَسْمَعْ مِنْ ابْنِ أَبِي نَجِيحٍ يَعْنِي هَذَا الْحَدِيثَ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Musa] dari [Sufyan] dari [Ibnu Abu Najih] dari [Ayahnya] dari [Ibnu Abbas], ia berkata; Tidaklah Rasulullah shallallahu 'alaihi wasallam memerangi suatu kaum hingga beliau mengajak mereka (kepada Islam).\" Abdullah berkata; Sufyan tidak mendengar hadits ini dari Ibnu Najih.\""},"1982":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يُغِيرُ عِنْدَ صَلَاةِ الْفَجْرِ وَكَانَ يَسْتَمِعُ فَإِنْ سَمِعَ أَذَانًا أَمْسَكَ وَإِنْ لَمْ يَسْمَعْ أَذَانًا أَغَارَ","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa Nabi shallallahu 'alaihi wasallam pernah menyerang dengan tiba-tiba ketika waktu Shubuh, dan beliau mendengarkan dengan cermat, apabila beliau mendengar adzan, maka beliau menahan diri, dan apabila tidak mendengar adzan, maka beliau menyerang.\""},"1983":{"ar":" أَخْبَرَنَا هَاشِمُ بْنُ الْقَاسِمِ حَدَّثَنَا شُعْبَةُ عَنْ النُّعْمَانِ بْنِ سَالِمٍ قَالَ سَمِعْتُ أَوْسَ بْنَ أَبِي أَوْسٍ الثَّقَفِيَّ قَالَ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي وَفْدِ ثَقِيفٍ قَالَ وَكُنْتُ فِي أَسْفَلِ الْقُبَّةِ لَيْسَ فِيهَا أَحَدٌ إِلَّا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَائِمٌ إِذْ أَتَاهُ رَجُلٌ فَسَارَّهُ فَقَالَ اذْهَبْ فَاقْتُلْهُ ثُمَّ قَالَ أَلَيْسَ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ قَالَ شُعْبَةُ وَأَشُكُّ مُحَمَّدًا رَسُولُ اللَّهِ قَالَ بَلَى قَالَ إِنِّي أُمِرْتُ أَنْ أُقَاتِلَ النَّاسَ حَتَّى يَقُولُوا لَا إِلَهَ إِلَّا اللَّهُ فَإِذَا قَالُوهَا حَرُمَتْ عَلَيَّ دِمَاؤُهُمْ وَأَمْوَالُهُمْ إِلَّا بِحَقِّهَا وَحِسَابُهُمْ عَلَى اللَّهِ قَالَ وَهُوَ الَّذِي قَتَلَ أَبَا مَسْعُودٍ قَالَ وَمَا مَاتَ حَتَّى قَتَلَ خَيْرَ إِنْسَانٍ بِالطَّائِفِ","id":"Telah mengabarkan kepada kami [Hasyim bin Al Qasim] telah menceritakan kepada kami [Syu'bah] dari [An Nu'man bin Salim], ia berkata; aku mendengar [Aus bin Abu Aus Ats Tsaqafi] ia berkata; aku datang menemui Rasulullah shallallahu 'alaihi wasallam di antara delegasi Tsaqif, Aus melanjutkan; \"Ketika itu aku berada di bawah tenda, dan tidak ada seorangpun di dalam tebda tersebut kecuali Nabi shallallahu 'alaihi wasallam yang sedang tidur, tiba-tiba seorang laki-laki datang kepada beliau sambil berbisik, beliau bersabda: \"Pergilah dan bunuhlah dia.\" Kemudian beliau bersabda: \"Bukankah ia telah mengucapkan bahwa tidak ada sesembahan yang berhak disembah selain Allah?\" - [Syu'bah] berkata; dan saya ragu apakah beliau mengatakan: \"Dan aku adalah rasulullah?.\"- Orang tersebut berkata; \"Ya.\" Beliau bersabda: \"Sesungguhnya aku diperintahkan untuk memerangi manusia hingga mereka mengucapkan; tidak ada sesembahan yang berhak disembah selain Allah., apabila mereka mengucapkan hal itu, maka telah haram atasku darah dan harta mereka kecuali dengan haknya dan perhitungannya kembali kepada Allah.\" Aus bin Abu Aus Ats Tsaqafi berkata; \"Orang tersebut adalah yang membunuh Abu Mas'ud. Dan tidaklah ia mati sampai ia membunuh orang-orang terbaik di Tha`if."},"1984":{"ar":" أَخْبَرَنَا يَعْلَى حَدَّثَنَا الْأَعْمَشُ عَنْ عَبْدِ اللَّهِ بْنِ مُرَّةَ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَحِلُّ دَمُ رَجُلٍ يَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ إِلَّا إِحْدَى ثَلَاثَةِ نَفَرٍ النَّفْسُ بِالنَّفْسِ وَالثَّيِّبُ الزَّانِي وَالتَّارِكُ لِدِينِهِ الْمُفَارِقُ لِلْجَمَاعَةِ","id":"Telah mengabarkan kepada kami [Ya'la] telah menceritakan kepada kami [Al A'masy] dari [Abdullah bin Murrah] dari [Masruq] dari [Abdullah] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal darah seseorang yang bersaksi bahwa tidak ada sesembahan yang berhak disembah selain Allah, kecuali salah satu dari tiga orang, yaitu; orang yang dibunuh karena membunuh jiwa, janda (duda) yang berzina, orang yang meninggalkan agamanya dan memisahkan diri dari jama'ah.\""},"1985":{"ar":" حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ حَدَّثَنَا الْأَسْوَدُ بْنُ شَيْبَانَ عَنْ خَالِدِ بْنِ سُمَيْرٍ قَالَ قَدِمَ عَلَيْنَا عَبْدُ اللَّهِ بْنُ رَبَاحٍ الْأَنْصَارِيُّ وَكَانَتْ الْأَنْصَارُ تُفَقِّهُهُ قَالَ حَدَّثَنَا أَبُو قَتَادَةَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ جَيْشَ الْأُمَرَاءِ قَالَ فَانْطَلَقُوا فَلَبِثُوا مَا شَاءَ اللَّهُ ثُمَّ صَعِدَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمِنْبَرَ فَأَمَرَ فَنُودِيَ الصَّلَاةُ جَامِعَةٌ","id":"Telah menceritakan kepada kami [Sulaiman bin Harb] telah menceritakan kepada kami [Al Aswad bin Syaiban] dari [Khalid bin Sumair] ia berkata; [Abdullah bin Rabah Al Anshari] datang kepada kami, sementara orang-orang Anshar-lah yang memberikan pemahaman kepadanya, ia berkata; telah menceritakan kepada kami [Abu Qatadah] bahwa Rasulullah shallallahu 'alaihi wasallam pernah mengutus pasukan Umara` (pasukan pada saat perang mu'tah), Abdullah bin Rabah berkata; kemudian mereka pergi dan tinggal dalam waktu yang dikehendaki Allah, kemudian Rasulullah shallallahu 'alaihi wasallam naik mimbar, beliau memerintahkan agar dikumandangkan seruan untuk shalat berjama'ah, maka diserulah; \"Shalat berjama'ah!.\""},"1986":{"ar":" أَخْبَرَنَا الْأَسْوَدُ بْنُ عَامِرٍ حَدَّثَنَا شَرِيكٌ عَنْ الْأَعْمَشِ عَنْ أَبِي عَمْرٍو الشَّيْبَانِيِّ عَنْ أَبِي مَسْعُودٍ الْأَنْصَارِيِّ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُسْتَشَارُ مُؤْتَمَنٌ","id":"Telah mengabarkan kepada kami [Al Aswad bin 'Amir] telah menceritakan kepada kami [Syarik] dari [Al A'masy] dari [Abu 'Amr Asy Syaibani] dari [Abu Mas'ud Al Anshari] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Hendaknya orang yang dimintai nasehat adalah orang yang dapat dipercaya (amanah).\""},"1987":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يَزِيدَ الْحِزَامِيُّ حَدَّثَنَا ابْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ كَعْبِ بْنِ مَالِكٍ قَالَ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا أَرَادَ غَزْوَةً وَرَّى بِغَيْرِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Yazid Al Hizami] telah menceritakan kepada kami [Ibnu Al Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Abdurrahman bin Ka'b bin Malik] dari [Ka'b Malik] ia berkata; \"Apabila Rasulullah shallallahu 'alaihi wasallam hendak berperang, maka beliau merahasiakannya.\""},"1988":{"ar":" حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا وَكِيعٌ عَنْ أَبِي عُمَيْسٍ عَنْ إِيَاسِ بْنِ سَلَمَةَ بْنِ الْأَكْوَعِ عَنْ أَبِيهِ قَالَ بَارَزْتُ رَجُلًا فَقَتَلْتُهُ فَنَفَّلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَلَبَهُ فَكَانَ شِعَارُنَا مَعَ خَالِدِ بْنِ الْوَلِيدِ أَمِتْ يَعْنِي اقْتُلْ","id":"Telah menceritakan kepada kami [Ishaq bin Ibrahim] telah menceritakan kepada kami [Waki'] dari [Abu 'Umais] dari [Iyas bin Salamah bin Al Akwa'] dari [Ayahnya] ia berkata; \"Aku pernah perang tanding melawan seseorang, kemudian aku membunuhnya, lalu Rasulullah shallallahu 'alaihi wasallam memberiku segala sesuatu yang melekat pada musuh tersebut, sedangkan motto kami bersama Khalid bin Al Walid adalah matikan; \"Yaitu bunuhlah!.\""},"1989":{"ar":" حَدَّثَنَا حَجَّاجُ بْنُ مِنْهَالٍ وَعَفَّانُ قَالَا حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ يَعْلَى بْنِ عَطَاءٍ عَنْ عَبْدِ اللَّهِ بْنِ يَسَارٍ أَبِي هَمَّامٍ عَنْ أَبِي عَبْدِ الرَّحْمَنِ الْفِهْرِيِّ قَ��لَ كُنَّا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ حُنَيْنٍ فَكُنَّا فِي يَوْمٍ قَائِظٍ شَدِيدِ الْحَرِّ فَنَزَلْنَا تَحْتَ ظِلَالِ الشَّجَرِ فَذَكَرَ الْقِصَّةَ ثُمَّ أَخَذَ كَفًّا مِنْ تُرَابٍ قَالَ فَحَدَّثَنِي الَّذِي هُوَ أَقْرَبُ إِلَيْهِ مِنِّي أَنَّهُ ضَرَبَ بِهِ وُجُوهَهُمْ وَقَالَ شَاهَتْ الْوُجُوهُ فَهَزَمَ اللَّهُ الْمُشْرِكِينَ قَالَ يَعْلَى فَحَدَّثَنِي أَبْنَاؤُهُمْ أَنَّ أَبَاءَهُمْ قَالُوا فَمَا بَقِيَ مِنَّا أَحَدٌ إِلَّا امْتَلَأَتْ عَيْنَاهُ وَفَمُهُ تُرَابًا","id":"Telah menceritakan kepada kami [Hajjaj bin Minhal] dan ['Affan] keduanya berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ya'la bin 'Atha`] dari [Abdullah bin Yasar Abu Hammam] dari [Abu Abdurrahman Al Fihri] ia berkata; kami bersama Rasulullah shallallahu 'alaihi wasallam dalam perang Hunain, ketika itu kami berada di hari yang sangat panas, kami pun singgah di bawah naungan pohon.\" Abdurrahman lalu menyebutkan kisah tersebut, \"…kemudian beliau mengambil segenggam tanah. Perawi berkata; telah menceritakan kepadaku orang yang lebih dekat denganku bahwa beliau menaburi wajah musuh dengan tanah tersebut sambil bersabda: \"Wajah-wajah yang buruk.\" Kemudian Allah mengalahkan orang-orang musyrik.\" Ya'la berkata; telah menceritakan kepadaku anak-anak mereka, bahwa bapak-bapak mereka berkata; \"Tidak ada seorangpun dari kami (waktu itu) melainkan mata dan mulut kami penuh dengan tanah.\""},"1990":{"ar":" حَدَّثَنَا عُثْمَانُ بْنُ عُمَرَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ أَبِي إِدْرِيسَ عَنْ عُبَادَةَ بْنِ الصَّامِتِ قَالَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَنَحْنُ مَعَهُ فِي مَجْلِسٍ بَايِعُونِي عَلَى أَنْ لَا تُشْرِكُوا بِاللَّهِ شَيْئًا وَلَا تَسْرِقُوا وَلَا تَزْنُوا وَلَا تَقْتُلُوا أَوْلَادَكُمْ وَلَا تَأْتُوا بِبُهْتَانٍ تَفْتَرُونَهُ بَيْنَ أَيْدِيكُمْ وَأَرْجُلِكُمْ فَمَنْ وَفَى مِنْكُمْ فَأَجْرُهُ عَلَى اللَّهِ وَمَنْ أَصَابَ شَيْئًا مِنْ ذَلِكَ فَسَتَرَهُ اللَّهُ فَأَمْرُهُ إِلَى اللَّهِ إِنْ شَاءَ عَاقَبَهُ وَإِنْ شَاءَ عَفَا عَنْهُ وَمَنْ أَصَابَ مِنْ ذَلِكَ شَيْئًا فَعُوقِبَ بِهِ فِي الدُّنْيَا فَهُوَ كَفَّارَةٌ لَهُ قَالَ فَبَايَعْنَاهُ عَلَى ذَلِكَ","id":"Telah menceritakan kepada kami [Utsman bin Umar] telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Abu Idris] dari ['Ubadah bin Ash Shamit] ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami, keitka kami bersama beliau disuatu majelis: \"Berbai'atlah kepadaku untuk tidak mensekutukan Allah dengan sesuatupun, tidak mencuri, tidak berzina, tidak membunuh anak-anak kalian dan tidak mengadakan kebohongan yang kalian ada-adakan antara tangan dan kaki kalian. Barangsiapa memenuhinya, maka pahalanya di sisi Allah. Dan barangsiapa melakukan satu dari hal tersebut, kemudian Allah menutupinya, maka urusannya kembali kepada Allah, apabila Allah menghendaki, maka Dia akan menghukumnya dan apabila Allah menghendaki maka Dia akan memaafkannya. Dan barangsiapa melakukan satu dari hal tersebut kemudian dihukum di dunia, maka hal itu sebagai penghapus dosa baginya.\" 'Ubadah bin Ash Shamit berkata; kemudian kami berbai'at kepada beliau untuk hal itu.\""},"1991":{"ar":" أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ حَدَّثَنَا لَيْثُ بْنُ سَعْدٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ أَنَّهُ قَالَ كُنَّا يَوْمَ الْحُدَيْبِيَةِ أَلْفًا وَأَرْبَعَ مِائَةٍ فَبَايَعْنَاهُ وَعُمَرُ آخِذٌ بِيَدِهِ تَحْتَ الشَّجَرَةِ وَهِيَ سَمُرَةٌ وَقَالَ بَايَعْنَاهُ عَلَى أَنْ لَا نَفِرَّ وَلَمْ نُبَايِعْهُ عَلَى الْمَوْتِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah] telah menceritakan kepada kami [Laits bin Sa'd] dari [Abu Az Zubair] dari [Jabir bin Abdullah] bahwa ia berkata; \"Pada saat perjanjian Hudaibiyah, kami berjumlah seribu empat ratus orang, kemudian kami berbai'at kepada beliau, sementara Umar menggandeng tangan beliau di bawah Pohon Samurah.\" Jabir berkata; \"Kami berbai'at kepada beliau untuk tidak lari dan tidak berbai'at untuk mati.\""},"1992":{"ar":" أَخْبَرَنَا أَبُو الْوَلِيدِ حَدَّثَنَا شُعْبَةُ حَدَّثَنَا أَبُو إِسْحَقَ قَالَ سَمِعْتُ الْبَرَاءَ بْنَ عَازِبٍ يَقُولُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَنْقُلُ مَعَنَا التُّرَابَ يَوْمَ الْأَحْزَابِ وَقَدْ وَارَى التُّرَابُ بَيَاضَ إِبِطَيْهِ وَهُوَ يَقُولُ اللَّهُمَّ لَوْلَا أَنْتَ مَا اهْتَدَيْنَا وَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَا فَأَنْزِلَنَّ سَكِينَةً عَلَيْنَا وَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَا إِنَّ الْأُولَى قَدْ بَغَوْا عَلَيْنَا وَإِنْ أَرَادُوا فِتْنَةً أَبَيْنَا وَيَرْفَعُ بِهَا صَوْتَهُ","id":"Telah mengabarkan kepada kami [Abu Al Walid] telah menceritakan kepada kami [Syu'bah] telah menceritakan kepada kami [Abu Ishaq] ia berkata; Aku mendengar [Al Bara` bin 'Azib] berkata; Kami bersama Rasulullah shallallahu 'alaihi wasallam pernah memindahkan tanah pada saat perang Ahzab, tanah tersebut telah menutupi kedua ketiak beliau yang putih, sementara beliau bersenandung: \"Ya Allah, seandainya bukan karenaMu, maka kami tidak akan mendapatkan petunjuk, tidak akan bersedekah dan tidak akan melakukan shalat, maka turunkanlah ketenangan kepada kami, serta kokohkan kaki-kaki kami apabila bertemu dengan musuh. Sesungguhnya orang-orang musyrik telah berlaku semena-mena kepada kami, apabila mereka menghendaki fitnah, maka kami menolaknya.\" Beliau menyenandungkan itu sambil mengeraskan suaranya."},"1993":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ خَالِدِ بْنِ حَازِمٍ حَدَّثَنَا مَالِكٌ عَنْ الزُّهْرِيِّ عَنْ أَنَسٍ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ مَكَّةَ عَامَ الْفَتْحِ وَعَلَى رَأْسِهِ مِغْفَرٌ فَلَمَّا نَزَعَهُ جَاءَهُ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ هَذَا ابْنُ خَطَلٍ مُتَعَلِّقٌ بِأَسْتَارِ الْكَعْبَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْتُلُوهُ","id":"Telah menceritakan kepada kami [Abdullah bin Khalid bin Hazim] telah menceritakan kepada kami [Malik] dari [Az Zuhri] dari [Anas] bahwa pada waktu penaklukan kota Makkah, Nabi shallallahu 'alaihi wasallam memasuki kota Makkah sambil mengenakan penutup kepala diatas kepala beliau, ketika beliau membukannya, seorang laki-laki langsung menemuinya sambil berkata; \"Wahai Rasulullah, ini Ibnu Khathal sedang bergelayutan ditirai Ka'bah.\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bunuhlah dia! \""},"1994":{"ar":" أَخْبَرَنَا أَبُو النُّعْمَانِ حَدَّثَنَا جَرِيرُ بْنُ حَازِمٍ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَ كَانَ قَبِيعَةُ سَيْفِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ فِضَّةٍ قَالَ عَبْد اللَّهِ هِشَامٌ الدَّسْتَوَائِيُّ خَالَفَهُ قَالَ قَتَادَةُ عَنْ سَعِيدِ بْنِ أَبِي الْحَسَنِ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَزَعَمَ النَّاسُ أَنَّهُ هُوَ الْمَحْفُوظُ","id":"Telah mengabarkan kepada kami [Abu An Nu'man] telah menceritakan kepada kami [Jarir bin Hazim] dari [Qatadah] dari [Anas], ia berkata; \"Sarung pedang Nabi shallallahu 'alaihi wasallam terbuat dari perak.\" Abdullah berkata; namun [Hisyam Ad Dastawa`i] menyelisihinya. [Qatadah] mengatakan dari [Sa'id bin Al Hasan] dari Nabi shallallahu 'alaihi wasallam...\" sementara orang-orang menyangka bahwa hadits tersebut adalah hadits mahfuzh.\""},"1995":{"ar":" أَخْبَرَنَا الْمُعَلَّى بْنُ أَسَدٍ حَدَّثَنَا مُعَاذُ بْنُ مُعَاذٍ حَدَّثَنَا سَعِيدُ بْنُ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ عَنْ أَبِي طَلْحَةَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ إِذَا ظَهَرَ عَلَى قَوْمٍ أَحَبَّ أَنْ يُقِيمَ بِعَرْصَتِهِمْ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Al Mu'alla bin Asad] telah menceritakan kepada kami [Mu'adz bin Mu'adz] telah menceritakan kepada kami [Sa'id bin Abu 'Arubah] dari [Qatadah] dari [Anas] dari [Abu Thalhah] bahwa apabila Nabi shallallahu 'alaihi wasallam menang terhadap suatu kaum, maka beliau senang tinggal di wilayah mereka selama tiga hari.\""},"1996":{"ar":" حَدَّثَنَا عَبْدُ اللَّهِ بْنُ سَعِيدٍ حَدَّثَنَا عُقْبَةُ بْنُ خَالِدٍ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ حَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَخْلَ بَنِي النَّضِيرِ","id":"Telah menceritakan kepada kami [Abdullah bin Sa'id] telah menceritakan kepada kami ['Uqbah bin Khalid] telah menceritakan kepada kami ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah membakar pohon kurma Bani Nadhir.\""},"1997":{"ar":" أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عُمَرَ بْنِ أَبَانَ حَدَّثَنَا عَبْدُ الرَّحِيمِ بْنُ سُلَيْمَانَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ أَبِي إِسْحَقَ الدَّوْسِيِّ عَنْ أَبِي هُرَيْرَةَ الدَّوْسِيِّ قَالَ بَعَثَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي سَرِيَّةٍ فَقَالَ إِنْ ظَفِرْتُمْ بِفُلَانٍ وَفُلَانٍ فَحَرِّقُوهُمَا بِالنَّارِ حَتَّى إِذَا كَانَ الْغَدُ بَعَثَ إِلَيْنَا فَقَالَ إِنِّي كُنْتُ أَمَرْتُكُمْ بِتَحْرِيقِ هَذَيْنِ الرَّجُلَيْنِ ثُمَّ رَأَيْتُ أَنَّهُ لَا يَنْبَغِي لِأَحَدٍ أَنْ يُعَذِّبَ بِالنَّارِ إِلَّا اللَّهُ فَإِنْ ظَفِرْتُمْ بِهِمَا فَاقْتُلُوهُمَا","id":"Telah mengabarkan kepada kami [Abdullah bin Umar bin Aban] telah menceritakan kepada kami [Abdurrahim bin Sulaiman] dari [Muhammad bin Ishaq] dari [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyaj] dari [Abu Ishaq Ad Dausi] dari [Abu Hurairah Ad Dausi] ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengutus kami dalam suatu ekspedisi, beliau bersabda: \"Apabila kalian menangkap Fulan dan Fulan, maka bakarlah mereka berdua dengan api.\" Keesokan harinya beliau mengutus kami dan bersabda: \"Sesungguhnya aku pernah memerintahkan kalian untuk membunuh dua orang ini, kemudian aku melihat bahwa hal itu tidak layak bagi seorangpun untuk menyiksa dengan api, kecuali Allah, oleh karena itu jika kalian menangkap mereka berdua, maka bunuhlah.\""},"1998":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ عُيَيْنَةَ عَنْ عَلِيِّ بْنِ مُسْهِرٍ عَنْ عُبَيْدِ اللَّهِ هُوَ ابْنُ عُمَرَ بْنِ حَفْصِ بْنِ عَاصِمٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَ وُجِدَ فِي بَعْضِ مَغَازِي رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةٌ مَقْتُولَةٌ فَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ قَتْلِ النِّسَاءِ وَالصِّبْيَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Uyainah] dari [Ali bin Mushir] dari ['Ubaidullah yaitu Ibnu Umar bin Hafsh in 'Ashim] dari [Nafi'] dari [Ibnu Umar] ia berkata; \"Didapati seorang wanita yang terbunuh disebagian peperangan Rasulullah shallallahu 'alaihi wasallam. Setelah itu Rasulullah shallallahu 'alaihi wasallam melarang membunuh para wanita dan anak-anak.\""},"1999":{"ar":" أَخْبَرَنَا عَاصِمُ بْنُ يُوسُفَ حَدَّثَنَا أَبُو إِسْحَقَ الْفَزَارِيُّ عَنْ يُونُسَ بْنِ عُبَيْدٍ عَنْ الْحَسَنِ عَنْ الْأَسْوَدِ بْنِ سَرِيعٍ قَالَ خَرَجْنَا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزَاةٍ فَظَفِرَ بِالْمُشْرِكِينَ فَأَسْرَعَ النَّاسُ فِي الْقَتْلِ حَتَّى قَتَلُوا الذُّرِّيَّةَ فَبَلَغَ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا بَالُ أَقْوَامٍ ذَهَبَ بِهُمْ الْقَتْلُ حَتَّى قَتَلُوا الذُّرِّيَّةَ أَلَا لَا تُقْتَلَنَّ ذُرِّيَّةٌ ثَلَاثًا","id":"Telah mengabarkan kepada kami ['Ashim bin Yusuf] telah menceritakan kepada kami [Abu Ishaq Al Fazari] dari [Yunus bin 'Ubaid] dari [Al Hasan] dari [Al Aswad bin Sari'] ia berkata; \"Kami keluar bersama Rasulullah shallallahu 'alaihi wasallam dalam suatu pertempuran, kemudian kami berhasil menangkap orang-orang musyrik. orang-orangpun bersegera membunuh mereka hingga anak keturunan mereka. Ketika hal itu sampai kepada Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Bagaimana manusia berlaku semena-mena dalam membunuh, hingga mereka membunuh anak-anak, ketahuilah tidak boleh anak-anak dibunuh.\" Beliau mengucapkannya hingga tiga kali."},"2000":{"ar":" أَخْبَرَنَا مُحَمَّدُ بْنُ يُوسُفَ عَنْ سُفْيَانَ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَطِيَّةَ الْقُرَظِيِّ قَالَ عُرِضْنَا عَلَى النَّبِيِّ صَلّ��ى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَئِذٍ فَمَنْ أَنْبَتَ الشَّعْرَ قُتِلَ وَمَنْ لَمْ يُنْبِتْ تُرِكَ فَكُنْتُ أَنَا مِمَّنْ لَمْ يُنْبِتْ الشَّعْرَ فَلَمْ يَقْتُلُونِي يَعْنِي يَوْمَ قُرَيْظَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yusuf] dari [Sufyan] dari [Abdul Malik bin 'Umair] dari ['Athiyyah Al Qurazhi] ia berkata; \"Ketika kami pernah dihadapkan kepada Nabi shallallahu 'alaihi wasallam, maka orang-orang yang telah tumbuh rambut kemaluannya dibunuh, sementara orang-orang yang belum tumbuh dibiarkan, dan aku termasuk dari orang yang belum tumbuh rambut kemaluanku, hingga mereka tidak membunuhku, yaitu ketika perang Quraizhah.\""}};
